export function localizedAgentGuidesPartJ(en: Guides): Partial<Record<LandingLocaleCode, Guides>> {
  return {
    'pl': {
      'claude-code': {
        ...en['claude-code']!,
        title: "Claude Code dla projektowania — Open Design",
        description: "Jak projektanci wykorzystują Claude Code do projektowania UI i stron internetowych oraz jak Open Design zamienia go w prawdziwego agenta projektowego — local-first, BYOK, z wyselekcjonowaną biblioteką skills i systemów projektowych.",
        breadcrumb: "Claude Code",
        label: "Agent · Claude Code",
        heading: "Claude Code dla projektowania.",
        lead: "Claude Code to terminalowy agent kodujący od Anthropic. Ludzie już używają go do budowania interfejsów, systemów projektowych i stron docelowych. Open Design wpina go w prawdziwy proces projektowy — przynieś swój klucz Anthropic lub subskrypcję Claude i zachowaj każdy plik lokalnie.",
        rich: {"heroCtaLead": "Open Design zamienia Claude Code w local-first, open-source'owego agenta projektowego — twój klucz Anthropic lub subskrypcja Claude, twoje pliki, a wokół nich wyselekcjonowana biblioteka skills i systemów projektowych.", "heroCtaActions": [{"label": "Użyj Claude Code w Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Zostaw gwiazdkę na GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Pobierz aplikację desktopową", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["Claude Code jest powszechnie uważany za agenta kodującego o najlepszym wyczuciu frontendu — rozumuje o interfejsach z niezwykłą precyzją, podając dokładne wartości hex, odstępy i skale typograficzne, oraz refaktoryzuje UI w dużej bazie kodu, nie gubiąc wątku. Ale prosto z pudełka i tak skłania się ku generycznemu wyglądowi, dopóki nie podasz mu systemu projektowego, skills i prawdziwych referencji. To praktyczny, kompleksowy przewodnik po wykorzystaniu Claude Code do pracy nad UI, frontendem i systemami projektowymi oraz po wpięciu go w ustrukturyzowany proces z Open Design.", "Obejmuje on to, czym właściwie jest Claude Code, dlaczego jest mocny we frontendzie, jak skonfigurować go od zera, proces pracy z CLAUDE.md i Skills, oficjalny obieg dwukierunkowy z Figmą, jak wypada na tle Codeksa i Cursora, pułapki, przez które wynik AI wygląda generycznie, oraz jak Open Design zasypuje tę lukę jako otwarta, local-first warstwa projektowa."], "heroImage": {"src": "/agents/claude-code-design/claude-code-design-hero.webp", "alt": "Pętla informacji zwrotnej w projektowaniu z Claude Code: terminalowy agent podejmujący konkretne decyzje projektowe, przeglądarka renderująca UI oraz przestrzeń robocza, ze strzałką sprzężenia zwrotnego zawracającą do początku", "caption": "Główna pętla: Claude Code wyrozumowuje konkretne decyzje dotyczące UI w terminalu, renderuje je i weryfikuje w prawdziwej przeglądarce oraz zbiega się ku twoim referencjom."}, "tocLabel": "Na tej stronie", "toc": [{"id": "what-is-claude-code", "label": "Czym właściwie jest Claude Code"}, {"id": "why-design", "label": "Dlaczego Claude Code jest dobry w projektowaniu"}, {"id": "setup", "label": "Skonfiguruj Claude Code do projektowania (od zera)"}, {"id": "skills-workflow", "label": "Proces pracy z CLAUDE.md i Skills"}, {"id": "figma", "label": "Claude Code + dwukierunkowy obieg z Figmą"}, {"id": "vs", "label": "Claude Code kontra Codex kontra Cursor"}, {"id": "pitfalls", "label": "Pułapki i wygląd „AI slop”"}, {"id": "open-design", "label": "Projektowanie z Claude Code w Open Design"}, {"id": "faq", "label": "FAQ"}], "sections": [{"id": "what-is-claude-code", "heading": "Czym właściwie jest Claude Code", "blocks": [{"kind": "p", "text": "Claude Code to agentowe narzędzie do kodowania od Anthropic. Czyta twoją bazę kodu, edytuje pliki, uruchamia polecenia i integruje się z twoimi narzędziami deweloperskimi — planuje, pisze i weryfikuje pracę na podstawie zadań w języku naturalnym, zamiast tylko uzupełniać linijki."}, {"kind": "p", "text": "Dostarczany jest na kilku powierzchniach, które dzielą ten sam silnik: terminalowy CLI, rozszerzenia IDE dla VS Code, Cursora i JetBrains, aplikacja desktopowa z wizualnym przeglądem diffów oraz wersja webowa do długotrwałych zadań. Twoje pliki CLAUDE.md, ustawienia i serwery MCP przenoszą się między nimi wszystkimi."}, {"kind": "steps", "items": [{"label": "Plik instrukcji", "body": "Claude Code czyta plik CLAUDE.md w korzeniu projektu na początku każdej sesji — to naturalne miejsce, by zakodować swoje konwencje projektowe, tokens i listy kontrolne przeglądu."}, {"label": "Skills", "body": "Agent Skills pakują powtarzalne instrukcje, skrypty i zasoby, które Claude ładuje na żądanie, w tym oficjalny skill Frontend Design od Anthropic dla wyczucia smaku."}, {"label": "Plan i podagenci", "body": "Może planować przed działaniem i powoływać podagentów pracujących równolegle nad różnymi częściami zadania, co utrzymuje spójność dużych refaktoryzacji UI."}]}, {"kind": "ul", "items": ["Dostawca: Anthropic", "Poświadczenie: klucz API Anthropic (BYOK, przez Console) lub subskrypcja Claude (Pro / Max)", "Powierzchnie: terminalowy CLI, rozszerzenia VS Code / Cursor / JetBrains, aplikacja desktopowa, web"]}]}, {"id": "why-design", "heading": "Dlaczego Claude Code jest dobry w projektowaniu", "blocks": [{"kind": "p", "text": "Wśród agentów kodujących Claude Code ma reputację narzędzia o wyczuciu smaku w pracy frontendowej. Wyjaśnia to kilka rzeczy."}, {"kind": "steps", "items": [{"label": "Konkretne, a nie mgliste decyzje", "body": "Claude Code zwykle zobowiązuje się do konkretnych wyborów — dokładnych wartości hex, skal odstępów, ramp typograficznych i hierarchii komponentów — zamiast machać ręką, a właśnie to odróżnia prawdziwy interfejs od atrapy."}, {"label": "Rozumowanie świadome bazy kodu", "body": "Dysponując dużym kontekstem roboczym, refaktoryzuje UI w wielu plikach naraz, ponownie wykorzystując twoje istniejące komponenty i tokens zamiast wymyślać jednorazowe style."}, {"label": "Oficjalny skill frontendowy", "body": "Anthropic dostarcza skill Frontend Design, który sprawia, że Claude najpierw spisuje kierunek projektowy i celowo odchodzi od generycznych czcionek systemowych i przewidywalnych fioletowych gradientów."}]}, {"kind": "image", "src": "/agents/claude-code-design/claude-code-design-taste-triangle.webp", "alt": "Diagram pokazujący, jak system projektowy, skill i obraz referencyjny zbiegają się w dobry wynik projektowy", "caption": "Wyczucie smaku bierze się z trzech wkładów, które dostarczasz: systemu projektowego, skilla i prawdziwych obrazów referencyjnych."}, {"kind": "p", "text": "Wniosek jest ten sam, który Anthropic formułuje o własnych modelach: Claude domyślnie nie ma wyczucia smaku — pozostawiony sam sobie zbiega ku statystycznemu środkowi projektowania webowego (Inter, fioletowe gradienty, miękkie cienie). Tworzy dobry projekt, gdy podasz mu ograniczenia. Open Design pakuje dokładnie te wkłady, dlatego te dwie rzeczy do siebie pasują (więcej poniżej)."}]}, {"id": "setup", "heading": "Skonfiguruj Claude Code do pracy projektowej, od zera", "blocks": [{"kind": "p", "text": "Oto pełna ścieżka od czystej maszyny do Claude Code, który potrafi budować i weryfikować UI."}, {"kind": "code", "lang": "bash", "code": "# 1. Install Claude Code (native install, recommended)\ncurl -fsSL https://claude.ai/install.sh | bash\n# or: brew install --cask claude-code\n# Windows PowerShell: irm https://claude.ai/install.ps1 | iex\n\n# 2. Start it in your project and sign in on first run\ncd your-project\nclaude            # sign in with your Claude subscription or API key\n\n# 3. Generate project context\n/init             # creates a CLAUDE.md for this project\n\n# 4. Add the official Frontend Design skill\nclaude plugin install frontend-design@claude-plugins-official\n\n# 5. Wire the Figma MCP server (optional, for design handoff)\nclaude plugin install figma@claude-plugins-official"}, {"kind": "image", "src": "/agents/claude-code-design/claude-code-design-setup-flow.webp", "alt": "Pięciokrokowy proces konfiguracji: instalacja, uwierzytelnienie, konfiguracja CLAUDE.md, dodanie skilla, weryfikacja", "caption": "Sekwencja konfiguracji: instalacja → uwierzytelnienie → konfiguracja CLAUDE.md → dodanie skilla Frontend Design → włączenie weryfikacji w przeglądarce."}, {"kind": "steps", "items": [{"label": "Zakoduj swoje reguły projektowe", "body": "Umieść swoje tokens, prymitywy i konwencje w CLAUDE.md i nakieruj na nie Claude'a, aby wynik pasował do marki, zamiast domyślać się generycznego wyglądu."}, {"label": "Dodaj weryfikację w przeglądarce", "body": "Podłącz MCP Playwright lub Chrome, aby Claude renderował w prawdziwej przeglądarce i sprawdzał swój wynik na różnych breakpointach, zamiast tylko potwierdzać, że build przechodzi."}]}]}, {"id": "skills-workflow", "heading": "Proces pracy z CLAUDE.md i Skills", "blocks": [{"kind": "p", "text": "Najbardziej dźwigniową pętlą projektową z Claude Code jest podawanie mu prawdziwych referencji wraz z twoim kontekstem projektowym, a następnie iterowanie, aż UI się zgodzi — przy czym CLAUDE.md i Skills niosą ograniczenia, więc nie musisz tłumaczyć ich od nowa przy każdym poleceniu."}, {"kind": "ol", "items": ["Zacznij od najczytelniejszych referencji wizualnych, jakie masz — i uwzględnij wiele stanów (desktop i mobile, hover, pusty, ładowanie), nie tylko jeden kadr bohaterski.", "Bądź konkretny w poleceniu; mgliste polecenia dają generyczne UI nawet przy silnym agencie.", "Trzymaj swój system projektowy i konwencje w CLAUDE.md i powiedz Claude'owi, gdzie znajdują się tokens i kanoniczne prymitywy.", "Dodaj skill Frontend Design, aby Claude zobowiązał się do prawdziwego kierunku estetycznego, zanim napisze kod.", "Podłącz weryfikację w przeglądarce, aby Claude renderował, zmieniał rozmiar do breakpointów i porównywał z referencjami — a nie tylko potwierdzał, że się buduje."]}, {"kind": "p", "text": "Wrzuć obraz referencyjny do sesji i daj polecenie z konkretnymi ograniczeniami:"}, {"kind": "code", "lang": "bash", "code": "claude \"Implement reference-desktop.png and reference-mobile.png in\n  React + Vite + Tailwind + TypeScript.\n  Reuse the design-system components and tokens described in CLAUDE.md.\n  Match spacing, layout, and hierarchy; make it responsive.\n  Render it in the browser, verify it matches the references across\n  breakpoints, and iterate until it does.\""}, {"kind": "p", "text": "Uruchom obok serwer deweloperski, trzymaj polecenia krótkie i skupione oraz commituj dobre iteracje / cofaj złe (mówiąc Claude'owi, kiedy cofasz), aby każde przejście budowało na czystej bazie. Używaj trybu planu do większych refaktoryzacji, abyś mógł przejrzeć podejście przed jakąkolwiek zmianą plików."}]}, {"id": "figma", "heading": "Claude Code + Figma: dwukierunkowy obieg projekt ↔ kod", "blocks": [{"kind": "p", "text": "W lutym 2026 Anthropic i Figma dostarczyły pierwszorzędną, dwukierunkową integrację za pośrednictwem serwera Figma MCP. Działa w obie strony."}, {"kind": "steps", "items": [{"label": "Projekt → Kod", "body": "Zaznacz ramkę w Figmie lub wklej link do Claude Code, pobierz kontekst projektowy i poproś go o implementację projektu z użyciem twojej istniejącej biblioteki komponentów. Code Connect utrzymuje wynik zgodny z twoimi rzeczywistymi komponentami."}, {"label": "Kod → Projekt", "body": "Zbuduj i podejrzyj funkcję w przeglądarce, a następnie powiedz „Send this to Figma”, aby uchwycić działające UI jako edytowalne warstwy Figmy — cały ekran lub wybrany element."}]}, {"kind": "p", "text": "Zainstaluj go raz poleceniem claude plugin install figma@claude-plugins-official (Dev Mode MCP wymaga płatnego planu Figma). Ten sam Figma MCP jest dostępny dla Claude Code, Codeksa, Cursora i VS Code — dokładnie ten rodzaj przenośnej, wieloagentowej możliwości, do orkiestracji której zbudowany jest Open Design."}]}, {"id": "vs", "heading": "Claude Code kontra Codex kontra Cursor w projektowaniu", "blocks": [{"kind": "p", "text": "Nie ma jednego zwycięzcy w pracy projektowej — każdy agent ma inną mocną stronę, a doświadczone zespoły zestawiają je ze sobą. Uczciwe podsumowanie:"}, {"kind": "table", "columns": ["Agent", "Mocna strona projektowa", "Najlepszy do"], "rows": [["Claude Code", "Konkretne decyzje projektowe (hex, odstępy, typografia) i rozumowanie UX świadome bazy kodu", "Rozumowanie frontendowe i refaktoryzacje w dużym kontekście"], ["Codex", "Mocne dopracowanie wizualne i rozumienie obrazów; asynchroniczne buildy w sandboksie", "Delegowane asynchroniczne buildy i przenośne reguły AGENTS.md"], ["Cursor", "Wizualna pętla buduj-i-zobacz z podglądem na żywo i edycjami inline", "Ciasna praca nad UI w trybie iteruj-i-obserwuj wewnątrz IDE"]]}, {"kind": "p", "text": "Powracający werdykt społeczności jest taki, że wyczucie smaku pochodzi od ludzi: cała trójka domyślnie zbiega ku generycznej estetyce bez skills, referencji i ograniczeń. To jest prawdziwy problem do rozwiązania — i ma on kształt narzędzia projektowego, a nie modelu."}]}, {"id": "pitfalls", "heading": "Pułapki i jak unikać wyglądu „AI slop”", "blocks": [{"kind": "p", "text": "Nawet przy reputacji Claude Code za wyczucie smaku najczęstszą skargą na projekty generowane przez AI jest to, że wyglądają generycznie — czcionki Inter, fioletowe gradienty na bieli, miękkie cienie, przeskalowane zaokrąglone rogi, estetyka, która „krzyczy, że zrobiło to AI”. Sam Anthropic przypisuje to zbieżności rozkładowej: bezpieczne wybory dominują w danych treningowych z sieci. Inne zgłaszane problemy to popsute układy mobilne i przeciekanie instrukcji do treści UI."}, {"kind": "steps", "items": [{"label": "Zainstaluj skill Frontend Design", "body": "Zmusza Claude'a do zobowiązania się do prawdziwego kierunku i wyraźnie unika czcionek oraz gradientów nadużywanych przez AI."}, {"label": "Włącz weryfikację w przeglądarce", "body": "Spraw, aby Claude renderował i sam się sprawdzał na różnych breakpointach, tak by układy nie psuły się po cichu na mobile."}, {"label": "Dostarcz tokens i referencje", "body": "Prawdziwe design tokens i zrzuty ekranu referencji to pojedyncza największa dźwignia jakości wyniku."}, {"label": "Zakoduj reguły w CLAUDE.md", "body": "Umieść reguły w stylu „bez kart bohaterskich, najwyżej dwa kroje pisma, hierarchia stawiająca markę na pierwszym miejscu” tam, gdzie agent czyta je przy każdym uruchomieniu."}]}, {"kind": "p", "text": "Zauważ, że każde z tych zabezpieczeń polega na daniu agentowi wyselekcjonowanego kontekstu projektowego. Ręczne utrzymywanie tego kontekstu, projekt po projekcie, to mozół, który usuwa Open Design."}]}, {"id": "open-design", "heading": "Projektowanie z Claude Code wewnątrz Open Design", "blocks": [{"kind": "p", "text": "Open Design to open-source'owa warstwa projektowa, o którą powyższy proces wciąż się dopomina. Traktuje Claude Code jako adapter pierwszej kategorii i otacza go wyselekcjonowaną biblioteką skills i systemów projektowych, ustrukturyzowanym potokiem renderowania oraz lokalnym desktopowym UI — więc kontekst projektowy, który czyni Claude Code dobrym, jest dostępny od pierwszego uruchomienia, a nie składany ręcznie za każdym razem."}, {"kind": "ol", "items": ["Zainstaluj Open Design i wybierz Claude Code jako swojego agenta.", "Uwierzytelnij się swoim kluczem API Anthropic (BYOK) lub subskrypcją Claude — poświadczenia pozostają na twojej maszynie i nigdy nie są przekierowywane przez nas.", "Wybierz system projektowy i skill, a następnie generuj prezentacje, prototypy i strony docelowe ze spójnym wyczuciem smaku.", "Każdy artefakt i plik DESIGN.md żyje w twoim własnym repozytorium, a nie w hostowanej chmurze."]}, {"kind": "p", "text": "Ten sam agent Claude Code, ten sam klucz — plus prawdziwy, przenośny, open-source'owy proces projektowy wokół niego. Jest local-first i na licencji Apache-2.0, więc nic z twojej pracy ani twoich poświadczeń nie opuszcza twojej maszyny."}]}], "faqTitle": "Najczęściej zadawane pytania", "faq": [{"name": "Czy Claude Code nadaje się do pracy projektowej?", "text": "Tak — jest powszechnie uważany za agenta kodującego o najlepszym wyczuciu frontendu, podejmującego konkretne, świadome bazy kodu decyzje dotyczące wartości hex, odstępów i skal typograficznych. Mając w kontekście skill Frontend Design, system projektowy i prawdziwe obrazy referencyjne, tworzy responsywne UI o jakości produkcyjnej i potrafi je zweryfikować w przeglądarce. Bez tego kontekstu skłania się ku generycznemu wyglądowi, i to jest luka, którą wypełnia Open Design."}, {"name": "Czy potrzebuję subskrypcji Claude, aby projektować z Claude Code?", "text": "Możesz użyć albo klucza API Anthropic (BYOK, przez Console), albo subskrypcji Claude (Pro / Max). Tak czy inaczej Open Design nigdy nie przekierowuje twoich poświadczeń — są one używane bezpośrednio przez twojego agenta na twojej maszynie."}, {"name": "Claude Code czy Codex do projektowania frontendu?", "text": "Oba są mocne. Claude Code jest znany z konkretnych, świadomych bazy kodu decyzji projektowych i rozumowania frontendowego; Codex ma mocne dopracowanie wizualne i wyróżnia się w delegowanych buildach w sandboksie. Wiele zespołów używa obu — Open Design pozwala przełączać agentów bez zmiany twojego procesu projektowego."}, {"name": "Jak połączyć Claude Code z Figmą?", "text": "Zainstaluj oficjalny plugin Figma poleceniem claude plugin install figma@claude-plugins-official. Następnie możesz implementować ramki Figmy w kodzie z użyciem kontekstu projektowego oraz wypchnąć działające UI z powrotem do edytowalnych ramek Figmy za pomocą „Send this to Figma”. Dev Mode MCP wymaga płatnego planu Figma."}, {"name": "Czym są Skills i CLAUDE.md?", "text": "CLAUDE.md to plik markdown w korzeniu projektu, który Claude Code czyta na początku każdej sesji — miejsce na zakodowanie twoich konwencji projektowych. Skills pakują powtarzalne instrukcje i zasoby, które Claude ładuje na żądanie, w tym oficjalny skill Frontend Design od Anthropic. Open Design dostarcza wyselekcjonowaną bibliotekę obu, więc omijasz konfigurację dla każdego projektu z osobna."}, {"name": "Jak uniknąć generycznej estetyki „AI slop”?", "text": "Zainstaluj skill Frontend Design, dostarcz prawdziwe design tokens i zrzuty ekranu referencji, zakoduj reguły marki w CLAUDE.md oraz włącz weryfikację w przeglądarce. Open Design dostarcza je jako wyselekcjonowaną bibliotekę, więc omijasz konfigurację dla każdego projektu z osobna."}, {"name": "Czy Open Design jest powiązany z Anthropic?", "text": "Nie. Claude Code jest produktem Anthropic; Open Design to niezależny projekt open-source, który wspiera go jako adapter pierwszej kategorii. Claude i Claude Code są znakami towarowymi Anthropic."}, {"name": "Czy moje pliki i poświadczenia są bezpieczne?", "text": "Tak — Open Design jest local-first i na licencji Apache-2.0. Twoje pliki, artefakty i DESIGN.md pozostają w twoim własnym repozytorium, a twoje poświadczenia Anthropic są używane bezpośrednio przez twojego agenta, nigdy nie są przekierowywane przez serwery Open Design."}], "ctaTitle": "Projektuj z Claude Code, w otwarty sposób.", "ctaBody": "Przynieś własny klucz Anthropic lub subskrypcję Claude, zachowaj każdy plik lokalnie i zyskaj wyselekcjonowaną bibliotekę projektową wokół agenta, którego już używasz.", "ctaActions": [{"label": "Użyj Claude Code w Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Zostaw gwiazdkę na GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Pobierz aplikację desktopową", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Zobacz wszystkich obsługiwanych agentów"},
      },
      'codex': {
        ...en['codex']!,
        title: "Codex dla projektowania — Open Design",
        description: "Jak ludzie wykorzystują OpenAI Codex do projektowania UI i stron internetowych — plugin Product Design, integracja z Figmą, skills frontendowe — i jak Open Design zamienia Codeksa w local-first, open-source'owego agenta projektowego.",
        breadcrumb: "Codex",
        label: "Agent · Codex",
        heading: "Codex dla projektowania.",
        lead: "Codex to agent kodujący od OpenAI. Dzięki swojemu pluginowi Product Design i integracji z Figmą stał się poważnym narzędziem projektowym. Open Design wpina Codeksa w open-source'owy proces projektowy — twój klucz OpenAI lub subskrypcja ChatGPT, twoje pliki, local-first.",
        rich: {"heroCtaLead": "Open Design zamienia Codeksa w local-first, open-source'owego agenta projektowego — twój klucz OpenAI, twoje pliki, a wokół nich wyselekcjonowana biblioteka skills i systemów projektowych.", "heroCtaActions": [{"label": "Użyj Codeksa w Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Zostaw gwiazdkę na GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Pobierz aplikację desktopową", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["OpenAI Codex zaczynał jako generator kodu, ale w 2026 stał się wiarygodnym narzędziem do projektowania prawdziwych interfejsów — gdy tylko podasz mu właściwe referencje, skills i pętlę weryfikacji. To praktyczny, kompleksowy przewodnik po wykorzystaniu Codeksa do pracy nad UI, frontendem i systemami projektowymi oraz po wpięciu go w ustrukturyzowany proces projektowy z Open Design.", "Obejmuje on to, czym Codex jest dzisiaj, dlaczego nagle jest dobry we frontendzie, jak skonfigurować go od zera, pętlę zrzut-ekranu-do-UI, oficjalny dwukierunkowy obieg z Figmą, jak wypada na tle Cursora i Claude Code, pułapki, przez które wynik AI wygląda generycznie, oraz jak Open Design zasypuje tę lukę jako otwarta, local-first warstwa projektowa."], "heroImage": {"src": "/agents/codex-design/codex-design-workflow-loop.webp", "alt": "Pętla informacji zwrotnej w projektowaniu z Codeksem: terminalowy agent, przeglądarka renderująca UI oraz przestrzeń robocza, ze strzałką sprzężenia zwrotnego zawracającą do początku", "caption": "Główna pętla: Codex buduje UI w terminalu, renderuje je i weryfikuje w prawdziwej przeglądarce oraz iteruje względem twoich referencji."}, "tocLabel": "Na tej stronie", "toc": [{"id": "what-is-codex", "label": "Czym właściwie jest OpenAI Codex"}, {"id": "why-design", "label": "Dlaczego Codex jest teraz dobry w projektowaniu"}, {"id": "setup", "label": "Skonfiguruj Codeksa do projektowania (od zera)"}, {"id": "screenshot-workflow", "label": "Proces zrzut-ekranu-do-UI"}, {"id": "figma", "label": "Codex + dwukierunkowy obieg z Figmą"}, {"id": "vs", "label": "Codex kontra Cursor kontra Claude Code"}, {"id": "pitfalls", "label": "Pułapki i wygląd „AI slop”"}, {"id": "open-design", "label": "Projektowanie z Codeksem w Open Design"}, {"id": "faq", "label": "FAQ"}], "sections": [{"id": "what-is-codex", "heading": "Czym właściwie jest OpenAI Codex (a czym nie jest)", "blocks": [{"kind": "p", "text": "Najpierw rozróżnienie, które myli niemal każdego, kto szuka „Codeksa”. Pierwotny OpenAI Codex był modelem uzupełniania kodu z 2021 roku, który napędzał wczesny GitHub Copilot i został wycofany w 2023. Nie o tym jest ta strona. Dzisiejszy Codex to agentowe narzędzie do kodowania od OpenAI — planuje, pisze, uruchamia i weryfikuje kod na podstawie zadań w języku naturalnym."}, {"kind": "p", "text": "Nowoczesny Codex dostarczany jest na czterech powierzchniach: terminalowy CLI (przepisany w Rust, na licencji Apache-2.0), rozszerzenie IDE dla VS Code, Cursora i Windsurfa, doświadczenie chmurowe/webowe do delegowanych zadań asynchronicznych oraz aplikacja desktopowa z wbudowaną przeglądarką i Computer Use."}, {"kind": "steps", "items": [{"label": "Domyślny model", "body": "Od połowy 2026 zalecanym modelem jest gpt-5.5, przy czym gpt-5.4 to model, który OpenAI wprost wytrenowało pod frontend i computer use."}, {"label": "Plik instrukcji", "body": "Codex czyta plik AGENTS.md w twoim projekcie (standard międzynarzędziowy) w poszukiwaniu reguł projektu — naturalne miejsce, by zakodować twoje konwencje projektowe."}, {"label": "Sandbox", "body": "Działa w sandboksie na poziomie jądra (domyślnie workspace-write), więc agent edytujący twoje UI nie może wyjść poza projekt."}]}, {"kind": "ul", "items": ["Dostawca: OpenAI", "Poświadczenie: klucz API OpenAI (BYOK) lub subskrypcja ChatGPT (Free / Go / Plus / Pro / Business / Enterprise)", "Licencja CLI: Apache-2.0, open source"]}]}, {"id": "why-design", "heading": "Dlaczego Codex jest teraz dobry w projektowaniu", "blocks": [{"kind": "p", "text": "Na początku 2026 zbiegły się trzy rzeczy, które uczyniły z Codeksa prawdziwe narzędzie projektowe, a nie generyczny generator kodu."}, {"kind": "steps", "items": [{"label": "Model wytrenowany pod frontend", "body": "OpenAI dostarczyło GPT-5.4, swój pierwszy główny model wytrenowany pod frontend i computer use, ze znacznie lepszym rozumieniem obrazów w całym procesie projektowym i silniejszą samoweryfikacją. Potrafi nawet generować mood boardy i opcje wizualne, zanim zobowiąże się do finalnych zasobów."}, {"label": "Oficjalny skill frontendowy", "body": "Katalog openai/skills dostarcza wyselekcjonowany skill frontendowy, który egzekwuje prawdziwe wyczucie smaku: układy bez kart, hero na całą szerokość, hierarchia stawiająca markę na pierwszym miejscu, powściągliwy ruch, najwyżej dwa kroje pisma i jeden kolor akcentu — i sprawia, że Codex spisuje tezę wizualną przed budowaniem."}, {"label": "Weryfikacja w przeglądarce", "body": "Dzięki skillowi Playwright Codex otwiera prawdziwą przeglądarkę, zmienia rozmiar do breakpointów i porównuje swój wynik z referencją, zamiast tylko sprawdzać, że build przechodzi."}]}, {"kind": "image", "src": "/agents/codex-design/codex-design-taste-triangle.webp", "alt": "Diagram pokazujący, jak system projektowy, skill i obraz referencyjny zbiegają się w dobry wynik projektowy", "caption": "Wyczucie smaku bierze się z trzech wkładów, które dostarczasz: systemu projektowego, skilla i prawdziwych obrazów referencyjnych."}, {"kind": "p", "text": "Wniosek za całą trójką: Codex domyślnie nie ma wyczucia smaku. Tworzy dobry projekt, gdy podasz mu ograniczenia — system projektowy, skill estetyczny i konkretne referencje. Open Design pakuje dokładnie te wkłady, dlatego te dwie rzeczy do siebie pasują (więcej poniżej)."}]}, {"id": "setup", "heading": "Skonfiguruj Codeksa do pracy projektowej, od zera", "blocks": [{"kind": "p", "text": "Oto pełna ścieżka od czystej maszyny do Codeksa, który potrafi budować i weryfikować UI."}, {"kind": "code", "lang": "bash", "code": "# 1. Install the Codex CLI\nnpm install -g @openai/codex\n# or: brew install --cask codex\n# or: curl -fsSL https://chatgpt.com/codex/install.sh | sh\n\n# 2. Authenticate (ChatGPT sign-in recommended for higher limits)\ncodex            # then choose “Sign in with ChatGPT”\n\n# 3. Generate project context\ncodex            # inside your project, run /init to create AGENTS.md\n\n# 4. Add the official frontend skill, then restart Codex\n# (in the Codex app) $skill-installer frontend-skill\n\n# 5. Wire the Figma MCP server (optional, for design handoff)\ncodex mcp add figma --url https://mcp.figma.com/mcp"}, {"kind": "image", "src": "/agents/codex-design/codex-design-setup-flow.webp", "alt": "Pięciokrokowy proces konfiguracji: instalacja, uwierzytelnienie, konfiguracja, instalacja skilla, weryfikacja", "caption": "Sekwencja konfiguracji: instalacja → uwierzytelnienie → konfiguracja AGENTS.md → instalacja skilla frontendowego → włączenie weryfikacji w przeglądarce."}, {"kind": "steps", "items": [{"label": "Zakoduj swoje reguły projektowe", "body": "Umieść swoje tokens, prymitywy i konwencje w AGENTS.md lub DESIGN.md i nakieruj na nie Codeksa, aby wynik pasował do marki, zamiast domyślać się generycznego wyglądu."}, {"label": "Wybierz właściwy poziom rozumowania", "body": "OpenAI zauważa, że niskie-do-średnich poziomy rozumowania często dają silniejsze rezultaty frontendowe niż ustawienie najwyższe."}]}]}, {"id": "screenshot-workflow", "heading": "Proces zrzut-ekranu-do-UI", "blocks": [{"kind": "p", "text": "Najbardziej dźwigniową pętlą projektową z Codeksem jest zamiana obrazu referencyjnego w działające, responsywne UI i iterowanie, aż się zgodzi. Własne wskazówki OpenAI sprowadzają się do pięciu kroków."}, {"kind": "ol", "items": ["Zacznij od najczytelniejszych referencji wizualnych, jakie masz — i uwzględnij wiele stanów (desktop i mobile, hover, pusty, ładowanie), nie tylko jeden kadr bohaterski.", "Bądź konkretny w poleceniu; mgliste polecenia dają generyczne UI.", "Przygotuj system projektowy i powiedz Codeksowi, gdzie znajdują się tokens i kanoniczne prymitywy.", "Włącz interaktywny skill Playwright, aby Codex renderował w prawdziwej przeglądarce i zmieniał rozmiar do breakpointów.", "Iteruj, każąc Codeksowi porównywać swoją implementację z powrotem ze zrzutami ekranu — a nie tylko potwierdzać, że się buduje."]}, {"kind": "p", "text": "Podaj obrazy, przeciągając zrzut ekranu do terminala lub używając flagi obrazu, a następnie daj polecenie z konkretnymi ograniczeniami:"}, {"kind": "code", "lang": "bash", "code": "codex -i reference-desktop.png -i reference-mobile.png \\\n  \"Implement this design in React + Vite + Tailwind + TypeScript.\n   Reuse my existing design-system components and tokens.\n   Match spacing, layout, and hierarchy; make it responsive.\n   Use the Playwright skill to verify the UI matches the\n   references and iterate until it does.\""}, {"kind": "p", "text": "Uruchom serwer deweloperski w drugim terminalu, trzymaj polecenia krótkie i skupione oraz commituj dobre iteracje / cofaj złe (mówiąc Codeksowi, kiedy cofasz), aby każde przejście budowało na czystej bazie."}]}, {"id": "figma", "heading": "Codex + Figma: dwukierunkowy obieg projekt ↔ kod", "blocks": [{"kind": "p", "text": "W lutym 2026 OpenAI i Figma ogłosiły oficjalne partnerstwo, zamieniając wcześniejszą betę Figma MCP w pierwszorzędną, dwukierunkową integrację. Działa w obie strony."}, {"kind": "steps", "items": [{"label": "Projekt → Kod", "body": "Skopiuj „link to selection” ramki w Figmie, wklej go do Codeksa z get_design_context i poproś o implementację projektu z użyciem twojej istniejącej biblioteki komponentów."}, {"label": "Kod → Projekt", "body": "Narzędzie generate_figma_design („Code to Canvas”) zamienia działające, uruchomione UI z powrotem w edytowalne ramki Figmy — cały ekran, wybrany element lub cały plik."}]}, {"kind": "p", "text": "Figma MCP działa jako serwer zdalny i jest zwolniony z limitów przepustowości. Dodaj go raz, a jest dostępny dla Codeksa, Claude Code, Cursora, VS Code i innych — dokładnie ten rodzaj przenośnej, wieloagentowej możliwości, do orkiestracji której zbudowany jest Open Design."}]}, {"id": "vs", "heading": "Codex kontra Cursor kontra Claude Code w projektowaniu", "blocks": [{"kind": "p", "text": "Nie ma jednego zwycięzcy w pracy projektowej — każdy agent ma inną mocną stronę, a doświadczone zespoły zestawiają je ze sobą. Uczciwe podsumowanie:"}, {"kind": "table", "columns": ["Agent", "Mocna strona projektowa", "Najlepszy do"], "rows": [["Codex", "Mocne dopracowanie wizualne po GPT-5.4 + skill frontendowy; rozumienie obrazów", "Delegowane asynchroniczne buildy, uruchomienia w sandboksie, przenośne reguły AGENTS.md"], ["Cursor", "Wizualna pętla buduj-i-zobacz z podglądem na żywo i edycjami inline", "Ciasna praca nad UI w trybie iteruj-i-obserwuj wewnątrz IDE"], ["Claude Code", "Konkretne decyzje projektowe (hex, odstępy, typografia) i UX świadomy bazy kodu", "Rozumowanie frontendowe i refaktoryzacje w dużym kontekście"]]}, {"kind": "p", "text": "Powracający werdykt społeczności jest taki, że wyczucie smaku pochodzi od ludzi: cała trójka domyślnie zbiega ku generycznej estetyce bez skills, referencji i ograniczeń. To jest prawdziwy problem do rozwiązania — i ma on kształt narzędzia projektowego, a nie modelu."}]}, {"id": "pitfalls", "heading": "Pułapki i jak unikać wyglądu „AI slop”", "blocks": [{"kind": "p", "text": "Najczęstszą skargą na projekty generowane przez Codeksa jest to, że wyglądają generycznie — miękkie gradienty, unoszące się panele, przeskalowane zaokrąglone rogi, dramatyczne cienie, klimat Inter-i-fiolet, który „krzyczy, że zrobiło to AI”. Inne zgłaszane problemy to popsute układy mobilne, przeciekanie instrukcji do treści UI oraz szybkie osiąganie limitów użycia."}, {"kind": "steps", "items": [{"label": "Zainstaluj skill frontendowy", "body": "Wyselekcjonowany skill estetyczny zmusza Codeksa do zobowiązania się do prawdziwego kierunku zamiast domyślnego wyglądu."}, {"label": "Włącz weryfikację Playwright", "body": "Spraw, aby Codex renderował i sam się sprawdzał na różnych breakpointach, tak by układy nie psuły się po cichu na mobile."}, {"label": "Dostarcz tokens i referencje", "body": "Prawdziwe design tokens i zrzuty ekranu referencji to pojedyncza największa dźwignia jakości wyniku."}, {"label": "Zakoduj reguły w AGENTS.md", "body": "Umieść reguły w stylu „bez kart bohaterskich, najwyżej dwa kroje pisma, hierarchia stawiająca markę na pierwszym miejscu” tam, gdzie agent czyta je przy każdym uruchomieniu."}]}, {"kind": "p", "text": "Zauważ, że każde z tych zabezpieczeń polega na daniu agentowi wyselekcjonowanego kontekstu projektowego. Ręczne utrzymywanie tego kontekstu, projekt po projekcie, to mozół, który usuwa Open Design."}]}, {"id": "open-design", "heading": "Projektowanie z Codeksem wewnątrz Open Design", "blocks": [{"kind": "p", "text": "Open Design to open-source'owa warstwa projektowa, o którą powyższy proces wciąż się dopomina. Traktuje Codeksa jako adapter pierwszej kategorii i otacza go wyselekcjonowaną biblioteką skills i systemów projektowych, ustrukturyzowanym potokiem renderowania oraz lokalnym desktopowym UI — więc kontekst projektowy, który czyni Codeksa dobrym, jest dostępny od pierwszego uruchomienia, a nie składany ręcznie za każdym razem."}, {"kind": "ol", "items": ["Zainstaluj Open Design i wybierz Codeksa jako swojego agenta.", "Uwierzytelnij się swoim kluczem API OpenAI (BYOK) lub subskrypcją ChatGPT — poświadczenia pozostają na twojej maszynie i nigdy nie są przekierowywane przez nas.", "Wybierz system projektowy i skill, a następnie generuj prezentacje, prototypy i strony docelowe ze spójnym wyczuciem smaku.", "Każdy artefakt i plik DESIGN.md żyje w twoim własnym repozytorium, a nie w hostowanej chmurze."]}, {"kind": "p", "text": "Ten sam agent Codex, ten sam klucz — plus prawdziwy, przenośny, open-source'owy proces projektowy wokół niego. Jest local-first i na licencji Apache-2.0, więc nic z twojej pracy ani twoich poświadczeń nie opuszcza twojej maszyny."}]}], "faqTitle": "Najczęściej zadawane pytania", "faq": [{"name": "Czy OpenAI Codex naprawdę potrafi wykonywać pracę projektową?", "text": "Tak — mając w kontekście skill frontendowy, system projektowy i prawdziwe obrazy referencyjne, Codex (zwłaszcza na GPT-5.4) tworzy responsywne UI o jakości produkcyjnej i potrafi je zweryfikować w przeglądarce. Bez tego kontekstu skłania się ku generycznemu wyglądowi, i to jest luka, którą wypełnia Open Design."}, {"name": "Czy to plugin Product Design od OpenAI Codex?", "text": "Nie. Open Design to niezależny projekt open-source, który integruje Codeksa jako agenta. Uzupełnia własne narzędzia OpenAI o local-first, otwartą bibliotekę skills i systemów projektowych."}, {"name": "Czy potrzebuję subskrypcji ChatGPT, aby projektować z Codeksem?", "text": "Możesz użyć albo klucza API OpenAI (BYOK), albo swojej subskrypcji ChatGPT. Logowanie do ChatGPT zazwyczaj daje hojniejsze limity; Open Design tak czy inaczej nigdy nie przekierowuje twoich poświadczeń."}, {"name": "Codex czy Claude Code do projektowania frontendu?", "text": "Oba są mocne. Claude Code jest znany z konkretnych, świadomych bazy kodu decyzji projektowych; Codex ma mocne dopracowanie wizualne po GPT-5.4 i wyróżnia się w delegowanych buildach w sandboksie. Wiele zespołów używa obu — Open Design pozwala przełączać agentów bez zmiany twojego procesu projektowego."}, {"name": "Jak połączyć Codeksa z Figmą?", "text": "Dodaj oficjalny serwer Figma MCP (codex mcp add figma --url https://mcp.figma.com/mcp). Następnie możesz implementować ramki Figmy w kodzie za pomocą get_design_context oraz wypchnąć działające UI z powrotem do edytowalnych ramek Figmy za pomocą generate_figma_design."}, {"name": "Jak uniknąć generycznej estetyki „AI slop”?", "text": "Zainstaluj skill frontendowy, dostarcz prawdziwe design tokens i zrzuty ekranu referencji, zakoduj reguły marki w AGENTS.md oraz włącz weryfikację Playwright. Open Design dostarcza je jako wyselekcjonowaną bibliotekę, więc omijasz konfigurację dla każdego projektu z osobna."}, {"name": "Czy Open Design jest powiązany z OpenAI?", "text": "Nie. Codex jest produktem OpenAI; Open Design to niezależny projekt open-source, który wspiera go jako adapter pierwszej kategorii. OpenAI i Codex są znakami towarowymi OpenAI."}, {"name": "Czy moje pliki i poświadczenia są bezpieczne?", "text": "Tak — Open Design jest local-first. Twoje pliki, artefakty i DESIGN.md pozostają w twoim własnym repozytorium, a twoje poświadczenia OpenAI są używane bezpośrednio przez twojego agenta, nigdy nie są przekierowywane przez serwery Open Design."}], "ctaTitle": "Projektuj z Codeksem, w otwarty sposób.", "ctaBody": "Przynieś własny klucz OpenAI, zachowaj każdy plik lokalnie i zyskaj wyselekcjonowaną bibliotekę projektową wokół agenta, którego już używasz.", "ctaActions": [{"label": "Użyj Codeksa w Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Zostaw gwiazdkę na GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Pobierz aplikację desktopową", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Zobacz wszystkich obsługiwanych agentów"},
      },
      'cursor': {
        ...en['cursor']!,
        title: "Cursor dla projektantów — Open Design",
        description: "Jak projektanci wykorzystują Cursora do projektowania UI i stron internetowych — Design Mode, Figma-do-kodu, Figma MCP — i jak Open Design zamienia Cursora w local-first, open-source'owego agenta projektowego.",
        breadcrumb: "Cursor Agent",
        label: "Agent · Cursor",
        heading: "Cursor dla projektantów.",
        lead: "Cursor to edytor kodu oparty na AI, teraz z wizualnym Design Mode. Projektanci używają go do edycji UI poprzez wskazywanie i rysowanie oraz do zamiany Figmy w kod. Open Design wpina Cursor Agent w open-source'owy proces projektowy, który zachowuje twoje pliki lokalnie.",
        rich: {"heroCtaLead": "Open Design zamienia Cursora w local-first, open-source'owego agenta projektowego — twoje konto Cursor lub klucze modeli, twoje pliki, a wokół nich wyselekcjonowana biblioteka skills i systemów projektowych.", "heroCtaActions": [{"label": "Użyj Cursora w Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Zostaw gwiazdkę na GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Pobierz aplikację desktopową", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["Cursor to edytor kodu AI-first, który uczynił z „zbuduj i obserwuj, jak się renderuje” domyślny sposób dostarczania UI. Dzięki trybowi Agent, edycjom inline, podglądowi w edytorze i Figmie przez MCP stał się prawdziwym narzędziem projektowym — gdy tylko podasz mu właściwe referencje, reguły i pętlę weryfikacji. To praktyczny, kompleksowy przewodnik po wykorzystaniu Cursora do pracy nad UI, frontendem i systemami projektowymi oraz po wpięciu go w ustrukturyzowany proces projektowy z Open Design.", "Obejmuje on to, czym właściwie jest Cursor, dlaczego jego ciasna pętla iteruj-i-obserwuj jest dobra do projektowania, jak skonfigurować go od zera, pętlę zrzut-ekranu-i-podgląd-do-UI, dwukierunkowy obieg z Figmą przez MCP, jak wypada na tle Codeksa i Claude Code, pułapki, przez które wynik AI wygląda generycznie, oraz jak Open Design zasypuje tę lukę jako otwarta, local-first warstwa projektowa."], "heroImage": {"src": "/agents/cursor-design/cursor-design-hero.webp", "alt": "Zbieżność projektowa Cursora: edytor po lewej, wyselekcjonowane centrum skills i systemu projektowego pośrodku ze znakiem Cursora w środku oraz wyrenderowane UI po prawej", "caption": "Główna idea: Cursor edytuje i renderuje UI w edytorze, podczas gdy wyselekcjonowane centrum projektowe zasila go systemem, skills i referencjami, które sprawiają, że wynik wygląda celowo."}, "tocLabel": "Na tej stronie", "toc": [{"id": "what-is-cursor", "label": "Czym właściwie jest Cursor"}, {"id": "why-design", "label": "Dlaczego Cursor jest dobry w projektowaniu"}, {"id": "setup", "label": "Skonfiguruj Cursora do projektowania (od zera)"}, {"id": "preview-workflow", "label": "Proces podgląd-do-UI"}, {"id": "figma", "label": "Cursor + Figma przez MCP"}, {"id": "vs", "label": "Cursor kontra Codex kontra Claude Code"}, {"id": "pitfalls", "label": "Pułapki i wygląd „AI slop”"}, {"id": "open-design", "label": "Projektowanie z Cursorem w Open Design"}, {"id": "faq", "label": "FAQ"}], "sections": [{"id": "what-is-cursor", "heading": "Czym właściwie jest Cursor", "blocks": [{"kind": "p", "text": "Cursor to edytor kodu AI-first zbudowany przez Anysphere. To fork VS Code, więc zachowuje znajomy edytor, rozszerzenia i skróty klawiszowe, ale przebudowuje proces wokół agenta AI, który potrafi czytać cały twój projekt, edytować wiele plików, uruchamiać polecenia i iterować z tobą w pętli."}, {"kind": "p", "text": "Do pracy projektowej ważnymi powierzchniami są tryb Agent (opisujesz wynik, a Cursor planuje i edytuje w wielu plikach), edycje inline i uzupełnienia Tab do szybkich poprawek, podgląd / przeglądarka w edytorze, dzięki czemu widzisz działające UI bez opuszczania okna, oraz wsparcie MCP, które pozwala mu wciągać zewnętrzny kontekst, jak żywy plik Figmy."}, {"kind": "steps", "items": [{"label": "Reguły projektu", "body": "Cursor czyta pliki instrukcji projektu — wersjonowane reguły `.mdc` w `.cursor/rules` oraz zwykły `AGENTS.md` — więc możesz zakodować swoje konwencje projektowe tam, gdzie agent czyta je przy każdym uruchomieniu."}, {"label": "Modele", "body": "Cursor jest elastyczny pod względem modeli: dostarczany jest z czołowymi modelami przez twoją subskrypcję, a także obsługuje wnoszenie własnych kluczy modeli, więc wybierasz silnik stojący za tym samym procesem w edytorze."}, {"label": "MCP", "body": "Mówi w Model Context Protocol, więc zewnętrzne serwery — najistotniejszy serwer Figma MCP — stają się pierwszorzędnym kontekstem dla agenta."}]}, {"kind": "ul", "items": ["Dostawca: Anysphere", "Poświadczenie: konto / subskrypcja Cursor (Hobby / Pro / Business) lub własne klucze modeli (BYOK)", "Forma: edytor kodu AI-first (fork VS Code) z agentem i podglądem w edytorze"]}]}, {"id": "why-design", "heading": "Dlaczego Cursor jest dobry w projektowaniu", "blocks": [{"kind": "p", "text": "Przewaga projektowa Cursora to nie pojedyncza funkcja — to ciasność pętli buduj-i-zobacz. Trzy rzeczy sprawiają, że odczuwa się go jak narzędzie projektowe, a nie generyczny generator kodu."}, {"kind": "steps", "items": [{"label": "Ciasna pętla iteruj-i-obserwuj", "body": "Dajesz polecenie, Cursor edytuje w wielu plikach, a podgląd w edytorze natychmiast renderuje wynik — więc dostrajasz odstępy, hierarchię i ruch w sekundy, zamiast krążyć przez osobny terminal i przeglądarkę."}, {"label": "Bezpośrednia edycja wizualna", "body": "Poza czatem Cursor pozwala zaznaczać elementy w podglądzie i korygować style, więc drobne poprawki wizualne odczuwa się jak edycje projektowe, a nie archeologię kodu."}, {"label": "Reguły projektu i kontekst MCP", "body": "Dzięki `.cursor/rules` (lub `AGENTS.md`) i serwerowi Figma MCP agent pracuje względem twoich tokens, komponentów i prawdziwych specyfikacji projektowych zamiast zgadywać."}]}, {"kind": "image", "src": "/agents/cursor-design/cursor-design-taste-triangle.webp", "alt": "Diagram pokazujący, jak system projektowy, skill i obraz referencyjny zbiegają się w dobry wynik projektowy", "caption": "Wyczucie smaku bierze się z trzech wkładów, które dostarczasz: systemu projektowego, skilla i prawdziwych obrazów referencyjnych."}, {"kind": "p", "text": "Wniosek jest ten sam, którego uczy każdy agent: Cursor domyślnie nie ma wyczucia smaku. Tworzy dobry projekt, gdy podasz mu ograniczenia — system projektowy, skill estetyczny i konkretne referencje. Open Design pakuje dokładnie te wkłady, dlatego te dwie rzeczy do siebie pasują (więcej poniżej)."}]}, {"id": "setup", "heading": "Skonfiguruj Cursora do pracy projektowej, od zera", "blocks": [{"kind": "p", "text": "Oto pełna ścieżka od czystej maszyny do Cursora, który potrafi budować, podglądać i weryfikować UI względem twojego systemu projektowego."}, {"kind": "ol", "items": ["Zainstaluj Cursora z cursor.com i zaloguj się swoim kontem Cursor lub skonfiguruj własne klucze modeli (BYOK) w Ustawieniach.", "Otwórz swój projekt i wybierz model w panelu czatu / Agent.", "Dodaj reguły projektu: utwórz `.cursor/rules/*.mdc` dla ustrukturyzowanych, ograniczonych globami konwencji lub zwykły `AGENTS.md` dla prostych, czytelnych instrukcji.", "Połącz serwer Figma MCP (opcjonalnie), aby agent mógł czytać żywy kontekst projektowy.", "Uruchom serwer deweloperski i używaj podglądu w edytorze, aby widzieć i weryfikować UI w trakcie iterowania."]}, {"kind": "image", "src": "/agents/cursor-design/cursor-design-setup-flow.webp", "alt": "Pięciokrokowy proces konfiguracji: instalacja, uwierzytelnienie, konfiguracja reguł, dodanie skilla, weryfikacja", "caption": "Sekwencja konfiguracji: instalacja → uwierzytelnienie → konfiguracja reguł projektu → dodanie skilla → włączenie weryfikacji w podglądzie."}, {"kind": "p", "text": "Minimalny plik reguł projektu sprawia, że agent projektuje pod markę zamiast domyślać się generycznego wyglądu. Umieść go tam, gdzie Cursor czyta go przy każdym uruchomieniu:"}, {"kind": "code", "lang": "markdown", "code": "# .cursor/rules/design.mdc\n---\ndescription: Project design conventions\nalwaysApply: true\n---\n\n- Reuse existing design-system tokens and components; never hardcode hex or spacing.\n- At most two typefaces and one accent color.\n- Brand-first hierarchy; restrained motion. No hero cards, no oversized rounded corners.\n- Build responsive by default; verify desktop and mobile in the preview before finishing."}, {"kind": "steps", "items": [{"label": "Zakoduj swoje reguły projektowe", "body": "Umieść swoje tokens, prymitywy i konwencje w `.cursor/rules` lub `AGENTS.md` i nakieruj na nie Cursora, aby wynik pasował do marki, zamiast domyślać się generycznego wyglądu."}, {"label": "Trzymaj polecenia krótkie", "body": "Ciasna pętla Cursora nagradza skupione prośby — iteruj po jednym komponencie lub stanie naraz i obserwuj podgląd między przejściami."}]}]}, {"id": "preview-workflow", "heading": "Proces podgląd-do-UI", "blocks": [{"kind": "p", "text": "Najbardziej dźwigniową pętlą projektową z Cursorem jest zamiana referencji w działające, responsywne UI i iterowanie w edytorze, aż się zgodzi — obserwując podgląd na żywo przez cały czas zamiast zgadywać."}, {"kind": "ol", "items": ["Zacznij od najczytelniejszych referencji wizualnych, jakie masz — i uwzględnij wiele stanów (desktop i mobile, hover, pusty, ładowanie), nie tylko jeden kadr bohaterski.", "Bądź konkretny w poleceniu; mgliste polecenia dają generyczne UI.", "Przygotuj system projektowy i powiedz Cursorowi, gdzie znajdują się tokens i kanoniczne prymitywy.", "Trzymaj podgląd w edytorze otwarty, a serwer deweloperski uruchomiony, aby każda edycja renderowała się natychmiast na breakpointach, na których ci zależy.", "Iteruj, porównując wyrenderowane UI z powrotem z referencjami — i używaj bezpośredniego zaznaczania elementów w podglądzie do drobnych poprawek wizualnych."]}, {"kind": "p", "text": "Podaj referencje, dołączając obraz do czatu, a następnie daj polecenie z konkretnymi ograniczeniami:"}, {"kind": "code", "lang": "text", "code": "Implement this design in React + Vite + Tailwind + TypeScript.\nReuse my existing design-system components and tokens.\nMatch spacing, layout, and hierarchy; make it responsive.\nKeep the preview open — verify desktop and mobile match the\nreferences and iterate until they do."}, {"kind": "p", "text": "Commituj dobre iteracje i cofaj złe (mówiąc Cursorowi, kiedy cofasz), aby każde przejście budowało na czystej bazie — ta sama dyscyplina, która chroni każdą pętlę agenta przed dryfowaniem."}]}, {"id": "figma", "heading": "Cursor + Figma: projekt ↔ kod przez MCP", "blocks": [{"kind": "p", "text": "Cursor łączy się z Figmą przez oficjalny serwer Figma MCP, który daje agentowi ustrukturyzowany dostęp do żywego pliku Figmy zamiast płaskiego zrzutu ekranu. To usuwa zgadywanie z przekazania."}, {"kind": "steps", "items": [{"label": "Projekt → Kod", "body": "Skopiuj link ramki w Figmie, wklej go do Cursora i poproś o implementację projektu. Serwer MCP udostępnia prawdziwy kontekst projektowy — komponenty, zmienne, dane układu, tokens — więc wygenerowany kod pasuje do źródła zamiast je przybliżać."}, {"label": "Zachowaj zgodność", "body": "Przy spójnie używanych w Figmie design tokens, stylach i komponentach (oraz Code Connect tam, gdzie jest dostępny) wynik Cursora pozostaje zmapowany na twój prawdziwy system projektowy zamiast wymyślać prymitywy na nowo."}]}, {"kind": "p", "text": "Skonfiguruj zdalny serwer Figma MCP raz, a jest dostępny dla Cursora jako pierwszorzędny kontekst. Ponieważ MCP jest otwartym standardem, ten sam serwer można ponownie wykorzystać w Cursorze, Claude Code, Codeksie i VS Code — dokładnie ten rodzaj przenośnej, wieloagentowej możliwości, do orkiestracji której zbudowany jest Open Design."}]}, {"id": "vs", "heading": "Cursor kontra Codex kontra Claude Code w projektowaniu", "blocks": [{"kind": "p", "text": "Nie ma jednego zwycięzcy w pracy projektowej — każdy agent ma inną mocną stronę, a doświadczone zespoły zestawiają je ze sobą. Uczciwe podsumowanie:"}, {"kind": "table", "columns": ["Agent", "Mocna strona projektowa", "Najlepszy do"], "rows": [["Cursor", "Wizualna pętla buduj-i-zobacz z podglądem na żywo w edytorze i bezpośrednią edycją elementów", "Ciasna praca nad UI w trybie iteruj-i-obserwuj wewnątrz IDE"], ["Codex", "Mocne dopracowanie wizualne ze skillem frontendowym; rozumienie obrazów i uruchomienia w sandboksie", "Delegowane asynchroniczne buildy i przenośne reguły AGENTS.md"], ["Claude Code", "Konkretne decyzje projektowe (hex, odstępy, typografia) i UX świadomy bazy kodu", "Rozumowanie frontendowe i refaktoryzacje w dużym kontekście"]]}, {"kind": "p", "text": "Powracający werdykt społeczności jest taki, że wyczucie smaku pochodzi od ludzi: cała trójka domyślnie zbiega ku generycznej estetyce bez skills, referencji i ograniczeń. To jest prawdziwy problem do rozwiązania — i ma on kształt narzędzia projektowego, a nie modelu."}]}, {"id": "pitfalls", "heading": "Pułapki i jak unikać wyglądu „AI slop”", "blocks": [{"kind": "p", "text": "Najczęstszą skargą na projekty generowane przez Cursora jest to, że wyglądają generycznie — miękkie gradienty, unoszące się panele, przeskalowane zaokrąglone rogi, dramatyczne cienie, klimat Inter-i-fiolet, który „krzyczy, że zrobiło to AI”. Inne zgłaszane problemy to układy psujące się na mobile oraz przeciekanie instrukcji do treści UI."}, {"kind": "steps", "items": [{"label": "Dodaj skill projektowy", "body": "Wyselekcjonowany skill estetyczny zmusza Cursora do zobowiązania się do prawdziwego kierunku zamiast domyślnego wyglądu."}, {"label": "Użyj podglądu do weryfikacji", "body": "Renderuj i sam się sprawdzaj na różnych breakpointach w podglądzie w edytorze, tak by układy nie psuły się po cichu na mobile."}, {"label": "Dostarcz tokens i referencje", "body": "Prawdziwe design tokens i zrzuty ekranu referencji to pojedyncza największa dźwignia jakości wyniku."}, {"label": "Zakoduj reguły w `.cursor/rules`", "body": "Umieść reguły w stylu „bez kart bohaterskich, najwyżej dwa kroje pisma, hierarchia stawiająca markę na pierwszym miejscu” tam, gdzie agent czyta je przy każdym uruchomieniu."}]}, {"kind": "p", "text": "Zauważ, że każde z tych zabezpieczeń polega na daniu agentowi wyselekcjonowanego kontekstu projektowego. Ręczne utrzymywanie tego kontekstu, projekt po projekcie, to mozół, który usuwa Open Design."}]}, {"id": "open-design", "heading": "Projektowanie z Cursorem wewnątrz Open Design", "blocks": [{"kind": "p", "text": "Open Design to open-source'owa warstwa projektowa, o którą powyższy proces wciąż się dopomina. Traktuje Cursora jako adapter pierwszej kategorii i otacza go wyselekcjonowaną biblioteką skills i systemów projektowych, ustrukturyzowanym potokiem renderowania oraz lokalnym desktopowym UI — więc kontekst projektowy, który czyni Cursora dobrym, jest dostępny od pierwszego uruchomienia, a nie składany ręcznie za każdym razem."}, {"kind": "ol", "items": ["Zainstaluj Open Design i wybierz Cursora jako swojego agenta.", "Uwierzytelnij się swoim kontem Cursor lub własnymi kluczami modeli (BYOK) — poświadczenia pozostają na twojej maszynie i nigdy nie są przekierowywane przez nas.", "Wybierz system projektowy i skill, a następnie generuj prezentacje, prototypy i strony docelowe ze spójnym wyczuciem smaku.", "Każdy artefakt i plik DESIGN.md żyje w twoim własnym repozytorium, a nie w hostowanej chmurze."]}, {"kind": "p", "text": "Ten sam agent Cursor, ten sam klucz — plus prawdziwy, przenośny, open-source'owy proces projektowy wokół niego. Jest local-first i na licencji Apache-2.0, więc nic z twojej pracy ani twoich poświadczeń nie opuszcza twojej maszyny."}]}], "faqTitle": "Najczęściej zadawane pytania", "faq": [{"name": "Czy Cursor naprawdę potrafi wykonywać pracę projektową?", "text": "Tak — mając w kontekście skill projektowy, system projektowy i prawdziwe obrazy referencyjne, Cursor tworzy responsywne UI o jakości produkcyjnej, a jego podgląd w edytorze pozwala je wizualnie zweryfikować i dopracować. Bez tego kontekstu skłania się ku generycznemu wyglądowi, i to jest luka, którą wypełnia Open Design."}, {"name": "Czy to oficjalny produkt Cursora?", "text": "Nie. Open Design to niezależny projekt open-source, który integruje Cursora jako agenta. Uzupełnia Cursora o local-first, otwartą bibliotekę skills i systemów projektowych."}, {"name": "Czy potrzebuję subskrypcji Cursor, aby projektować z Cursorem?", "text": "Możesz użyć konta / subskrypcji Cursor albo wnieść własne klucze modeli (BYOK). Open Design tak czy inaczej nigdy nie przekierowuje twoich poświadczeń — są one używane bezpośrednio przez twojego agenta."}, {"name": "Cursor czy Claude Code do projektowania frontendu?", "text": "Oba są mocne. Claude Code jest znany z konkretnych, świadomych bazy kodu decyzji projektowych; przewagą Cursora jest jego ciasna pętla buduj-i-zobacz z podglądem na żywo wewnątrz edytora. Wiele zespołów używa obu — Open Design pozwala przełączać agentów bez zmiany twojego procesu projektowego."}, {"name": "Jak połączyć Cursora z Figmą?", "text": "Dodaj oficjalny serwer Figma MCP w Cursorze, a następnie wklej link ramki Figmy do czatu i poproś Cursora o jej implementację. Serwer udostępnia prawdziwe komponenty, zmienne i dane układu, więc wygenerowany kod pasuje do źródłowego projektu."}, {"name": "Jak uniknąć generycznej estetyki „AI slop”?", "text": "Dodaj skill projektowy, dostarcz prawdziwe design tokens i zrzuty ekranu referencji, zakoduj reguły marki w `.cursor/rules` lub `AGENTS.md` oraz weryfikuj na różnych breakpointach w podglądzie. Open Design dostarcza je jako wyselekcjonowaną bibliotekę, więc omijasz konfigurację dla każdego projektu z osobna."}, {"name": "Czy Open Design jest powiązany z Cursorem lub Anysphere?", "text": "Nie. Cursor jest produktem Anysphere; Open Design to niezależny projekt open-source, który wspiera go jako adapter pierwszej kategorii. Cursor i Anysphere są znakami towarowymi Anysphere, Inc."}, {"name": "Czy moje pliki i poświadczenia są bezpieczne?", "text": "Tak — Open Design jest local-first. Twoje pliki, artefakty i DESIGN.md pozostają w twoim własnym repozytorium, a twoje poświadczenia Cursora lub modeli są używane bezpośrednio przez twojego agenta, nigdy nie są przekierowywane przez serwery Open Design."}], "ctaTitle": "Projektuj z Cursorem, w otwarty sposób.", "ctaBody": "Przynieś własne konto Cursor lub klucze modeli, zachowaj każdy plik lokalnie i zyskaj wyselekcjonowaną bibliotekę projektową wokół agenta, którego już używasz.", "ctaActions": [{"label": "Użyj Cursora w Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Zostaw gwiazdkę na GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Pobierz aplikację desktopową", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Zobacz wszystkich obsługiwanych agentów"},
      },
      'opencode': {
        ...en['opencode']!,
        title: "OpenCode dla projektowania — Open Design",
        description: "Jak ludzie wykorzystują OpenCode do projektowania UI i stron internetowych — pliki design.md, skills UI/UX, Figma MCP — i jak Open Design zamienia OpenCode w local-first, open-source'owego agenta projektowego.",
        breadcrumb: "OpenCode",
        label: "Agent · OpenCode",
        heading: "OpenCode dla projektowania.",
        lead: "OpenCode to open-source'owy, terminalowy agent kodujący AI. Projektanci dokręcają do niego skills projektowe i pliki DESIGN.md, aby generować prawdziwe UI. Open Design czyni z tego ustrukturyzowany, open-source'owy proces — przynieś swoje klucze dostawców i zachowaj wszystko lokalnie.",
        rich: {"heroCtaLead": "Open Design zamienia OpenCode w local-first, open-source'owego agenta projektowego — dowolny model, który wybierzesz, z własnym kluczem dostawcy, twoje pliki, a wokół nich wyselekcjonowana biblioteka skills i systemów projektowych.", "heroCtaActions": [{"label": "Użyj OpenCode w Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Zostaw gwiazdkę na GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Pobierz aplikację desktopową", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["OpenCode to open-source'owy, terminalowy w pierwszej kolejności agent kodujący AI, który jest celowo niezależny od modelu: przynosisz własny klucz dostawcy i uruchamiasz dowolny model za tym samym procesem. Ta otwartość czyni go naturalną bazą do pracy projektowej — ale jak każdy agent, tworzy dobre UI tylko wtedy, gdy podasz mu właściwe referencje, skills i pętlę weryfikacji. To praktyczny, kompleksowy przewodnik po wykorzystaniu OpenCode do pracy nad UI, frontendem i systemami projektowymi oraz po wpięciu go w ustrukturyzowany proces projektowy z Open Design.", "Obejmuje on to, czym właściwie jest OpenCode, dlaczego niezależny od modelu otwarty agent jest dobrym wyborem do projektowania, jak skonfigurować go od zera, pętlę zrzut-ekranu-do-UI, jak AGENTS.md i MCP go rozszerzają, jak wypada na tle Codeksa, Claude Code i Cursora, pułapki, przez które wynik AI wygląda generycznie, oraz jak Open Design zasypuje tę lukę jako otwarta, local-first warstwa projektowa — naturalne połączenie, skoro oba projekty są open-source i działają na twojej własnej maszynie."], "heroImage": {"src": "/agents/opencode-design/opencode-design-hero.webp", "alt": "Pętla informacji zwrotnej w projektowaniu z OpenCode: terminalowy agent TUI, przeglądarka renderująca UI oraz przestrzeń robocza, ze strzałką sprzężenia zwrotnego zawracającą do początku", "caption": "Główna pętla: OpenCode buduje UI w terminalu, renderuje je i weryfikuje w prawdziwej przeglądarce oraz iteruje względem twoich referencji — na dowolnym modelu, który wybierzesz."}, "tocLabel": "Na tej stronie", "toc": [{"id": "what-is-opencode", "label": "Czym właściwie jest OpenCode"}, {"id": "why-design", "label": "Dlaczego otwarty, dowolnomodelowy agent pasuje do projektowania"}, {"id": "setup", "label": "Skonfiguruj OpenCode do projektowania (od zera)"}, {"id": "screenshot-workflow", "label": "Proces zrzut-ekranu-do-UI"}, {"id": "extend", "label": "AGENTS.md, MCP i udostępnialne sesje"}, {"id": "vs", "label": "OpenCode kontra Codex kontra Claude Code kontra Cursor"}, {"id": "pitfalls", "label": "Pułapki i wygląd „AI slop”"}, {"id": "open-design", "label": "Projektowanie z OpenCode w Open Design"}, {"id": "faq", "label": "FAQ"}], "sections": [{"id": "what-is-opencode", "heading": "Czym właściwie jest OpenCode", "blocks": [{"kind": "p", "text": "OpenCode to open-source'owy agent kodujący AI zbudowany pod terminal, utrzymywany przez zespół stojący za SST (Anomaly Innovations). Czyta twoje repozytorium, uruchamia polecenia, edytuje pliki i rozmawia z dużym modelem językowym — ale w przeciwieństwie do agentów związanych z dostawcą nie dostarcza własnego modelu. Kierujesz go na dowolnego dostawcę i model, jaki chcesz, i przynosisz własny klucz."}, {"kind": "p", "text": "Działa jako terminalowy interfejs (TUI), z aplikacją desktopową i rozszerzeniami IDE nadbudowanymi na tym samym silniku. Pod maską używa architektury klient/serwer, więc agent wykonujący pracę jest odsprzężony od powierzchni, z której nim sterujesz. Dwaj wbudowani agenci — build i plan — przełączają się klawiszem Tab."}, {"kind": "steps", "items": [{"label": "Niezależny od modelu", "body": "Modele i dostawcy pochodzą z models.dev, otwartego katalogu. Konfigurujesz je w opencode.json łańcuchem provider/model-id i możesz wyłączać dostawców, których nie chcesz ładować — więc ten sam proces projektowy działa na Anthropic, OpenAI, Google, OpenRouter, modelach lokalnych i innych."}, {"label": "Plik instrukcji", "body": "OpenCode czyta plik AGENTS.md w twoim projekcie (standard międzynarzędziowy, zgodny także z CLAUDE.md) w poszukiwaniu reguł projektu — naturalne miejsce, by zakodować twoje konwencje projektowe. Uruchom /init, aby wygenerować jeden."}, {"label": "Rozszerzalny", "body": "Obsługuje integrację LSP, serwery MCP, motywy, skróty klawiszowe i niestandardowe polecenia, a także udostępnialne linki do sesji dla współpracy."}]}, {"kind": "ul", "items": ["Opiekun: SST / Anomaly Innovations (projekt open-source)", "Poświadczenie: twój własny klucz/klucze API dostawcy modeli — BYOK, bez uwiązania do dostawcy", "Licencja: MIT, open source"]}]}, {"id": "why-design", "heading": "Dlaczego otwarty, dowolnomodelowy agent pasuje do pracy projektowej", "blocks": [{"kind": "p", "text": "OpenCode nie ma jednego „modelu projektowego” tak jak agent związany z dostawcą — i o to właśnie chodzi. Ponieważ jest niezależny od modelu i otwarty, możesz uruchamiać ten sam proces projektowy na modelu, który aktualnie jest najlepszy we frontendzie, później go wymienić lub cofnąć się do modelu lokalnego, a wszystko to bez zmiany konfiguracji."}, {"kind": "p", "text": "Ale sam wybór modelu nie kupuje wyczucia smaku. Jak każdy agent kodujący, OpenCode tworzy generyczne UI, dopóki nie podasz mu ograniczeń. Dobry wynik projektowy bierze się z trzech wkładów, które dostarczasz."}, {"kind": "steps", "items": [{"label": "System projektowy", "body": "Prawdziwe tokens, prymitywy i konwencje, które agent ponownie wykorzystuje, aby wynik pasował do marki, zamiast domyślać się generycznego wyglądu."}, {"label": "Skill estetyczny", "body": "Wyselekcjonowany skill, który egzekwuje prawdziwe wyczucie smaku — powściągliwy ruch, hierarchia stawiająca markę na pierwszym miejscu, najwyżej dwa kroje pisma i jeden kolor akcentu — i sprawia, że agent zobowiązuje się do kierunku przed budowaniem."}, {"label": "Konkretne referencje", "body": "Faktyczne obrazy referencyjne i wiele stanów (desktop i mobile, hover, pusty, ładowanie), a nie pojedynczy kadr bohaterski."}]}, {"kind": "image", "src": "/agents/opencode-design/opencode-design-taste-triangle.webp", "alt": "Diagram pokazujący, jak system projektowy, skill i obraz referencyjny zbiegają się w dobry wynik projektowy", "caption": "Wyczucie smaku bierze się z trzech wkładów, które dostarczasz: systemu projektowego, skilla i prawdziwych obrazów referencyjnych — niezależnie od tego, który model uruchamiasz."}, {"kind": "p", "text": "Wniosek: OpenCode daje ci swobodę modelu, ale wyczucie smaku wciąż bierze się z wyselekcjonowanego kontekstu projektowego. Open Design pakuje dokładnie te wkłady, dlatego te dwie rzeczy do siebie pasują — oba są open-source i local-first (więcej poniżej)."}]}, {"id": "setup", "heading": "Skonfiguruj OpenCode do pracy projektowej, od zera", "blocks": [{"kind": "p", "text": "Oto pełna ścieżka od czystej maszyny do OpenCode, który potrafi budować i weryfikować UI."}, {"kind": "code", "lang": "bash", "code": "# 1. Install OpenCode\ncurl -fsSL https://opencode.ai/install | bash\n# or: npm i -g opencode-ai@latest\n# or: brew install sst/tap/opencode\n\n# 2. Start the TUI in your project, then authenticate your provider\nopencode          # then run /login and pick your provider + paste your key\n\n# 3. Generate project context\nopencode          # inside your project, run /init to create AGENTS.md\n\n# 4. Pick your model (any provider, via models.dev)\n#    set \"provider/model-id\" in opencode.json or switch in the TUI\n\n# 5. Add an MCP server (optional, e.g. for design handoff)\n#    configure it under the \"mcp\" key in opencode.json"}, {"kind": "image", "src": "/agents/opencode-design/opencode-design-setup-flow.webp", "alt": "Pięciokrokowy proces konfiguracji: instalacja, uwierzytelnienie kluczem dostawcy, konfiguracja AGENTS.md, dodanie skilla, weryfikacja", "caption": "Sekwencja konfiguracji: instalacja → uwierzytelnienie (twój klucz dostawcy) → konfiguracja AGENTS.md → dodanie skilla → weryfikacja w prawdziwej przeglądarce."}, {"kind": "steps", "items": [{"label": "Zakoduj swoje reguły projektowe", "body": "Umieść swoje tokens, prymitywy i konwencje w AGENTS.md (lub DESIGN.md przywoływanym z niego), aby wynik pasował do marki, zamiast domyślać się generycznego wyglądu. Opcja instructions w opencode.json może wskazywać na dodatkowe pliki reguł przez globy."}, {"label": "Wybierz zdolny model", "body": "Ponieważ OpenCode jest niezależny od modelu, wybierz dostawcę/model aktualnie najsilniejszy we frontendzie na przejście projektowe — i zostaw resztę swojego procesu bez zmian."}]}]}, {"id": "screenshot-workflow", "heading": "Proces zrzut-ekranu-do-UI", "blocks": [{"kind": "p", "text": "Najbardziej dźwigniową pętlą projektową z dowolnym agentem jest zamiana obrazu referencyjnego w działające, responsywne UI i iterowanie, aż się zgodzi. Ten sam pięciokrokowy kształt obowiązuje w OpenCode."}, {"kind": "ol", "items": ["Zacznij od najczytelniejszych referencji wizualnych, jakie masz — i uwzględnij wiele stanów (desktop i mobile, hover, pusty, ładowanie), nie tylko jeden kadr bohaterski.", "Bądź konkretny w poleceniu; mgliste polecenia dają generyczne UI.", "Przygotuj system projektowy i powiedz OpenCode, gdzie znajdują się tokens i kanoniczne prymitywy (w AGENTS.md).", "Uruchom serwer deweloperski i każ agentowi renderować w prawdziwej przeglądarce, zmieniając rozmiar do breakpointów, aby sprawdzić wynik.", "Iteruj, każąc OpenCode porównywać swoją implementację z powrotem ze zrzutami ekranu — a nie tylko potwierdzać, że się buduje."]}, {"kind": "p", "text": "Odwołuj się do plików za pomocą @ w TUI, aby uzyskać rozmyte wyszukiwanie w twoim katalogu roboczym, uruchamiaj polecenia powłoki inline z wiodącym !, a akcjami steruj poleceniami /. Następnie daj polecenie z konkretnymi ograniczeniami:"}, {"kind": "code", "lang": "bash", "code": "opencode\n# in the TUI:\n> @reference-desktop.png @reference-mobile.png\n  Implement this design in React + Vite + Tailwind + TypeScript.\n  Reuse my existing design-system components and tokens from AGENTS.md.\n  Match spacing, layout, and hierarchy; make it responsive.\n  Run the dev server, open it in a browser, and iterate until the\n  UI matches the references across breakpoints."}, {"kind": "p", "text": "Trzymaj polecenia krótkie i skupione, commituj dobre iteracje i cofaj złe (mówiąc OpenCode, kiedy cofasz), aby każde przejście budowało na czystej bazie."}]}, {"id": "extend", "heading": "AGENTS.md, MCP i udostępnialne sesje", "blocks": [{"kind": "p", "text": "Trzy punkty rozszerzeń czynią OpenCode praktycznym do długotrwałej pracy projektowej, a wszystkie trzy czysto odwzorowują się na otwarty proces projektowy."}, {"kind": "steps", "items": [{"label": "Reguły AGENTS.md", "body": "Reguły projektu żyją w AGENTS.md w korzeniu repozytorium (lub reguły globalne w ~/.config/opencode/AGENTS.md). To trwały dom dla twoich konwencji projektowych, czytany przy każdym uruchomieniu, i jest zgodny z plikami CLAUDE.md, których używają inne agenty."}, {"label": "Serwery MCP", "body": "OpenCode obsługuje zarówno lokalne (command), jak i zdalne (URL) serwery MCP, konfigurowane pod kluczem mcp — przenośny sposób wnoszenia kontekstu projektowego i zewnętrznych narzędzi, które działają w wielu agentach, nie tylko w OpenCode."}, {"label": "Udostępnialne sesje", "body": "Polecenie /share tworzy publiczny link do rozmowy dla współpracy lub przeglądu, a /unshare go odwołuje — przydatne do uzyskania informacji zwrotnej na temat przejścia projektowego."}]}, {"kind": "p", "text": "To są przenośne, wieloagentowe możliwości — dokładnie to, do orkiestracji czego zbudowany jest Open Design, zamiast odtwarzać je dla każdego projektu z osobna."}]}, {"id": "vs", "heading": "OpenCode kontra Codex kontra Claude Code kontra Cursor w projektowaniu", "blocks": [{"kind": "p", "text": "Nie ma jednego zwycięzcy w pracy projektowej — każdy agent ma inną mocną stronę, a doświadczone zespoły zestawiają je ze sobą. Uczciwe podsumowanie:"}, {"kind": "table", "columns": ["Agent", "Mocna strona projektowa", "Najlepszy do"], "rows": [["OpenCode", "Open-source i niezależny od modelu; uruchom dowolnego dostawcę za jednym terminalowym procesem", "Swoboda BYOK, przełączanie modeli, w pełni otwarte i local-first konfiguracje"], ["Codex", "Mocne dopracowanie wizualne ze skillem frontendowym; rozumienie obrazów", "Delegowane asynchroniczne, buildy w sandboksie, przenośne reguły AGENTS.md"], ["Claude Code", "Konkretne decyzje projektowe (hex, odstępy, typografia) i UX świadomy bazy kodu", "Rozumowanie frontendowe i refaktoryzacje w dużym kontekście"], ["Cursor", "Wizualna pętla buduj-i-zobacz z podglądem na żywo i edycjami inline", "Ciasna praca nad UI w trybie iteruj-i-obserwuj wewnątrz IDE"]]}, {"kind": "p", "text": "Powracający werdykt społeczności jest taki, że wyczucie smaku pochodzi od ludzi: wszystkie z nich domyślnie zbiegają ku generycznej estetyce bez skills, referencji i ograniczeń. To jest prawdziwy problem do rozwiązania — i ma on kształt narzędzia projektowego, a nie modelu, co jest dokładnie powodem, dla którego otwarty agent jak OpenCode tak dobrze łączy się z otwartą warstwą projektową."}]}, {"id": "pitfalls", "heading": "Pułapki i jak unikać wyglądu „AI slop”", "blocks": [{"kind": "p", "text": "Najczęstszą skargą na projekty generowane przez AI jest to, że wyglądają generycznie — miękkie gradienty, unoszące się panele, przeskalowane zaokrąglone rogi, dramatyczne cienie, klimat Inter-i-fiolet, który „krzyczy, że zrobiło to AI”. Inne zgłaszane problemy to popsute układy mobilne i przeciekanie instrukcji do treści UI. Żaden z nich nie jest charakterystyczny wyłącznie dla OpenCode; to się dzieje, gdy dowolny agent działa bez wyselekcjonowanego kontekstu projektowego."}, {"kind": "steps", "items": [{"label": "Dodaj skill estetyczny", "body": "Wyselekcjonowany skill projektowy zmusza agenta do zobowiązania się do prawdziwego kierunku zamiast domyślnego wyglądu."}, {"label": "Weryfikuj w prawdziwej przeglądarce", "body": "Renderuj i sam się sprawdzaj na różnych breakpointach, tak by układy nie psuły się po cichu na mobile."}, {"label": "Dostarcz tokens i referencje", "body": "Prawdziwe design tokens i zrzuty ekranu referencji to pojedyncza największa dźwignia jakości wyniku."}, {"label": "Zakoduj reguły w AGENTS.md", "body": "Umieść reguły w stylu „bez kart bohaterskich, najwyżej dwa kroje pisma, hierarchia stawiająca markę na pierwszym miejscu” tam, gdzie agent czyta je przy każdym uruchomieniu."}]}, {"kind": "p", "text": "Zauważ, że każde z tych zabezpieczeń polega na daniu agentowi wyselekcjonowanego kontekstu projektowego — niezależnie od tego, który model uruchamiasz. Ręczne utrzymywanie tego kontekstu, projekt po projekcie, to mozół, który usuwa Open Design."}]}, {"id": "open-design", "heading": "Projektowanie z OpenCode wewnątrz Open Design", "blocks": [{"kind": "p", "text": "Open Design to open-source'owa warstwa projektowa, o którą powyższy proces wciąż się dopomina. Traktuje OpenCode jako adapter pierwszej kategorii i otacza go wyselekcjonowaną biblioteką skills i systemów projektowych, ustrukturyzowanym potokiem renderowania oraz lokalnym desktopowym UI — więc kontekst projektowy, który czyni dowolnego agenta dobrym, jest dostępny od pierwszego uruchomienia, a nie składany ręcznie za każdym razem. Oba projekty są open-source i local-first, co czyni to połączenie naturalnym dopasowaniem."}, {"kind": "ol", "items": ["Zainstaluj Open Design i wybierz OpenCode jako swojego agenta.", "Uwierzytelnij się własnym kluczem API dostawcy modeli (BYOK) — poświadczenia pozostają na twojej maszynie i nigdy nie są przekierowywane przez nas.", "Wybierz dowolnego dostawcę i model, a także system projektowy i skill, a następnie generuj prezentacje, prototypy i strony docelowe ze spójnym wyczuciem smaku.", "Każdy artefakt i plik DESIGN.md żyje w twoim własnym repozytorium, a nie w hostowanej chmurze."]}, {"kind": "p", "text": "Ten sam agent OpenCode, ta sama swoboda modelu — plus prawdziwy, przenośny, open-source'owy proces projektowy wokół niego. Jest local-first i na licencji Apache-2.0, więc nic z twojej pracy ani twoich poświadczeń nie opuszcza twojej maszyny."}]}], "faqTitle": "Najczęściej zadawane pytania", "faq": [{"name": "Czy OpenCode naprawdę potrafi wykonywać pracę projektową?", "text": "Tak — mając w kontekście skill estetyczny, system projektowy i prawdziwe obrazy referencyjne, OpenCode tworzy responsywne UI o jakości produkcyjnej i potrafi je zweryfikować w przeglądarce. Ponieważ jest niezależny od modelu, uruchamiasz model aktualnie najlepszy we frontendzie. Bez tego wyselekcjonowanego kontekstu skłania się ku generycznemu wyglądowi, i to jest luka, którą wypełnia Open Design."}, {"name": "Którego modelu powinienem użyć z OpenCode do projektowania?", "text": "Dowolnego, jaki lubisz — OpenCode jest niezależny od dostawcy przez models.dev, więc możesz uruchamiać Anthropic, OpenAI, Google, OpenRouter lub modele lokalne za tym samym procesem i przełączać się w dowolnym momencie. Jakość wyniku projektowego zależy znacznie bardziej od twojego skilla, systemu projektowego i referencji niż od samego modelu."}, {"name": "Czy Open Design jest tworzony przez zespół OpenCode (SST)?", "text": "Nie. Open Design to niezależny projekt open-source, który integruje OpenCode jako agenta. Uzupełnia OpenCode o local-first, otwartą bibliotekę skills i systemów projektowych."}, {"name": "Czy potrzebuję specjalnej subskrypcji, aby projektować z OpenCode?", "text": "Nie — OpenCode jest BYOK. Przynosisz własny klucz API dostawcy modeli, a Open Design nigdy nie przekierowuje twoich poświadczeń. Nie ma uwiązania do dostawcy."}, {"name": "OpenCode, Codex czy Claude Code do projektowania frontendu?", "text": "Wszystkie są mocne, a wiele zespołów zestawia je ze sobą. Przewagą OpenCode jest bycie w pełni open-source i niezależnym od modelu; Codex wyróżnia się w delegowanych buildach w sandboksie; Claude Code jest znany z konkretnych, świadomych bazy kodu decyzji projektowych. Open Design pozwala przełączać agentów bez zmiany twojego procesu projektowego."}, {"name": "Jak rozszerzyć OpenCode o kontekst projektowy?", "text": "Zakoduj reguły w AGENTS.md, dodaj serwery MCP pod kluczem mcp dla przenośnych narzędzi i kontekstu projektowego oraz używaj udostępnialnych sesji do przeglądu. Open Design dostarcza wyselekcjonowaną bibliotekę skills i systemów projektowych, więc omijasz konfigurację dla każdego projektu z osobna."}, {"name": "Czy Open Design jest powiązany z OpenCode lub SST?", "text": "Nie. OpenCode to projekt open-source utrzymywany przez SST (Anomaly Innovations); Open Design to niezależny projekt open-source, który wspiera go jako adapter pierwszej kategorii."}, {"name": "Czy moje pliki i poświadczenia są bezpieczne?", "text": "Tak — Open Design jest local-first. Twoje pliki, artefakty i DESIGN.md pozostają w twoim własnym repozytorium, a twoje poświadczenia dostawcy modeli są używane bezpośrednio przez twojego agenta, nigdy nie są przekierowywane przez serwery Open Design."}], "ctaTitle": "Projektuj z OpenCode, w otwarty sposób.", "ctaBody": "Przynieś własny klucz dostawcy modeli, zachowaj każdy plik lokalnie i zyskaj wyselekcjonowaną bibliotekę projektową wokół otwartego agenta, którego już używasz.", "ctaActions": [{"label": "Użyj OpenCode w Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Zostaw gwiazdkę na GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Pobierz aplikację desktopową", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Zobacz wszystkich obsługiwanych agentów"},
      },
      'gemini': {
        ...en['gemini']!,
        title: "Gemini CLI w projektowaniu — Open Design",
        description: "Jak ludzie wykorzystują Gemini CLI od Google do projektowania interfejsów i stron — jego multimodalne rozumienie obrazu, kontekst o pojemności 1M tokenów, GEMINI.md i MCP — oraz jak Open Design przekształca Gemini CLI w lokalny, open-source'owy agent projektowy.",
        breadcrumb: "Gemini CLI",
        label: "Agent · Gemini CLI",
        heading: "Gemini CLI w projektowaniu.",
        lead: "Gemini CLI to open-source'owy agent terminalowy od Google. Jego multimodalne modele odczytują zrzuty ekranu, a kontekst o pojemności 1M tokenów mieści cały system projektowy, co czyni go realnym narzędziem projektowym — gdy tylko dostarczysz mu referencje, konwencje i pętlę weryfikacji. Open Design wpina go w open-source'owy proces projektowy: twoje konto Google lub klucz API, twoje pliki, lokalnie u ciebie.",
        rich: {"heroCtaLead": "Open Design przekształca Gemini CLI w lokalny, open-source'owy agent projektowy — twoje konto Google lub klucz API Gemini, twoje pliki, a wokół nich wyselekcjonowana biblioteka skilli i systemów projektowych.", "heroCtaActions": [{"label": "Użyj Gemini CLI w Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Dodaj gwiazdkę na GitHubie", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Pobierz aplikację desktopową", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["Gemini CLI to open-source'owy agent AI od Google przeznaczony do terminala. Dwie rzeczy czynią go interesującym akurat dla projektowania: jego modele są silnie multimodalne, więc odczytuje zrzut ekranu i wnioskuje o układzie, odstępach i hierarchii; a jego okno kontekstowe o pojemności 1M tokenów potrafi pomieścić cały system projektowy i bazę kodu naraz. W połączeniu z odpowiednimi referencjami, konwencjami i pętlą weryfikacji buduje realny, responsywny interfejs — a zacząć można za darmo z kontem Google. To praktyczny przewodnik od początku do końca po wykorzystaniu Gemini CLI do pracy nad interfejsami, frontendem i systemami projektowymi oraz po wpięciu go w ustrukturyzowany proces projektowy z Open Design.", "Omawia, czym faktycznie jest Gemini CLI, dlaczego jego multimodalne modele i ogromny kontekst pasują do projektowania, jak skonfigurować go od zera, pętlę „od zrzutu ekranu do interfejsu”, jak GEMINI.md i MCP go rozszerzają, jak wypada na tle Codex, Claude Code i Cursor, pułapki, przez które efekty AI wyglądają generycznie, oraz jak Open Design domyka tę lukę jako otwarta, lokalna warstwa projektowa — naturalne połączenie, skoro oba są open-source'owe i działają na twojej własnej maszynie."], "heroImage": {"src": "/agents/gemini-design/gemini-design-hero.webp", "alt": "Pętla sprzężenia zwrotnego w projektowaniu z Gemini CLI: agent terminalowy odczytujący obraz referencyjny, przeglądarka renderująca interfejs i przestrzeń robocza, ze strzałką sprzężenia zwrotnego zapętloną z powrotem", "caption": "Rdzeń pętli: Gemini CLI odczytuje twoje referencje w terminalu, buduje i weryfikuje interfejs w prawdziwej przeglądarce oraz iteruje względem nich — mając cały system projektowy w kontekście."}, "tocLabel": "Na tej stronie", "toc": [{"id": "what-is-gemini-cli", "label": "Czym faktycznie jest Gemini CLI"}, {"id": "why-design", "label": "Dlaczego multimodalność + ogromny kontekst pasują do projektowania"}, {"id": "setup", "label": "Skonfiguruj Gemini CLI do projektowania (od zera)"}, {"id": "screenshot-workflow", "label": "Proces „od zrzutu ekranu do interfejsu”"}, {"id": "extend", "label": "GEMINI.md, MCP i rozszerzenia"}, {"id": "vs", "label": "Gemini CLI kontra Codex kontra Claude Code kontra Cursor"}, {"id": "pitfalls", "label": "Pułapki i wygląd „AI slop”"}, {"id": "open-design", "label": "Projektowanie z Gemini CLI w Open Design"}, {"id": "faq", "label": "FAQ"}], "sections": [{"id": "what-is-gemini-cli", "heading": "Czym faktycznie jest Gemini CLI", "blocks": [{"kind": "p", "text": "Gemini CLI to open-source'owy (Apache-2.0) agent AI, który Google dostarcza do terminala. Odczytuje twoje repozytorium, edytuje pliki, uruchamia polecenia powłoki, pobiera dane z sieci i potrafi opierać odpowiedzi na Google Search — planuje i weryfikuje pracę na podstawie zadań w języku naturalnym, a nie tylko uzupełnia linijki kodu. Ten sam silnik napędza również agenta Gemini Code Assist wewnątrz VS Code."}, {"kind": "p", "text": "Dla pracy projektowej wyróżniają się dwie cechy. Jego modele są natywnie multimodalne, więc możesz podać mu zrzut ekranu, a on wnioskuje o rzeczywistym układzie. A jego okno kontekstowe sięga aż 1M tokenów — na tyle dużo, by pomieścić cały twój system projektowy, bibliotekę komponentów i zestaw referencji naraz, zamiast skracać je do streszczeń."}, {"kind": "steps", "items": [{"label": "Pliki kontekstu", "body": "Gemini CLI odczytuje plik GEMINI.md jako trwały kontekst projektu — to naturalne miejsce na zapisanie twoich konwencji projektowych, tokenów i list kontrolnych do przeglądów. Ustawienia osobiste i zespołowe nakładają się na to."}, {"label": "Wbudowane narzędzia + MCP", "body": "Domyślnie udostępnia narzędzia do plików, powłoki, pobierania z sieci i Google Search oraz obsługuje serwery MCP (konfigurowane w ~/.gemini/settings.json), by dodać zewnętrzny kontekst, na przykład żywy plik Figma."}, {"label": "Darmowy start", "body": "Logowanie się prywatnym kontem Google daje hojny darmowy limit zapytań do Gemini; możesz też podać własny klucz API Gemini lub skorzystać z Vertex AI."}]}, {"kind": "ul", "items": ["Dostawca: Google", "Poświadczenia: konto Google (darmowy limit) lub klucz API Gemini z AI Studio (BYOK) bądź Vertex AI", "Licencja: Apache-2.0, open source"]}]}, {"id": "why-design", "heading": "Dlaczego multimodalne modele i ogromny kontekst pasują do projektowania", "blocks": [{"kind": "p", "text": "Przewaga Gemini CLI w projektowaniu wynika z dwóch cech modelu — ale, jak w przypadku każdego agenta, gust nadal trzeba dostarczyć."}, {"kind": "steps", "items": [{"label": "Silne rozumienie multimodalne", "body": "Ponieważ modele Gemini są natywnie multimodalne, agent dobrze odczytuje referencyjne zrzuty ekranu — porównując wyrenderowany efekt z obrazem, zamiast zgadywać na podstawie opisu słownego."}, {"label": "Okno kontekstowe o pojemności 1M tokenów", "body": "Duży kontekst oznacza, że cały system projektowy, tokeny i wiele stanów referencyjnych mieszczą się naraz, więc agent ponownie wykorzystuje twoje realne prymitywy, zamiast wymyślać jednorazowe style."}, {"label": "Konwencje w GEMINI.md", "body": "Plik GEMINI.md (plus serwer Figma MCP) kieruje agenta do twoich tokenów, komponentów i realnych specyfikacji, więc pracuje on zgodnie z marką, a nie z domyślnym wyglądem."}]}, {"kind": "image", "src": "/agents/gemini-design/gemini-design-taste-triangle.webp", "alt": "Diagram pokazujący, jak system projektowy, skill i obraz referencyjny zbiegają się w dobry efekt projektowy", "caption": "Gust pochodzi z trzech dostarczanych przez ciebie elementów: systemu projektowego, skilla i realnych obrazów referencyjnych."}, {"kind": "p", "text": "Wniosek jest taki sam, jakiego uczy każdy agent: Gemini CLI domyślnie nie ma gustu. Tworzy dobre projekty, gdy nadasz mu ograniczenia — system projektowy, skill estetyczny i konkretne referencje. Open Design pakuje dokładnie te elementy, dlatego oba tak dobrze do siebie pasują (więcej poniżej)."}]}, {"id": "setup", "heading": "Skonfiguruj Gemini CLI do pracy projektowej, od zera", "blocks": [{"kind": "p", "text": "Oto pełna droga od czystej maszyny do Gemini CLI, które potrafi budować i weryfikować interfejs."}, {"kind": "code", "lang": "bash", "code": "# 1. Install Gemini CLI (Node 20+)\nnpm install -g @google/gemini-cli\n# or run without installing: npx https://github.com/google-gemini/gemini-cli\n\n# 2. Start it in your project and authenticate on first run\ncd your-project\ngemini            # sign in with your Google account, or set GEMINI_API_KEY\n\n# 3. Generate project context\n/init             # scaffolds a GEMINI.md for this project\n\n# 4. Wire the Figma MCP server (optional, for design handoff)\n#    add it under \"mcpServers\" in ~/.gemini/settings.json"}, {"kind": "image", "src": "/agents/gemini-design/gemini-design-setup-flow.webp", "alt": "Pięcioetapowy przebieg konfiguracji: instalacja, uwierzytelnienie, konfiguracja GEMINI.md, dodanie skilla, weryfikacja", "caption": "Sekwencja konfiguracji: instalacja → uwierzytelnienie → konfiguracja GEMINI.md → dodanie skilla → włączenie weryfikacji w przeglądarce."}, {"kind": "steps", "items": [{"label": "Zapisz swoje reguły projektowe", "body": "Umieść swoje tokeny, prymitywy i konwencje w GEMINI.md i wskaż je Gemini, by efekt pasował do marki, a nie domyślał się generycznego wyglądu."}, {"label": "Dodaj weryfikację w przeglądarce", "body": "Wepnij Playwright lub przeglądarkowe MCP, by Gemini renderował w prawdziwej przeglądarce i sprawdzał efekt na różnych punktach granicznych, zamiast jedynie potwierdzać, że kompilacja przechodzi."}]}]}, {"id": "screenshot-workflow", "heading": "Proces „od zrzutu ekranu do interfejsu”", "blocks": [{"kind": "p", "text": "Najbardziej wartościową pętlą projektową z Gemini CLI jest przekształcanie obrazu referencyjnego w działający, responsywny interfejs i iterowanie, aż będzie pasował — przy wsparciu modelu multimodalnego, który porównuje efekt z referencją."}, {"kind": "ol", "items": ["Zacznij od najklarowniejszych referencji wizualnych, jakie masz — i uwzględnij wiele stanów (desktop i mobile, hover, pusty, ładowanie), a nie tylko jeden efektowny kadr.", "Bądź konkretny w promptcie; niejasne prompty dają generyczny interfejs nawet przy silnym modelu.", "Trzymaj swój system projektowy i konwencje w GEMINI.md oraz powiedz Gemini, gdzie znajdują się tokeny i kanoniczne prymitywy.", "Uruchom serwer deweloperski i każ Gemini renderować w prawdziwej przeglądarce, zmieniając rozmiar do punktów granicznych, by sprawdzić efekt.", "Iteruj, każąc Gemini porównywać swoją implementację ze zrzutami ekranu — a nie jedynie potwierdzać, że się kompiluje."]}, {"kind": "p", "text": "Odwołaj się do obrazu znakiem @, by dołączyć go do promptu, a następnie podaj konkretne ograniczenia:"}, {"kind": "code", "lang": "bash", "code": "gemini\n# in the prompt:\n> @reference-desktop.png @reference-mobile.png\n  Implement this design in React + Vite + Tailwind + TypeScript.\n  Reuse my existing design-system components and tokens from GEMINI.md.\n  Match spacing, layout, and hierarchy; make it responsive.\n  Render it in the browser and iterate until it matches the references\n  across breakpoints."}, {"kind": "p", "text": "Utrzymuj prompty krótkie i skupione, commituj dobre iteracje i cofaj złe (informując Gemini, gdy cofasz), aby każdy przebieg opierał się na czystej bazie."}]}, {"id": "extend", "heading": "GEMINI.md, MCP i rozszerzenia", "blocks": [{"kind": "p", "text": "Trzy punkty rozszerzeń czynią Gemini CLI praktycznym do długotrwałej pracy projektowej, a wszystkie trzy czysto mapują się na otwarty proces projektowy."}, {"kind": "steps", "items": [{"label": "Kontekst GEMINI.md", "body": "Reguły projektu znajdują się w pliku GEMINI.md w katalogu głównym repozytorium (z warstwami globalną i zespołową). To trwały dom twoich konwencji projektowych, odczytywany przy każdym przebiegu."}, {"label": "Serwery MCP", "body": "Skonfiguruj serwery MCP w ~/.gemini/settings.json — to przenośny sposób na wprowadzenie kontekstu projektowego i zewnętrznych narzędzi, a najbardziej istotnie serwera Figma MCP, które działają w różnych agentach, nie tylko w Gemini."}, {"label": "Rozszerzenia i wbudowane narzędzia", "body": "Rozszerzenia Gemini CLI oraz jego wbudowane narzędzia Google Search, plików, powłoki i pobierania z sieci pozwalają mu zbierać referencje i uruchamiać pętlę weryfikacji bez opuszczania terminala."}]}, {"kind": "p", "text": "To przenośne, wieloagentowe możliwości — dokładnie to, co Open Design zostało zbudowane, by orkiestrować, zamiast odtwarzać dla każdego projektu od nowa."}]}, {"id": "vs", "heading": "Gemini CLI kontra Codex kontra Claude Code kontra Cursor w projektowaniu", "blocks": [{"kind": "p", "text": "Nie ma jednego zwycięzcy w pracy projektowej — każdy agent ma inną mocną stronę, a doświadczone zespoły je łączą. Rzetelne podsumowanie:"}, {"kind": "table", "columns": ["Agent", "Mocna strona w projektowaniu", "Najlepszy do"], "rows": [["Gemini CLI", "Silne multimodalne rozumienie obrazu i kontekst o pojemności 1M tokenów; open-source z darmowym limitem", "Pracy mocno opartej na zrzutach ekranu i utrzymywania całego systemu projektowego w kontekście"], ["Codex", "Silny dopracowany efekt wizualny ze skillem frontendowym; izolowane, asynchroniczne kompilacje", "Delegowanych asynchronicznych kompilacji i przenośnych reguł AGENTS.md"], ["Claude Code", "Konkretne decyzje projektowe (hex, odstępy, typografia) i UX świadomy bazy kodu", "Rozumowania frontendowego i refaktoryzacji w dużym kontekście"], ["Cursor", "Wizualna pętla buduj-i-zobacz z podglądem na żywo i edycjami w miejscu", "Ścisłej pracy nad interfejsem typu iteruj-i-obserwuj wewnątrz IDE"]]}, {"kind": "p", "text": "Powtarzający się werdykt społeczności jest taki, że gust pochodzi od ludzi: wszystkie domyślnie sięgają po generyczną estetykę bez skilli, referencji i ograniczeń. To jest prawdziwy problem do rozwiązania — i ma kształt narzędzia projektowego, a nie modelu."}]}, {"id": "pitfalls", "heading": "Pułapki i jak uniknąć wyglądu „AI slop”", "blocks": [{"kind": "p", "text": "Najczęstszą skargą na projekty generowane przez AI jest to, że wyglądają generycznie — miękkie gradienty, unoszące się panele, przesadnie zaokrąglone rogi, dramatyczne cienie, klimat Inter-i-fioletu, który „krzyczy, że zrobiło to AI”. Inne zgłaszane problemy to zepsute układy mobilne i instrukcje przeciekające do tekstu interfejsu. Żaden z nich nie jest unikalny dla Gemini CLI; to się dzieje, gdy dowolny agent działa bez wyselekcjonowanego kontekstu projektowego."}, {"kind": "steps", "items": [{"label": "Dodaj skill estetyczny", "body": "Wyselekcjonowany skill projektowy zmusza agenta do zaangażowania się w realny kierunek zamiast w domyślny wygląd."}, {"label": "Weryfikuj w prawdziwej przeglądarce", "body": "Wykorzystaj model multimodalny do renderowania i samodzielnego sprawdzania na różnych punktach granicznych, aby układy po cichu nie psuły się na mobile."}, {"label": "Dostarczaj tokeny i referencje", "body": "Realne tokeny projektowe i referencyjne zrzuty ekranu to największa pojedyncza dźwignia jakości efektu."}, {"label": "Zapisz reguły w GEMINI.md", "body": "Umieść reguły w stylu „bez kart hero, maksymalnie dwa kroje pisma, hierarchia marka-przede-wszystkim” tam, gdzie agent czyta je przy każdym przebiegu."}]}, {"kind": "p", "text": "Zauważ, że każde zaradzenie polega na daniu agentowi wyselekcjonowanego kontekstu projektowego. Utrzymywanie tego kontekstu ręcznie, dla każdego projektu, to mozół, który Open Design eliminuje."}]}, {"id": "open-design", "heading": "Projektowanie z Gemini CLI w Open Design", "blocks": [{"kind": "p", "text": "Open Design to open-source'owa warstwa projektowa, o którą powyższy proces wciąż się dopomina. Traktuje Gemini CLI jako adapter pierwszej kategorii i otacza go wyselekcjonowaną biblioteką skilli i systemów projektowych, ustrukturyzowanym potokiem renderowania oraz lokalnym interfejsem desktopowym — więc kontekst projektowy, który czyni Gemini dobrym, jest tam od pierwszego przebiegu, a nie składany ręcznie za każdym razem. Oba są open-source'owe i lokalne, co czyni to połączenie naturalnym dopasowaniem."}, {"kind": "ol", "items": ["Zainstaluj Open Design i wybierz Gemini CLI jako swojego agenta.", "Uwierzytelnij się kontem Google lub kluczem API Gemini (BYOK) — poświadczenia pozostają na twojej maszynie i nigdy nie są przepuszczane przez nas jako pośrednika.", "Wybierz system projektowy i skill, a następnie generuj prezentacje, prototypy i strony docelowe ze spójnym gustem.", "Każdy artefakt i plik DESIGN.md żyje w twoim własnym repozytorium, a nie w hostowanej chmurze."]}, {"kind": "p", "text": "Ten sam agent Gemini CLI, ten sam klucz — plus realny, przenośny, open-source'owy proces projektowy wokół niego. Jest lokalny i na licencji Apache-2.0, więc nic z twojej pracy ani twoich poświadczeń nie opuszcza twojej maszyny."}]}], "faqTitle": "Najczęściej zadawane pytania", "faq": [{"name": "Czy Gemini CLI naprawdę poradzi sobie z pracą projektową?", "text": "Tak — mając w kontekście skill estetyczny, system projektowy i realne obrazy referencyjne, Gemini CLI tworzy produkcyjnej jakości, responsywny interfejs, a jego silne modele multimodalne weryfikują efekt względem referencji. Bez tego kontekstu skłania się ku generycznemu wyglądowi, co jest luką, którą wypełnia Open Design."}, {"name": "Czy muszę płacić, by projektować z Gemini CLI?", "text": "Nie — logowanie się kontem Google daje hojny darmowy limit, a możesz też podać własny klucz API Gemini (BYOK) lub skorzystać z Vertex AI. Open Design tak czy inaczej nigdy nie pośredniczy w twoich poświadczeniach."}, {"name": "Co dokładnie czyni Gemini CLI dobrym do projektowania?", "text": "Dwie rzeczy: jego modele są silnie multimodalne, więc dobrze odczytuje referencyjne zrzuty ekranu, a jego kontekst o pojemności 1M tokenów potrafi pomieścić cały system projektowy i zestaw referencji naraz. Oba pomagają — ale gust nadal pochodzi z systemu projektowego, skilla i referencji, które dostarczasz."}, {"name": "Gemini CLI czy Claude Code do projektowania frontendu?", "text": "Oba są mocne. Claude Code jest znany z konkretnych, świadomych bazy kodu decyzji projektowych; przewagą Gemini CLI jest rozumienie multimodalne plus ogromny kontekst i darmowy limit. Wiele zespołów używa obu — Open Design pozwala przełączać agentów bez zmiany twojego procesu projektowego."}, {"name": "Jak połączyć Gemini CLI z Figmą?", "text": "Dodaj serwer Figma MCP w sekcji mcpServers w ~/.gemini/settings.json. Gemini może wtedy pobrać realny kontekst projektowy — komponenty, zmienne, dane o układzie — więc wygenerowany kod pasuje do źródła, zamiast je przybliżać."}, {"name": "Czy Open Design jest powiązany z Google?", "text": "Nie. Gemini CLI jest produktem Google; Open Design to niezależny projekt open-source, który obsługuje go jako adapter pierwszej kategorii. Gemini jest znakiem towarowym Google."}, {"name": "Czy moje pliki i poświadczenia są bezpieczne?", "text": "Tak — Open Design jest lokalny i na licencji Apache-2.0. Twoje pliki, artefakty i DESIGN.md pozostają w twoim własnym repozytorium, a twoje poświadczenia Google są używane bezpośrednio przez twojego agenta, nigdy nie są kierowane przez serwery Open Design."}], "ctaTitle": "Projektuj z Gemini CLI w otwarty sposób.", "ctaBody": "Przynieś własne konto Google lub klucz API Gemini, trzymaj każdy plik lokalnie i otrzymaj wyselekcjonowaną bibliotekę projektową wokół agenta, którego już używasz.", "ctaActions": [{"label": "Użyj Gemini CLI w Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Dodaj gwiazdkę na GitHubie", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Pobierz aplikację desktopową", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Zobacz wszystkie obsługiwane agenty"},
      },
      'copilot': {
        ...en['copilot']!,
        title: "GitHub Copilot CLI do projektowania — Open Design",
        description: "Jak ludzie wykorzystują GitHub Copilot CLI w projektowaniu interfejsów i stron — terminalowego agenta kodującego, niestandardowe pliki z instrukcjami, obsługę MCP i wybór spośród wielu modeli — oraz jak Open Design zamienia Copilot CLI w lokalnie działającego, open source'owego agenta projektowego.",
        breadcrumb: "GitHub Copilot CLI",
        label: "Agent · GitHub Copilot CLI",
        heading: "GitHub Copilot CLI do projektowania.",
        lead: "GitHub Copilot CLI to terminalowy agent kodujący od GitHub. Planuje i edytuje zmiany w całym repozytorium, korzysta z czołowych modeli takich jak Claude i GPT oraz czyta instrukcje repozytorium — co czyni go realnym narzędziem projektowym, gdy tylko dasz mu referencje, konwencje i pętlę weryfikacji. Open Design wpina go w open source'owy proces projektowania: Twoja subskrypcja GitHub Copilot, Twoje pliki, działanie lokalne.",
        rich: {"heroCtaLead": "Open Design zamienia GitHub Copilot CLI w lokalnie działającego, open source'owego agenta projektowego — Twoja subskrypcja GitHub Copilot, Twoje pliki oraz wyselekcjonowana biblioteka skilli i systemów projektowych wokół niego.", "heroCtaActions": [{"label": "Użyj Copilot CLI w Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Dodaj gwiazdkę na GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Pobierz aplikację desktopową", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["GitHub Copilot CLI to terminalowy agent kodujący od GitHub — ta sama agentowa platforma, która napędza Copilot coding agent, przeniesiona do Twojej linii poleceń. Dwie rzeczy czynią go interesującym właśnie do projektowania: czyta instrukcje repozytorium oraz AGENTS.md, więc Twoje konwencje projektowe podróżują z agentem przy każdym uruchomieniu; i pozwala wybierać spośród czołowych modeli od Anthropic, OpenAI i Google dla każdego zadania, dzięki czemu możesz sięgnąć po ten, który najlepiej rozumuje o danym interfejsie. W połączeniu z odpowiednimi referencjami, konwencjami i pętlą weryfikacji buduje realny, responsywny interfejs — a działa na subskrypcji Copilot, którą być może już masz. To praktyczny, kompleksowy przewodnik po wykorzystaniu Copilot CLI do pracy nad interfejsem, frontendem i systemami projektowymi oraz po wpięciu go w ustrukturyzowany proces projektowania z Open Design.", "Omawia, czym tak naprawdę jest Copilot CLI, dlaczego instrukcje repozytorium i wybór modelu pasują do projektowania, jak skonfigurować go od zera, pętlę „od zrzutu ekranu do interfejsu”, jak rozszerzają go niestandardowe instrukcje i MCP, jak wypada na tle Codex, Claude Code, Cursor i Gemini CLI, jakie pułapki sprawiają, że efekty AI wyglądają generycznie, oraz jak Open Design domyka tę lukę jako otwarta, lokalnie działająca warstwa projektowa — Twoja subskrypcja i poświadczenia zostają na Twoim komputerze, a Twoje artefakty w Twoim własnym repozytorium."], "heroImage": {"src": "/agents/copilot-design/copilot-design-hero.webp", "alt": "Pętla sprzężenia zwrotnego w projektowaniu z GitHub Copilot CLI: terminalowy agent czytający obraz referencyjny, przeglądarka renderująca interfejs i przestrzeń robocza, ze strzałką sprzężenia zwrotnego zawracającą do początku", "caption": "Główna pętla: Copilot CLI czyta Twoje referencje w terminalu, buduje i weryfikuje interfejs w prawdziwej przeglądarce oraz iteruje względem nich — z konwencjami projektowymi w instrukcjach repozytorium."}, "tocLabel": "Na tej stronie", "toc": [{"id": "what-is-copilot", "label": "Czym tak naprawdę jest GitHub Copilot CLI"}, {"id": "why-design", "label": "Dlaczego instrukcje + wybór modelu pasują do projektowania"}, {"id": "setup", "label": "Konfiguracja Copilot CLI do projektowania (od zera)"}, {"id": "screenshot-workflow", "label": "Proces „od zrzutu ekranu do interfejsu”"}, {"id": "extend", "label": "Niestandardowe instrukcje, MCP i rozszerzenia"}, {"id": "vs", "label": "Copilot CLI vs Codex vs Claude Code vs Cursor vs Gemini CLI"}, {"id": "pitfalls", "label": "Pułapki i wygląd „AI slop”"}, {"id": "open-design", "label": "Projektowanie z Copilot CLI w Open Design"}, {"id": "faq", "label": "FAQ"}], "sections": [{"id": "what-is-copilot", "heading": "Czym tak naprawdę jest GitHub Copilot CLI", "blocks": [{"kind": "p", "text": "GitHub Copilot CLI to terminalowy agent kodujący od GitHub. Czyta Twoje repozytorium, edytuje pliki, uruchamia polecenia powłoki i pracuje bezpośrednio z Twoim kontekstem GitHub — zgłoszeniami, pull requestami i repozytoriami — uwierzytelniony za pomocą Twojego istniejącego konta GitHub. Napędza go ta sama agentowa platforma co Copilot coding agent od GitHub, więc planuje złożone zadania i iteruje, zamiast jedynie uzupełniać linie. Stał się ogólnie dostępny w lutym 2026 roku, po publicznej wersji zapoznawczej otwartej we wrześniu 2025 roku."}, {"kind": "p", "text": "W pracy projektowej wyróżniają się dwie cechy. Czyta niestandardowe pliki z instrukcjami — reguły obowiązujące w całym repozytorium w .github/copilot-instructions.md oraz AGENTS.md — więc Twoje konwencje projektowe są automatycznie uwzględniane przy każdym uruchomieniu. I obsługuje wielu dostawców modeli podstawowych, więc dla każdego zadania możesz przełączyć model poleceniem /model na ten, który najlepiej rozumuje o danym interfejsie."}, {"kind": "steps", "items": [{"label": "Pliki z instrukcjami", "body": "Copilot CLI czyta instrukcje repozytorium w .github/copilot-instructions.md, pliki specyficzne dla ścieżek w .github/instructions oraz AGENTS.md — naturalne miejsce na zakodowanie Twoich konwencji projektowych, tokenów i list kontrolnych do przeglądu."}, {"label": "Wbudowane narzędzia + MCP", "body": "Dostarczany jest z wbudowanym serwerem MCP od GitHub i uruchamia narzędzia plikowe oraz powłokowe, a niestandardowe serwery MCP możesz dodać poleceniem /mcp add (zapisywane w mcp-config.json w ~/.copilot), aby dostarczyć zewnętrzny kontekst, taki jak żywy plik Figma."}, {"label": "Wybór modelu", "body": "Użyj polecenia /model, aby wybierać spośród czołowych modeli od Anthropic, OpenAI i Google — przełączając je dla każdego zadania, wszystko w ramach Twojej istniejącej subskrypcji Copilot."}]}, {"kind": "ul", "items": ["Dostawca: GitHub", "Poświadczenie: aktywna subskrypcja GitHub Copilot (Pro, Pro+, Business lub Enterprise)", "Instalacja: npm install -g @github/copilot, a następnie uruchom copilot"]}]}, {"id": "why-design", "heading": "Dlaczego instrukcje repozytorium i wybór modelu pasują do projektowania", "blocks": [{"kind": "p", "text": "Przewaga Copilot CLI w projektowaniu wynika z dwóch cech — ale, jak w przypadku każdego agenta, gust nadal trzeba dostarczyć."}, {"kind": "steps", "items": [{"label": "Konwencje, które podróżują z repozytorium", "body": "Ponieważ Copilot CLI automatycznie czyta .github/copilot-instructions.md i AGENTS.md, Twoje tokeny, prymitywy i reguły przeglądu są w kontekście przy każdym uruchomieniu — agent pracuje na rzecz marki, a nie domyślnego wyglądu."}, {"label": "Wybierz właściwy model do zadania", "body": "Wybór modelu spośród Anthropic, OpenAI i Google oznacza, że możesz sięgnąć po ten, który najlepiej rozumuje o danym układzie, a potem przełączyć go do kolejnego zadania — bez zmiany swojego procesu pracy."}, {"label": "Prawdziwe specyfikacje przez MCP", "body": "Wbudowany serwer MCP od GitHub oraz serwer MCP do Figma kierują agenta do Twoich tokenów, komponentów i prawdziwych specyfikacji, dzięki czemu buduje na podstawie źródła, zamiast je przybliżać."}]}, {"kind": "image", "src": "/agents/copilot-design/copilot-design-taste-triangle.webp", "alt": "Diagram pokazujący system projektowy, skill i obraz referencyjny zbiegające się w dobry efekt projektowy", "caption": "Gust pochodzi z trzech dostarczanych przez Ciebie wejść: systemu projektowego, skilla i prawdziwych obrazów referencyjnych."}, {"kind": "p", "text": "Lekcja jest ta sama, której uczy każdy agent: Copilot CLI domyślnie nie ma gustu. Tworzy dobry projekt, gdy dasz mu ograniczenia — system projektowy, skill estetyczny i konkretne referencje. Open Design pakuje dokładnie te wejścia, dlatego oba do siebie pasują (więcej poniżej)."}]}, {"id": "setup", "heading": "Konfiguracja Copilot CLI do pracy projektowej, od zera", "blocks": [{"kind": "p", "text": "Oto pełna droga od czystej maszyny do Copilot CLI, który potrafi budować i weryfikować interfejs."}, {"kind": "code", "lang": "bash", "code": "# 1. Install Copilot CLI (Node.js required)\nnpm install -g @github/copilot\n\n# 2. Start it in your project and authenticate on first run\ncd your-project\ncopilot           # run /login and follow the prompts to sign in\n\n# 3. Choose a model for the task\n#    inside the session:\n/model            # pick a frontier model from Anthropic, OpenAI, or Google\n\n# 4. Add custom instructions and the Figma MCP server (optional)\n#    write .github/copilot-instructions.md or AGENTS.md\n/mcp add          # add the Figma MCP server for design handoff"}, {"kind": "image", "src": "/agents/copilot-design/copilot-design-setup-flow.webp", "alt": "Pięcioetapowy proces konfiguracji: instalacja, uwierzytelnienie, wybór modelu, konfiguracja instrukcji, weryfikacja", "caption": "Sekwencja konfiguracji: instalacja → uwierzytelnienie → wybór modelu → zapisanie instrukcji → włączenie weryfikacji w przeglądarce."}, {"kind": "steps", "items": [{"label": "Zakoduj swoje reguły projektowe", "body": "Umieść swoje tokeny, prymitywy i konwencje w .github/copilot-instructions.md lub AGENTS.md, aby efekt pasował do marki, zamiast domyślnie przyjmować generyczny wygląd."}, {"label": "Dodaj weryfikację w przeglądarce", "body": "Wepnij Playwright lub przeglądarkowe MCP, aby Copilot renderował w prawdziwej przeglądarce i sprawdzał swój efekt na różnych punktach granicznych, zamiast jedynie potwierdzać, że build przechodzi."}]}]}, {"id": "screenshot-workflow", "heading": "Proces „od zrzutu ekranu do interfejsu”", "blocks": [{"kind": "p", "text": "Najbardziej dźwigniowa pętla projektowa z Copilot CLI to przekształcanie obrazu referencyjnego w działający, responsywny interfejs i iterowanie aż do dopasowania — z wykorzystaniem mocnego modelu multimodalnego do porównywania efektu z referencją."}, {"kind": "ol", "items": ["Zacznij od najwyraźniejszych dostępnych referencji wizualnych — i uwzględnij wiele stanów (desktop i mobile, hover, pusty, ładowanie), nie tylko jeden kadr główny.", "Bądź konkretny w prompcie; niejasne prompty dają generyczny interfejs nawet przy mocnym modelu.", "Trzymaj swój system projektowy i konwencje w .github/copilot-instructions.md lub AGENTS.md i powiedz Copilotowi, gdzie znajdują się tokeny i kanoniczne prymitywy.", "Uruchom serwer deweloperski i poproś Copilota, by renderował w prawdziwej przeglądarce, zmieniając rozmiar do punktów granicznych w celu sprawdzenia rezultatu.", "Iteruj, każąc Copilotowi porównywać swoją implementację ze zrzutami ekranu — nie tylko potwierdzać, że się buduje."]}, {"kind": "p", "text": "Skieruj Copilota na swoje obrazy referencyjne i podaj konkretne ograniczenia; przed uruchomieniem wyświetla on do zatwierdzenia każdą edycję pliku lub polecenie:"}, {"kind": "code", "lang": "bash", "code": "copilot\n# in the prompt:\n> Implement the design in reference-desktop.png and reference-mobile.png\n  in React + Vite + Tailwind + TypeScript.\n  Reuse my existing design-system components and tokens described in\n  .github/copilot-instructions.md.\n  Match spacing, layout, and hierarchy; make it responsive.\n  Render it in the browser and iterate until it matches the references\n  across breakpoints."}, {"kind": "p", "text": "Utrzymuj prompty krótkie i skupione, zatwierdzaj dobre iteracje, a złe wycofuj (informując Copilota, gdy wycofujesz), aby każdy przebieg budował na czystej bazie."}]}, {"id": "extend", "heading": "Niestandardowe instrukcje, MCP i rozszerzenia", "blocks": [{"kind": "p", "text": "Trzy punkty rozszerzeń czynią Copilot CLI praktycznym do długotrwałej pracy projektowej, a wszystkie trzy odwzorowują się czysto na otwarty proces projektowania."}, {"kind": "steps", "items": [{"label": "Niestandardowe instrukcje", "body": "Reguły repozytorium żyją w .github/copilot-instructions.md (z plikami specyficznymi dla ścieżek w .github/instructions oraz AGENTS.md). To trwały dom Twoich konwencji projektowych, uwzględniany automatycznie przy każdym uruchomieniu."}, {"label": "Serwery MCP", "body": "Copilot CLI jest dostarczany z wbudowanym serwerem MCP od GitHub i pozwala dodawać niestandardowe serwery przez /mcp add (zapisywane w mcp-config.json w ~/.copilot) — przenośny sposób wprowadzania kontekstu projektowego, najbardziej istotnie serwera MCP do Figma, który działa w różnych agentach, nie tylko w Copilocie."}, {"label": "Wyspecjalizowani agenci i wbudowane narzędzia", "body": "Wyspecjalizowane tryby Copilot CLI — do eksploracji bazy kodu, uruchamiania buildów i testów, przeglądu zmian oraz planowania — plus jego narzędzia plikowe i powłokowe pozwalają mu zbierać referencje i uruchamiać pętlę weryfikacji bez opuszczania terminala."}]}, {"kind": "p", "text": "To przenośne, wieloagentowe możliwości — dokładnie taki rodzaj rzeczy, które Open Design jest stworzony orkiestrować, zamiast odtwarzać je w każdym projekcie."}]}, {"id": "vs", "heading": "Copilot CLI vs Codex vs Claude Code vs Cursor vs Gemini CLI w projektowaniu", "blocks": [{"kind": "p", "text": "Nie ma jednego zwycięzcy w pracy projektowej — każdy agent ma inną mocną stronę, a doświadczone zespoły łączą je w stos. Rzetelne podsumowanie:"}, {"kind": "table", "columns": ["Agent", "Mocna strona w projektowaniu", "Najlepszy do"], "rows": [["Copilot CLI", "Wybór spośród wielu modeli (Anthropic, OpenAI, Google) i głęboka integracja z GitHub w ramach Twojej subskrypcji Copilot", "Wybierania najlepszego modelu do zadania i pracy opartej na instrukcjach powiązanej z Twoim repozytorium GitHub"], ["Codex", "Mocne dopracowanie wizualne dzięki skillowi frontendowemu; izolowane asynchroniczne buildy", "Delegowanych asynchronicznych buildów i przenośnych reguł AGENTS.md"], ["Claude Code", "Konkretne decyzje projektowe (hex, odstępy, typografia) i UX świadomy bazy kodu", "Rozumowania frontendowego i refaktoryzacji w dużym kontekście"], ["Cursor", "Wizualna pętla buduj-i-zobacz z podglądem na żywo i edycjami w miejscu", "Ścisłej pracy iteruj-i-obserwuj nad interfejsem wewnątrz IDE"], ["Gemini CLI", "Mocne multimodalne rozumienie obrazów i kontekst 1 mln tokenów; open source z darmowym poziomem", "Pracy intensywnie opartej na zrzutach ekranu i trzymania całego systemu projektowego w kontekście"]]}, {"kind": "p", "text": "Powtarzający się werdykt społeczności jest taki, że gust pochodzi od ludzi: wszystkie z nich domyślnie przyjmują generyczną estetykę bez skilli, referencji i ograniczeń. To właśnie realny problem do rozwiązania — i ma on kształt narzędzia projektowego, a nie modelu."}]}, {"id": "pitfalls", "heading": "Pułapki i jak uniknąć wyglądu „AI slop”", "blocks": [{"kind": "p", "text": "Najczęstsza skarga na projekty generowane przez AI jest taka, że wyglądają generycznie — miękkie gradienty, unoszące się panele, przesadnie zaokrąglone rogi, dramatyczne cienie, klimat Inter-i-fioletu, który „krzyczy, że zrobiła to AI”. Inne zgłaszane problemy to popsute układy mobilne i instrukcje przeciekające do tekstów interfejsu. Żaden z nich nie jest unikalny dla Copilot CLI; to po prostu skutek uruchamiania dowolnego agenta bez wyselekcjonowanego kontekstu projektowego."}, {"kind": "steps", "items": [{"label": "Dodaj skill estetyczny", "body": "Wyselekcjonowany skill projektowy zmusza agenta do zaangażowania się w realny kierunek zamiast w domyślny wygląd."}, {"label": "Weryfikuj w prawdziwej przeglądarce", "body": "Renderuj i sprawdzaj samodzielnie na różnych punktach granicznych za pomocą przeglądarkowego MCP, aby układy nie psuły się po cichu na urządzeniach mobilnych."}, {"label": "Dostarcz tokeny i referencje", "body": "Prawdziwe tokeny projektowe i referencyjne zrzuty ekranu to pojedyncza, największa dźwignia jakości efektu."}, {"label": "Zakoduj reguły w niestandardowych instrukcjach", "body": "Umieść reguły w stylu „bez kart hero, maks. dwa kroje pisma, hierarchia z marką na pierwszym miejscu” w .github/copilot-instructions.md lub AGENTS.md, gdzie agent czyta je przy każdym uruchomieniu."}]}, {"kind": "p", "text": "Zauważ, że każde z tych zabezpieczeń polega na daniu agentowi wyselekcjonowanego kontekstu projektowego. Utrzymywanie tego kontekstu ręcznie, w każdym projekcie, to mozół, który Open Design eliminuje."}]}, {"id": "open-design", "heading": "Projektowanie z Copilot CLI wewnątrz Open Design", "blocks": [{"kind": "p", "text": "Open Design to open source'owa warstwa projektowa, o którą powyższy proces wciąż się dopomina. Traktuje GitHub Copilot CLI jako adapter pierwszej kategorii i opakowuje go w wyselekcjonowaną bibliotekę skilli i systemów projektowych, ustrukturyzowany potok renderowania oraz lokalny interfejs desktopowy — więc kontekst projektowy, który czyni Copilota dobrym, jest na miejscu od pierwszego uruchomienia, a nie składany ręcznie za każdym razem. Open Design jest niezależny, open source'owy (Apache-2.0) i działa lokalnie, dlatego to połączenie pasuje: agent wykonuje pracę, a Twoje pliki i poświadczenia pozostają Twoje."}, {"kind": "ol", "items": ["Zainstaluj Open Design i wybierz GitHub Copilot CLI jako swojego agenta.", "Uwierzytelnij się swoją subskrypcją GitHub Copilot — poświadczenia zostają na Twoim komputerze i nigdy nie są przekazywane przez nas.", "Wybierz system projektowy i skill, a następnie generuj prezentacje, prototypy i strony docelowe ze spójnym gustem.", "Każdy artefakt i plik DESIGN.md żyje w Twoim własnym repozytorium, a nie w hostowanej chmurze."]}, {"kind": "p", "text": "Ten sam agent Copilot CLI, ta sama subskrypcja — plus realny, przenośny, open source'owy proces projektowania wokół niego. Open Design działa lokalnie i jest na licencji Apache-2.0, więc nic z Twojej pracy ani Twoich poświadczeń nie opuszcza Twojego komputera."}]}], "faqTitle": "Najczęściej zadawane pytania", "faq": [{"name": "Czy GitHub Copilot CLI naprawdę potrafi wykonywać pracę projektową?", "text": "Tak — mając w kontekście skill estetyczny, system projektowy i prawdziwe obrazy referencyjne, Copilot CLI tworzy responsywny interfejs o jakości produkcyjnej, a Ty możesz wybrać model, który najlepiej weryfikuje efekt względem referencji. Bez tego kontekstu skłania się ku generycznemu wyglądowi, co jest luką, którą wypełnia Open Design."}, {"name": "Czy potrzebuję subskrypcji, aby projektować z Copilot CLI?", "text": "Tak — Copilot CLI działa na aktywnej subskrypcji GitHub Copilot (Pro, Pro+, Business lub Enterprise); nie jest to model BYOK. Uwierzytelniasz się swoim kontem GitHub. Open Design nigdy nie pośredniczy w Twoich poświadczeniach — Twoja subskrypcja jest używana bezpośrednio przez Twojego agenta."}, {"name": "Co konkretnie czyni Copilot CLI dobrym do projektowania?", "text": "Dwie rzeczy: automatycznie czyta instrukcje repozytorium i AGENTS.md, więc Twoje konwencje projektowe podróżują z repozytorium; i pozwala przełączać się dla każdego zadania spośród czołowych modeli od Anthropic, OpenAI i Google. Oba pomagają — ale gust nadal pochodzi z systemu projektowego, skilla i referencji, które dostarczasz."}, {"name": "Copilot CLI czy Claude Code do projektowania frontendu?", "text": "Oba są mocne. Claude Code jest znany z konkretnych decyzji projektowych świadomych bazy kodu; przewagą Copilot CLI jest wybór modeli różnych dostawców i głęboka integracja z GitHub w ramach subskrypcji, którą być może już masz. Wiele zespołów używa obu — Open Design pozwala przełączać agentów bez zmiany procesu projektowania."}, {"name": "Jak połączyć Copilot CLI z Figma?", "text": "Dodaj serwer MCP do Figma poleceniem /mcp add; ustawienia są zapisywane w mcp-config.json w ~/.copilot. Copilot może wtedy pobierać prawdziwy kontekst projektowy — komponenty, zmienne, dane układu — aby wygenerowany kod pasował do źródła, zamiast je przybliżać."}, {"name": "Czy Open Design jest powiązany z GitHub lub Microsoft?", "text": "Nie. GitHub Copilot CLI to produkt GitHub; Open Design to niezależny projekt open source, który wspiera go jako adapter pierwszej kategorii. GitHub Copilot jest znakiem towarowym GitHub, Inc. i Microsoft."}, {"name": "Czy moje pliki i poświadczenia są bezpieczne?", "text": "Tak — Open Design działa lokalnie i jest na licencji Apache-2.0. Twoje pliki, artefakty i DESIGN.md pozostają w Twoim własnym repozytorium, a Twoje poświadczenia GitHub Copilot są używane bezpośrednio przez Twojego agenta, nigdy nie są kierowane przez serwery Open Design."}], "ctaTitle": "Projektuj z GitHub Copilot CLI, w otwarty sposób.", "ctaBody": "Przynieś swoją subskrypcję GitHub Copilot, trzymaj każdy plik lokalnie i otrzymaj wyselekcjonowaną bibliotekę projektową wokół agenta, którego już używasz.", "ctaActions": [{"label": "Użyj Copilot CLI w Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Dodaj gwiazdkę na GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Pobierz aplikację desktopową", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Zobacz wszystkich obsługiwanych agentów"},
      },
      'qwen': {
        ...en['qwen']!,
        title: "Qwen Code do projektowania — Open Design",
        description: "Jak ludzie wykorzystują open source'owy Qwen Code CLI od Alibaba w projektowaniu interfejsów i stron — jego modele Qwen3-Coder, duże okno kontekstu, QWEN.md i MCP — oraz jak Open Design zamienia Qwen Code w lokalnie działającego, open source'owego agenta projektowego.",
        breadcrumb: "Qwen Code",
        label: "Agent · Qwen Code",
        heading: "Qwen Code do projektowania.",
        lead: "Qwen Code to open source'owy terminalowy agent od Alibaba, zaadaptowany z Gemini CLI i dostrojony do modeli Qwen3-Coder. Jego duże okno kontekstu mieści cały system projektowy naraz, co czyni go realnym narzędziem projektowym — gdy tylko dasz mu referencje, konwencje i pętlę weryfikacji. Open Design wpina go w open source'owy proces projektowania: Twój klucz API DashScope lub Qwen, Twoje pliki, działanie lokalne.",
        rich: {"heroCtaLead": "Open Design zamienia Qwen Code w lokalnie działającego, open source'owego agenta projektowego — Twój klucz API DashScope lub Qwen, Twoje pliki oraz wyselekcjonowana biblioteka skilli i systemów projektowych wokół niego.", "heroCtaActions": [{"label": "Użyj Qwen Code w Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Dodaj gwiazdkę na GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Pobierz aplikację desktopową", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["Qwen Code to open source'owy agent AI od Alibaba dla terminala. Jest zaadaptowany z Gemini CLI od Google, z adaptacjami na poziomie parsera i promptów, które pozwalają mu w pełni wykorzystać modele Qwen3-Coder. Dwie rzeczy czynią go interesującym właśnie do projektowania: to mocny agentowy model kodujący, więc planuje, edytuje pliki i uruchamia pętlę budowania oraz weryfikacji na podstawie zadania w języku naturalnym; a jego duże okno kontekstu mieści cały system projektowy i bazę kodu naraz. W połączeniu z odpowiednimi referencjami, konwencjami i pętlą weryfikacji buduje realny, responsywny interfejs — a jest open source'owy i BYOK, więc przynosisz własny klucz. To praktyczny, kompleksowy przewodnik po wykorzystaniu Qwen Code do pracy nad interfejsem, frontendem i systemami projektowymi oraz po wpięciu go w ustrukturyzowany proces projektowania z Open Design.", "Omawia, czym tak naprawdę jest Qwen Code, dlaczego mocny model kodujący plus duży kontekst pasują do projektowania, jak skonfigurować go od zera, pętlę „od referencji do interfejsu”, jak rozszerzają go QWEN.md i MCP, jak wypada na tle Codex, Claude Code, Cursor i Gemini CLI, jakie pułapki sprawiają, że efekty AI wyglądają generycznie, oraz jak Open Design domyka tę lukę jako otwarta, lokalnie działająca warstwa projektowa — naturalne połączenie, skoro oba są open source'owe i działają na Twoim własnym komputerze."], "heroImage": {"src": "/agents/qwen-design/qwen-design-hero.webp", "alt": "Pętla sprzężenia zwrotnego w projektowaniu z Qwen Code: terminalowy agent czytający obraz referencyjny, przeglądarka renderująca interfejs i przestrzeń robocza, ze strzałką sprzężenia zwrotnego zawracającą do początku", "caption": "Główna pętla: Qwen Code czyta Twoje referencje w terminalu, buduje i weryfikuje interfejs w prawdziwej przeglądarce oraz iteruje względem nich — z całym systemem projektowym w kontekście."}, "tocLabel": "Na tej stronie", "toc": [{"id": "what-is-qwen", "label": "Czym tak naprawdę jest Qwen Code"}, {"id": "why-design", "label": "Dlaczego mocny model kodujący + duży kontekst pasują do projektowania"}, {"id": "setup", "label": "Konfiguracja Qwen Code do projektowania (od zera)"}, {"id": "screenshot-workflow", "label": "Proces „od referencji do interfejsu”"}, {"id": "extend", "label": "QWEN.md, MCP i rozszerzenia"}, {"id": "vs", "label": "Qwen Code vs Codex vs Claude Code vs Cursor vs Gemini CLI"}, {"id": "pitfalls", "label": "Pułapki i wygląd „AI slop”"}, {"id": "open-design", "label": "Projektowanie z Qwen Code w Open Design"}, {"id": "faq", "label": "FAQ"}], "sections": [{"id": "what-is-qwen", "heading": "Czym tak naprawdę jest Qwen Code", "blocks": [{"kind": "p", "text": "Qwen Code to open source'owy (Apache-2.0) agent AI, którego Alibaba dostarcza dla terminala. Czyta Twoje repozytorium, edytuje pliki, uruchamia polecenia powłoki i korzysta z sieci — planując i weryfikując pracę na podstawie zadań w języku naturalnym, zamiast jedynie uzupełniać linie. Jest zaadaptowany z Gemini CLI od Google, z adaptacjami na poziomie parsera i promptów dostrojonymi tak, by uwolnić modele Qwen3-Coder w agentowych zadaniach kodowania."}, {"kind": "p", "text": "W pracy projektowej wyróżniają się dwie cechy. To zdolny agentowy programista, więc może wziąć referencję i jasny brief oraz budować, uruchamiać i samodzielnie korygować responsywny interfejs. A modele Qwen3-Coder mają duże okno kontekstu, na tyle obszerne, by pomieścić cały Twój system projektowy, bibliotekę komponentów i zestaw referencji naraz, zamiast je streszczać i pomijać."}, {"kind": "steps", "items": [{"label": "Pliki kontekstu", "body": "Qwen Code czyta plik QWEN.md jako trwały kontekst projektu — naturalne miejsce na zakodowanie Twoich konwencji projektowych, tokenów i list kontrolnych do przeglądu. Ustawienia osobiste i projektowe nakładają się na to warstwami."}, {"label": "Wbudowane narzędzia + MCP", "body": "Dostarczany jest z narzędziami plikowymi, powłokowymi i sieciowymi od razu po instalacji oraz obsługuje serwery MCP (konfigurowane w mcpServers w ~/.qwen/settings.json), aby dodać zewnętrzny kontekst, taki jak żywy plik Figma."}, {"label": "BYOK na start", "body": "Przynosisz własny klucz — klucz API DashScope (Alibaba Cloud Model Studio) lub dowolny zgodny z OpenAI endpoint albo ModelScope — i konfigurujesz go w settings.json."}]}, {"kind": "ul", "items": ["Dostawca: Alibaba", "Poświadczenie: klucz API DashScope / Qwen (BYOK) lub zgodny z OpenAI endpoint / ModelScope", "Licencja: Apache-2.0, open source (zaadaptowany z Gemini CLI)"]}]}, {"id": "why-design", "heading": "Dlaczego mocny model kodujący i duży kontekst pasują do projektowania", "blocks": [{"kind": "p", "text": "Przewaga Qwen Code w projektowaniu wynika z dwóch cech — ale, jak w przypadku każdego agenta, gust nadal trzeba dostarczyć."}, {"kind": "steps", "items": [{"label": "Mocne agentowe kodowanie", "body": "Modele Qwen3-Coder są dostrojone do zadań agentowych, więc agent planuje, edytuje, uruchamia build i samodzielnie się koryguje — zamieniając jasną referencję i brief w responsywny kod, zamiast jednorazowego zgadywania."}, {"label": "Duże okno kontekstu", "body": "Duży kontekst Qwen3-Coder oznacza, że cały system projektowy, tokeny i wiele stanów referencyjnych mieszczą się naraz, więc agent wykorzystuje ponownie Twoje prawdziwe prymitywy, zamiast wymyślać jednorazowe style."}, {"label": "Konwencje w QWEN.md", "body": "QWEN.md (plus serwer MCP do Figma) kieruje agenta do Twoich tokenów, komponentów i prawdziwych specyfikacji, więc pracuje na rzecz marki, a nie domyślnego wyglądu."}]}, {"kind": "image", "src": "/agents/qwen-design/qwen-design-taste-triangle.webp", "alt": "Diagram pokazujący system projektowy, skill i obraz referencyjny zbiegające się w dobry efekt projektowy", "caption": "Gust pochodzi z trzech dostarczanych przez Ciebie wejść: systemu projektowego, skilla i prawdziwych obrazów referencyjnych."}, {"kind": "p", "text": "Lekcja jest ta sama, której uczy każdy agent: Qwen Code domyślnie nie ma gustu. Tworzy dobry projekt, gdy dasz mu ograniczenia — system projektowy, skill estetyczny i konkretne referencje. Open Design pakuje dokładnie te wejścia, dlatego oba do siebie pasują (więcej poniżej)."}]}, {"id": "setup", "heading": "Konfiguracja Qwen Code do pracy projektowej, od zera", "blocks": [{"kind": "p", "text": "Oto pełna droga od czystej maszyny do Qwen Code, który potrafi budować i weryfikować interfejs."}, {"kind": "code", "lang": "bash", "code": "# 1. Install Qwen Code (Node 22+)\nnpm install -g @qwen-code/qwen-code@latest\n# or: brew install qwen-code\n\n# 2. Start it in your project and authenticate on first run\ncd your-project\nqwen              # run /auth, or set a key in ~/.qwen/settings.json\n\n# 3. Configure a DashScope (OpenAI-compatible) key in settings.json\n#    baseUrl: https://dashscope.aliyuncs.com/compatible-mode/v1\n#    model:   qwen3-coder-plus   (set DASHSCOPE_API_KEY)\n\n# 4. Add a QWEN.md and wire the Figma MCP server (optional)\n#    add MCP under \"mcpServers\" in ~/.qwen/settings.json"}, {"kind": "image", "src": "/agents/qwen-design/qwen-design-setup-flow.webp", "alt": "Pięcioetapowy proces konfiguracji: instalacja, uwierzytelnienie, konfiguracja QWEN.md, dodanie skilla, weryfikacja", "caption": "Sekwencja konfiguracji: instalacja → uwierzytelnienie → konfiguracja QWEN.md → dodanie skilla → włączenie weryfikacji w przeglądarce."}, {"kind": "steps", "items": [{"label": "Zakoduj swoje reguły projektowe", "body": "Umieść swoje tokeny, prymitywy i konwencje w QWEN.md i skieruj na nie Qwen Code, aby efekt pasował do marki, zamiast domyślnie przyjmować generyczny wygląd."}, {"label": "Dodaj weryfikację w przeglądarce", "body": "Wepnij Playwright lub przeglądarkowe MCP, aby Qwen Code renderował w prawdziwej przeglądarce i sprawdzał swój efekt na różnych punktach granicznych, zamiast jedynie potwierdzać, że build przechodzi."}]}]}, {"id": "screenshot-workflow", "heading": "Proces „od referencji do interfejsu”", "blocks": [{"kind": "p", "text": "Najbardziej dźwigniowa pętla projektowa z Qwen Code to przekształcanie referencji w działający, responsywny interfejs i iterowanie aż do dopasowania — z wykorzystaniem agenta do budowania, renderowania i porównywania swojego efektu z referencją."}, {"kind": "ol", "items": ["Zacznij od najwyraźniejszych dostępnych referencji wizualnych — i opisz wiele stanów (desktop i mobile, hover, pusty, ładowanie), nie tylko jeden kadr główny.", "Bądź konkretny w prompcie; niejasne prompty dają generyczny interfejs nawet przy mocnym modelu.", "Trzymaj swój system projektowy i konwencje w QWEN.md i powiedz Qwen Code, gdzie znajdują się tokeny i kanoniczne prymitywy.", "Uruchom serwer deweloperski i poproś Qwen Code, by renderował w prawdziwej przeglądarce, zmieniając rozmiar do punktów granicznych w celu sprawdzenia rezultatu.", "Iteruj, każąc Qwen Code porównywać swoją implementację z referencjami — nie tylko potwierdzać, że się buduje."]}, {"kind": "p", "text": "Odwołaj się do pliku za pomocą @, aby dołączyć go do promptu, a następnie podaj konkretne ograniczenia:"}, {"kind": "code", "lang": "bash", "code": "qwen\n# in the prompt:\n> @reference-desktop.png @reference-mobile.png\n  Implement this design in React + Vite + Tailwind + TypeScript.\n  Reuse my existing design-system components and tokens from QWEN.md.\n  Match spacing, layout, and hierarchy; make it responsive.\n  Render it in the browser and iterate until it matches the references\n  across breakpoints."}, {"kind": "p", "text": "Utrzymuj prompty krótkie i skupione, zatwierdzaj dobre iteracje, a złe wycofuj (informując Qwen Code, gdy wycofujesz), aby każdy przebieg budował na czystej bazie."}]}, {"id": "extend", "heading": "QWEN.md, MCP i rozszerzenia", "blocks": [{"kind": "p", "text": "Trzy punkty rozszerzeń czynią Qwen Code praktycznym do długotrwałej pracy projektowej, a wszystkie trzy odwzorowują się czysto na otwarty proces projektowania."}, {"kind": "steps", "items": [{"label": "Kontekst QWEN.md", "body": "Reguły projektu żyją w QWEN.md w katalogu głównym repozytorium (z warstwą globalną i projektową). To trwały dom Twoich konwencji projektowych, czytany przy każdym uruchomieniu."}, {"label": "Serwery MCP", "body": "Skonfiguruj serwery MCP w mcpServers w ~/.qwen/settings.json — przenośny sposób wprowadzania kontekstu projektowego i zewnętrznych narzędzi, najbardziej istotnie serwera MCP do Figma, które działają w różnych agentach, nie tylko w Qwen Code."}, {"label": "Skille i wbudowane narzędzia", "body": "Skille Qwen Code oraz jego wbudowane narzędzia plikowe, powłokowe i sieciowe pozwalają mu zbierać referencje i uruchamiać pętlę weryfikacji bez opuszczania terminala."}]}, {"kind": "p", "text": "To przenośne, wieloagentowe możliwości — dokładnie taki rodzaj rzeczy, które Open Design jest stworzony orkiestrować, zamiast odtwarzać je w każdym projekcie."}]}, {"id": "vs", "heading": "Qwen Code vs Codex vs Claude Code vs Cursor vs Gemini CLI w projektowaniu", "blocks": [{"kind": "p", "text": "Nie ma jednego zwycięzcy w pracy projektowej — każdy agent ma inną mocną stronę, a doświadczone zespoły łączą je w stos. Rzetelne podsumowanie:"}, {"kind": "table", "columns": ["Agent", "Mocna strona w projektowaniu", "Najlepszy do"], "rows": [["Qwen Code", "Mocne agentowe kodowanie na otwartych modelach Qwen3-Coder z dużym kontekstem; open source i BYOK", "Open source'owych, elastycznych co do klucza buildów, które trzymają cały system projektowy w kontekście"], ["Codex", "Mocne dopracowanie wizualne dzięki skillowi frontendowemu; izolowane asynchroniczne buildy", "Delegowanych asynchronicznych buildów i przenośnych reguł AGENTS.md"], ["Claude Code", "Konkretne decyzje projektowe (hex, odstępy, typografia) i UX świadomy bazy kodu", "Rozumowania frontendowego i refaktoryzacji w dużym kontekście"], ["Cursor", "Wizualna pętla buduj-i-zobacz z podglądem na żywo i edycjami w miejscu", "Ścisłej pracy iteruj-i-obserwuj nad interfejsem wewnątrz IDE"], ["Gemini CLI", "Mocne multimodalne rozumienie obrazów i kontekst 1 mln tokenów; agent, z którego zaadaptowano Qwen Code", "Pracy intensywnie opartej na zrzutach ekranu i bardzo dużego kontekstu"]]}, {"kind": "p", "text": "Powtarzający się werdykt społeczności jest taki, że gust pochodzi od ludzi: wszystkie z nich domyślnie przyjmują generyczną estetykę bez skilli, referencji i ograniczeń. To właśnie realny problem do rozwiązania — i ma on kształt narzędzia projektowego, a nie modelu."}]}, {"id": "pitfalls", "heading": "Pułapki i jak uniknąć wyglądu „AI slop”", "blocks": [{"kind": "p", "text": "Najczęstsza skarga na projekty generowane przez AI jest taka, że wyglądają generycznie — miękkie gradienty, unoszące się panele, przesadnie zaokrąglone rogi, dramatyczne cienie, klimat Inter-i-fioletu, który „krzyczy, że zrobiła to AI”. Inne zgłaszane problemy to popsute układy mobilne i instrukcje przeciekające do tekstów interfejsu. Żaden z nich nie jest unikalny dla Qwen Code; to po prostu skutek uruchamiania dowolnego agenta bez wyselekcjonowanego kontekstu projektowego."}, {"kind": "steps", "items": [{"label": "Dodaj skill estetyczny", "body": "Wyselekcjonowany skill projektowy zmusza agenta do zaangażowania się w realny kierunek zamiast w domyślny wygląd."}, {"label": "Weryfikuj w prawdziwej przeglądarce", "body": "Każ agentowi renderować i sprawdzać samodzielnie na różnych punktach granicznych, aby układy nie psuły się po cichu na urządzeniach mobilnych."}, {"label": "Dostarcz tokeny i referencje", "body": "Prawdziwe tokeny projektowe i referencyjne zrzuty ekranu to pojedyncza, największa dźwignia jakości efektu."}, {"label": "Zakoduj reguły w QWEN.md", "body": "Umieść reguły w stylu „bez kart hero, maks. dwa kroje pisma, hierarchia z marką na pierwszym miejscu” tam, gdzie agent czyta je przy każdym uruchomieniu."}]}, {"kind": "p", "text": "Zauważ, że każde z tych zabezpieczeń polega na daniu agentowi wyselekcjonowanego kontekstu projektowego. Utrzymywanie tego kontekstu ręcznie, w każdym projekcie, to mozół, który Open Design eliminuje."}]}, {"id": "open-design", "heading": "Projektowanie z Qwen Code wewnątrz Open Design", "blocks": [{"kind": "p", "text": "Open Design to open source'owa warstwa projektowa, o którą powyższy proces wciąż się dopomina. Traktuje Qwen Code jako adapter pierwszej kategorii i opakowuje go w wyselekcjonowaną bibliotekę skilli i systemów projektowych, ustrukturyzowany potok renderowania oraz lokalny interfejs desktopowy — więc kontekst projektowy, który czyni Qwen Code dobrym, jest na miejscu od pierwszego uruchomienia, a nie składany ręcznie za każdym razem. Oba są open source'owe i działają lokalnie, co czyni to połączenie naturalnym."}, {"kind": "ol", "items": ["Zainstaluj Open Design i wybierz Qwen Code jako swojego agenta.", "Uwierzytelnij się swoim kluczem API DashScope lub Qwen (BYOK) — poświadczenia zostają na Twoim komputerze i nigdy nie są przekazywane przez nas.", "Wybierz system projektowy i skill, a następnie generuj prezentacje, prototypy i strony docelowe ze spójnym gustem.", "Każdy artefakt i plik DESIGN.md żyje w Twoim własnym repozytorium, a nie w hostowanej chmurze."]}, {"kind": "p", "text": "Ten sam agent Qwen Code, ten sam klucz — plus realny, przenośny, open source'owy proces projektowania wokół niego. Działa lokalnie i jest na licencji Apache-2.0, więc nic z Twojej pracy ani Twoich poświadczeń nie opuszcza Twojego komputera."}]}], "faqTitle": "Najczęściej zadawane pytania", "faq": [{"name": "Czy Qwen Code naprawdę potrafi wykonywać pracę projektową?", "text": "Tak — mając w kontekście skill estetyczny, system projektowy i prawdziwe obrazy referencyjne, Qwen Code tworzy responsywny interfejs o jakości produkcyjnej, a jego pętla agentowa buduje, renderuje i weryfikuje efekt względem referencji. Bez tego kontekstu skłania się ku generycznemu wyglądowi, co jest luką, którą wypełnia Open Design."}, {"name": "Czy muszę płacić, aby projektować z Qwen Code?", "text": "Qwen Code jest darmowy i open source'owy, ale działa w modelu BYOK — przynosisz klucz API DashScope (Alibaba Cloud Model Studio), zgodny z OpenAI endpoint lub ModelScope. Alibaba oferuje też plan kodowania ze stałą opłatą. Open Design tak czy inaczej nigdy nie pośredniczy w Twoich poświadczeniach."}, {"name": "Co konkretnie czyni Qwen Code dobrym do projektowania?", "text": "Dwie rzeczy: modele Qwen3-Coder są dostrojone do agentowego kodowania, więc agent buduje i samodzielnie koryguje responsywny interfejs, a ich duży kontekst może pomieścić cały system projektowy i zestaw referencji naraz. Oba pomagają — ale gust nadal pochodzi z systemu projektowego, skilla i referencji, które dostarczasz."}, {"name": "Czy Qwen Code to to samo co Gemini CLI?", "text": "Nie. Qwen Code jest zaadaptowany z Gemini CLI od Google — ten sam open source'owy rodowód — z adaptacjami na poziomie parsera i promptów, które dostrajają go do modeli Qwen3-Coder. Open Design wspiera oba, więc możesz przełączać agentów bez zmiany procesu projektowania."}, {"name": "Jak połączyć Qwen Code z Figma?", "text": "Dodaj serwer MCP do Figma w mcpServers w ~/.qwen/settings.json. Qwen Code może wtedy pobierać prawdziwy kontekst projektowy — komponenty, zmienne, dane układu — aby wygenerowany kod pasował do źródła, zamiast je przybliżać."}, {"name": "Czy Open Design jest powiązany z Alibaba lub Qwen?", "text": "Nie. Qwen Code to produkt Alibaba; Open Design to niezależny projekt open source, który wspiera go jako adapter pierwszej kategorii. Qwen jest znakiem towarowym Alibaba."}, {"name": "Czy moje pliki i poświadczenia są bezpieczne?", "text": "Tak — Open Design działa lokalnie i jest na licencji Apache-2.0. Twoje pliki, artefakty i DESIGN.md pozostają w Twoim własnym repozytorium, a Twoje poświadczenia DashScope lub Qwen są używane bezpośrednio przez Twojego agenta, nigdy nie są kierowane przez serwery Open Design."}], "ctaTitle": "Projektuj z Qwen Code, w otwarty sposób.", "ctaBody": "Przynieś własny klucz API DashScope lub Qwen, trzymaj każdy plik lokalnie i otrzymaj wyselekcjonowaną bibliotekę projektową wokół agenta, którego już używasz.", "ctaActions": [{"label": "Użyj Qwen Code w Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Dodaj gwiazdkę na GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Pobierz aplikację desktopową", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Zobacz wszystkich obsługiwanych agentów"},
      },
      'grok': {
        ...en['grok']!,
        title: "Grok Build do projektowania — Open Design",
        description: "Jak ludzie wykorzystują Grok Build (Grok Build) od xAI w projektowaniu interfejsów i stron — jego tryb planowania, AGENTS.md i MCP, świadome obrazów modele Grok i duży kontekst — oraz jak Open Design zamienia Grok Build w lokalnie działającego, open source'owego agenta projektowego.",
        breadcrumb: "Grok Build",
        label: "Agent · Grok Build",
        heading: "Grok Build do projektowania.",
        lead: "Grok Build to terminalowy agent kodujący od xAI. Planuje wieloetapową pracę, zanim dotknie Twoich plików, czyta obrazy obok kodu i uruchamia pętlę budowania oraz weryfikacji w Twoim repozytorium — co czyni go realnym narzędziem projektowym, gdy tylko dasz mu referencje, konwencje i krok weryfikacji. Open Design wpina go w open source'owy proces projektowania: Twoje logowanie SuperGrok lub klucz API xAI, Twoje pliki, działanie lokalne.",
        rich: {"heroCtaLead": "Open Design zamienia Grok Build w lokalnie działającego, open source'owego agenta projektowego — Twoje logowanie SuperGrok lub klucz API xAI, Twoje pliki oraz wyselekcjonowana biblioteka skilli i systemów projektowych wokół niego.", "heroCtaActions": [{"label": "Użyj Grok Build w Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Dodaj gwiazdkę na GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Pobierz aplikację desktopową", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["Grok Build — terminalowy agent kodujący od xAI, dostarczany jako Grok Build — to agentowe narzędzie, które żyje w Twoim terminalu. Dwie rzeczy czynią go interesującym właśnie do projektowania: planuje ryzykowną pracę, zanim zacznie działać, więc możesz przejrzeć proponowane podejście, zanim jakiekolwiek pliki się zmienią; a jego modele Grok przyjmują wejście obrazowe, więc potrafi rozumować o referencyjnym zrzucie ekranu obok pisanego kodu. W połączeniu z odpowiednimi referencjami, konwencjami i pętlą weryfikacji buduje realny, responsywny interfejs — uwierzytelniony wprost przez Twoje konto SuperGrok lub X Premium+, bez żonglowania kluczami API. To praktyczny, kompleksowy przewodnik po wykorzystaniu Grok Build do pracy nad interfejsem, frontendem i systemami projektowymi oraz po wpięciu go w ustrukturyzowany proces projektowania z Open Design.", "Omawia, czym tak naprawdę jest Grok Build, dlaczego tryb planowania i świadome obrazów modele pasują do projektowania, jak skonfigurować go od zera, pętlę „od zrzutu ekranu do interfejsu”, jak rozszerzają go AGENTS.md i MCP, jak wypada na tle Codex, Claude Code, Cursor i Gemini CLI, jakie pułapki sprawiają, że efekty AI wyglądają generycznie, oraz jak Open Design domyka tę lukę jako otwarta, lokalnie działająca warstwa projektowa — Twoje poświadczenia i artefakty nigdy nie opuszczają Twojego komputera."], "heroImage": {"src": "/agents/grok-design/grok-design-hero.webp", "alt": "Pętla sprzężenia zwrotnego w projektowaniu z Grok Build: terminalowy agent planujący na podstawie obrazu referencyjnego, przeglądarka renderująca interfejs i przestrzeń robocza, ze strzałką sprzężenia zwrotnego zawracającą do początku", "caption": "Główna pętla: Grok Build planuje na podstawie Twoich referencji w terminalu, buduje i weryfikuje interfejs w prawdziwej przeglądarce oraz iteruje względem nich — z Twoimi konwencjami w AGENTS.md."}, "tocLabel": "Na tej stronie", "toc": [{"id": "what-is-grok", "label": "Czym tak naprawdę jest Grok Build"}, {"id": "why-design", "label": "Dlaczego tryb planowania + wejście obrazowe pasują do projektowania"}, {"id": "setup", "label": "Konfiguracja Grok Build do projektowania (od zera)"}, {"id": "screenshot-workflow", "label": "Proces „od zrzutu ekranu do interfejsu”"}, {"id": "extend", "label": "AGENTS.md, MCP i subagenci"}, {"id": "vs", "label": "Grok Build vs Codex vs Claude Code vs Cursor vs Gemini CLI"}, {"id": "pitfalls", "label": "Pułapki i wygląd „AI slop”"}, {"id": "open-design", "label": "Projektowanie z Grok Build w Open Design"}, {"id": "faq", "label": "FAQ"}], "sections": [{"id": "what-is-grok", "heading": "Czym tak naprawdę jest Grok Build", "blocks": [{"kind": "p", "text": "Grok Build to terminalowy agent kodujący od xAI, dostarczany pod nazwą Grok Build. Czyta Twoje repozytorium, edytuje pliki, uruchamia polecenia powłoki i planuje wieloetapową pracę inżynieryjną na podstawie zadań w języku naturalnym, zamiast jedynie uzupełniać linie. Jest zbudowany wokół modeli Grok od xAI — udostępnianych w API xAI jako rodzina modeli grok-build — i uwierzytelnia się przez Twoje konto xAI, więc agent i modele pochodzą od tego samego dostawcy."}, {"kind": "p", "text": "W pracy projektowej wyróżniają się dwie cechy. Ma tryb planowania, który tworzy ustrukturyzowane podejście, jakie możesz zatwierdzić, skomentować lub przepisać, zanim jakakolwiek zmiana wejdzie w życie — przydatna bramka, gdy iterujesz nad interfejsem. A jego modele Grok przyjmują wejście obrazowe, więc możesz podać mu referencyjny zrzut ekranu, a on rozumuje o rzeczywistym układzie, zamiast zgadywać z opisu prozą."}, {"kind": "steps", "items": [{"label": "Pliki kontekstu", "body": "Grok Build czyta plik AGENTS.md jako trwały kontekst projektu — naturalne miejsce na zakodowanie Twoich konwencji projektowych, tokenów i list kontrolnych do przeglądu. Stosuje tę samą otwartą konwencję AGENTS.md, której używają Codex i inni agenci."}, {"label": "Narzędzia, MCP + subagenci", "body": "Edytuje pliki, uruchamia polecenia powłoki i obsługuje serwery MCP, aby dodać zewnętrzny kontekst, taki jak żywy plik Figma; przy większych zadaniach potrafi delegować pracę do równoległych subagentów, którzy jednocześnie badają, budują i przeglądają."}, {"label": "Zaloguj się swoim kontem", "body": "Uwierzytelniasz się, logując się przez przeglądarkę za pomocą subskrypcji SuperGrok lub X Premium+; możesz też przynieść klucz API xAI do użycia bezgłowego i w CI."}]}, {"kind": "ul", "items": ["Dostawca: xAI", "Poświadczenie: OAuth SuperGrok od xAI (`grok login`) lub klucz API xAI (BYOK) do użycia bezgłowego", "Modele: modele Grok od xAI (rodzina grok-build w API xAI), z wejściem obrazowym"]}]}, {"id": "why-design", "heading": "Dlaczego tryb planowania i świadome obrazów modele pasują do projektowania", "blocks": [{"kind": "p", "text": "Przewaga Grok Build w projektowaniu wynika z dwóch cech — ale, jak w przypadku każdego agenta, gust nadal trzeba dostarczyć."}, {"kind": "steps", "items": [{"label": "Rozumowanie świadome obrazów", "body": "Ponieważ modele Grok przyjmują wejście obrazowe, agent czyta referencyjne zrzuty ekranu — porównując swój wyrenderowany efekt z obrazem, zamiast zgadywać z opisu prozą."}, {"label": "Tryb planowania przed wejściem zmian w życie", "body": "Tryb planowania tworzy ustrukturyzowane podejście, które zatwierdzasz, zanim pliki się zmienią, więc intencja projektowa jest przeglądana z góry, a nie odkrywana po diffie."}, {"label": "Konwencje w AGENTS.md", "body": "AGENTS.md (plus serwer MCP do Figma) kieruje agenta do Twoich tokenów, komponentów i prawdziwych specyfikacji, więc pracuje na rzecz marki, a nie domyślnego wyglądu."}]}, {"kind": "image", "src": "/agents/grok-design/grok-design-taste-triangle.webp", "alt": "Diagram pokazujący system projektowy, skill i obraz referencyjny zbiegające się w dobry efekt projektowy", "caption": "Gust pochodzi z trzech dostarczanych przez Ciebie wejść: systemu projektowego, skilla i prawdziwych obrazów referencyjnych."}, {"kind": "p", "text": "Lekcja jest ta sama, której uczy każdy agent: Grok Build domyślnie nie ma gustu. Tworzy dobry projekt, gdy dasz mu ograniczenia — system projektowy, skill estetyczny i konkretne referencje. Open Design pakuje dokładnie te wejścia, dlatego oba do siebie pasują (więcej poniżej)."}]}, {"id": "setup", "heading": "Konfiguracja Grok Build do pracy projektowej, od zera", "blocks": [{"kind": "p", "text": "Oto pełna droga od czystej maszyny do Grok Build, który potrafi budować i weryfikować interfejs."}, {"kind": "code", "lang": "bash", "code": "# 1. Install Grok Build (Grok Build) on macOS/Linux\ncurl -fsSL https://x.ai/cli/install.sh | bash\n\n# 2. Start it in your project and authenticate on first run\ncd your-project\ngrok login   # opens your browser; sign in with SuperGrok / X Premium+\n#   or, for headless / CI use, set an xAI API key:\n#   export XAI_API_KEY=xai-...\n\n# 3. Add project context\n#    create an AGENTS.md at the repo root with your design conventions\n\n# 4. Wire the Figma MCP server (optional, for design handoff)\n#    add it to your MCP server configuration"}, {"kind": "image", "src": "/agents/grok-design/grok-design-setup-flow.webp", "alt": "Pięcioetapowy proces konfiguracji: instalacja, uwierzytelnienie, konfiguracja AGENTS.md, dodanie skilla, weryfikacja", "caption": "Sekwencja konfiguracji: instalacja → uwierzytelnienie → konfiguracja AGENTS.md → dodanie skilla → włączenie weryfikacji w przeglądarce."}, {"kind": "steps", "items": [{"label": "Zakoduj swoje reguły projektowe", "body": "Umieść swoje tokeny, prymitywy i konwencje w AGENTS.md i skieruj na nie Grok, aby efekt pasował do marki, zamiast domyślnie przyjmować generyczny wygląd."}, {"label": "Dodaj weryfikację w przeglądarce", "body": "Wepnij Playwright lub przeglądarkowe MCP, aby Grok renderował w prawdziwej przeglądarce i sprawdzał swój efekt na różnych punktach granicznych, zamiast jedynie potwierdzać, że build przechodzi."}]}]}, {"id": "screenshot-workflow", "heading": "Proces „od zrzutu ekranu do interfejsu”", "blocks": [{"kind": "p", "text": "Najbardziej dźwigniowa pętla projektowa z Grok Build to przekształcanie obrazu referencyjnego w działający, responsywny interfejs i iterowanie aż do dopasowania — z wykorzystaniem trybu planowania do uzgodnienia podejścia oraz świadomego obrazów modelu do porównywania efektu z referencją."}, {"kind": "ol", "items": ["Zacznij od najwyraźniejszych dostępnych referencji wizualnych — i uwzględnij wiele stanów (desktop i mobile, hover, pusty, ładowanie), nie tylko jeden kadr główny.", "Bądź konkretny w prompcie; niejasne prompty dają generyczny interfejs nawet przy mocnym modelu.", "Trzymaj swój system projektowy i konwencje w AGENTS.md i powiedz Grok, gdzie znajdują się tokeny i kanoniczne prymitywy.", "Użyj trybu planowania, by przejrzeć podejście, a następnie uruchom serwer deweloperski i poproś Grok, by renderował w prawdziwej przeglądarce, zmieniając rozmiar do punktów granicznych w celu sprawdzenia rezultatu.", "Iteruj, każąc Grok porównywać swoją implementację ze zrzutami ekranu — nie tylko potwierdzać, że się buduje."]}, {"kind": "p", "text": "Dołącz swoje obrazy referencyjne i podaj konkretne ograniczenia:"}, {"kind": "code", "lang": "bash", "code": "grok\n# in the prompt (attach reference-desktop.png and reference-mobile.png):\n> Implement this design in React + Vite + Tailwind + TypeScript.\n  Reuse my existing design-system components and tokens from AGENTS.md.\n  Match spacing, layout, and hierarchy; make it responsive.\n  Show me the plan first, then render it in the browser and iterate\n  until it matches the references across breakpoints."}, {"kind": "p", "text": "Utrzymuj prompty krótkie i skupione, zatwierdzaj dobre iteracje, a złe wycofuj (informując Grok, gdy wycofujesz), aby każdy przebieg budował na czystej bazie."}]}, {"id": "extend", "heading": "AGENTS.md, MCP i subagenci", "blocks": [{"kind": "p", "text": "Trzy punkty rozszerzeń czynią Grok Build praktycznym do długotrwałej pracy projektowej, a wszystkie trzy odwzorowują się czysto na otwarty proces projektowania."}, {"kind": "steps", "items": [{"label": "Kontekst AGENTS.md", "body": "Reguły projektu żyją w AGENTS.md w katalogu głównym repozytorium. To trwały dom Twoich konwencji projektowych, czytany przy każdym uruchomieniu — i jest to ten sam otwarty format, który rozumieją inni agenci, więc reguły podróżują z Tobą."}, {"label": "Serwery MCP", "body": "Skonfiguruj serwery MCP, aby wprowadzić kontekst projektowy i zewnętrzne narzędzia, najbardziej istotnie serwer MCP do Figma — przenośny sposób podawania prawdziwych specyfikacji do kodu, który działa w różnych agentach, nie tylko w Grok."}, {"label": "Subagenci i wbudowane narzędzia", "body": "Grok Build może uruchamiać równoległych subagentów, by jednocześnie badać, budować i przeglądać, a jego narzędzia plikowe, powłokowe i wyszukiwania pozwalają mu zbierać referencje i uruchamiać pętlę weryfikacji bez opuszczania terminala."}]}, {"kind": "p", "text": "To przenośne, wieloagentowe możliwości — dokładnie taki rodzaj rzeczy, które Open Design jest stworzony orkiestrować, zamiast odtwarzać je w każdym projekcie."}]}, {"id": "vs", "heading": "Grok Build vs Codex vs Claude Code vs Cursor vs Gemini CLI w projektowaniu", "blocks": [{"kind": "p", "text": "Nie ma jednego zwycięzcy w pracy projektowej — każdy agent ma inną mocną stronę, a doświadczone zespoły łączą je w stos. Rzetelne podsumowanie:"}, {"kind": "table", "columns": ["Agent", "Mocna strona w projektowaniu", "Najlepszy do"], "rows": [["Grok Build", "Przegląd w trybie planowania przed wejściem zmian w życie, świadome obrazów modele Grok i równolegli subagenci; logowanie Twoim kontem SuperGrok", "Przeglądanych, opartych na wcześniejszym planie buildów interfejsu z modelami xAI w pętli"], ["Codex", "Mocne dopracowanie wizualne dzięki skillowi frontendowemu; izolowane asynchroniczne buildy", "Delegowanych asynchronicznych buildów i przenośnych reguł AGENTS.md"], ["Claude Code", "Konkretne decyzje projektowe (hex, odstępy, typografia) i UX świadomy bazy kodu", "Rozumowania frontendowego i refaktoryzacji w dużym kontekście"], ["Cursor", "Wizualna pętla buduj-i-zobacz z podglądem na żywo i edycjami w miejscu", "Ścisłej pracy iteruj-i-obserwuj nad interfejsem wewnątrz IDE"], ["Gemini CLI", "Mocne multimodalne rozumienie obrazów i bardzo duży kontekst; open source z darmowym poziomem", "Pracy intensywnie opartej na zrzutach ekranu i trzymania całego systemu projektowego w kontekście"]]}, {"kind": "p", "text": "Powtarzający się werdykt społeczności jest taki, że gust pochodzi od ludzi: wszystkie z nich domyślnie przyjmują generyczną estetykę bez skilli, referencji i ograniczeń. To właśnie realny problem do rozwiązania — i ma on kształt narzędzia projektowego, a nie modelu."}]}, {"id": "pitfalls", "heading": "Pułapki i jak uniknąć wyglądu „AI slop”", "blocks": [{"kind": "p", "text": "Najczęstsza skarga na projekty generowane przez AI jest taka, że wyglądają generycznie — miękkie gradienty, unoszące się panele, przesadnie zaokrąglone rogi, dramatyczne cienie, klimat Inter-i-fioletu, który „krzyczy, że zrobiła to AI”. Inne zgłaszane problemy to popsute układy mobilne i instrukcje przeciekające do tekstów interfejsu. Żaden z nich nie jest unikalny dla Grok Build; to po prostu skutek uruchamiania dowolnego agenta bez wyselekcjonowanego kontekstu projektowego."}, {"kind": "steps", "items": [{"label": "Dodaj skill estetyczny", "body": "Wyselekcjonowany skill projektowy zmusza agenta do zaangażowania się w realny kierunek zamiast w domyślny wygląd."}, {"label": "Weryfikuj w prawdziwej przeglądarce", "body": "Renderuj i sprawdzaj samodzielnie na różnych punktach granicznych, aby układy nie psuły się po cichu na urządzeniach mobilnych."}, {"label": "Dostarcz tokeny i referencje", "body": "Prawdziwe tokeny projektowe i referencyjne zrzuty ekranu to pojedyncza, największa dźwignia jakości efektu."}, {"label": "Zakoduj reguły w AGENTS.md", "body": "Umieść reguły w stylu „bez kart hero, maks. dwa kroje pisma, hierarchia z marką na pierwszym miejscu” tam, gdzie agent czyta je przy każdym uruchomieniu."}]}, {"kind": "p", "text": "Zauważ, że każde z tych zabezpieczeń polega na daniu agentowi wyselekcjonowanego kontekstu projektowego. Utrzymywanie tego kontekstu ręcznie, w każdym projekcie, to mozół, który Open Design eliminuje."}]}, {"id": "open-design", "heading": "Projektowanie z Grok Build wewnątrz Open Design", "blocks": [{"kind": "p", "text": "Open Design to open source'owa warstwa projektowa, o którą powyższy proces wciąż się dopomina. Traktuje Grok Build jako adapter pierwszej kategorii i opakowuje go w wyselekcjonowaną bibliotekę skilli i systemów projektowych, ustrukturyzowany potok renderowania oraz lokalny interfejs desktopowy — więc kontekst projektowy, który czyni Grok dobrym, jest na miejscu od pierwszego uruchomienia, a nie składany ręcznie za każdym razem. Open Design jest niezależny i na licencji Apache-2.0 oraz działa na Twoim własnym komputerze, co czyni to połączenie naturalnym."}, {"kind": "ol", "items": ["Zainstaluj Open Design i wybierz Grok Build jako swojego agenta.", "Uwierzytelnij się swoim kontem SuperGrok lub kluczem API xAI (BYOK) — poświadczenia zostają na Twoim komputerze i nigdy nie są przekazywane przez nas.", "Wybierz system projektowy i skill, a następnie generuj prezentacje, prototypy i strony docelowe ze spójnym gustem.", "Każdy artefakt i plik DESIGN.md żyje w Twoim własnym repozytorium, a nie w hostowanej chmurze."]}, {"kind": "p", "text": "Ten sam agent Grok Build, te same poświadczenia — plus realny, przenośny, open source'owy proces projektowania wokół niego. Działa lokalnie i jest na licencji Apache-2.0, więc nic z Twojej pracy ani Twoich poświadczeń nie opuszcza Twojego komputera."}]}], "faqTitle": "Najczęściej zadawane pytania", "faq": [{"name": "Czy Grok Build naprawdę potrafi wykonywać pracę projektową?", "text": "Tak — mając w kontekście skill estetyczny, system projektowy i prawdziwe obrazy referencyjne, Grok Build tworzy responsywny interfejs o jakości produkcyjnej, a jego świadome obrazów modele Grok pomagają weryfikować efekt względem referencji. Bez tego kontekstu skłania się ku generycznemu wyglądowi, co jest luką, którą wypełnia Open Design."}, {"name": "Jak uwierzytelnić Grok Build?", "text": "Logujesz się przez przeglądarkę za pomocą subskrypcji SuperGrok lub X Premium+ (`grok login`), więc nie ma klucza API do zarządzania. Do użycia bezgłowego lub w CI możesz zamiast tego przynieść klucz API xAI. Open Design tak czy inaczej nigdy nie pośredniczy w Twoich poświadczeniach."}, {"name": "Co konkretnie czyni Grok Build dobrym do projektowania?", "text": "Dwie rzeczy: jego tryb planowania pozwala przejrzeć podejście, zanim jakakolwiek zmiana wejdzie w życie, a jego modele Grok przyjmują wejście obrazowe, więc dobrze czytają referencyjne zrzuty ekranu. Oba pomagają — ale gust nadal pochodzi z systemu projektowego, skilla i referencji, które dostarczasz."}, {"name": "Grok Build czy Claude Code do projektowania frontendu?", "text": "Oba są mocne. Claude Code jest znany z konkretnych decyzji projektowych świadomych bazy kodu; przewagą Grok Build jest przegląd w trybie planowania i świadome obrazów modele xAI. Wiele zespołów używa obu — Open Design pozwala przełączać agentów bez zmiany procesu projektowania."}, {"name": "Jak połączyć Grok Build z Figma?", "text": "Dodaj serwer MCP do Figma w swojej konfiguracji MCP. Grok może wtedy pobierać prawdziwy kontekst projektowy — komponenty, zmienne, dane układu — aby wygenerowany kod pasował do źródła, zamiast je przybliżać."}, {"name": "Czy Open Design jest powiązany z xAI?", "text": "Nie. Grok Build to produkt xAI; Open Design to niezależny projekt open source, który wspiera go jako adapter pierwszej kategorii. Grok jest znakiem towarowym xAI."}, {"name": "Czy moje pliki i poświadczenia są bezpieczne?", "text": "Tak — Open Design działa lokalnie i jest na licencji Apache-2.0. Twoje pliki, artefakty i DESIGN.md pozostają w Twoim własnym repozytorium, a Twoje poświadczenia xAI są używane bezpośrednio przez Twojego agenta, nigdy nie są kierowane przez serwery Open Design."}], "ctaTitle": "Projektuj z Grok Build, w otwarty sposób.", "ctaBody": "Przynieś własne konto SuperGrok lub klucz API xAI, trzymaj każdy plik lokalnie i otrzymaj wyselekcjonowaną bibliotekę projektową wokół agenta, którego już używasz.", "ctaActions": [{"label": "Użyj Grok Build w Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Dodaj gwiazdkę na GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Pobierz aplikację desktopową", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Zobacz wszystkich obsługiwanych agentów"},
      },
      'kimi': {
        ...en['kimi']!,
        title: "Kimi CLI do projektowania — Open Design",
        description: "Jak ludzie wykorzystują Kimi CLI od Moonshot AI w projektowaniu interfejsów i stron — jego agentowe modele Kimi K2, duży kontekst, AGENTS.md i MCP — oraz jak Open Design zamienia Kimi CLI w lokalnie działającego, open source'owego agenta projektowego.",
        breadcrumb: "Kimi CLI",
        label: "Agent · Kimi CLI",
        heading: "Kimi CLI do projektowania.",
        lead: "Kimi CLI to open source'owy terminalowy agent od Moonshot AI, napędzany serią modeli Kimi K2. Jego mocne agentowe kodowanie i duże okno kontekstu pozwalają mu trzymać cały system projektowy i iterować względem referencji — gdy tylko dasz mu konwencje i pętlę weryfikacji, staje się realnym narzędziem projektowym. Open Design wpina go w open source'owy proces projektowania: Twój klucz API Moonshot, Twoje pliki, działanie lokalne.",
        rich: {"heroCtaLead": "Open Design zamienia Kimi CLI w lokalnie działającego, open source'owego agenta projektowego — Twój klucz API Moonshot, Twoje pliki oraz wyselekcjonowana biblioteka skilli i systemów projektowych wokół niego.", "heroCtaActions": [{"label": "Użyj Kimi CLI w Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Dodaj gwiazdkę na GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Pobierz aplikację desktopową", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["Kimi CLI to open source'owy agent AI od Moonshot AI dla terminala. Dwie rzeczy czynią go interesującym właśnie do projektowania: napędza go seria Kimi K2 — bilionparametrowy model typu mixture-of-experts skrupulatnie zoptymalizowany pod agentowe kodowanie i użycie narzędzi; a ten model ma duże okno kontekstu (256 tys. tokenów w najnowszych wydaniach K2), na tyle obszerne, by pomieścić cały system projektowy i bazę kodu naraz. W połączeniu z odpowiednimi referencjami, konwencjami i pętlą weryfikacji buduje realny, responsywny interfejs — a możesz zacząć od logowania OAuth lub własnego klucza API Moonshot. To praktyczny, kompleksowy przewodnik po wykorzystaniu Kimi CLI do pracy nad interfejsem, frontendem i systemami projektowymi oraz po wpięciu go w ustrukturyzowany proces projektowania z Open Design.", "Omawia, czym tak naprawdę jest Kimi CLI, dlaczego jego agentowe modele Kimi K2 i duży kontekst pasują do projektowania, jak skonfigurować go od zera, pętlę „od referencji do interfejsu”, jak rozszerzają go AGENTS.md, MCP i subagenci, jak wypada na tle Codex, Claude Code, Cursor i Gemini CLI, jakie pułapki sprawiają, że efekty AI wyglądają generycznie, oraz jak Open Design domyka tę lukę jako otwarta, lokalnie działająca warstwa projektowa — naturalne połączenie, skoro oba są open source'owe i działają na Twoim własnym komputerze."], "heroImage": {"src": "/agents/kimi-design/kimi-design-hero.webp", "alt": "Pętla sprzężenia zwrotnego w projektowaniu z Kimi CLI: terminalowy agent czytający obraz referencyjny, przeglądarka renderująca interfejs i przestrzeń robocza, ze strzałką sprzężenia zwrotnego zawracającą do początku", "caption": "Główna pętla: Kimi CLI czyta Twoje referencje w terminalu, buduje i weryfikuje interfejs w prawdziwej przeglądarce oraz iteruje względem nich — z całym systemem projektowym w kontekście."}, "tocLabel": "Na tej stronie", "toc": [{"id": "what-is-kimi", "label": "Czym tak naprawdę jest Kimi CLI"}, {"id": "why-design", "label": "Dlaczego agentowe K2 + duży kontekst pasują do projektowania"}, {"id": "setup", "label": "Konfiguracja Kimi CLI do projektowania (od zera)"}, {"id": "screenshot-workflow", "label": "Proces „od referencji do interfejsu”"}, {"id": "extend", "label": "AGENTS.md, MCP i subagenci"}, {"id": "vs", "label": "Kimi CLI vs Codex vs Claude Code vs Cursor vs Gemini CLI"}, {"id": "pitfalls", "label": "Pułapki i wygląd „AI slop”"}, {"id": "open-design", "label": "Projektowanie z Kimi CLI w Open Design"}, {"id": "faq", "label": "FAQ"}], "sections": [{"id": "what-is-kimi", "heading": "Czym tak naprawdę jest Kimi CLI", "blocks": [{"kind": "p", "text": "Kimi CLI to open source'owy (Apache-2.0) agent AI, którego Moonshot AI dostarcza dla terminala. Czyta Twoje repozytorium, edytuje pliki, uruchamia polecenia powłoki, przeszukuje pliki, pobiera strony internetowe i wybiera swój kolejny krok na podstawie otrzymywanego sprzężenia zwrotnego — planując i weryfikując pracę na podstawie zadań w języku naturalnym, zamiast jedynie uzupełniać linie. To narzędzie w Pythonie, instalowane za pomocą uv, które za kulisami napędza rodzinę modeli Kimi K2."}, {"kind": "p", "text": "W pracy projektowej wyróżniają się dwie cechy. Modele Kimi K2 są jawnie dostrojone do agentowego, długoterminowego kodowania i użycia narzędzi, więc agent potrafi przeprowadzić wieloetapowy build aż do działającego rezultatu. A okno kontekstu sięga do 256 tys. tokenów w najnowszych wydaniach K2, na tyle obszerne, by pomieścić cały Twój system projektowy, bibliotekę komponentów i zestaw referencji naraz, zamiast je streszczać i pomijać."}, {"kind": "steps", "items": [{"label": "Pliki kontekstu", "body": "Kimi CLI czyta plik AGENTS.md jako trwały kontekst projektu — naturalne miejsce na zakodowanie Twoich konwencji projektowych, tokenów i list kontrolnych do przeglądu. Uruchom /init, aby utworzyć szkielet dla projektu, który go nie ma."}, {"label": "MCP, ACP + subagenci", "body": "Zarządza serwerami MCP konwersacyjnie za pomocą /mcp-config, udostępnia sesję przez Agent Client Protocol (kimi acp) dla Zed i JetBrains oraz potrafi uruchamiać wbudowanych subagentów coder, explore i plan w odizolowanych kontekstach."}, {"label": "Logowanie lub BYOK", "body": "Przy pierwszym uruchomieniu /login pozwala autoryzować się przez OAuth (Kimi Code) lub wprowadzić własny klucz API Moonshot; platforma Kimi udostępnia też endpointy zgodne z OpenAI i Anthropic."}]}, {"kind": "ul", "items": ["Dostawca: Moonshot AI", "Poświadczenie: klucz API Moonshot (BYOK) lub logowanie OAuth przez Kimi Code", "Licencja: Apache-2.0, open source"]}]}, {"id": "why-design", "heading": "Dlaczego agentowe modele K2 i duży kontekst pasują do projektowania", "blocks": [{"kind": "p", "text": "Przewaga Kimi CLI w projektowaniu wynika z dwóch cech modelu — ale, jak w przypadku każdego agenta, gust nadal trzeba dostarczyć."}, {"kind": "steps", "items": [{"label": "Agentowe, długoterminowe kodowanie", "body": "Modele Kimi K2 są zoptymalizowane pod użycie narzędzi i pracę wieloetapową, więc agent potrafi wziąć referencję i brief oraz faktycznie zbudować, uruchomić i dopracować interfejs, zamiast zatrzymywać się na pierwszej wersji."}, {"label": "Duże okno kontekstu", "body": "Do 256 tys. tokenów w najnowszych wydaniach K2 oznacza, że cały system projektowy, tokeny i wiele stanów referencyjnych mieszczą się naraz, więc agent wykorzystuje ponownie Twoje prawdziwe prymitywy, zamiast wymyślać jednorazowe style."}, {"label": "Konwencje w AGENTS.md", "body": "AGENTS.md (plus serwer MCP, taki jak Figma) kieruje agenta do Twoich tokenów, komponentów i prawdziwych specyfikacji, więc pracuje na rzecz marki, a nie domyślnego wyglądu."}]}, {"kind": "image", "src": "/agents/kimi-design/kimi-design-taste-triangle.webp", "alt": "Diagram pokazujący system projektowy, skill i obraz referencyjny zbiegające się w dobry efekt projektowy", "caption": "Gust pochodzi z trzech dostarczanych przez Ciebie wejść: systemu projektowego, skilla i prawdziwych obrazów referencyjnych."}, {"kind": "p", "text": "Lekcja jest ta sama, której uczy każdy agent: Kimi CLI domyślnie nie ma gustu. Tworzy dobry projekt, gdy dasz mu ograniczenia — system projektowy, skill estetyczny i konkretne referencje. Open Design pakuje dokładnie te wejścia, dlatego oba do siebie pasują (więcej poniżej)."}]}, {"id": "setup", "heading": "Konfiguracja Kimi CLI do pracy projektowej, od zera", "blocks": [{"kind": "p", "text": "Oto pełna droga od czystej maszyny do Kimi CLI, który potrafi budować i weryfikować interfejs."}, {"kind": "code", "lang": "bash", "code": "# 1. Install Kimi CLI (uses uv; Python 3.12–3.14, 3.13 recommended)\ncurl -LsSf https://code.kimi.com/install.sh | bash\n# or, if you already have uv:\nuv tool install --python 3.13 kimi-cli\n\n# 2. Start it in your project and authenticate on first run\ncd your-project\nkimi              # then run /login: OAuth via Kimi Code, or paste a Moonshot API key\n\n# 3. Generate project context\n/init             # scaffolds an AGENTS.md for this project\n\n# 4. Wire an MCP server (optional, e.g. Figma for design handoff)\n/mcp-config       # add, edit, and authenticate MCP servers conversationally"}, {"kind": "image", "src": "/agents/kimi-design/kimi-design-setup-flow.webp", "alt": "Pięcioetapowy proces konfiguracji: instalacja, uwierzytelnienie, konfiguracja AGENTS.md, dodanie skilla, weryfikacja", "caption": "Sekwencja konfiguracji: instalacja → uwierzytelnienie → konfiguracja AGENTS.md → dodanie skilla → włączenie weryfikacji w przeglądarce."}, {"kind": "steps", "items": [{"label": "Zakoduj swoje reguły projektowe", "body": "Umieść swoje tokeny, prymitywy i konwencje w AGENTS.md i skieruj na nie Kimi, aby efekt pasował do marki, zamiast domyślnie przyjmować generyczny wygląd."}, {"label": "Dodaj weryfikację w przeglądarce", "body": "Wepnij Playwright lub przeglądarkowe MCP, aby Kimi renderował w prawdziwej przeglądarce i sprawdzał swój efekt na różnych punktach granicznych, zamiast jedynie potwierdzać, że build przechodzi."}]}]}, {"id": "screenshot-workflow", "heading": "Proces „od referencji do interfejsu”", "blocks": [{"kind": "p", "text": "Najbardziej dźwigniowa pętla projektowa z Kimi CLI to przekształcanie materiału referencyjnego w działający, responsywny interfejs i iterowanie aż do dopasowania — podając agentowi Twoje referencje i każąc mu porównywać swój wyrenderowany efekt z nimi w prawdziwej przeglądarce."}, {"kind": "ol", "items": ["Zacznij od najwyraźniejszych dostępnych referencji — i uwzględnij wiele stanów (desktop i mobile, hover, pusty, ładowanie), nie tylko jeden kadr główny.", "Bądź konkretny w prompcie; niejasne prompty dają generyczny interfejs nawet przy mocnym agencie.", "Trzymaj swój system projektowy i konwencje w AGENTS.md i powiedz Kimi, gdzie znajdują się tokeny i kanoniczne prymitywy.", "Uruchom serwer deweloperski i poproś Kimi, by renderował w prawdziwej przeglądarce, zmieniając rozmiar do punktów granicznych w celu sprawdzenia rezultatu.", "Iteruj, każąc Kimi porównywać swoją implementację z referencjami — nie tylko potwierdzać, że się buduje."]}, {"kind": "p", "text": "Skieruj Kimi na swoje referencje i serwer deweloperski, a następnie podaj konkretne ograniczenia:"}, {"kind": "code", "lang": "bash", "code": "kimi\n# in the prompt:\n> Implement the design in ./references (reference-desktop.png,\n  reference-mobile.png) using React + Vite + Tailwind + TypeScript.\n  Reuse my existing design-system components and tokens from AGENTS.md.\n  Match spacing, layout, and hierarchy; make it responsive.\n  Run the dev server, render it in the browser, and iterate until it\n  matches the references across breakpoints."}, {"kind": "p", "text": "Utrzymuj prompty krótkie i skupione, zatwierdzaj dobre iteracje, a złe wycofuj (informując Kimi, gdy wycofujesz), aby każdy przebieg budował na czystej bazie. Kimi CLI potrafi też przyjąć krótkie nagranie ekranu lub klip demonstracyjny, gdy dany przepływ trudno opisać słowami."}]}, {"id": "extend", "heading": "AGENTS.md, MCP i subagenci", "blocks": [{"kind": "p", "text": "Trzy punkty rozszerzeń czynią Kimi CLI praktycznym do długotrwałej pracy projektowej, a wszystkie trzy odwzorowują się czysto na otwarty proces projektowania."}, {"kind": "steps", "items": [{"label": "Kontekst AGENTS.md", "body": "Reguły projektu żyją w AGENTS.md w katalogu głównym repozytorium. To trwały dom Twoich konwencji projektowych, czytany przy każdym uruchomieniu — i jest to ten sam przenośny format, którego używają inni agenci."}, {"label": "Serwery MCP", "body": "Dodawaj serwery MCP konwersacyjnie za pomocą /mcp-config — przenośny sposób wprowadzania kontekstu projektowego i zewnętrznych narzędzi, najbardziej istotnie serwera MCP do Figma, które działają w różnych agentach, nie tylko w Kimi."}, {"label": "Subagenci i marketplace wtyczek", "body": "Uruchamiaj wbudowanych subagentów coder, explore i plan w odizolowanych kontekstach oraz instaluj skille, serwery MCP i źródła danych z marketplace'u lub dowolnego repozytorium GitHub, aby zbierać referencje i uruchamiać pętlę weryfikacji."}]}, {"kind": "p", "text": "To przenośne, wieloagentowe możliwości — dokładnie taki rodzaj rzeczy, które Open Design jest stworzony orkiestrować, zamiast odtwarzać je w każdym projekcie."}]}, {"id": "vs", "heading": "Kimi CLI vs Codex vs Claude Code vs Cursor vs Gemini CLI w projektowaniu", "blocks": [{"kind": "p", "text": "Nie ma jednego zwycięzcy w pracy projektowej — każdy agent ma inną mocną stronę, a doświadczone zespoły łączą je w stos. Rzetelne podsumowanie:"}, {"kind": "table", "columns": ["Agent", "Mocna strona w projektowaniu", "Najlepszy do"], "rows": [["Kimi CLI", "Agentowe modele Kimi K2 dostrojone do długoterminowego kodowania i użycia narzędzi, z dużym kontekstem; open source i BYOK", "Wieloetapowych buildów i niedrogiego trzymania całego systemu projektowego w kontekście"], ["Codex", "Mocne dopracowanie wizualne dzięki skillowi frontendowemu; izolowane asynchroniczne buildy", "Delegowanych asynchronicznych buildów i przenośnych reguł AGENTS.md"], ["Claude Code", "Konkretne decyzje projektowe (hex, odstępy, typografia) i UX świadomy bazy kodu", "Rozumowania frontendowego i refaktoryzacji w dużym kontekście"], ["Cursor", "Wizualna pętla buduj-i-zobacz z podglądem na żywo i edycjami w miejscu", "Ścisłej pracy iteruj-i-obserwuj nad interfejsem wewnątrz IDE"], ["Gemini CLI", "Mocne multimodalne rozumienie obrazów i kontekst 1 mln tokenów; darmowy poziom", "Pracy intensywnie opartej na zrzutach ekranu i bardzo dużego kontekstu"]]}, {"kind": "p", "text": "Powtarzający się werdykt społeczności jest taki, że gust pochodzi od ludzi: wszystkie z nich domyślnie przyjmują generyczną estetykę bez skilli, referencji i ograniczeń. To właśnie realny problem do rozwiązania — i ma on kształt narzędzia projektowego, a nie modelu."}]}, {"id": "pitfalls", "heading": "Pułapki i jak uniknąć wyglądu „AI slop”", "blocks": [{"kind": "p", "text": "Najczęstsza skarga na projekty generowane przez AI jest taka, że wyglądają generycznie — miękkie gradienty, unoszące się panele, przesadnie zaokrąglone rogi, dramatyczne cienie, klimat Inter-i-fioletu, który „krzyczy, że zrobiła to AI”. Inne zgłaszane problemy to popsute układy mobilne i instrukcje przeciekające do tekstów interfejsu. Żaden z nich nie jest unikalny dla Kimi CLI; to po prostu skutek uruchamiania dowolnego agenta bez wyselekcjonowanego kontekstu projektowego."}, {"kind": "steps", "items": [{"label": "Dodaj skill estetyczny", "body": "Wyselekcjonowany skill projektowy zmusza agenta do zaangażowania się w realny kierunek zamiast w domyślny wygląd."}, {"label": "Weryfikuj w prawdziwej przeglądarce", "body": "Każ Kimi renderować i sprawdzać samodzielnie na różnych punktach granicznych, aby układy nie psuły się po cichu na urządzeniach mobilnych."}, {"label": "Dostarcz tokeny i referencje", "body": "Prawdziwe tokeny projektowe i referencyjne zrzuty ekranu to pojedyncza, największa dźwignia jakości efektu."}, {"label": "Zakoduj reguły w AGENTS.md", "body": "Umieść reguły w stylu „bez kart hero, maks. dwa kroje pisma, hierarchia z marką na pierwszym miejscu” tam, gdzie agent czyta je przy każdym uruchomieniu."}]}, {"kind": "p", "text": "Zauważ, że każde z tych zabezpieczeń polega na daniu agentowi wyselekcjonowanego kontekstu projektowego. Utrzymywanie tego kontekstu ręcznie, w każdym projekcie, to mozół, który Open Design eliminuje."}]}, {"id": "open-design", "heading": "Projektowanie z Kimi CLI wewnątrz Open Design", "blocks": [{"kind": "p", "text": "Open Design to open source'owa warstwa projektowa, o którą powyższy proces wciąż się dopomina. Traktuje Kimi CLI jako adapter pierwszej kategorii i opakowuje go w wyselekcjonowaną bibliotekę skilli i systemów projektowych, ustrukturyzowany potok renderowania oraz lokalny interfejs desktopowy — więc kontekst projektowy, który czyni Kimi dobrym, jest na miejscu od pierwszego uruchomienia, a nie składany ręcznie za każdym razem. Oba są open source'owe i działają lokalnie, co czyni to połączenie naturalnym."}, {"kind": "ol", "items": ["Zainstaluj Open Design i wybierz Kimi CLI jako swojego agenta.", "Uwierzytelnij się swoim kluczem API Moonshot (BYOK) — poświadczenia zostają na Twoim komputerze i nigdy nie są przekazywane przez nas.", "Wybierz system projektowy i skill, a następnie generuj prezentacje, prototypy i strony docelowe ze spójnym gustem.", "Każdy artefakt i plik DESIGN.md żyje w Twoim własnym repozytorium, a nie w hostowanej chmurze."]}, {"kind": "p", "text": "Ten sam agent Kimi CLI, ten sam klucz — plus realny, przenośny, open source'owy proces projektowania wokół niego. Działa lokalnie i jest na licencji Apache-2.0, więc nic z Twojej pracy ani Twoich poświadczeń nie opuszcza Twojego komputera."}]}], "faqTitle": "Najczęściej zadawane pytania", "faq": [{"name": "Czy Kimi CLI naprawdę potrafi wykonywać pracę projektową?", "text": "Tak — mając w kontekście skill estetyczny, system projektowy i prawdziwe obrazy referencyjne, Kimi CLI tworzy responsywny interfejs o jakości produkcyjnej, a jego agentowe modele Kimi K2 potrafią renderować i weryfikować efekt względem referencji. Bez tego kontekstu skłania się ku generycznemu wyglądowi, co jest luką, którą wypełnia Open Design."}, {"name": "Czy muszę płacić, aby projektować z Kimi CLI?", "text": "Przynosisz własne poświadczenia: autoryzuj się przez logowanie OAuth Kimi Code lub wklej klucz API Moonshot (BYOK), rozliczany przez platformę Moonshot. Open Design tak czy inaczej nigdy nie pośredniczy w Twoich poświadczeniach."}, {"name": "Co konkretnie czyni Kimi CLI dobrym do projektowania?", "text": "Dwie rzeczy: modele Kimi K2 są dostrojone do agentowego, długoterminowego kodowania i użycia narzędzi, więc agent potrafi budować i dopracowywać aż do działającego rezultatu, a okno kontekstu sięga do 256 tys. tokenów, wystarczająco, by pomieścić cały system projektowy i zestaw referencji naraz. Oba pomagają — ale gust nadal pochodzi z systemu projektowego, skilla i referencji, które dostarczasz."}, {"name": "Kimi CLI czy Claude Code do projektowania frontendu?", "text": "Oba są mocne. Claude Code jest znany z konkretnych decyzji projektowych świadomych bazy kodu; przewagą Kimi CLI są jego agentowe modele Kimi K2 i duży kontekst przy ekonomii BYOK. Wiele zespołów używa obu — Open Design pozwala przełączać agentów bez zmiany procesu projektowania."}, {"name": "Jak połączyć Kimi CLI z Figma?", "text": "Uruchom /mcp-config wewnątrz Kimi CLI, aby dodać i uwierzytelnić serwer MCP do Figma. Kimi może wtedy pobierać prawdziwy kontekst projektowy — komponenty, zmienne, dane układu — aby wygenerowany kod pasował do źródła, zamiast je przybliżać."}, {"name": "Czy Open Design jest powiązany z Moonshot AI?", "text": "Nie. Kimi CLI to produkt Moonshot AI; Open Design to niezależny projekt open source, który wspiera go jako adapter pierwszej kategorii. Kimi jest znakiem towarowym Moonshot AI."}, {"name": "Czy moje pliki i poświadczenia są bezpieczne?", "text": "Tak — Open Design działa lokalnie i jest na licencji Apache-2.0. Twoje pliki, artefakty i DESIGN.md pozostają w Twoim własnym repozytorium, a Twoje poświadczenia Moonshot są używane bezpośrednio przez Twojego agenta, nigdy nie są kierowane przez serwery Open Design."}], "ctaTitle": "Projektuj z Kimi CLI, w otwarty sposób.", "ctaBody": "Przynieś własny klucz API Moonshot, trzymaj każdy plik lokalnie i otrzymaj wyselekcjonowaną bibliotekę projektową wokół agenta, którego już używasz.", "ctaActions": [{"label": "Użyj Kimi CLI w Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Dodaj gwiazdkę na GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Pobierz aplikację desktopową", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Zobacz wszystkich obsługiwanych agentów"},
      },
      'deepseek': {
        ...en['deepseek']!,
        title: "DeepSeek TUI do projektowania — Open Design",
        description: "Jak ludzie wykorzystują terminalowego agenta kodującego napędzanego przez DeepSeek w projektowaniu interfejsów i stron — jego mocne modele kodujące, kontekst 1 mln tokenów, oszczędność kosztową, pliki kontekstu i MCP — oraz jak Open Design zamienia DeepSeek TUI w lokalnie działającego, open source'owego agenta projektowego.",
        breadcrumb: "DeepSeek TUI",
        label: "Agent · DeepSeek TUI",
        heading: "DeepSeek TUI do projektowania.",
        lead: "DeepSeek TUI to terminalowy agent kodujący napędzany modelami DeepSeek. Jego mocne, oszczędne kosztowo modele kodujące i kontekst 1 mln tokenów potrafią pomieścić cały system projektowy i bazę kodu naraz, co czyni go realnym narzędziem projektowym — gdy tylko dasz mu referencje, konwencje i pętlę weryfikacji. Open Design wpina go w open source'owy proces projektowania: Twój klucz API DeepSeek, Twoje pliki, działanie lokalne.",
        rich: {"heroCtaLead": "Open Design zamienia DeepSeek TUI w lokalnie działającego, open source'owego agenta projektowego — Twój klucz API DeepSeek, Twoje pliki oraz wyselekcjonowana biblioteka skilli i systemów projektowych wokół niego.", "heroCtaActions": [{"label": "Użyj DeepSeek TUI w Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Dodaj gwiazdkę na GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Pobierz aplikację desktopową", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["DeepSeek TUI to terminalowy agent kodujący AI napędzany modelami DeepSeek. Dwie rzeczy czynią go interesującym właśnie do projektowania: jego modele kodujące są mocne i niezwykle oszczędne kosztowo, więc możesz agresywnie iterować bez patrzenia na licznik; a jego okno kontekstu sięga do 1 mln tokenów, na tyle obszerne, by pomieścić cały system projektowy i bazę kodu naraz, zamiast je streszczać i pomijać. W połączeniu z odpowiednimi referencjami, konwencjami i pętlą weryfikacji buduje realny, responsywny interfejs. To praktyczny, kompleksowy przewodnik po wykorzystaniu terminalowego agenta napędzanego przez DeepSeek do pracy nad interfejsem, frontendem i systemami projektowymi oraz po wpięciu go w ustrukturyzowany proces projektowania z Open Design.", "Omawia, czym tak naprawdę jest DeepSeek TUI, dlaczego mocne modele kodujące, ogromny kontekst i niski koszt pasują do projektowania, jak skonfigurować go od zera, pętlę „od referencji do interfejsu”, jak rozszerzają go pliki kontekstu i MCP, jak wypada na tle Codex, Claude Code, Cursor i Gemini CLI, jakie pułapki sprawiają, że efekty AI wyglądają generycznie, oraz jak Open Design domyka tę lukę jako otwarta, lokalnie działająca warstwa projektowa — naturalne połączenie, skoro oba są otwarte i działają na Twoim własnym komputerze."], "heroImage": {"src": "/agents/deepseek-design/deepseek-design-hero.webp", "alt": "Pętla sprzężenia zwrotnego w projektowaniu z DeepSeek TUI: terminalowy agent czytający referencje i konwencje, przeglądarka renderująca interfejs i przestrzeń robocza, ze strzałką sprzężenia zwrotnego zawracającą do początku", "caption": "Główna pętla: DeepSeek TUI czyta Twoje referencje i konwencje w terminalu, buduje i weryfikuje interfejs w prawdziwej przeglądarce oraz iteruje względem nich — z całym systemem projektowym w kontekście."}, "tocLabel": "Na tej stronie", "toc": [{"id": "what-is-deepseek", "label": "Czym tak naprawdę jest DeepSeek TUI"}, {"id": "why-design", "label": "Dlaczego mocne modele kodujące + ogromny kontekst pasują do projektowania"}, {"id": "setup", "label": "Konfiguracja DeepSeek TUI do projektowania (od zera)"}, {"id": "screenshot-workflow", "label": "Proces „od referencji do interfejsu”"}, {"id": "extend", "label": "Pliki kontekstu, MCP i narzędzia"}, {"id": "vs", "label": "DeepSeek TUI vs Codex vs Claude Code vs Cursor vs Gemini CLI"}, {"id": "pitfalls", "label": "Pułapki i wygląd „AI slop”"}, {"id": "open-design", "label": "Projektowanie z DeepSeek TUI w Open Design"}, {"id": "faq", "label": "FAQ"}], "sections": [{"id": "what-is-deepseek", "heading": "Czym tak naprawdę jest DeepSeek TUI", "blocks": [{"kind": "p", "text": "DeepSeek TUI to sterowany klawiaturą terminalowy agent AI, który uruchamia modele DeepSeek. Czyta Twoje repozytorium, edytuje pliki, uruchamia polecenia powłoki, zarządza git i potrafi przeszukiwać sieć — planując i weryfikując pracę na podstawie zadań w języku naturalnym, zamiast jedynie uzupełniać linie. Sam DeepSeek jest dostawcą modeli: API zgodne z OpenAI (udostępnia też endpoint w formacie Anthropic), więc szeroki wachlarz społecznościowych agentów terminalowych można skierować na DeepSeek przez ustawienie bazowego URL i klucza. Kilka open source'owych TUI dostarcza DeepSeek jako dostawcę pierwszej kategorii."}, {"kind": "p", "text": "W pracy projektowej wyróżniają się trzy cechy. Modele kodujące DeepSeek są mocne, więc agent rozumuje o układzie, strukturze i hierarchii komponentów na podstawie jasnego opisu. Jego okno kontekstu sięga do 1 mln tokenów, na tyle obszerne, by pomieścić cały Twój system projektowy i bibliotekę komponentów naraz. A jego cennik jest bardzo niski w przeliczeniu na token, z buforowaniem kontekstu prefiksów na dodatek — więc iterowanie nad projektem kosztuje niewiele."}, {"kind": "steps", "items": [{"label": "Pliki kontekstu", "body": "Agenci terminalowi czytają plik kontekstu projektu (plik w stylu AGENTS.md lub własną konwencję agenta) z trwałymi regułami — naturalne miejsce na zakodowanie Twoich konwencji projektowych, tokenów i list kontrolnych do przeglądu."}, {"label": "Narzędzia + MCP", "body": "Większość DeepSeek TUI dostarcza narzędzia plikowe, powłokowe, git i sieciowe oraz obsługuje serwery MCP, aby dodać zewnętrzny kontekst, taki jak żywy plik Figma — API DeepSeek obsługuje wywoływanie narzędzi, na którym ci agenci się opierają."}, {"label": "Przynieś własny klucz", "body": "Uwierzytelniasz się kluczem API DeepSeek z platformy DeepSeek. Ponieważ API jest zgodne z OpenAI, skierowanie agenta na DeepSeek to zwykle dwie linijki: bazowy URL i klucz."}]}, {"kind": "ul", "items": ["Dostawca: DeepSeek (dostawca modeli i API)", "Poświadczenie: klucz API DeepSeek (BYOK) z platformy DeepSeek", "Modele: deepseek-v4-flash i deepseek-v4-pro (tylko tekst; brak natywnego wejścia obrazowego)"]}]}, {"id": "why-design", "heading": "Dlaczego mocne modele kodujące i ogromny kontekst pasują do projektowania", "blocks": [{"kind": "p", "text": "Przewaga DeepSeek TUI w projektowaniu wynika z modelu i jego ekonomii — ale, jak w przypadku każdego agenta, gust nadal trzeba dostarczyć."}, {"kind": "steps", "items": [{"label": "Mocne, oszczędne kosztowo kodowanie", "body": "Modele kodujące DeepSeek są zdolne i niedrogie, więc agent dobrze rozumuje o układzie i strukturze, a Ty możesz iterować wielokrotnie bez tego, by koszt był ograniczeniem."}, {"label": "Okno kontekstu 1 mln tokenów", "body": "Duży kontekst oznacza, że cały system projektowy, tokeny i wiele stanów referencyjnych mieszczą się naraz, więc agent wykorzystuje ponownie Twoje prawdziwe prymitywy, zamiast wymyślać jednorazowe style — a buforowanie kontekstu utrzymuje powtarzane prompty tanio."}, {"label": "Konwencje w pliku kontekstu", "body": "Plik kontekstu projektu (plus serwer MCP do Figma) kieruje agenta do Twoich tokenów, komponentów i prawdziwych specyfikacji, więc pracuje na rzecz marki, a nie domyślnego wyglądu."}]}, {"kind": "image", "src": "/agents/deepseek-design/deepseek-design-taste-triangle.webp", "alt": "Diagram pokazujący system projektowy, skill i referencję zbiegające się w dobry efekt projektowy", "caption": "Gust pochodzi z trzech dostarczanych przez Ciebie wejść: systemu projektowego, skilla i prawdziwych referencji."}, {"kind": "p", "text": "Lekcja jest ta sama, której uczy każdy agent: DeepSeek TUI domyślnie nie ma gustu. Tworzy dobry projekt, gdy dasz mu ograniczenia — system projektowy, skill estetyczny i konkretne referencje. Open Design pakuje dokładnie te wejścia, dlatego oba do siebie pasują (więcej poniżej)."}]}, {"id": "setup", "heading": "Konfiguracja DeepSeek TUI do pracy projektowej, od zera", "blocks": [{"kind": "p", "text": "Oto pełna droga od czystej maszyny do DeepSeek TUI, który potrafi budować i weryfikować interfejs. Dokładne nazwy instalacji i poleceń różnią się w zależności od tego, którego agenta terminalowego wybierzesz, więc kroki poniżej pozostają na poziomie, który jest wspólny dla wszystkich."}, {"kind": "code", "lang": "bash", "code": "# 1. Get a DeepSeek API key from the DeepSeek platform\n#    https://platform.deepseek.com\nexport DEEPSEEK_API_KEY=sk-...\n\n# 2. Install a DeepSeek-capable terminal agent (follow its README),\n#    then point it at DeepSeek. The API is OpenAI-compatible:\n#      base URL: https://api.deepseek.com\n#      model:    deepseek-v4-flash (or deepseek-v4-pro)\n#    (an Anthropic-format endpoint also exists at /anthropic)\n\n# 3. Start it in your project and generate project context\ncd your-project\n#   create/scaffold a project context file with your design rules\n\n# 4. Wire the Figma MCP server (optional, for design handoff)\n#    add it to the agent's MCP server configuration"}, {"kind": "image", "src": "/agents/deepseek-design/deepseek-design-setup-flow.webp", "alt": "Pięcioetapowy proces konfiguracji: zdobądź klucz, zainstaluj agenta, skonfiguruj plik kontekstu, dodaj skill, zweryfikuj", "caption": "Sekwencja konfiguracji: zdobądź klucz → skieruj agenta na DeepSeek → skonfiguruj plik kontekstu → dodaj skill → włącz weryfikację w przeglądarce."}, {"kind": "steps", "items": [{"label": "Zakoduj swoje reguły projektowe", "body": "Umieść swoje tokeny, prymitywy i konwencje w pliku kontekstu agenta i skieruj go na nie, aby efekt pasował do marki, zamiast domyślnie przyjmować generyczny wygląd."}, {"label": "Dodaj weryfikację w przeglądarce", "body": "Wepnij Playwright lub przeglądarkowe MCP, aby agent renderował w prawdziwej przeglądarce i sprawdzał swój efekt na różnych punktach granicznych, zamiast jedynie potwierdzać, że build przechodzi."}]}]}, {"id": "screenshot-workflow", "heading": "Proces „od referencji do interfejsu”", "blocks": [{"kind": "p", "text": "Modele DeepSeek obsługują tylko tekst — nie czytają obrazów natywnie — więc najbardziej dźwigniowa pętla projektowa to przekształcanie jasnych referencji i opisanych układów w działający, responsywny interfejs, a następnie weryfikowanie rezultatu w prawdziwej przeglądarce, zamiast proszenia modelu, by spojrzał na zrzut ekranu."}, {"kind": "ol", "items": ["Zacznij od najwyraźniejszych dostępnych referencji — i opisz wiele stanów (desktop i mobile, hover, pusty, ładowanie), nie tylko jeden kadr główny.", "Bądź konkretny w prompcie; niejasne prompty dają generyczny interfejs nawet przy mocnym modelu. Wyłóż odstępy, hierarchię i komponenty do ponownego wykorzystania.", "Trzymaj swój system projektowy i konwencje w pliku kontekstu i powiedz agentowi, gdzie znajdują się tokeny i kanoniczne prymitywy.", "Uruchom serwer deweloperski i poproś agenta, by renderował w prawdziwej przeglądarce, zmieniając rozmiar do punktów granicznych w celu sprawdzenia rezultatu — to tutaj odbywa się weryfikacja, skoro model nie widzi obrazu sam.", "Iteruj, każąc agentowi porównywać wyrenderowany DOM i obliczone style z Twoją opisaną specyfikacją — nie tylko potwierdzać, że się buduje."]}, {"kind": "p", "text": "Opisz cel precyzyjnie i podaj konkretne ograniczenia:"}, {"kind": "code", "lang": "bash", "code": "# in the agent's prompt:\n> Implement this design in React + Vite + Tailwind + TypeScript.\n  Layout: two-column dashboard, 240px sidebar, 24px gutters,\n  card grid at 3/2/1 columns for desktop/tablet/mobile.\n  Reuse my existing design-system components and tokens from the\n  context file. Match spacing, layout, and hierarchy; make it responsive.\n  Run the dev server, render it in the browser, and iterate against the\n  spec across breakpoints until it matches."}, {"kind": "p", "text": "Utrzymuj prompty krótkie i skupione, zatwierdzaj dobre iteracje, a złe wycofuj (informując agenta, gdy wycofujesz), aby każdy przebieg budował na czystej bazie."}]}, {"id": "extend", "heading": "Pliki kontekstu, MCP i narzędzia", "blocks": [{"kind": "p", "text": "Trzy punkty rozszerzeń czynią DeepSeek TUI praktycznym do długotrwałej pracy projektowej, a wszystkie trzy odwzorowują się czysto na otwarty proces projektowania."}, {"kind": "steps", "items": [{"label": "Plik kontekstu projektu", "body": "Reguły projektu żyją w pliku kontekstu w katalogu głównym repozytorium (z warstwą globalną i zespołową). To trwały dom Twoich konwencji projektowych, czytany przy każdym uruchomieniu."}, {"label": "Serwery MCP", "body": "Skonfiguruj serwery MCP w agencie — przenośny sposób wprowadzania kontekstu projektowego i zewnętrznych narzędzi, najbardziej istotnie serwera MCP do Figma, które działają w różnych agentach, nie tylko w jednym. API DeepSeek obsługuje wywoływanie narzędzi, na którym te serwery się opierają."}, {"label": "Wbudowane narzędzia", "body": "DeepSeek TUI dostarczają narzędzia plikowe, powłokowe, git i sieciowe, aby agent mógł zbierać referencje i uruchamiać pętlę weryfikacji bez opuszczania terminala."}]}, {"kind": "p", "text": "To przenośne, wieloagentowe możliwości — dokładnie taki rodzaj rzeczy, które Open Design jest stworzony orkiestrować, zamiast odtwarzać je w każdym projekcie."}]}, {"id": "vs", "heading": "DeepSeek TUI vs Codex vs Claude Code vs Cursor vs Gemini CLI w projektowaniu", "blocks": [{"kind": "p", "text": "Nie ma jednego zwycięzcy w pracy projektowej — każdy agent ma inną mocną stronę, a doświadczone zespoły łączą je w stos. Rzetelne podsumowanie:"}, {"kind": "table", "columns": ["Agent", "Mocna strona w projektowaniu", "Najlepszy do"], "rows": [["DeepSeek TUI", "Mocne, bardzo oszczędne kosztowo modele kodujące z otwartymi wagami i kontekstem 1 mln tokenów; tylko tekst (brak natywnego widzenia)", "Iteracji o dużej objętości przy ograniczonym budżecie i trzymania całego systemu projektowego w kontekście"], ["Codex", "Mocne dopracowanie wizualne dzięki skillowi frontendowemu; izolowane asynchroniczne buildy", "Delegowanych asynchronicznych buildów i przenośnych reguł AGENTS.md"], ["Claude Code", "Konkretne decyzje projektowe (hex, odstępy, typografia) i UX świadomy bazy kodu", "Rozumowania frontendowego i refaktoryzacji w dużym kontekście"], ["Cursor", "Wizualna pętla buduj-i-zobacz z podglądem na żywo i edycjami w miejscu", "Ścisłej pracy iteruj-i-obserwuj nad interfejsem wewnątrz IDE"], ["Gemini CLI", "Natywne multimodalne rozumienie obrazów i kontekst 1 mln tokenów; open source z darmowym poziomem", "Pracy intensywnie opartej na zrzutach ekranu, gdzie agent czyta referencje bezpośrednio"]]}, {"kind": "p", "text": "Powtarzający się werdykt społeczności jest taki, że gust pochodzi od ludzi: wszystkie z nich domyślnie przyjmują generyczną estetykę bez skilli, referencji i ograniczeń. To właśnie realny problem do rozwiązania — i ma on kształt narzędzia projektowego, a nie modelu."}]}, {"id": "pitfalls", "heading": "Pułapki i jak uniknąć wyglądu „AI slop”", "blocks": [{"kind": "p", "text": "Najczęstsza skarga na projekty generowane przez AI jest taka, że wyglądają generycznie — miękkie gradienty, unoszące się panele, przesadnie zaokrąglone rogi, dramatyczne cienie, klimat Inter-i-fioletu, który „krzyczy, że zrobiła to AI”. Inne zgłaszane problemy to popsute układy mobilne i instrukcje przeciekające do tekstów interfejsu. Żaden z nich nie jest unikalny dla DeepSeek TUI; to po prostu skutek uruchamiania dowolnego agenta bez wyselekcjonowanego kontekstu projektowego. Ponieważ DeepSeek obsługuje tylko tekst, szczególnie ważne jest weryfikowanie w prawdziwej przeglądarce, zamiast ufać, że model „spojrzy” na rezultat."}, {"kind": "steps", "items": [{"label": "Dodaj skill estetyczny", "body": "Wyselekcjonowany skill projektowy zmusza agenta do zaangażowania się w realny kierunek zamiast w domyślny wygląd."}, {"label": "Weryfikuj w prawdziwej przeglądarce", "body": "Renderuj i sprawdzaj samodzielnie na różnych punktach granicznych za pomocą narzędzia przeglądarkowego — tutaj niezbędne, skoro model nie potrafi sam odczytać zrzutu ekranu — aby układy nie psuły się po cichu na urządzeniach mobilnych."}, {"label": "Dostarcz tokeny i referencje", "body": "Prawdziwe tokeny projektowe i konkretne, opisane referencje to pojedyncza, największa dźwignia jakości efektu."}, {"label": "Zakoduj reguły w pliku kontekstu", "body": "Umieść reguły w stylu „bez kart hero, maks. dwa kroje pisma, hierarchia z marką na pierwszym miejscu” tam, gdzie agent czyta je przy każdym uruchomieniu."}]}, {"kind": "p", "text": "Zauważ, że każde z tych zabezpieczeń polega na daniu agentowi wyselekcjonowanego kontekstu projektowego. Utrzymywanie tego kontekstu ręcznie, w każdym projekcie, to mozół, który Open Design eliminuje."}]}, {"id": "open-design", "heading": "Projektowanie z DeepSeek TUI wewnątrz Open Design", "blocks": [{"kind": "p", "text": "Open Design to open source'owa warstwa projektowa, o którą powyższy proces wciąż się dopomina. Traktuje agenta DeepSeek jako adapter pierwszej kategorii i opakowuje go w wyselekcjonowaną bibliotekę skilli i systemów projektowych, ustrukturyzowany potok renderowania oraz lokalny interfejs desktopowy — więc kontekst projektowy, który czyni DeepSeek dobrym, jest na miejscu od pierwszego uruchomienia, a nie składany ręcznie za każdym razem. Oba są otwarte i działają lokalnie, co czyni to połączenie naturalnym."}, {"kind": "ol", "items": ["Zainstaluj Open Design i wybierz DeepSeek TUI jako swojego agenta.", "Uwierzytelnij się własnym kluczem API DeepSeek (BYOK) — poświadczenia zostają na Twoim komputerze i nigdy nie są przekazywane przez nas.", "Wybierz system projektowy i skill, a następnie generuj prezentacje, prototypy i strony docelowe ze spójnym gustem.", "Każdy artefakt i plik DESIGN.md żyje w Twoim własnym repozytorium, a nie w hostowanej chmurze."]}, {"kind": "p", "text": "Ten sam agent DeepSeek, ten sam klucz — plus realny, przenośny, open source'owy proces projektowania wokół niego. Działa lokalnie i jest na licencji Apache-2.0, więc nic z Twojej pracy ani Twoich poświadczeń nie opuszcza Twojego komputera."}]}], "faqTitle": "Najczęściej zadawane pytania", "faq": [{"name": "Czy DeepSeek TUI naprawdę potrafi wykonywać pracę projektową?", "text": "Tak — mając w kontekście skill estetyczny, system projektowy i konkretne referencje, terminalowy agent napędzany przez DeepSeek tworzy responsywny interfejs o jakości produkcyjnej, a Ty weryfikujesz efekt w prawdziwej przeglądarce. Modele DeepSeek obsługują tylko tekst, więc pętla weryfikacji zastępuje natywne czytanie obrazów. Bez tego kontekstu skłania się ku generycznemu wyglądowi, co jest luką, którą wypełnia Open Design."}, {"name": "Ile kosztuje projektowanie z DeepSeek TUI?", "text": "Niewiele — API DeepSeek należy do najtańszych w przeliczeniu na token, a buforowanie kontekstu prefiksów dodatkowo obniża koszt powtarzanych promptów, więc możesz agresywnie iterować. Przynosisz własny klucz API DeepSeek (BYOK); Open Design nigdy nie pośredniczy w Twoich poświadczeniach."}, {"name": "Co konkretnie czyni DeepSeek dobrym do projektowania?", "text": "Mocne, oszczędne kosztowo modele kodujące, otwarte wagi i kontekst 1 mln tokenów, który mieści cały system projektowy i zestaw referencji naraz. DeepSeek obsługuje tylko tekst — nie czyta obrazów natywnie — więc gust nadal pochodzi z systemu projektowego, skilla i opisanych referencji, które dostarczasz, zweryfikowanych w przeglądarce."}, {"name": "DeepSeek TUI czy Claude Code do projektowania frontendu?", "text": "Oba są mocne. Claude Code jest znany z konkretnych decyzji projektowych świadomych bazy kodu; przewagą DeepSeek TUI są otwarte wagi, bardzo niski koszt i ogromny kontekst do iteracji o dużej objętości. Wiele zespołów używa obu — Open Design pozwala przełączać agentów bez zmiany procesu projektowania."}, {"name": "Jak połączyć DeepSeek TUI z Figma?", "text": "Dodaj serwer MCP do Figma w konfiguracji MCP swojego agenta terminalowego. Agent może wtedy pobierać prawdziwy kontekst projektowy — komponenty, zmienne, dane układu — aby wygenerowany kod pasował do źródła, zamiast je przybliżać. API DeepSeek obsługuje wywoływanie narzędzi, na którym opiera się MCP."}, {"name": "Czy Open Design jest powiązany z DeepSeek?", "text": "Nie. DeepSeek jest dostawcą modeli i API; Open Design to niezależny projekt open source, który wspiera terminalowych agentów napędzanych przez DeepSeek jako adapter pierwszej kategorii. DeepSeek jest znakiem towarowym DeepSeek."}, {"name": "Czy moje pliki i poświadczenia są bezpieczne?", "text": "Tak — Open Design działa lokalnie i jest na licencji Apache-2.0. Twoje pliki, artefakty i DESIGN.md pozostają w Twoim własnym repozytorium, a Twój klucz API DeepSeek jest używany bezpośrednio przez Twojego agenta, nigdy nie jest kierowany przez serwery Open Design."}], "ctaTitle": "Projektuj z DeepSeek TUI, w otwarty sposób.", "ctaBody": "Przynieś własny klucz API DeepSeek, trzymaj każdy plik lokalnie i otrzymaj wyselekcjonowaną bibliotekę projektową wokół agenta, którego już używasz.", "ctaActions": [{"label": "Użyj DeepSeek TUI w Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Dodaj gwiazdkę na GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Pobierz aplikację desktopową", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Zobacz wszystkich obsługiwanych agentów"},
      },
      'trae-cli': {
        ...en['trae-cli']!,
        title: "Trae CLI dla designu — Open Design",
        description: "Jak ludzie używają ByteDance Trae CLI (trae-agent) do projektowania UI i stron internetowych — jego open-source'owy, model-agnostyczny agent CLI, możliwość użycia własnego dostawcy LLM i workflow oparty na konfiguracji — oraz jak Open Design przekształca Trae CLI w local-first, open-source'owego agenta projektowego przez ACP.",
        breadcrumb: "Trae CLI",
        label: "Agent · Trae CLI",
        heading: "Trae CLI dla designu.",
        lead: "Trae CLI to otwartoźródłowy agent terminalowy ByteDance (trae-agent). Jest niezależny od modelu — wskazujesz dostawcę LLM, któremu ufasz — i czyta twoje repozytorium, edytuje pliki oraz wykonuje polecenia na podstawie zadań w języku naturalnym, co czyni go prawdziwym narzędziem projektowym, gdy dostarczysz mu odniesienia, konwencje i pętlę weryfikacji. Open Design podłącza go do otwartoźródłowego procesu projektowego przez ACP: twój własny klucz dostawcy, twoje pliki, najpierw lokalnie.",
        rich: {"heroCtaLead": "Open Design zamienia Trae CLI w lokalny, open-source'owy agent designu — Twój własny klucz dostawcy LLM, Twoje pliki, wyselekcjonowana biblioteka Skills i systemów projektowych wokół tego, sterowany przez ACP.", "heroCtaActions": [{"label": "Użyj Trae CLI wewnątrz Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Gwiazdka na GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Pobierz aplikację desktopową", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["Trae CLI to open-source'owy agent AI dla terminala od ByteDance, wydany jako projekt trae-agent. Dwie rzeczy czynią go interesującym specyficznie dla designu: jest model-agnostyczny, więc możesz przynieść dowolnego dostawcę LLM, któremu ufasz, zamiast być przywiązanym do jednego vendora; i jest transparentnym, licencjonowanym na MIT agentem, który czyta twój codebase, edytuje pliki i wykonuje komendy shell z zadań w języku naturalnym. Sparowany z odpowiednimi referencjami, konwencjami i pętlą weryfikacyjną, buduje prawdziwy, responsywny UI — i jest darmowy i otwarty na start, wystarczy że dostarczysz klucz dostawcy. To praktyczny, end-to-end przewodnik po używaniu Trae CLI do pracy nad UI, frontendem i systemem projektowym oraz po podłączeniu go do strukturalnego workflow projektowego z Open Design.", "Omawia, czym właściwie jest Trae CLI, dlaczego otwarty, model-agnostyczny agent pasuje do projektowania, jak skonfigurować go od zera, pętlę screenshot-to-UI, jak jego plik konfiguracyjny i narzędzia go rozszerzają, jak wypada na tle Codex, Claude Code, Cursor i Gemini CLI, pułapki sprawiające, że wynik AI wygląda generycznie, oraz jak Open Design wypełnia tę lukę jako otwarta, local-first warstwa projektowa — naturalne połączenie, ponieważ oba są open-source i działają na Twoim własnym komputerze, przy czym Open Design steruje Trae CLI poprzez Agent Client Protocol (ACP)."], "heroImage": {"src": "/agents/trae-cli-design/trae-cli-design-hero.webp", "alt": "Pętla feedbacku projektowego Trae CLI: agent terminalowy czytający obraz referencyjny, przeglądarka renderująca UI i workspace, z strzałką feedbacku zawracającą w pętli", "caption": "Podstawowa pętla: Trae CLI czyta Twoje referencje i konwencje w terminalu, buduje i weryfikuje interfejs w prawdziwej przeglądarce i iteruje w oparciu o nie."}, "tocLabel": "Na tej stronie", "toc": [{"id": "what-is-trae-cli", "label": "Czym właściwie jest Trae CLI"}, {"id": "why-design", "label": "Dlaczego otwarty, niezależny od modelu agent pasuje do projektowania"}, {"id": "setup", "label": "Skonfiguruj Trae CLI do projektowania (od zera)"}, {"id": "screenshot-workflow", "label": "Proces tworzenia interfejsu ze zrzutu ekranu"}, {"id": "extend", "label": "Konfiguracja, narzędzia i dostawcy"}, {"id": "vs", "label": "Trae CLI vs Codex vs Claude Code vs Cursor vs Gemini CLI"}, {"id": "pitfalls", "label": "Pułapki i wygląd „AI slop\"\n```"}, {"id": "open-design", "label": "Projektowanie z Trae CLI w Open Design"}, {"id": "faq", "label": "FAQ"}], "sections": [{"id": "what-is-trae-cli", "heading": "Czym właściwie jest Trae CLI", "blocks": [{"kind": "p", "text": "Trae CLI to agent wiersza poleceń z otwartoźródłowego projektu trae-agent ByteDance. Czyta twoje repozytorium, przegląda, tworzy i edytuje pliki oraz wykonuje polecenia powłoki w trwałym środowisku — planując i weryfikując pracę na podstawie zadań w języku naturalnym, a nie tylko uzupełniając linie. Jest licencjonowany na MIT i zbudowany wokół przejrzystej, modularnej architektury, dzięki czemu łatwo go sprawdzić i rozszerzyć. Różni się od osobnego Trae IDE, edytora AI ByteDance opartego na VS Code, choć oba pochodzą od tego samego dostawcy."}, {"kind": "p", "text": "W pracy projektowej wyróżniają się dwie właściwości. Jest niezależny od modelu — ty wybierasz dostawcę LLM, więc nigdy nie jesteś przywiązany do mocnych stron lub ograniczeń jednego modelu. I jest w pełni otwarty i sterowany konfiguracją, więc jego zachowanie, narzędzia i dostawca mogą być przypięte w kontroli wersji obok twojego projektu, zamiast być ukryte za hostowaną usługą."}, {"kind": "steps", "items": [{"label": "Tryby uruchomieniowy i interaktywny", "body": "Trae CLI wykonuje pojedyncze zadanie za pomocą `trae-cli run \"...\"` lub prowadzi ciągłą sesję z `trae-cli interactive` — naturalne miejsce do iteracji nad UI względem twoich konwencji projektowych."}, {"label": "Wbudowane narzędzia", "body": "Dostarcza narzędzia do edycji plików, wykonywania bash/shell i strukturalnego rozumowania od razu, dzięki czemu może budować, uruchamiać serwer deweloperski i sprawdzać błędy runtime bez wychodzenia z terminala."}, {"label": "Przynieś własnego dostawcę", "body": "Podajesz klucz API dla wybranego przez siebie dostawcy — OpenAI, Anthropic, Google, OpenRouter, Doubao, Azure lub lokalny model Ollama — poprzez zmienne środowiskowe lub plik konfiguracyjny."}]}, {"kind": "ul", "items": ["Dostawca: ByteDance (projekt open-source trae-agent)", "Dane uwierzytelniające: klucz API dostawcy LLM (BYOK) — np. OpenAI, Anthropic, Google, OpenRouter, Doubao, Azure lub model lokalny Ollama", "Licencja: MIT, open source"]}]}, {"id": "why-design", "heading": "Dlaczego otwarty, niezależny od modelu agent pasuje do projektowania", "blocks": [{"kind": "p", "text": "Przewaga designerska Trae CLI wynika z otwartości i elastyczności dostawców — ale, jak w przypadku każdego agenta, gust wciąż musi być dostarczony."}, {"kind": "steps", "items": [{"label": "Niezależny od modelu z założenia", "body": "Ponieważ wybierasz dostawcę, możesz kierować pracę projektową do tego modelu, który dziś najlepiej rozumuje o układzie i kodzie frontendowym, i zamienić go później bez zmiany swojego przepływu pracy."}, {"label": "Otwarty i sterowany konfiguracją", "body": "Agent, jego narzędzia i dostawca są przypięci w pliku konfiguracyjnym, który możesz commitować, dzięki czemu zespół otrzymuje to samo zachowanie agenta na każdej maszynie zamiast dryfowania per-developer."}, {"label": "Konwencje w Twoim repozytorium", "body": "Skieruj agenta na swoje tokeny, komponenty i rzeczywiste specyfikacje — przechowywane w Twoim projekcie — dzięki czemu pracuje zgodnie z marką zamiast domyślnie przyjmować generyczny wygląd."}]}, {"kind": "image", "src": "/agents/trae-cli-design/trae-cli-design-taste-triangle.webp", "alt": "Diagram pokazujący system projektowy, skill oraz obraz referencyjny zbiegające się w dobry wynik projektowy", "caption": "Smak pochodzi z trzech danych wejściowych, które dostarczasz: systemu projektowego, skill oraz prawdziwych obrazów referencyjnych."}, {"kind": "p", "text": "Lekcja jest taka sama, jakiej uczy każdy agent: Trae CLI nie ma smaku z definicji. Tworzy dobry design, gdy nadasz mu ograniczenia — system projektowy, estetyczny skill i konkretne odniesienia. Open Design pakuje dokładnie te dane wejściowe i przekazuje je do Trae CLI przez ACP, dlatego oba rozwiązania pasują do siebie (więcej poniżej)."}]}, {"id": "setup", "heading": "Skonfiguruj Trae CLI do pracy projektowej, od zera", "blocks": [{"kind": "p", "text": "Oto pełna ścieżka od czystej maszyny do Trae CLI, które potrafi budować i weryfikować UI. Trae CLI jest instalowane ze źródeł za pomocą uv, a następnie konfigurowane z wybranym dostawcą LLM."}, {"kind": "code", "lang": "bash", "code": "# 1. Get Trae CLI (trae-agent) from source — needs uv\ngit clone https://github.com/bytedance/trae-agent.git\ncd trae-agent\nuv sync --all-extras\nsource .venv/bin/activate\n\n# 2. Authenticate by pointing it at your LLM provider key\n#    set it in the environment (or a trae_config.yaml file)\nexport OPENAI_API_KEY=...        # or ANTHROPIC_API_KEY, GOOGLE_API_KEY, etc.\n\n# 3. Run a task in your project\ntrae-cli run \"Create a hello world page\"\n#    or hold a session:\ntrae-cli interactive\n\n# 4. Check the resolved configuration (keys are masked)\ntrae-cli show-config"}, {"kind": "image", "src": "/agents/trae-cli-design/trae-cli-design-setup-flow.webp", "alt": "Pięciokrokowy przepływ konfiguracji: zainstaluj, uwierzytelnij się, skonfiguruj konwencje, dodaj skill, zweryfikuj", "caption": "Sekwencja konfiguracji: instalacja → uwierzytelnienie kluczem dostawcy → skonfigurowanie konwencji projektowych → dodanie skill → włączenie weryfikacji w przeglądarce."}, {"kind": "steps", "items": [{"label": "Zakoduj swoje zasady projektowe", "body": "Przechowuj swoje tokens, prymitywy i konwencje w repozytorium i skieruj na nie Trae CLI, aby wynik odpowiadał brandowi, zamiast domyślnie przyjmować generyczny wygląd."}, {"label": "Dodaj weryfikację przeglądarki", "body": "Niech Trae CLI uruchomi serwer deweloperski i renderuje w prawdziwej przeglądarce, żeby sprawdzać swój wynik na punktach przerwania, zamiast tylko potwierdzać, że build przeszedł."}]}]}, {"id": "screenshot-workflow", "heading": "Proces tworzenia interfejsu ze zrzutu ekranu", "blocks": [{"kind": "p", "text": "Najbardziej efektywna pętla projektowania z Trae CLI polega na przekształceniu obrazu referencyjnego w działający, responsywny interfejs użytkownika i iterowaniu, aż będzie pasował. Ponieważ Trae CLI jest niezależny od modelu, wskaż dostawcę, którego model dobrze radzi sobie z Twoimi referencjami, i oprzyj się na prawdziwej przeglądarce, aby sprawdzić wynik."}, {"kind": "ol", "items": ["Zacznij od najjaśniejszych referencji wizualnych, jakie masz — i opisz wiele stanów (desktop i mobile, hover, empty, loading), nie tylko jeden hero shot.", "Bądź precyzyjny w prompcie; niejasne prompty generują ogólnikowy UI nawet z mocnym modelem.", "Przechowuj swój system projektowy i konwencje w repozytorium i wskaż Trae CLI, gdzie znajdują się tokens i kanoniczne prymitywy.", "Uruchom serwer deweloperski i pozwól Trae CLI renderować w prawdziwej przeglądarce, zmieniając rozmiar do breakpointów, aby sprawdzić wynik.", "Iteruj, zlecając Trae CLI porównanie swojej implementacji z odniesieniami — a nie tylko potwierdzenie, że buduje się."]}, {"kind": "p", "text": "Uruchom sesję interaktywną i podaj konkretne ograniczenia zamiast jednoliniowego zapytania:"}, {"kind": "code", "lang": "bash", "code": "trae-cli interactive\n# in the session:\n> Implement the attached reference design in React + Vite + Tailwind + TypeScript.\n  Reuse my existing design-system components and tokens.\n  Match spacing, layout, and hierarchy; make it responsive.\n  Run the dev server, render it in the browser, and iterate until it\n  matches the references across breakpoints."}, {"kind": "p", "text": "Utrzymuj komunikaty małe i zwięzłe, commituj dobre iteracje i revertuj złe (informując Trae CLI o revercie), by każde podejście budowało na czystej bazie."}]}, {"id": "extend", "heading": "Konfiguracja, narzędzia i dostawcy", "blocks": [{"kind": "p", "text": "Trzy punkty rozszerzenia sprawiają, że Trae CLI jest praktyczny w trwałej pracy projektowej, i wszystkie trzy czytelnie mapują się na otwarty przepływ pracy projektowej."}, {"kind": "steps", "items": [{"label": "Plik konfiguracyjny", "body": "Trae CLI czyta trae_config.yaml, który ustala twojego dostawcę, model i ustawienia — trwały, kontrolowalny wersyjnie dom dla sposobu, w jaki agent działa w projekcie."}, {"label": "Wybór dostawcy", "body": "Ponieważ obsługuje wielu dostawców (OpenAI, Anthropic, Google, OpenRouter, Doubao, Azure, Ollama), kierujesz pracę projektową do modelu, któremu ufasz, i zmieniasz go bez przepinania swojego przepływu pracy."}, {"label": "Wbudowane narzędzia", "body": "Jego narzędzia do edycji plików, powłoki i strukturalnego wnioskowania pozwalają mu zbierać kontekst, budować, uruchamiać serwer deweloperski i wykonywać pętlę weryfikacyjną bez wychodzenia z terminala."}]}, {"kind": "p", "text": "To przenośne możliwości na poziomie agenta — dokładnie ten rodzaj rzeczy, które Open Design zostało stworzone, aby orkiestrować przez ACP, zamiast odtwarzać je w każdym projekcie."}]}, {"id": "vs", "heading": "Trae CLI vs Codex vs Claude Code vs Cursor vs Gemini CLI do projektowania", "blocks": [{"kind": "p", "text": "Nie ma jednego zwycięzcy w pracy projektowej — każdy agent ma inną mocną stronę, a doświadczone zespoły je łączą. Uczciwe podsumowanie:"}, {"kind": "table", "columns": ["Agent", "Siła projektowa", "Najlepsze do"], "rows": [["Trae CLI", "Open-source (MIT) i niezależny od modelu; przynieś własny klucz dostawcy, sterowany konfiguracją i transparentny", "Zespoły, które chcą darmowego, możliwego do inspekcji agenta oraz swobody wyboru lub zamiany dostawców LLM"], ["Codex", "Silne wykończenie wizualne z frontendem skill; izolowane asynchroniczne buildy", "Delegowane asynchroniczne buildy i przenośne reguły AGENTS.md"], ["Claude Code", "Konkretne decyzje projektowe (hex, spacing, type) i UX świadomy bazy kodu", "Rozumowanie frontend i refaktoring dużych kontekstów"], ["Cursor", "Wizualna pętla budowania i podglądu z podglądem na żywo i edycją inline", "Zwarta praca iteracyjna nad UI z podglądem wewnątrz IDE"], ["Gemini CLI", "Silne wielomodalne rozumienie obrazu i kontekst 1M tokens; open-source z darmowym tierem", "Praca z dużą liczbą zrzutów ekranu i utrzymywanie całego systemu designu w kontekście"]]}, {"kind": "p", "text": "Powtarzający się werdykt społeczności jest taki, że gust pochodzi od ludzi: wszyscy bez wyjątku domyślnie stosują generyczną estetykę bez skills, referencji i ograniczeń. To jest prawdziwy problem do rozwiązania — i ma kształt narzędzia projektowego, a nie modelu."}]}, {"id": "pitfalls", "heading": "Pułapki i jak uniknąć wrażenia „AI slop\"", "blocks": [{"kind": "p", "text": "Najczęstszą skargą na projektowanie generowane przez AI jest to, że wygląda ono generycznie — miękkie gradienty, unoszące się panele, powiększone zaokrąglone rogi, dramatyczne cienie, atmosfera Inter-i-fioletu, która „krzyczy, że zrobiło to AI\". Inne zgłaszane problemy obejmują uszkodzone układy mobilne i instrukcje wyciekające do tekstu interfejsu. Żadne z tych problemów nie są unikalne dla Trae CLI; to po prostu to, co się dzieje, gdy jakikolwiek agent działa bez starannie przygotowanego kontekstu projektowego."}, {"kind": "steps", "items": [{"label": "Dodaj skill estetyczny", "body": "Wyselekcjonowany skill projektowy zmusza agenta do przyjęcia konkretnego kierunku zamiast domyślnego wyglądu."}, {"label": "Zweryfikuj w prawdziwej przeglądarce", "body": "Niech Trae CLI renderuje i sprawdza się na punktach przerwania, by układy nie psuły się po cichu na mobile."}, {"label": "Dostarczaj tokeny i odniesienia", "body": "Prawdziwe design tokens i referencyjne screenshoty to najważniejsza dźwignia jakości wyników."}, {"label": "Zakoduj zasady w swoim repozytorium", "body": "Umieść zasady stylu typu „żadnych kart bohaterów, maksymalnie dwa kroje pisma, hierarchia najpierw brand\" tam, gdzie agent odczytuje je przy każdym uruchomieniu."}]}, {"kind": "p", "text": "Zauważ, że każde rozwiązanie polega na dostarczeniu agentowi wyselekcjonowanego kontekstu projektowego. Ręczne utrzymywanie tego kontekstu dla każdego projektu to właśnie trud, którego Open Design Cię zwalnia."}]}, {"id": "open-design", "heading": "Projektowanie z Trae CLI wewnątrz Open Design", "blocks": [{"kind": "p", "text": "Open Design to warstwa projektowa open-source, o którą prosi powyższy workflow. Traktuje Trae CLI jako adapter first-party — sterując nim przez Agent Client Protocol (ACP) za pomocą binarki trae-cli — i otacza go wyselekcjonowaną biblioteką skill i systemów projektowych, ustrukturyzowanym potokiem renderowania oraz lokalnym interfejsem desktopowym, dzięki czemu kontekst projektowy, który czyni Trae CLI dobrym, jest dostępny od pierwszego uruchomienia, a nie składany ręcznie za każdym razem. Oba projekty są open-source i local-first, co czyni to połączenie naturalnym wyborem."}, {"kind": "ol", "items": ["Zainstaluj Open Design i wybierz Trae CLI jako swojego agenta.", "Uwierzytelnij się swoim własnym kluczem providera LLM (BYOK) — poświadczenia zostają na twojej maszynie i nigdy nie są proxowane przez nas.", "Wybierz system projektowy i skill, a następnie generuj prezentacje, prototypy i strony docelowe ze spójnym gustem.", "Każdy artefakt i plik DESIGN.md znajduje się w Twoim własnym repozytorium, a nie w hostowanej chmurze."]}, {"kind": "p", "text": "Ten sam agent CLI Trae, ten sam klucz providera — plus prawdziwy, przenośny, open-source'owy workflow projektowy wokół niego. Jest local-first i open-source, więc nic dotyczącego Twojej pracy ani danych uwierzytelniających nie opuszcza Twojej maszyny."}]}], "faqTitle": "Często zadawane pytania", "faq": [{"name": "Czy Trae CLI naprawdę potrafi wykonywać pracę projektową?", "text": "Tak — z aesthetic skill, systemem projektowym i prawdziwymi referencjami w kontekście, Trae CLI produkuje responsywny UI jakości produkcyjnej, a ponieważ jest agnostyczny względem modeli, możesz skierować pracę do dostawcy, który najlepiej rozumuje o Twoim frontendzie. Bez tego kontekstu ma tendencję do domyślnego generycznego wyglądu, co jest luką, którą wypełnia Open Design."}, {"name": "Czy muszę płacić za projektowanie z Trae CLI?", "text": "Sam Trae CLI jest darmowy i otwartoźródłowy (MIT). Przynosisz własny klucz dostawcy LLM, więc twoim jedynym kosztem jest to, co obciąża ten dostawca — lub nic, jeśli uruchomisz lokalny model przez Ollama. Open Design nigdy nie pośredniczy też w twoich danych uwierzytelniających."}, {"name": "Co sprawia, że Trae CLI jest dobry specjalnie do projektowania?", "text": "Dwie rzeczy: jest niezależny od modelu, więc wybierasz dostawcę LLM najlepiej dopasowanego do pracy frontendowej, i jest w pełni otwarty i sterowany konfiguracją, więc jego zachowanie jest transparentne i powtarzalne w zespole. Ale gust nadal pochodzi z systemu designu, skill i referencji, które dostarczasz."}, {"name": "Trae CLI czy Claude Code do projektowania frontendu?", "text": "Oba są kompetentne. Claude Code jest znany ze specyficznych, świadomych kontekstu kodu decyzji projektowych; przewagą Trae CLI jest bycie open-source i elastyczność dostawców, więc nigdy nie jesteś przywiązany do jednego modelu. Wiele zespołów używa obu — Open Design pozwala przełączać agentów bez zmiany przepływu pracy projektowej."}, {"name": "Co jest potrzebne Open Design do uruchomienia Trae CLI?", "text": "Open Design steruje plikiem binarnym trae-cli z Trae CLI przez Agent Client Protocol (ACP) i wykorzystuje skonfigurowany klucz dostawcy LLM. Wybierasz Trae CLI jako swojego agenta, wskazujesz dostawcę, a Open Design dostarcza wokół niego wyselekcjonowany kontekst projektowy."}, {"name": "Czy Open Design jest powiązany z ByteDance lub Trae?", "text": "Nie. Trae CLI (trae-agent) jest produktem ByteDance; Open Design to niezależny projekt open-source, który obsługuje go jako adapter first-party. Trae jest znakiem towarowym ByteDance."}, {"name": "Czy moje pliki i poświadczenia są bezpieczne?", "text": "Tak — Open Design jest lokalny i open-source. Twoje pliki, artefakty i DESIGN.md pozostają w Twoim własnym repo, a dane uwierzytelniające dostawcy LLM są używane bezpośrednio przez Twojego agenta, nigdy nie są kierowane przez serwery Open Design."}], "ctaTitle": "Projektuj z Trae CLI, w sposób otwarty.", "ctaBody": "Przynieś własny klucz dostawcy LLM, przechowuj każdy plik lokalnie i uzyskaj wyselekcjonowaną bibliotekę projektową wokół agenta, którego już używasz.", "ctaActions": [{"label": "Użyj Trae CLI wewnątrz Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Gwiazdka na GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Pobierz aplikację desktopową", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Zobacz wszystkich wspieranych agentów"},
      },
      'aider': {
        ...en['aider']!,
        title: "Aider dla designu — Open Design",
        description: "Jak ludzie używają Aider — open-source'owego, model-agnostycznego AI pair-programmera w terminalu — do projektowania UI i stron internetowych, z edycją natywną dla git, plikiem CONVENTIONS.md, wsparciem dla obrazów i BYOK, oraz jak Open Design przekształca Aider w local-first, open-source'owego agenta projektowego.",
        breadcrumb: "Aider",
        label: "Agent · Aider",
        heading: "Aider dla designu.",
        lead: "Aider to open-source'owy AI pair-programmer, który żyje w terminalu i pracuje bezpośrednio na twoim repozytorium git. Jest model-agnostic — wskaż mu Claude, GPT-4o, DeepSeek lub Gemini własnym kluczem — i edytuje pliki, auto-commituje oraz czyta obrazy na modelach z vision. To czyni go prawdziwym narzędziem projektowym, gdy dostarczysz mu referencje, konwencje i pętlę weryfikacji. Open Design włącza go w open-source'owy workflow designowy: twoje klucze providerów, twoje pliki, local-first.",
        rich: {"heroCtaLead": "Open Design zmienia Aider w lokalnego, open-source'owego agenta projektowego — Twoje własne klucze API dostawców, Twoje pliki, wyselekcjonowana biblioteka skill i systemów projektowych wokół niego.", "heroCtaActions": [{"label": "Użyj Aider wewnątrz Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Gwiazdka na GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Pobierz aplikację desktopową", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["Aider to open-source'owe narzędzie do programowania w parze z AI, które działa w terminalu i operuje na kodzie w twoim repozytorium git. Dwie rzeczy czynią je interesującym szczególnie dla designu: jest model-agnostic, więc używasz własnego klucza dla niemal każdego LLM — Claude, GPT-4o, DeepSeek, Gemini lub modelu lokalnego — i jest natywnie zintegrowane z git, edytując pliki w miejscu i commitując każdą zmianę z sensownym komunikatem, więc każda iteracja jest recenzowalna i odwracalna. Na modelach z vision może także czytać obrazy, więc zrzut ekranu staje się częścią promptu. W parze z odpowiednimi referencjami, konwencjami i pętlą weryfikacji buduje rzeczywiste, responsywne interfejsy. To praktyczny, kompleksowy przewodnik po używaniu Aider do pracy nad UI, frontendem i systemami designu oraz po włączeniu go w ustrukturyzowany workflow designowy z Open Design.", "Obejmuje to, czym właściwie jest Aider, dlaczego narzędzie niezależne od modelu i natywnie zintegrowane z gitem pasuje do projektowania, jak je skonfigurować od podstaw, pętlę screenshot-to-UI, jak CONVENTIONS.md i polecenia Aider je rozszerzają, jak wypada w porównaniu z Codex, Claude Code, Cursor i Gemini CLI, pułapki, które sprawiają, że output AI wygląda generycznie, oraz jak Open Design zamyka tę lukę jako otwarta, local-first warstwa projektowania — naturalne połączenie, ponieważ oba są open-source i działają na Twojej własnej maszynie."], "heroImage": {"src": "/agents/aider-design/aider-design-hero.webp", "alt": "Pętla feedbacku projektowego Aider: agent terminalowy czytający obraz referencyjny, repozytorium git z commitami, przeglądarka renderująca interfejs, ze strzałką feedbacku prowadzącą z powrotem", "caption": "Główna pętla: Aider odczytuje twoje odniesienia w terminalu, edytuje i commituje UI w twoim repozytorium git oraz iteruje na ich podstawie — z jakimkolwiek modelem przyniesiesz."}, "tocLabel": "Na tej stronie", "toc": [{"id": "what-is-aider", "label": "Czym właściwie jest Aider"}, {"id": "why-design", "label": "Dlaczego niezależność od modelu + natywna obsługa git pasują do projektowania"}, {"id": "setup", "label": "Skonfiguruj Aider do pracy z designem (od zera)"}, {"id": "screenshot-workflow", "label": "Proces tworzenia interfejsu ze zrzutu ekranu"}, {"id": "extend", "label": "CONVENTIONS.md, obrazy i polecenia"}, {"id": "vs", "label": "Aider vs Codex vs Claude Code vs Cursor vs Gemini CLI"}, {"id": "pitfalls", "label": "Pułapki i wygląd „AI slop\"\n```"}, {"id": "open-design", "label": "Projektowanie z Aider w Open Design"}, {"id": "faq", "label": "FAQ"}], "sections": [{"id": "what-is-aider", "heading": "Czym właściwie jest Aider", "blocks": [{"kind": "p", "text": "Aider to open-source'owe (Apache-2.0) narzędzie do programowania w parze z AI, które działa w terminalu. Czyta istniejący kod, mapuje całe repozytorium dla kontekstu, edytuje pliki w miejscu i automatycznie commituje każdą zmianę z sensownym komunikatem — dzięki czemu możesz przeglądać diff, zarządzać i cofać pracę AI za pomocą narzędzi git, których już używasz. Działa ze 100+ językami programowania i rozpoczyna nowe projekty lub rozwija istniejące."}, {"kind": "p", "text": "W pracy projektowej wyróżniają się dwie właściwości. Aider jest niezależny od modelu: przynosisz własny klucz i łączysz go z niemal dowolnym LLM — Claude, GPT-4o, DeepSeek, Gemini lub modelem lokalnym — więc nigdy nie jesteś przywiązany do jednego dostawcy. A na modelach z możliwościami wizyjnymi jak GPT-4o i Claude może odczytywać pliki obrazów, zamieniając referencyjny screenshot w część promptu."}, {"kind": "steps", "items": [{"label": "Plik konwencji", "body": "Aider czyta plik CONVENTIONS.md, który ładujesz za pomocą /read CONVENTIONS.md (lub aider --read CONVENTIONS.md) — naturalne miejsce do zakodowania konwencji projektowych, tokens i list kontrolnych recenzji jako kontekstu tylko do odczytu."}, {"label": "Edycje natywne dla Git", "body": "Każda zmiana jest aplikowana do plików w Twoim repozytorium i automatycznie commitowana, więc każda iteracja projektu jest możliwa do przejrzenia i odwrócenia za pomocą znanych narzędzi git."}, {"label": "Przynieś własny model", "body": "Połącz OpenAI, Anthropic, DeepSeek, Gemini lub model lokalny przy użyciu własnego klucza API; Aider nie jest przywiązany do jednego dostawcy ani hostowanego backendu."}]}, {"kind": "ul", "items": ["Dostawca: Aider (Aider-AI, open source) — niezależny od modelu", "Poświadczenie: własny klucz API dostawcy — BYOK (OpenAI, Anthropic, DeepSeek, Gemini lub model lokalny)", "Licencja: Apache-2.0, open source"]}]}, {"id": "why-design", "heading": "Dlaczego narzędzie model-agnostic, natywne dla git pasuje do projektowania", "blocks": [{"kind": "p", "text": "Przewaga projektowa Aider wynika z tego, jak pracuje z twoim repo i twoim wyborem modelu — ale, jak przy każdym agencie, gust nadal trzeba dostarczyć."}, {"kind": "steps", "items": [{"label": "Niezależny od modelu, BYOK", "body": "Wybierz model, który najlepiej projektuje dla Twojego zadania i budżetu — Claude, GPT-4o, DeepSeek, Gemini — i przełączaj się swobodnie bez zmiany przepływu pracy, wszystko na Twoim własnym kluczu."}, {"label": "Iteracja natywna dla Git", "body": "Automatyczne commity sprawiają, że każde przejście projektowe to diff możliwy do przejrzenia i cofnięcia, dzięki czemu iterujesz względem czystej bazy zamiast nieśledzonej sterty edycji."}, {"label": "Konwencje w CONVENTIONS.md", "body": "Plik CONVENTIONS.md (wczytywany tylko do odczytu) wskazuje agentowi twoje tokeny, komponenty i reguły, dzięki czemu pracuje zgodnie z marką zamiast domyślnego wyglądu."}]}, {"kind": "image", "src": "/agents/aider-design/aider-design-taste-triangle.webp", "alt": "Diagram pokazujący system projektowy, skill oraz obraz referencyjny zbiegające się w dobry wynik projektowy", "caption": "Smak pochodzi z trzech danych wejściowych, które dostarczasz: systemu projektowego, skill oraz prawdziwych obrazów referencyjnych."}, {"kind": "p", "text": "Lekcja jest taka sama, jakiej uczy każdy agent: Aider nie ma domyślnie wyczucia smaku. Produkuje dobre projekty, gdy otrzyma ograniczenia — system projektowania, skill estetyczny i konkretne referencje. Open Design pakuje dokładnie te dane wejściowe, dlatego te dwa elementy do siebie pasują (więcej poniżej)."}]}, {"id": "setup", "heading": "Skonfiguruj Aider do pracy z designem, od zera", "blocks": [{"kind": "p", "text": "Oto pełna ścieżka od czystej maszyny do Aider, które potrafi budować i weryfikować UI."}, {"kind": "code", "lang": "bash", "code": "# 1. Install Aider (recommended installer; Python 3.8–3.13)\npython -m pip install aider-install\naider-install\n# or with pipx: pipx install aider-chat\n\n# 2. Start it in your git project and bring your own key\ncd your-project\naider --model sonnet --api-key anthropic=<your-key>\n# or: aider --api-key openai=<your-key>   (also deepseek=, gemini=)\n\n# 3. Load your design conventions as read-only context\naider --read CONVENTIONS.md\n\n# 4. Add a reference image (on a vision-capable model)\n#    inside the chat: /add reference-desktop.png"}, {"kind": "image", "src": "/agents/aider-design/aider-design-setup-flow.webp", "alt": "Pięciokrokowy przepływ konfiguracji: zainstaluj, przynieś własny klucz, wczytaj CONVENTIONS.md, dodaj odniesienie, zweryfikuj", "caption": "Sekwencja konfiguracji: instalacja → dodanie własnego klucza → wczytanie CONVENTIONS.md → dodanie odniesienia → włączenie weryfikacji w przeglądarce."}, {"kind": "steps", "items": [{"label": "Zakoduj swoje zasady projektowe", "body": "Umieść swoje tokeny, prymitywy i konwencje w CONVENTIONS.md i ładuj je tylko do odczytu, aby wynik odpowiadał marce zamiast domyślnie wyglądać generycznie."}, {"label": "Dodaj weryfikację przeglądarki", "body": "Uruchom serwer deweloperski i pozwól Aider wyrenderować w prawdziwej przeglądarce, sprawdzając jego output w różnych breakpointach zamiast tylko potwierdzać, że build przechodzi."}]}]}, {"id": "screenshot-workflow", "heading": "Proces tworzenia interfejsu ze zrzutu ekranu", "blocks": [{"kind": "p", "text": "Najbardziej efektywna pętla projektowa z Aider polega na przekształceniu obrazu referencyjnego w działający, responsywny UI i iterowaniu, aż będzie pasował — wykorzystując model z obsługą wizji do porównywania wyniku z odniesieniem, z każdym przebiegiem zapisywanym do git."}, {"kind": "ol", "items": ["Zacznij od najjaśniejszych referencji wizualnych, jakie masz — i uwzględnij wiele stanów (desktop i mobile, hover, empty, loading), nie tylko jeden hero shot.", "Bądź precyzyjny w prompcie; niejasne prompty generują ogólnikowy UI nawet z mocnym modelem.", "Trzymaj swój design system i konwencje w CONVENTIONS.md i powiedz Aider, gdzie znajdują się tokens i kanoniczne prymitywy.", "Uruchom serwer deweloperski i sprawdź wyrenderowany rezultat w prawdziwej przeglądarce, zmieniając rozmiar do breakpointów.", "Iteruj, zlecając Aider porównanie swojej implementacji ze zrzutami ekranu — a nie tylko potwierdzenie, że buduje się."]}, {"kind": "p", "text": "Dodaj obraz za pomocą /add (lub /paste ze schowka) na modelu z obsługą wizji, następnie podaj konkretne ograniczenia:"}, {"kind": "code", "lang": "bash", "code": "aider --model gpt-4o --read CONVENTIONS.md\n# in the chat:\n> /add reference-desktop.png\n> /add reference-mobile.png\n> Implement this design in React + Vite + Tailwind + TypeScript.\n  Reuse my existing design-system components and tokens from CONVENTIONS.md.\n  Match spacing, layout, and hierarchy; make it responsive.\n  I'll render it in the browser and tell you what to fix until it matches\n  the references across breakpoints."}, {"kind": "p", "text": "Utrzymuj komunikaty małe i zwięzłe. Ponieważ Aider commituje każdą zmianę, zachowujesz dobre iteracje i używasz git (albo /undo) do revertowania złych — więc każde podejście buduje na czystej bazie."}]}, {"id": "extend", "heading": "CONVENTIONS.md, obrazy i polecenia", "blocks": [{"kind": "p", "text": "Trzy możliwości sprawiają, że Aider jest praktyczny w trwałej pracy projektowej, i wszystkie trzy czytelnie mapują się na otwarty przepływ pracy projektowej."}, {"kind": "steps", "items": [{"label": "Kontekst CONVENTIONS.md", "body": "Załaduj konwencje kodowania i designu za pomocą /read CONVENTIONS.md lub aider --read CONVENTIONS.md, albo ustaw read: CONVENTIONS.md w .aider.conf.yml, aby ładować je przy każdym uruchomieniu. To trwały dom dla twoich tokens, prymitywów i zasad."}, {"label": "Obrazy i strony internetowe", "body": "W przypadku modeli obsługujących obraz użyj /add dla pliku obrazu lub /paste ze schowka, aby dać Aider prawdziwy punkt odniesienia; /web <url> pobiera tekst ze strony do czatu jako dodatkowy kontekst."}, {"label": "Polecenia w czacie", "body": "Polecenia takie jak /add do wprowadzania plików do kontekstu, /read do referencji tylko do odczytu i /undo do cofnięcia ostatniego commita pozwalają mu zbierać referencje i uruchamiać pętlę weryfikacji bez opuszczania terminala."}]}, {"kind": "p", "text": "To przenośne możliwości natywne dla repozytorium — dokładnie ten rodzaj rzeczy, które Open Design zostało stworzone, aby orkiestrować, zamiast odtwarzać je w każdym projekcie."}]}, {"id": "vs", "heading": "Aider vs Codex vs Claude Code vs Cursor vs Gemini CLI dla designu", "blocks": [{"kind": "p", "text": "Nie ma jednego zwycięzcy w pracy projektowej — każdy agent ma inną mocną stronę, a doświadczone zespoły je łączą. Uczciwe podsumowanie:"}, {"kind": "table", "columns": ["Agent", "Siła projektowa", "Najlepsze do"], "rows": [["Aider", "Open-source, niezależny od modelu (BYOK) i natywny dla git; auto-commity sprawiają, że każda iteracja jest możliwa do przeglądnięcia i cofnięcia", "Natywna dla repozytorium iteracja nad istniejącą bazą kodu z dowolnym modelem, który najlepiej projektuje"], ["Codex", "Silne wykończenie wizualne z frontendem skill; izolowane asynchroniczne buildy", "Delegowane asynchroniczne buildy i przenośne reguły AGENTS.md"], ["Claude Code", "Konkretne decyzje projektowe (hex, spacing, type) i UX świadomy bazy kodu", "Rozumowanie frontend i refaktoring dużych kontekstów"], ["Cursor", "Wizualna pętla budowania i podglądu z podglądem na żywo i edycją inline", "Zwarta praca iteracyjna nad UI z podglądem wewnątrz IDE"], ["Gemini CLI", "Silne wielomodalne rozumienie obrazu i kontekst 1M tokens; open-source z darmowym tierem", "Praca z dużą liczbą zrzutów ekranu i utrzymywanie całego systemu designu w kontekście"]]}, {"kind": "p", "text": "Powtarzający się werdykt społeczności jest taki, że gust pochodzi od ludzi: wszyscy bez wyjątku domyślnie stosują generyczną estetykę bez skills, referencji i ograniczeń. To jest prawdziwy problem do rozwiązania — i ma kształt narzędzia projektowego, a nie modelu."}]}, {"id": "pitfalls", "heading": "Pułapki i jak uniknąć wrażenia „AI slop\"", "blocks": [{"kind": "p", "text": "Najczęstszą skargą na projekty generowane przez AI jest to, że wyglądają generycznie — miękkie gradienty, unoszące się panele, przesadnie zaokrąglone narożniki, dramatyczne cienie, klimat Inter-i-fioletu, który „krzyczy, że zrobił to AI\". Inne zgłaszane problemy obejmują zepsute layouty mobilne i instrukcje wyciekające do tekstów interfejsu. Żadne z nich nie są unikalne dla Aider; to po prostu efekt działania dowolnego agenta bez odpowiednio przygotowanego kontekstu projektowego."}, {"kind": "steps", "items": [{"label": "Dodaj skill estetyczny", "body": "Wyselekcjonowany skill projektowy zmusza agenta do przyjęcia konkretnego kierunku zamiast domyślnego wyglądu."}, {"label": "Zweryfikuj w prawdziwej przeglądarce", "body": "Renderuj i sprawdzaj na różnych breakpointach, aby układy nie psuły się po cichu na urządzeniach mobilnych — na modelu z możliwościami wizualnymi przekaż zrzuty ekranu z powrotem do analizy."}, {"label": "Dostarczaj tokeny i odniesienia", "body": "Prawdziwe design tokens i referencyjne screenshoty to najważniejsza dźwignia jakości wyników."}, {"label": "Zakoduj zasady w CONVENTIONS.md", "body": "Umieść zasady stylu typu „żadnych kart bohaterów, maksymalnie dwa kroje pisma, hierarchia najpierw brand\" tam, gdzie agent odczytuje je przy każdym uruchomieniu."}]}, {"kind": "p", "text": "Zauważ, że każde rozwiązanie polega na dostarczeniu agentowi wyselekcjonowanego kontekstu projektowego. Ręczne utrzymywanie tego kontekstu dla każdego projektu to właśnie trud, którego Open Design Cię zwalnia."}]}, {"id": "open-design", "heading": "Projektowanie z Aider wewnątrz Open Design", "blocks": [{"kind": "p", "text": "Open Design to warstwa projektowa open-source, o którą prosi powyższy workflow. Traktuje Aider jako adapter first-party i otacza go wyselekcjonowaną biblioteką skill i systemów projektowych, ustrukturyzowanym potokiem renderowania oraz lokalnym interfejsem desktopowym — dzięki czemu kontekst projektowy, który czyni Aider dobrym, jest dostępny od pierwszego uruchomienia, a nie składany ręcznie za każdym razem. Oba projekty są open-source i local-first, co czyni to połączenie naturalnym wyborem."}, {"kind": "ol", "items": ["Zainstaluj Open Design i wybierz Aider jako swojego agenta.", "Uwierzytelnij się własnym kluczem API dostawcy (BYOK) — OpenAI, Anthropic, DeepSeek lub Gemini; dane uwierzytelniające pozostają na Twoim komputerze i nigdy nie są przekazywane przez nas.", "Wybierz system projektowy i skill, a następnie generuj prezentacje, prototypy i strony docelowe ze spójnym gustem.", "Każdy artefakt i plik DESIGN.md znajduje się w Twoim własnym repozytorium git, a nie w hostowanej chmurze."]}, {"kind": "p", "text": "Ten sam agent Aider, ten sam klucz — plus prawdziwy, przenośny, otwartoźródłowy proces projektowy wokół niego. Jest local-first i open-source, więc nic z Twojej pracy ani Twoich danych uwierzytelniających nie opuszcza Twojej maszyny."}]}], "faqTitle": "Często zadawane pytania", "faq": [{"name": "Czy Aider naprawdę potrafi wykonywać pracę projektową?", "text": "Tak — z aesthetic skill, systemem projektowym i prawdziwymi obrazami referencyjnymi w kontekście, Aider produkuje responsywny UI jakości produkcyjnej, a na modelach z możliwością widzenia odczytuje zrzuty ekranu, aby zweryfikować wynik względem referencji. Bez tego kontekstu ma tendencję do domyślnego generycznego wyglądu, co jest luką, którą wypełnia Open Design."}, {"name": "Których modeli mogę używać z Aider do projektowania?", "text": "Aider jest model-agnostic. Używasz własnego klucza API i łączysz niemal każdy LLM — Claude, GPT-4o, DeepSeek, Gemini lub model lokalny. Do pracy projektowej opartej na obrazach używaj modelu z vision, takiego jak GPT-4o lub Claude. Open Design nigdy nie pośredniczy w twoich credentials."}, {"name": "Co sprawia, że Aider jest dobry specyficznie do projektowania?", "text": "Dwie rzeczy: jest niezależny od modelu, więc wybierasz model, który najlepiej projektuje dla twojego zadania, i jest natywnie zintegrowany z git, commitując każdą zmianę, aby każda iteracja designu była możliwa do przejrzenia i odwrócenia. Obie pomagają — ale gust nadal pochodzi z systemu designu, skill i referencji, które dostarczasz."}, {"name": "Czy Aider edytuje moje pliki i commituje do git?", "text": "Tak. Aider edytuje pliki bezpośrednio w Twoim repozytorium i automatycznie commituje każdą zmianę ze sensownym komunikatem, dzięki czemu możesz przeglądać, zarządzać i cofać pracę AI za pomocą narzędzi git, których już używasz."}, {"name": "Jak przekazać Aider moje konwencje projektowe?", "text": "Utwórz CONVENTIONS.md z własnymi tokens, prymitywami i regułami, a następnie załaduj go w trybie tylko do odczytu za pomocą /read CONVENTIONS.md lub aider --read CONVENTIONS.md (albo ustaw read: CONVENTIONS.md w .aider.conf.yml, aby ładować przy każdym uruchomieniu). Aider będzie wtedy pracował zgodnie z Twoją marką zamiast domyślnego wyglądu."}, {"name": "Czy Open Design jest powiązany z Aider?", "text": "Nie. Aider to niezależny projekt open-source (Aider-AI); Open Design to oddzielny niezależny projekt open-source, który wspiera Aider jako adapter first-party. Oba nie są powiązane."}, {"name": "Czy moje pliki i poświadczenia są bezpieczne?", "text": "Tak — Open Design jest lokalny i open-source. Twoje pliki, artefakty i DESIGN.md pozostają w Twoim własnym repozytorium git, a klucze API dostawców są używane bezpośrednio przez Twojego agenta, nigdy nie są kierowane przez serwery Open Design."}], "ctaTitle": "Projektuj z Aider, w sposób otwarty.", "ctaBody": "Przynieś własny klucz API dostawcy, przechowuj każdy plik lokalnie w swoim repozytorium git i uzyskaj wyselekcjonowaną bibliotekę projektową wokół agenta, którego już używasz.", "ctaActions": [{"label": "Użyj Aider wewnątrz Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Gwiazdka na GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Pobierz aplikację desktopową", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Zobacz wszystkich wspieranych agentów"},
      },
      'antigravity': {
        ...en['antigravity']!,
        title: "Antigravity dla projektowania — Open Design",
        description: "Jak ludzie używają Google Antigravity — platformy deweloperskiej Google opartej na agentach, zasilanej przez multimodalne modele Gemini 3.x, z jego Editor View, Manager Surface, zintegrowaną kontrolą przeglądarki i Artifacts — do projektowania UI i stron internetowych, oraz jak Open Design przekształca Antigravity w local-first, open-source'owego agenta projektowego.",
        breadcrumb: "Antigravity",
        label: "Agent · Antigravity",
        heading: "Antigravity dla projektowania.",
        lead: "Antigravity to agent-first platforma deweloperska Google. Jej modele Gemini 3.x czytają zrzuty ekranu i rozumują o układzie, jej zintegrowana przeglądarka pozwala agentom weryfikować to, co budują, a jej Artifacts zamieniają pracę agenta w sprawdzalne deliverables — co czyni ją prawdziwym narzędziem projektowym, gdy dasz jej referencje, konwencje i pętlę weryfikacji. Open Design wpina ją w open-source workflow projektowy: twoje konto Google, twoje pliki, local-first.",
        rich: {"heroCtaLead": "Open Design zmienia Antigravity w lokalnego, open-source'owego agenta projektowego — Twoje konto Google, Twoje pliki, wyselekcjonowana biblioteka skill i systemów projektowych wokół niego.", "heroCtaActions": [{"label": "Użyj Antigravity w Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Gwiazdka na GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Pobierz aplikację desktopową", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["Antigravity to agent-first platforma deweloperska Google, uruchomiona razem z Gemini 3. Trzy rzeczy czynią ją interesującą specyficznie dla projektowania: jej agenty działają na natywnie multimodalnych modelach Gemini 3.x, więc czytają zrzut ekranu i rozumują o układzie, odstępach i hierarchii; ma wbudowaną przeglądarkę, którą agent może sterować, więc renderuje i sprawdza własny UI zamiast zgadywać; i produkuje Artifacts — listy zadań, plany implementacji, zrzuty ekranu i nagrania przeglądarki — które zamieniają pracę agenta w coś, co faktycznie możesz przejrzeć. W parze z odpowiednimi referencjami, konwencjami i pętlą weryfikacji, buduje prawdziwy, responsywny UI — i jest darmowy na start z kontem Google. To praktyczny, kompleksowy przewodnik po używaniu Antigravity do pracy nad UI, frontendem i systemami projektowymi oraz po wpięciu go w ustrukturyzowany workflow projektowy z Open Design.", "Omawia, czym właściwie jest Antigravity, dlaczego multimodalny Gemini i zintegrowana przeglądarka pasują do projektowania, jak skonfigurować go od zera, pętlę screenshot-to-UI, jak kontekst agenta i narzędzia go rozszerzają, jak wypada na tle Codex, Claude Code, Cursor i Gemini CLI, pułapki sprawiające, że wynik AI wygląda generycznie, oraz jak Open Design wypełnia tę lukę jako otwarta, local-first warstwa projektowa — naturalne połączenie, ponieważ Open Design jest open-source i działa na Twoim własnym komputerze."], "heroImage": {"src": "/agents/antigravity-design/antigravity-design-hero.webp", "alt": "Pętla zwrotna projektowania Antigravity: agent-first IDE czytające obraz referencyjny, zintegrowana przeglądarka renderująca UI oraz powierzchnia Manager, ze strzałką zwrotną tworzącą pętlę", "caption": "Główna pętla: agent Antigravity odczytuje odniesienia, buduje i weryfikuje UI w zintegrowanej przeglądarce oraz iteruje względem nich — prezentując wyniki jako weryfikowalne Artifacts."}, "tocLabel": "Na tej stronie", "toc": [{"id": "what-is-antigravity", "label": "Czym właściwie jest Antigravity"}, {"id": "why-design", "label": "Dlaczego multimodalny Gemini + wbudowana przeglądarka pasują do projektowania"}, {"id": "setup", "label": "Skonfiguruj Antigravity do pracy z designem (od zera)"}, {"id": "screenshot-workflow", "label": "Proces tworzenia interfejsu ze zrzutu ekranu"}, {"id": "extend", "label": "Kontekst agenta, narzędzia i Artifacts"}, {"id": "vs", "label": "Antigravity vs Codex vs Claude Code vs Cursor vs Gemini CLI"}, {"id": "pitfalls", "label": "Pułapki i wygląd „AI slop\"\n```"}, {"id": "open-design", "label": "Projektowanie z Antigravity w Open Design"}, {"id": "faq", "label": "FAQ"}], "sections": [{"id": "what-is-antigravity", "heading": "Czym właściwie jest Antigravity", "blocks": [{"kind": "p", "text": "Antigravity to agent-first platforma deweloperska Google — IDE zasilane przez AI, zbudowane tak, aby autonomiczne agenty, a nie chatboty w panelu bocznym, wykonywały pracę. Ogłoszona 18 listopada 2025 roku razem z Gemini 3 i dostępna w publicznym podglądzie bezpłatnie dla osób indywidualnych, pozwala delegować złożone, wielonarzędziowe zadania softwarowe agentowi, który operuje w edytorze, terminalu i zintegrowanej przeglądarce. Jego agenty działają głównie na multimodalnych modelach Gemini 3.x Google."}, {"kind": "p", "text": "W pracy projektowej wyróżniają się trzy właściwości. Jej agenty czytają screenshoty i rozumują o faktycznym układzie, ponieważ Gemini 3.x jest natywnie multimodalny. Może sterować prawdziwą przeglądarką, więc renderuje i weryfikuje to, co buduje. I ujawnia Artifacts — listy zadań, plany, screenshoty i nagrania z przeglądarki — więc przeglądasz namacalne wyniki zamiast surowych logów narzędzi."}, {"kind": "steps", "items": [{"label": "Editor View + Manager Surface", "body": "Editor View to znajome środowisko AI IDE z uzupełnianiem kart i poleceniami inline; Manager Surface pozwala uruchamiać, orkiestrować i obserwować wielu agentów pracujących asynchronicznie w różnych przestrzeniach roboczych — naturalne miejsce do wykonywania długich zadań projektowych."}, {"label": "Zintegrowana przeglądarka + Artifacts", "body": "Agenty mogą działać we wbudowanej przeglądarce i generować Artifacts (zrzuty ekranu, nagrania z przeglądarki, listy zadań, plany), na które możesz zostawić feedback — pętla weryfikacji wbudowana w platformę, a nie dodana na siłę."}, {"label": "Darmowy start", "body": "Logowanie za pomocą osobistego konta Google daje hojne limity zapytań na Gemini 3.x; platforma działa na macOS, Windows i Linux."}]}, {"kind": "ul", "items": ["Dostawca: Google", "Dane uwierzytelniające: konto Google (osobiste Gmail), bezpłatnie podczas publicznego podglądu", "Binary: uruchom z agy; działa na macOS, Windows i Linux"]}]}, {"id": "why-design", "heading": "Dlaczego multimodalny Gemini i wbudowana przeglądarka pasują do projektowania", "blocks": [{"kind": "p", "text": "Przewaga projektowa Antigravity wynika z modelu i platformy razem — ale, jak z każdym agentem, gust wciąż trzeba dostarczyć."}, {"kind": "steps", "items": [{"label": "Silne rozumienie multimodalne", "body": "Ponieważ Gemini 3.x jest natywnie multimodalny, agent dobrze odczytuje referencyjne zrzuty ekranu — porównując swój wyrenderowany wynik ze zdjęciem zamiast zgadywać z opisu tekstowego."}, {"label": "Zintegrowana przeglądarka do weryfikacji", "body": "Agent steruje prawdziwą przeglądarką, więc renderuje UI, sprawdza go w różnych stanach i wychwytuje zepsute layouty — a rezultat przechwytuje jako Artifact z nagraniem przeglądarki, który możesz przejrzeć."}, {"label": "Konwencje odczytywane przez agenta", "body": "Zakoduj swoje tokens, komponenty i zasady weryfikacji w kontekście projektu agenta, aby działał zgodnie z Twoją marką zamiast domyślnego wyglądu."}]}, {"kind": "image", "src": "/agents/antigravity-design/antigravity-design-taste-triangle.webp", "alt": "Diagram pokazujący system projektowy, skill oraz obraz referencyjny zbiegające się w dobry wynik projektowy", "caption": "Smak pochodzi z trzech danych wejściowych, które dostarczasz: systemu projektowego, skill oraz prawdziwych obrazów referencyjnych."}, {"kind": "p", "text": "Lekcja jest taka sama, jakiej uczy każdy agent: Antigravity nie ma domyślnie wyczucia smaku. Produkuje dobre projekty, gdy otrzyma ograniczenia — system projektowania, skill estetyczny i konkretne referencje. Open Design pakuje dokładnie te dane wejściowe, dlatego te dwa elementy do siebie pasują (więcej poniżej)."}]}, {"id": "setup", "heading": "Skonfiguruj Antigravity do pracy z designem, od zera", "blocks": [{"kind": "p", "text": "Oto pełna ścieżka od czystej maszyny do agenta Antigravity, który potrafi budować i weryfikować UI. Dokładne menu w aplikacji mogą się zmieniać podczas okresu preview, więc ten przewodnik pozostaje na poziomie, na którym można polegać."}, {"kind": "code", "lang": "bash", "code": "# 1. Download Antigravity for your OS (macOS, Windows, Linux)\n#    from the official download page: antigravity.google/download\n\n# 2. Launch it and sign in\nagy               # opens Antigravity; sign in with your Google account\n\n# 3. Accept the data-use policy, pick a theme, and open your project folder\n\n# 4. Start an agent task in the Editor View or the Manager Surface,\n#    selecting a Gemini 3.x model (e.g. Gemini 3.1 Pro)"}, {"kind": "image", "src": "/agents/antigravity-design/antigravity-design-setup-flow.webp", "alt": "Pięciokrokowy przepływ konfiguracji: pobierz, zaloguj się przez Google, otwórz projekt, dodaj reguły projektowe i skill, włącz weryfikację w przeglądarce", "caption": "Sekwencja konfiguracji: pobierz → zaloguj się przez Google → otwórz swój projekt → dodaj reguły projektowania i skill → użyj zintegrowanej przeglądarki, aby zweryfikować."}, {"kind": "steps", "items": [{"label": "Zakoduj swoje zasady projektowe", "body": "Umieść swoje tokeny, prymitywy i konwencje w kontekście projektu agenta, aby wynik odpowiadał marce zamiast domyślnie wyglądać generycznie."}, {"label": "Użyj zintegrowanej przeglądarki", "body": "Niech agent renderuje we wbudowanej przeglądarce Antigravity i sprawdza swój wynik na punktach przerwania — weryfikując, że UI wygląda prawidłowo, a nie tylko że build przeszedł."}]}]}, {"id": "screenshot-workflow", "heading": "Proces tworzenia interfejsu ze zrzutu ekranu", "blocks": [{"kind": "p", "text": "Najbardziej efektywna pętla projektowa z Antigravity polega na przekształceniu obrazu referencyjnego w działający, responsywny UI i iterowaniu, aż będzie pasował — opierając się na modelu multimodalnym do porównywania wyniku z odniesieniem oraz na zintegrowanej przeglądarce do weryfikacji."}, {"kind": "ol", "items": ["Zacznij od najjaśniejszych referencji wizualnych, jakie masz — i uwzględnij wiele stanów (desktop i mobile, hover, empty, loading), nie tylko jeden hero shot.", "Bądź precyzyjny w prompcie; niejasne prompty generują ogólnikowy UI nawet z mocnym modelem.", "Przechowuj swój system projektowy i konwencje w kontekście projektu agenta i wskaż mu, gdzie znajdują się tokens i kanoniczne prymitywy.", "Pozwól agentowi renderować w zintegrowanej przeglądarce Antigravity, zmieniając rozmiar do breakpointów, aby sprawdzić wynik.", "Iteruj, zlecając agentowi porównanie swojej implementacji ze zrzutami ekranu — a nie tylko potwierdzenie, że buduje się — i przejrzyj nagrania przeglądarki oraz Artifacts ze zrzutami ekranu, które tworzy."]}, {"kind": "p", "text": "Dołącz swoje obrazy referencyjne i podaj konkretne ograniczenia, potem pozwól agentowi zweryfikować w przeglądarce:"}, {"kind": "code", "lang": "text", "code": "# In an Antigravity agent task, attach reference-desktop.png and\n# reference-mobile.png, then prompt:\n\nImplement this design in React + Vite + Tailwind + TypeScript.\nReuse my existing design-system components and tokens.\nMatch spacing, layout, and hierarchy; make it responsive.\nRender it in the integrated browser and iterate until it matches\nthe references across breakpoints, and show me the screenshots."}, {"kind": "p", "text": "Utrzymuj komunikaty małe i zwięzłe, commituj dobre iteracje i revertuj złe (informując agenta o revercie), by każde podejście budowało na czystej bazie."}]}, {"id": "extend", "heading": "Kontekst agenta, narzędzia i Artifacts", "blocks": [{"kind": "p", "text": "Trzy punkty rozszerzenia sprawiają, że Antigravity jest praktyczny w trwałej pracy projektowej, i wszystkie trzy czytelnie mapują się na otwarty przepływ pracy projektowej."}, {"kind": "steps", "items": [{"label": "Kontekst projektu", "body": "Trwałe reguły projektowe to stały dom dla Twoich konwencji projektowych — tokens, prymitywów i checklisty przeglądowych, które agent czyta przy każdym zadaniu, dzięki czemu wynik pozostaje zgodny z marką."}, {"label": "Zintegrowana przeglądarka + terminal", "body": "Agenty działają w edytorze, terminalu i wbudowanej przeglądarce, więc mogą zbierać referencje, uruchamiać serwer deweloperski i weryfikować renderowany interfejs bez opuszczania platformy."}, {"label": "Artifacts, które przeglądasz", "body": "Listy zadań, plany implementacji, zrzuty ekranu i nagrania przeglądarki czynią pracę agenta czytelną; zostawiasz feedback na Artifact, a agent wprowadza poprawki."}]}, {"kind": "p", "text": "To są możliwości, których potrzebuje poważna pętla projektowa — dokładnie taki rodzaj rzeczy, które Open Design został zbudowany do orkiestrowania, a nie odtwarzania w każdym projekcie."}]}, {"id": "vs", "heading": "Antigravity vs Codex vs Claude Code vs Cursor vs Gemini CLI dla projektowania", "blocks": [{"kind": "p", "text": "Nie ma jednego zwycięzcy w pracy projektowej — każdy agent ma inną mocną stronę, a doświadczone zespoły je łączą. Uczciwe podsumowanie:"}, {"kind": "table", "columns": ["Agent", "Siła projektowa", "Najlepsze do"], "rows": [["Antigravity", "IDE zorientowane na agentów z multimodalnym Gemini 3.x, zintegrowaną przeglądarką do samoweryfikacji i recenzowalnymi Artifacts; darmowe w wersji preview", "Asynchroniczne buildy wieloagentowe z wbudowaną weryfikacją UI w przeglądarce"], ["Codex", "Silne wykończenie wizualne z frontendem skill; izolowane asynchroniczne buildy", "Delegowane asynchroniczne buildy i przenośne reguły AGENTS.md"], ["Claude Code", "Konkretne decyzje projektowe (hex, spacing, type) i UX świadomy bazy kodu", "Rozumowanie frontend i refaktoring dużych kontekstów"], ["Cursor", "Wizualna pętla budowania i podglądu z podglądem na żywo i edycją inline", "Zwarta praca iteracyjna nad UI z podglądem wewnątrz IDE"], ["Gemini CLI", "Open-source'owy agent terminalowy oparty na multimodalnym Gemini z kontekstem 1M tokens i darmowym tierem", "Praca w terminalu z dużą liczbą zrzutów ekranu i utrzymywanie całego systemu designu w kontekście"]]}, {"kind": "p", "text": "Powtarzający się werdykt społeczności jest taki, że gust pochodzi od ludzi: wszyscy bez wyjątku domyślnie stosują generyczną estetykę bez skills, referencji i ograniczeń. To jest prawdziwy problem do rozwiązania — i ma kształt narzędzia projektowego, a nie modelu."}]}, {"id": "pitfalls", "heading": "Pułapki i jak uniknąć wrażenia „AI slop\"", "blocks": [{"kind": "p", "text": "Najczęstszą skargą na projekty generowane przez AI jest to, że wyglądają generycznie — miękkie gradienty, unoszące się panele, przesadnie zaokrąglone rogi, dramatyczne cienie, klimat Inter-i-fioletu, który „krzyczy, że zrobiło to AI\". Inne zgłaszane problemy obejmują zepsute layouty mobilne i instrukcje wyciekające do kopii UI. Żadna z tych kwestii nie jest unikalna dla Antigravity; to właśnie się dzieje, gdy dowolny agent działa bez wyselekcjonowanego kontekstu projektowego."}, {"kind": "steps", "items": [{"label": "Dodaj skill estetyczny", "body": "Wyselekcjonowany skill projektowy zmusza agenta do przyjęcia konkretnego kierunku zamiast domyślnego wyglądu."}, {"label": "Zweryfikuj w zintegrowanej przeglądarce", "body": "Użyj modelu multimodalnego i wbudowanej przeglądarki Antigravity, aby renderować i sprawdzać układ na różnych punktach przerwania, dzięki czemu układ nie ulegnie cichemu załamaniu na urządzeniach mobilnych."}, {"label": "Dostarczaj tokeny i odniesienia", "body": "Prawdziwe design tokens i referencyjne screenshoty to najważniejsza dźwignia jakości wyników."}, {"label": "Zakoduj zasady w kontekście projektu", "body": "Umieść reguły stylu w rodzaju „brak hero cards, maksymalnie dwa kroje pisma, hierarchia priorytetyzująca brand\" tam, gdzie agent odczytuje je przy każdym zadaniu."}]}, {"kind": "p", "text": "Zauważ, że każde rozwiązanie polega na dostarczeniu agentowi wyselekcjonowanego kontekstu projektowego. Ręczne utrzymywanie tego kontekstu dla każdego projektu to właśnie trud, którego Open Design Cię zwalnia."}]}, {"id": "open-design", "heading": "Projektowanie z Antigravity wewnątrz Open Design", "blocks": [{"kind": "p", "text": "Open Design to warstwa projektowa open-source, o którą prosi powyższy workflow. Traktuje Antigravity jako adapter first-party i otacza go wyselekcjonowaną biblioteką skill i systemów projektowych, ustrukturyzowanym potokiem renderowania oraz lokalnym interfejsem desktopowym — dzięki czemu kontekst projektowy, który czyni Antigravity dobrym, jest dostępny od pierwszego uruchomienia, a nie składany ręcznie za każdym razem. Open Design jest open-source i local-first, co czyni to połączenie naturalnym wyborem."}, {"kind": "ol", "items": ["Zainstaluj Open Design i wybierz Antigravity jako swojego agenta.", "Uwierzytelnij się swoim kontem Google — poświadczenia zostają na twojej maszynie i nigdy nie są proxowane przez nas.", "Wybierz system projektowy i skill, a następnie generuj prezentacje, prototypy i strony docelowe ze spójnym gustem.", "Każdy artefakt i plik DESIGN.md znajduje się w Twoim własnym repozytorium, a nie w hostowanej chmurze."]}, {"kind": "p", "text": "Ten sam agent Antigravity, to samo konto Google — plus prawdziwy, przenośny, otwartoźródłowy proces projektowy wokół niego. Open Design jest local-first i na licencji Apache-2.0, więc nic z Twojej pracy ani Twoich danych uwierzytelniających nie opuszcza Twojej maszyny."}]}], "faqTitle": "Często zadawane pytania", "faq": [{"name": "Czy Antigravity naprawdę potrafi wykonywać pracę projektową?", "text": "Tak — z umiejętnością estetyczną (aesthetic skill), systemem projektowym i rzeczywistymi obrazami referencyjnymi w kontekście, Antigravity produkuje responsywny UI o jakości produkcyjnej, a jego multimodalne agenty Gemini 3.x weryfikują wynik w zintegrowanej przeglądarce. Bez tego kontekstu ma tendencję do domyślnego generycznego wyglądu, co jest luką, którą wypełnia Open Design."}, {"name": "Czy muszę płacić, żeby projektować z Antigravity?", "text": "Antigravity jest dostępne w publicznym podglądzie bezpłatnie dla osób indywidualnych, z hojnymi limitami rate na Gemini 3.x gdy logujesz się osobistym kontem Google. Open Design nigdy nie proxuje twoich poświadczeń w żadną stronę."}, {"name": "Co sprawia, że Antigravity jest dobry specyficznie do projektowania?", "text": "Trzy rzeczy: jego agenty działają na natywnie multimodalnych modelach Gemini 3.x, które dobrze czytają zrzuty ekranu referencyjne, zawiera zintegrowaną przeglądarkę, którą agent może kontrolować w celu weryfikacji UI, i udostępnia Artifacts — zrzuty ekranu i nagrania przeglądarki — które możesz przejrzeć. Gust nadal pochodzi z systemu projektowego, skill i referencji, które dostarczasz."}, {"name": "Antigravity czy Claude Code do projektowania frontendu?", "text": "Oba są mocne. Claude Code jest znany ze specyficznych, świadomych kontekstu kodu decyzji projektowych; przewagą Antigravity jest platforma zorientowana na agentów — multimodalny Gemini 3.x, zintegrowana przeglądarka do weryfikacji oraz recenzowalne Artifacts. Wiele zespołów używa obu — Open Design pozwala przełączać agentów bez zmiany przepływu pracy projektowej."}, {"name": "Jak zweryfikować to, co tworzy Antigravity?", "text": "Antigravity ma wbudowaną przeglądarkę, którą jego agenty mogą sterować, więc renderują UI, sprawdzają ją w różnych breakpointach i przechwytują zrzuty ekranu oraz nagrania przeglądarki jako Artifacts. Przeglądanie tych Artifacts — i porównywanie przez agenta swojego outputu z twoimi referencjami — to sposób, w jaki trzymasz rezultat zgodnie ze specyfikacją."}, {"name": "Czy Open Design jest powiązany z Google?", "text": "Nie. Antigravity to produkt Google; Open Design to niezależny projekt open-source, który wspiera go jako adapter first-party. Antigravity i Gemini są znakami towarowymi Google."}, {"name": "Czy moje pliki i poświadczenia są bezpieczne?", "text": "Tak — Open Design jest local-first i Apache-2.0. Twoje pliki, artefakty i DESIGN.md pozostają we własnym repozytorium, a Twoje dane uwierzytelniające Google są używane bezpośrednio przez Twojego agenta, nigdy nie są kierowane przez serwery Open Design."}], "ctaTitle": "Projektuj z Antigravity, w sposób otwarty.", "ctaBody": "Przynieś własne konto Google, przechowuj każdy plik lokalnie i uzyskaj wyselekcjonowaną bibliotekę projektową wokół agenta, którego już używasz.", "ctaActions": [{"label": "Użyj Antigravity w Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Gwiazdka na GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Pobierz aplikację desktopową", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Zobacz wszystkich wspieranych agentów"},
      },
      'reasonix': {
        ...en['reasonix']!,
        title: "DeepSeek Reasonix dla projektowania — Open Design",
        description: "Jak ludzie używają DeepSeek Reasonix — tworzonego przez społeczność, natywnego dla DeepSeek agenta kodującego w terminalu — do projektowania UI i stron internetowych, oraz jak Open Design przekształca go w local-first, open-source'owego agenta projektowego. BYOK z własnym kluczem API DeepSeek.",
        breadcrumb: "DeepSeek Reasonix",
        label: "Agent · DeepSeek Reasonix",
        heading: "DeepSeek Reasonix dla projektowania.",
        lead: "DeepSeek Reasonix to agent kodujący terminalowy o otwartym kodzie źródłowym, zbudowany przez społeczność, zasilany modelami DeepSeek. Odczytuje Twoje repo, edytuje pliki i tanio uruchamia Twoją pętlę weryfikacji — cały jego projekt jest zbudowany wokół prefix cache DeepSeek, aby utrzymać długie sesje przystępnymi cenowo. Dzięki referencjom, konwencjom i kontroli przeglądarki staje się prawdziwym narzędziem projektowym. Open Design podłącza go do workflow projektowego o otwartym kodzie źródłowym: Twój własny klucz API DeepSeek, Twoje pliki, local-first.",
        rich: {"heroCtaLead": "Open Design zmienia DeepSeek Reasonix w lokalnego, open-source'owego agenta projektowego — Twój własny klucz API DeepSeek, Twoje pliki, wyselekcjonowana biblioteka skill i systemów projektowych wokół niego.", "heroCtaActions": [{"label": "Użyj DeepSeek Reasonix w Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Gwiazdka na GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Pobierz aplikację desktopową", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["DeepSeek Reasonix to agent kodujący AI o otwartym kodzie źródłowym, zbudowany przez społeczność dla terminala, zasilany modelami DeepSeek. Nie jest oficjalnym produktem DeepSeek — jest utrzymywany przez autora GitHub esengine oraz społeczność i został zbudowany specjalnie wokół mechaniki prefix-cache DeepSeek, dzięki czemu długie, iteracyjne sesje pozostają tanie. Odczytuje Twoje repozytorium, edytuje pliki, uruchamia polecenia i pracuje na podstawie zadań w języku naturalnym, zamiast tylko uzupełniać linie. Dostarczasz własny klucz API DeepSeek (BYOK), a agent działa na modelach DeepSeek, takich jak deepseek-v4-pro i deepseek-v4-flash. To praktyczny przewodnik end-to-end dotyczący używania DeepSeek Reasonix do pracy nad UI, frontendem i systemami projektowymi oraz podłączania go do ustrukturyzowanego workflow projektowego z Open Design.", "Omawia, czym właściwie jest DeepSeek Reasonix, dlaczego efektywny kosztowo agent napędzany przez DeepSeek pasuje do iteracyjnego projektowania, jak skonfigurować go od zera z własnym kluczem, pętlę reference-to-UI, jak skills i MCP go rozszerzają, jak wypada na tle Codex, Claude Code, Cursor i Gemini CLI, pułapki sprawiające, że wynik AI wygląda generycznie, oraz jak Open Design wypełnia tę lukę jako otwarta, local-first warstwa projektowa — naturalne połączenie, ponieważ oba są open-source i działają na Twoim własnym komputerze."], "heroImage": {"src": "/agents/reasonix-design/reasonix-design-hero.webp", "alt": "Pętla feedbacku projektowego DeepSeek Reasonix: agent terminalowy odczytujący referencje projektowe, przeglądarka renderująca UI oraz workspace, ze strzałką feedbacku zapętloną z powrotem", "caption": "Podstawowa pętla: DeepSeek Reasonix pracuje w terminalu w oparciu o Twoje referencje i konwencje, weryfikujesz interfejs w prawdziwej przeglądarce, a on iteruje — tanio, dzięki DeepSeek prefix caching."}, "tocLabel": "Na tej stronie", "toc": [{"id": "what-is-reasonix", "label": "Czym właściwie jest DeepSeek Reasonix"}, {"id": "why-design", "label": "Dlaczego opłacalny agent DeepSeek pasuje do projektowania"}, {"id": "setup", "label": "Skonfiguruj DeepSeek Reasonix do projektowania (od zera)"}, {"id": "screenshot-workflow", "label": "Przepływ pracy oparty na odwołaniach do UI"}, {"id": "extend", "label": "Skills, MCP i konfiguracja"}, {"id": "vs", "label": "DeepSeek Reasonix vs Codex vs Claude Code vs Cursor vs Gemini CLI"}, {"id": "pitfalls", "label": "Pułapki i wygląd „AI slop\"\n```"}, {"id": "open-design", "label": "Projektowanie z DeepSeek Reasonix w Open Design"}, {"id": "faq", "label": "FAQ"}], "sections": [{"id": "what-is-reasonix", "heading": "Czym właściwie jest DeepSeek Reasonix", "blocks": [{"kind": "p", "text": "DeepSeek Reasonix to agent kodujący AI o otwartym kodzie źródłowym (MIT) dla terminala, stworzony przez autora GitHub esengine oraz społeczność. Jest natywny dla DeepSeek: zaprojektowany wokół mechaniki prefix-cache DeepSeek, dzięki czemu długie, iteracyjne sesje pozostają tanie. Odczytuje Twoje repozytorium, edytuje pliki za pomocą edytora SEARCH/REPLACE z bramką recenzji, uruchamia polecenia powłoki i pracuje na podstawie zadań w języku naturalnym — planując i weryfikując, zamiast tylko uzupełniać linie. Ważne jest, aby było jasne, że jest to projekt społecznościowy, a nie oficjalny produkt firmy DeepSeek."}, {"kind": "p", "text": "W pracy projektowej liczy się to, że jest to sprawny, świadomy repozytorium agent kodujący, który działa na mocnych modelach DeepSeek przy niskich kosztach. Modele DeepSeek, których używa, są tylko tekstowe — nie czytają natywnie obrazów — więc praktyczna pętla projektowa jest sterowana odniesieniami i weryfikowana w prawdziwej przeglądarce, zamiast agenta \"widzącego\" screenshot bezpośrednio. Efektywność kosztowa jest istotną przewagą projektową: możesz iterować interfejs wiele razy bez rachunku, który zazwyczaj zniechęca do wąskich pętli."}, {"kind": "steps", "items": [{"label": "Natywny dla DeepSeek, BYOK", "body": "Reasonix działa na modelach DeepSeek, takich jak deepseek-v4-pro i deepseek-v4-flash. Przynosisz własny klucz API DeepSeek — dane uwierzytelniające znajdują się w Twoim środowisku, nie w konfiguracji agenta."}, {"label": "Edycja świadoma repozytorium", "body": "Czyta i edytuje pliki w Twoim projekcie za pomocą edytora z kontrolą przeglądową i uruchamia polecenia shella, dzięki czemu może budować i iterować nad prawdziwym kodem UI w Twoim własnym repozytorium."}, {"label": "Skills + MCP", "body": "Wspiera skills pisane w Markdown i serwery MCP, dzięki czemu możesz nadać mu trwałe konwencje i podłączyć zewnętrzny kontekst, taki jak źródło projektowe."}]}, {"kind": "ul", "items": ["Dostawca: społeczność / autor esengine na GitHubie (nie firma DeepSeek)", "Dane uwierzytelniające: własny klucz API DeepSeek (BYOK), dostarczany przez zmienną środowiskową", "Licencja: MIT, open source"]}]}, {"id": "why-design", "heading": "Dlaczego opłacalny agent DeepSeek pasuje do projektowania", "blocks": [{"kind": "p", "text": "Przewaga projektowa DeepSeek Reasonix polega mniej na pojedynczej efektownej funkcji, a bardziej na tym, że iteracyjna praca nad UI jest tania i powtarzalna — ale, jak w przypadku każdego agenta, gust wciąż trzeba dostarczyć."}, {"kind": "steps", "items": [{"label": "Tania, ścisła iteracja", "body": "Ponieważ jest zaprojektowany wokół prefix cache DeepSeek, długie sesje projektowe pozostają przystępne cenowo — możesz więc uruchamiać pętlę build-verify-refine wiele razy zamiast ją racjonować."}, {"label": "Ponowne użycie świadome repozytorium", "body": "Edytuje pliki bezpośrednio w Twoim repozytorium, dzięki czemu może wykorzystywać istniejące komponenty i tokens zamiast wymyślać jednorazowe style, gdy wskażesz mu je."}, {"label": "Konwencje w skills", "body": "Skills w Markdown i konfiguracja projektu pozwalają zakodować tokeny, komponenty i reguły przeglądu, dzięki czemu agent działa zgodnie z Twoją marką zamiast domyślnego wyglądu."}]}, {"kind": "image", "src": "/agents/reasonix-design/reasonix-design-taste-triangle.webp", "alt": "Diagram pokazujący system projektowy, skill oraz obraz referencyjny zbiegające się w dobry wynik projektowy", "caption": "Smak pochodzi z trzech danych wejściowych, które dostarczasz: systemu projektowego, skill oraz prawdziwych obrazów referencyjnych."}, {"kind": "p", "text": "Lekcja jest taka sama, jakiej uczy każdy agent: DeepSeek Reasonix nie ma domyślnie wyczucia smaku. Produkuje dobre projekty, gdy otrzyma ograniczenia — system projektowania, skill estetyczny i konkretne referencje opisane mu — oraz przeglądarkę do weryfikacji. Open Design pakuje dokładnie te dane wejściowe, dlatego te dwa elementy do siebie pasują (więcej poniżej)."}]}, {"id": "setup", "heading": "Skonfiguruj DeepSeek Reasonix do pracy projektowej, od zera", "blocks": [{"kind": "p", "text": "Oto ścieżka od czystej maszyny do DeepSeek Reasonix, który potrafi budować i weryfikować UI. Ponieważ jest to projekt społecznościowy, zawsze postępuj zgodnie z instrukcjami instalacji w README repozytorium; poniższy zarys przedstawia ogólny kształt."}, {"kind": "code", "lang": "bash", "code": "# 1. Install DeepSeek Reasonix (Node 22+) — see the repo README\nnpm install -g reasonix\n\n# 2. Bring your own DeepSeek API key (BYOK)\n#    Reasonix reads it from your environment, not from config files.\nexport DEEPSEEK_API_KEY=sk-...    # your DeepSeek key\n\n# 3. Start it in your project\ncd your-project\nreasonix                         # see README for the exact subcommands\n\n# 4. Add a design source via MCP (optional)\n#    e.g. a Figma MCP server, configured per the repo docs"}, {"kind": "image", "src": "/agents/reasonix-design/reasonix-design-setup-flow.webp", "alt": "Pięciokrokowy przepływ konfiguracji: zainstaluj, dodaj swój klucz DeepSeek, skonfiguruj konwencje, dodaj skill, zweryfikuj w przeglądarce", "caption": "Sekwencja konfiguracji: instalacja → dodanie klucza API DeepSeek → zakodowanie konwencji → dodanie skill → włączenie weryfikacji w przeglądarce."}, {"kind": "steps", "items": [{"label": "Zakoduj swoje zasady projektowe", "body": "Umieść swoje tokeny, prymitywy i konwencje w konfiguracji skill lub projektu i skieruj na nie Reasonix, aby wynik odpowiadał marce zamiast domyślnie generycznego wyglądu."}, {"label": "Dodaj weryfikację przeglądarki", "body": "Ponieważ modele DeepSeek obsługują tylko tekst, podłącz Playwright lub przeglądarkowy MCP, aby agent renderował w prawdziwej przeglądarce i sprawdzał swoje wyniki na różnych punktach granicznych, zamiast tylko potwierdzać, że build przechodzi."}]}]}, {"id": "screenshot-workflow", "heading": "Przepływ pracy oparty na odwołaniach do UI", "blocks": [{"kind": "p", "text": "Najbardziej efektywna pętla projektowa z DeepSeek Reasonix polega na przekształceniu jasnych odniesień w działający, responsywny UI i iterowaniu, aż będzie pasował. Ponieważ modele DeepSeek obsługują tylko tekst, odniesienia są przekazywane jako szczegółowe opisy i specyfikacje — nie są odczytywane natywnie jako obrazy — a dopasowanie jest potwierdzane przez renderowanie w prawdziwej przeglądarce."}, {"kind": "ol", "items": ["Przetłumacz swoje referencje na konkretne specyfikacje — opisz układ, odstępy, hierarchię i stany (desktop i mobile, hover, empty, loading) słowami, ponieważ model czyta tekst, a nie piksele.", "Bądź precyzyjny w prompcie; niejasne prompty generują ogólnikowy UI nawet z mocnym modelem.", "Przechowuj swój system projektowy i konwencje w skill lub konfiguracji projektu i wskaż Reasonix, gdzie znajdują się tokens i kanoniczne prymitywy.", "Uruchom serwer deweloperski i zweryfikuj wynik w prawdziwej przeglądarce, zmieniając rozmiar do breakpointów — podłącz przeglądarkowy MCP, aby agent mógł sam się sprawdzić.", "Iteruj, porównując wyrenderowany UI z referencjami w przeglądarce — nie tylko potwierdzając, że się buduje."]}, {"kind": "p", "text": "Podaj agentowi konkretne ograniczenia w prompcie zamiast mętnego briefu:"}, {"kind": "code", "lang": "bash", "code": "reasonix\n# in the prompt:\n> Implement this design in React + Vite + Tailwind + TypeScript.\n  Reference: a two-column hero, 48px vertical rhythm, brand teal\n  accent, system-ui type — desktop and mobile described in DESIGN.md.\n  Reuse my existing design-system components and tokens.\n  Match spacing, layout, and hierarchy; make it responsive.\n  Render it in a browser and iterate until it matches the spec\n  across breakpoints."}, {"kind": "p", "text": "Utrzymuj komunikaty małe i zwięzłe, commituj dobre iteracje i revertuj złe (informując Reasonix o revercie), by każde podejście budowało na czystej bazie — i by tania, przyjazna cache'owi pętla pozostała produktywna."}]}, {"id": "extend", "heading": "Skills, MCP i konfiguracja", "blocks": [{"kind": "p", "text": "Kilka punktów rozszerzenia czyni DeepSeek Reasonix praktycznym do długotrwałej pracy projektowej i mapują się one czytelnie na otwarty przepływ pracy projektowej."}, {"kind": "steps", "items": [{"label": "Skills w Markdown", "body": "Reasonix obsługuje skills napisane w Markdown — trwały dom dla twoich konwencji projektowych, tokenów i list kontrolnych recenzji, stosowanych przy każdym uruchomieniu."}, {"label": "Serwery MCP", "body": "Integruje serwery MCP, przenośny sposób na wprowadzenie kontekstu projektowego i zewnętrznych narzędzi — szczególnie istotnego źródła projektowego, takiego jak serwer Figma MCP — które działają w różnych agentach, nie tylko w Reasonix."}, {"label": "Konfiguracja projektu i wbudowane narzędzia", "body": "Konfiguracja per-projekt oraz wbudowane narzędzia do plików, powłoki i internetu pozwalają zbierać kontekst i uruchamiać pętlę weryfikacyjną bez opuszczania terminala. Sprawdź README repozytorium po dokładne ścieżki konfiguracji."}]}, {"kind": "p", "text": "To przenośne możliwości multi-agent — dokładnie ten rodzaj rzeczy, które Open Design zostało stworzone, aby orkiestrować, zamiast odtwarzać je w każdym projekcie."}]}, {"id": "vs", "heading": "DeepSeek Reasonix vs Codex vs Claude Code vs Cursor vs Gemini CLI dla projektowania", "blocks": [{"kind": "p", "text": "Nie ma jednego zwycięzcy w pracy projektowej — każdy agent ma inną mocną stronę, a doświadczone zespoły je łączą. Uczciwe podsumowanie:"}, {"kind": "table", "columns": ["Agent", "Siła projektowa", "Najlepsze do"], "rows": [["DeepSeek Reasonix", "Open-source i napędzany przez DeepSeek; efektywny kosztowo dzięki cache'owaniu prefiksów, BYOK z własnym kluczem DeepSeek (zbudowany przez społeczność, modele tylko tekstowe)", "Tania, masowa iteracja UI we własnym repozytorium"], ["Codex", "Silne wykończenie wizualne z frontendem skill; izolowane asynchroniczne buildy", "Delegowane asynchroniczne buildy i przenośne reguły AGENTS.md"], ["Claude Code", "Konkretne decyzje projektowe (hex, spacing, type) i UX świadomy bazy kodu", "Rozumowanie frontend i refaktoring dużych kontekstów"], ["Cursor", "Wizualna pętla budowania i podglądu z podglądem na żywo i edycją inline", "Zwarta praca iteracyjna nad UI z podglądem wewnątrz IDE"], ["Gemini CLI", "Silne wielomodalne rozumienie obrazu i kontekst 1M tokens; open-source z darmowym tierem", "Praca z dużą liczbą zrzutów ekranu i utrzymywanie całego systemu designu w kontekście"]]}, {"kind": "p", "text": "Powtarzający się werdykt społeczności jest taki, że gust pochodzi od ludzi: wszyscy bez wyjątku domyślnie stosują generyczną estetykę bez skills, referencji i ograniczeń. To jest prawdziwy problem do rozwiązania — i ma kształt narzędzia projektowego, a nie modelu."}]}, {"id": "pitfalls", "heading": "Pułapki i jak uniknąć wrażenia „AI slop\"", "blocks": [{"kind": "p", "text": "Najczęstszą skargą na projekty generowane przez AI jest to, że wyglądają sztampowo — miękkie gradienty, unoszące się panele, przesadnie zaokrąglone rogi, dramatyczne cienie, klimat Inter-i-fioletu, który „krzyczy, że zrobiło to AI\". Inne zgłaszane problemy obejmują zepsute layouty mobilne oraz instrukcje przenikające do treści interfejsu. Żadne z tych problemów nie są unikalne dla DeepSeek Reasonix; dzieje się tak, gdy dowolny agent działa bez wyselekcjonowanego kontekstu projektowego — a ponieważ jego modele są wyłącznie tekstowe, precyzyjne opisywanie odniesień ma jeszcze większe znaczenie."}, {"kind": "steps", "items": [{"label": "Dodaj skill estetyczny", "body": "Wyselekcjonowany skill projektowy zmusza agenta do przyjęcia konkretnego kierunku zamiast domyślnego wyglądu."}, {"label": "Zweryfikuj w prawdziwej przeglądarce", "body": "Ponieważ model nie widzi, renderuj i samosprawdzaj na różnych punktach granicznych w prawdziwej przeglądarce, aby layouty nie pękały po cichu na mobile."}, {"label": "Dostarczenie tokens i opisanych referencji", "body": "Prawdziwe design tokens i precyzyjnie opisane stany referencyjne to najważniejsza dźwignia jakości wyników dla agenta opartego wyłącznie na tekście."}, {"label": "Zakoduj zasady w skill lub config", "body": "Umieść zasady stylu typu „żadnych kart bohaterów, maksymalnie dwa kroje pisma, hierarchia najpierw brand\" tam, gdzie agent odczytuje je przy każdym uruchomieniu."}]}, {"kind": "p", "text": "Zauważ, że każde rozwiązanie polega na dostarczeniu agentowi wyselekcjonowanego kontekstu projektowego. Ręczne utrzymywanie tego kontekstu dla każdego projektu to właśnie trud, którego Open Design Cię zwalnia."}]}, {"id": "open-design", "heading": "Projektowanie z DeepSeek Reasonix wewnątrz Open Design", "blocks": [{"kind": "p", "text": "Open Design to warstwa projektowa open-source, o którą prosi powyższy workflow. Traktuje DeepSeek Reasonix jako adapter first-party i otacza go wyselekcjonowaną biblioteką skill i systemów projektowych, ustrukturyzowanym potokiem renderowania oraz lokalnym interfejsem desktopowym — dzięki czemu kontekst projektowy, który czyni Reasonix dobrym, jest dostępny od pierwszego uruchomienia, a nie składany ręcznie za każdym razem. Oba projekty są open-source i local-first, co czyni to połączenie naturalnym wyborem."}, {"kind": "ol", "items": ["Zainstaluj Open Design i wybierz DeepSeek Reasonix jako swojego agenta.", "Uwierzytelnij się swoim własnym kluczem API DeepSeek (BYOK) — poświadczenia zostają na twojej maszynie i nigdy nie są proxowane przez nas.", "Wybierz system projektowy i skill, a następnie generuj prezentacje, prototypy i strony docelowe ze spójnym gustem.", "Każdy artefakt i plik DESIGN.md znajduje się w Twoim własnym repozytorium, a nie w hostowanej chmurze."]}, {"kind": "p", "text": "Ten sam agent DeepSeek Reasonix, ten sam klucz — plus prawdziwy, przenośny, otwartoźródłowy proces projektowy wokół niego. Jest local-first i open-source, więc nic z Twojej pracy ani Twoich danych uwierzytelniających nie opuszcza Twojej maszyny."}]}], "faqTitle": "Często zadawane pytania", "faq": [{"name": "Czy DeepSeek Reasonix naprawdę potrafi wykonywać pracę projektową?", "text": "Tak — z aesthetic skill, systemem projektowym i precyzyjnie opisanymi referencjami w kontekście, DeepSeek Reasonix produkuje responsywny UI jakości produkcyjnej we własnym repo, a Ty weryfikujesz wynik w prawdziwej przeglądarce. Jego modele DeepSeek są wyłącznie tekstowe, więc pętla polega na opisywaniu i weryfikacji referencji, a nie odczytywaniu obrazów. Bez tego kontekstu ma tendencję do domyślnego generycznego wyglądu, co jest luką, którą wypełnia Open Design."}, {"name": "Czy muszę płacić za projektowanie z DeepSeek Reasonix?", "text": "Dostarczasz własny klucz API DeepSeek, więc płacisz DeepSeek za użycie (BYOK) — ale agent jest zbudowany wokół cache'u prefiksów DeepSeek, aby utrzymać ten koszt niskim podczas długich sesji. Reasonix sam w sobie jest darmowy i na licencji MIT. Open Design nigdy nie pośredniczy w Twoich poświadczeniach."}, {"name": "Czy DeepSeek Reasonix jest oficjalnym produktem DeepSeek?", "text": "Nie. DeepSeek Reasonix to zbudowany przez społeczność, open-source'owy projekt autora GitHub esengine — działa na modelach DeepSeek i używa klucza API DeepSeek, ale nie jest tworzony ani wspierany przez firmę DeepSeek. DeepSeek jest znakiem towarowym swojego właściciela."}, {"name": "DeepSeek Reasonix czy Claude Code do projektowania frontendu?", "text": "Oba mogą wykonywać prawdziwą pracę projektową. Claude Code jest znany ze specyficznych, świadomych kontekstu kodu decyzji projektowych; przewagą DeepSeek Reasonix jest bycie open-source i efektywnym kosztowo, uruchamiając tanie, wielokrotne iteracje na modelach DeepSeek z własnym kluczem. Wiele zespołów używa więcej niż jednego — Open Design pozwala przełączać agentów bez zmiany przepływu pracy projektowej."}, {"name": "Jak podłączyć DeepSeek Reasonix do źródła projektowego takiego jak Figma?", "text": "Reasonix obsługuje serwery MCP, więc możesz dodać MCP źródła projektowego (taki jak serwer Figma MCP) zgodnie z dokumentacją repozytorium. Agent może wtedy pobierać rzeczywisty kontekst projektowy — komponenty, zmienne, dane layoutu — jako tekst, na którym może działać, więc wygenerowany kod pasuje do źródła zamiast je przybliżać."}, {"name": "Czy Open Design jest powiązany z DeepSeek?", "text": "Nie. DeepSeek Reasonix to projekt społecznościowy działający na modelach DeepSeek; Open Design to niezależny projekt open-source, który wspiera go jako adapter first-party. Nie jest powiązany ani z firmą DeepSeek, ani z opiekunami Reasonix. DeepSeek jest znakiem towarowym swojego właściciela."}, {"name": "Czy moje pliki i poświadczenia są bezpieczne?", "text": "Tak — Open Design jest lokalny i open-source. Twoje pliki, artefakty i DESIGN.md pozostają w Twoim własnym repo, a Twój klucz API DeepSeek jest używany bezpośrednio przez Twojego agenta, nigdy nie jest kierowany przez serwery Open Design."}], "ctaTitle": "Projektuj z DeepSeek Reasonix, w sposób otwarty.", "ctaBody": "Przynieś własny klucz API DeepSeek, przechowuj każdy plik lokalnie i uzyskaj wyselekcjonowaną bibliotekę projektową wokół agenta open-source, którego już używasz.", "ctaActions": [{"label": "Użyj DeepSeek Reasonix w Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Gwiazdka na GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Pobierz aplikację desktopową", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Zobacz wszystkich wspieranych agentów"},
      },
      'hermes': {
        ...en['hermes']!,
        title: "Hermes do projektowania — Open Design",
        description: "Jak ludzie używają Nous Research Hermes — autonomicznego, wielodostawcowego agenta kodującego w terminalu — do projektowania UI i stron internetowych, oraz jak Open Design przekształca go w local-first, open-source'owego agenta projektowego z własnym kluczem xAI, OpenAI lub Anthropic.",
        breadcrumb: "Hermes",
        label: "Agent · Hermes",
        heading: "Hermes do projektowania.",
        lead: "Hermes to open-source'owy, autonomiczny agent terminalowy od Nous Research. Planuje, wykonuje i deleguje pracę na własnej maszynie — i jest agnostyczny wobec dostawcy, więc wnosisz własny klucz xAI, OpenAI lub Anthropic. Ta autonomia czyni go prawdziwym narzędziem projektowym, gdy dasz mu referencje, konwencje i pętlę weryfikacji. Open Design wplata go w open-source'owy workflow projektowy: Twój klucz, Twoje pliki, local-first.",
        rich: {"heroCtaLead": "Open Design zamienia Hermes w lokalny, open-source'owy agent designu — Twój własny klucz xAI, OpenAI lub Anthropic, Twoje pliki, wyselekcjonowana biblioteka Skills i systemów projektowych wokół tego.", "heroCtaActions": [{"label": "Użyj Hermes w Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Gwiazdka na GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Pobierz aplikację desktopową", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["Hermes to open-source'owy, autonomiczny agent AI od Nous Research. Dwie rzeczy czynią go interesującym szczególnie dla projektowania: jest prawdziwie agentyczny, więc planuje zadanie, wykonuje je i deleguje części do izolowanych subagentów, zamiast po prostu uzupełniać linie; oraz jest agnostyczny wobec dostawcy, więc wskazujesz mu model, któremu ufasz — domyślnie xAI Grok, lub OpenAI i Anthropic przez bring-your-own-key. W parze z odpowiednimi referencjami, konwencjami i pętlą weryfikacji buduje prawdziwe, responsywne UI na Twojej własnej maszynie. To praktyczny, kompleksowy przewodnik po używaniu Hermes do pracy nad UI, frontendem i systemami projektowymi oraz po włączeniu go w ustrukturyzowany workflow projektowy z Open Design.", "Omawia, czym właściwie jest Hermes, dlaczego autonomiczny, wieloproviderowy agent pasuje do projektowania, jak skonfigurować go od zera, pętlę screenshot-to-UI, jak skills i subagenci go rozszerzają, jak wypada na tle Codex, Claude Code, Cursor i Gemini CLI, pułapki sprawiające, że wynik AI wygląda generycznie, oraz jak Open Design wypełnia tę lukę jako otwarta, local-first warstwa projektowa — naturalne połączenie, ponieważ oba są open-source i działają na Twoim własnym komputerze."], "heroImage": {"src": "/agents/hermes-design/hermes-design-hero.webp", "alt": "Pętla feedbacku projektowego Hermes: autonomiczny agent terminalowy odczytujący obraz referencyjny, delegujący do subagentów, przeglądarka renderująca UI oraz workspace, ze strzałką feedbacku zapętlającą się z powrotem", "caption": "Podstawowa pętla: Hermes czyta Twoje referencje w terminalu, planuje i deleguje budowę, weryfikuje interfejs w prawdziwej przeglądarce i iteruje w oparciu o nie — na dowolnym modelu, który przyniesiesz."}, "tocLabel": "Na tej stronie", "toc": [{"id": "what-is-hermes", "label": "Czym właściwie jest Hermes"}, {"id": "why-design", "label": "Dlaczego autonomiczny, wielodostępowy agent pasuje do projektowania"}, {"id": "setup", "label": "Skonfiguruj Hermes do projektowania (od zera)"}, {"id": "screenshot-workflow", "label": "Proces tworzenia interfejsu ze zrzutu ekranu"}, {"id": "extend", "label": "Skills, subagenty i dostawcy"}, {"id": "vs", "label": "Hermes vs Codex vs Claude Code vs Cursor vs Gemini CLI"}, {"id": "pitfalls", "label": "Pułapki i wygląd „AI slop\"\n```"}, {"id": "open-design", "label": "Projektowanie z Hermes w Open Design"}, {"id": "faq", "label": "FAQ"}], "sections": [{"id": "what-is-hermes", "heading": "Czym właściwie jest Hermes", "blocks": [{"kind": "p", "text": "Hermes to open-source'owy (MIT) autonomiczny agent AI od Nous Research. Działa trwale na Twojej własnej maszynie lub serwerze, czyta repozytorium, edytuje pliki, uruchamia polecenia powłoki, przeszukuje sieć i — kluczowo — planuje i wykonuje wieloetapową pracę samodzielnie, delegując części do izolowanych subagentów. Jest to autonomiczny agent, a nie copilot przywiązany do IDE."}, {"kind": "p", "text": "W pracy projektowej wyróżniają się dwie właściwości. Jest prawdziwie agentowy, więc możesz mu przekazać cel, a on planuje, buduje i weryfikuje zamiast czekać na instrukcje linia po linii. I jest niezależny od dostawcy: przynosisz własny klucz, domyślnie do xAI Grok, ale możesz go wskazać na OpenAI, Anthropic lub dowolny inny obsługiwany endpoint — więc kontrolujesz, który model rozumuje o twoim projekcie."}, {"kind": "steps", "items": [{"label": "Skills", "body": "Hermes tworzy i wykorzystuje ponownie skills — pamięć proceduralną, którą tworzy z doświadczenia — naturalne miejsce do utrwalenia konwencji projektowych, tokens oraz checklist recenzji, tak aby przetrwały między uruchomieniami."}, {"label": "Subagenci + narzędzia", "body": "Tworzy izolowanych subagentów dla równoległych strumieni pracy i dostarcza narzędzia do plików, shella, sieci i przeglądarki, dzięki czemu może zbierać referencje i uruchamiać pętlę build-and-verify bez wychodzenia z terminala."}, {"label": "Przynieś własny klucz", "body": "Hermes domyślnie korzysta z xAI Grok i obsługuje OpenAI, Anthropic, OpenRouter oraz wielu innych dostawców przez BYOK — ustaw klucz lub przejdź przez przepływ OAuth i wybierz swój model."}]}, {"kind": "ul", "items": ["Dostawca: Nous Research", "Dane uwierzytelniające: klucz dostawcy przez BYOK — xAI (Grok, domyślnie), OpenAI lub Anthropic — dodawany za pomocą hermes auth add", "Licencja: MIT, open source"]}]}, {"id": "why-design", "heading": "Dlaczego autonomiczny, wielodostępowy agent pasuje do projektowania", "blocks": [{"kind": "p", "text": "Przewaga projektowa Hermes wynika z dwóch właściwości — ale, jak w przypadku każdego agenta, smak nadal musi być dostarczony."}, {"kind": "steps", "items": [{"label": "Autonomiczne planowanie i wykonanie", "body": "Ponieważ Hermes planuje, wykonuje i deleguje samodzielnie, może przyjąć cel projektowy — dopasuj to do odniesienia, zrób responsywne — i iterować w jego kierunku zamiast wymagać wyszczególnienia każdego kroku."}, {"label": "Przynieś model, któremu ufasz", "body": "Niezależny od dostawcy BYOK oznacza, że wybierasz model rozumowania odpowiedni do zadania: xAI Grok domyślnie, lub modele OpenAI i Anthropic, gdy potrzebujesz ich mocnych stron — bez przywiązania do estetyki jednego dostawcy."}, {"label": "Konwencje w skills", "body": "Skills (plus an MCP server like Figma) point the agent at your tokens, components, and real specs, so it works against a brand instead of a default look."}]}, {"kind": "image", "src": "/agents/hermes-design/hermes-design-taste-triangle.webp", "alt": "Diagram pokazujący system projektowy, skill oraz obraz referencyjny zbiegające się w dobry wynik projektowy", "caption": "Smak pochodzi z trzech danych wejściowych, które dostarczasz: systemu projektowego, skill oraz prawdziwych obrazów referencyjnych."}, {"kind": "p", "text": "Lekcja jest taka sama, jakiej uczy każdy agent: Hermes nie ma smaku z definicji. Tworzy dobry design, gdy nadasz mu ograniczenia — system projektowy, estetyczny skill i konkretne odniesienia. Open Design pakuje dokładnie te dane wejściowe, dlatego oba rozwiązania pasują do siebie (więcej poniżej)."}]}, {"id": "setup", "heading": "Skonfiguruj Hermes do pracy projektowej, od zera", "blocks": [{"kind": "p", "text": "Oto pełna ścieżka od czystej maszyny do Hermes, który potrafi budować i weryfikować UI."}, {"kind": "code", "lang": "bash", "code": "# 1. Install Hermes (one-line installer from Nous Research)\ncurl -fsSL https://hermes-agent.nousresearch.com/install.sh | bash\n\n# 2. Run the setup wizard\nhermes setup\n\n# 3. Add a provider and authenticate (BYOK)\n#    default is xAI Grok; OpenAI / Anthropic also supported\nhermes auth add        # add a provider key or run its OAuth flow\nhermes model           # pick the provider and model (grok-4.3 by default)\n\n# 4. Wire a Figma MCP server (optional, for design handoff)\n#    configure it among Hermes' MCP / tool settings"}, {"kind": "image", "src": "/agents/hermes-design/hermes-design-setup-flow.webp", "alt": "Pięciokrokowy przepływ konfiguracji: zainstaluj, uwierzytelnij się, skonfiguruj skill, dodaj system projektowy, zweryfikuj", "caption": "Sekwencja konfiguracji: instalacja → dodanie klucza dostawcy → zdefiniowanie reguł projektowych w skill → dodanie systemu projektowego → włączenie weryfikacji w przeglądarce."}, {"kind": "steps", "items": [{"label": "Zakoduj swoje zasady projektowe", "body": "Przechwyć swoje tokens, prymitywy i konwencje w skill Hermes i skieruj na nie agenta, aby wyniki odpowiadały marce, zamiast domyślnie przyjmować generyczny wygląd."}, {"label": "Dodaj weryfikację przeglądarki", "body": "Podłącz Playwright lub MCP przeglądarki, aby Hermes renderował w prawdziwej przeglądarce i sprawdzał wynik na różnych breakpointach zamiast tylko potwierdzać, że build przechodzi."}]}]}, {"id": "screenshot-workflow", "heading": "Proces tworzenia interfejsu ze zrzutu ekranu", "blocks": [{"kind": "p", "text": "Najbardziej efektywna pętla projektowa z Hermes polega na przekształceniu obrazu referencyjnego w działający, responsywny UI i iterowaniu, aż będzie pasował — pozwalając autonomicznemu agentowi zaplanować budowę i porównać wynik z odniesieniem."}, {"kind": "ol", "items": ["Zacznij od najjaśniejszych referencji wizualnych, jakie masz — i uwzględnij wiele stanów (desktop i mobile, hover, empty, loading), nie tylko jeden hero shot.", "Bądź precyzyjny w prompcie; niejasne prompty generują ogólnikowy UI nawet z mocnym modelem.", "Przechowuj swój system projektowy i konwencje w skill i wskaż Hermes, gdzie znajdują się tokens i kanoniczne prymitywy.", "Uruchom serwer deweloperski i pozwól Hermes wyrenderować w prawdziwej przeglądarce, zmieniając rozmiar do breakpointów, by sprawdzić rezultat.", "Iteruj, zlecając Hermes porównanie swojej implementacji ze zrzutami ekranu — a nie tylko potwierdzenie, że buduje się."]}, {"kind": "p", "text": "Skieruj Hermes na swoje referencje i podaj konkretne ograniczenia:"}, {"kind": "code", "lang": "bash", "code": "hermes\n# in the prompt:\n> Use reference-desktop.png and reference-mobile.png in this folder.\n  Implement this design in React + Vite + Tailwind + TypeScript.\n  Reuse my existing design-system components and tokens from my skill.\n  Match spacing, layout, and hierarchy; make it responsive.\n  Render it in the browser and iterate until it matches the references\n  across breakpoints."}, {"kind": "p", "text": "Utrzymuj komunikaty małe i zwięzłe, commituj dobre iteracje i revertuj złe (informując Hermes o revercie), by każde podejście budowało na czystej bazie."}]}, {"id": "extend", "heading": "Skills, subagenty i dostawcy", "blocks": [{"kind": "p", "text": "Trzy punkty rozszerzenia sprawiają, że Hermes jest praktyczny w trwałej pracy projektowej, i wszystkie trzy czytelnie mapują się na otwarty przepływ pracy projektowej."}, {"kind": "steps", "items": [{"label": "Skills", "body": "Hermes tworzy i wykorzystuje ponownie skills — pamięć proceduralną stworzoną z doświadczenia. Są one trwałym miejscem dla konwencji projektowych, stosowanych w późniejszych uruchomieniach zamiast ich wielokrotnego wyjaśniania."}, {"label": "Subagenci i MCP", "body": "Deleguje pracę do izolowanych subagentów i wspiera serwery MCP — przenośny sposób na wprowadzenie kontekstu projektowego i zewnętrznych narzędzi, szczególnie istotny dla serwera Figma MCP, które działają w różnych agentach, nie tylko w Hermes."}, {"label": "Wybór dostawcy", "body": "Ponieważ Hermes jest niezależny od dostawcy (domyślnie xAI Grok, OpenAI i Anthropic przez BYOK), możesz dopasować model do zadania bez przebudowy swojego przepływu pracy."}]}, {"kind": "p", "text": "To przenośne możliwości multi-agent — dokładnie ten rodzaj rzeczy, które Open Design zostało stworzone, aby orkiestrować, zamiast odtwarzać je w każdym projekcie."}]}, {"id": "vs", "heading": "Hermes vs Codex vs Claude Code vs Cursor vs Gemini CLI do projektowania", "blocks": [{"kind": "p", "text": "Nie ma jednego zwycięzcy w pracy projektowej — każdy agent ma inną mocną stronę, a doświadczone zespoły je łączą. Uczciwe podsumowanie:"}, {"kind": "table", "columns": ["Agent", "Siła projektowa", "Najlepsze do"], "rows": [["Hermes", "Autonomiczny agent planuj-wykonaj-deleguj; niezależny od dostawcy BYOK (domyślnie xAI Grok, także OpenAI/Anthropic); open-source i self-hosted", "Autonomiczne buildy bez ingerencji na dowolnym zaufanym modelu, trzymane lokalnie"], ["Codex", "Silne wykończenie wizualne z frontendem skill; izolowane asynchroniczne buildy", "Delegowane asynchroniczne buildy i przenośne reguły AGENTS.md"], ["Claude Code", "Konkretne decyzje projektowe (hex, spacing, type) i UX świadomy bazy kodu", "Rozumowanie frontend i refaktoring dużych kontekstów"], ["Cursor", "Wizualna pętla budowania i podglądu z podglądem na żywo i edycją inline", "Zwarta praca iteracyjna nad UI z podglądem wewnątrz IDE"], ["Gemini CLI", "Silne wielomodalne rozumienie obrazu i kontekst 1M tokens; darmowy tier", "Praca z dużą liczbą zrzutów ekranu i utrzymywanie całego systemu designu w kontekście"]]}, {"kind": "p", "text": "Powtarzający się werdykt społeczności jest taki, że gust pochodzi od ludzi: wszyscy bez wyjątku domyślnie stosują generyczną estetykę bez skills, referencji i ograniczeń. To jest prawdziwy problem do rozwiązania — i ma kształt narzędzia projektowego, a nie modelu."}]}, {"id": "pitfalls", "heading": "Pułapki i jak uniknąć wrażenia „AI slop\"", "blocks": [{"kind": "p", "text": "Najczęstszą skargą dotyczącą projektów generowanych przez AI jest to, że wyglądają generycznie — miękkie gradienty, unoszące się panele, przesadnie zaokrąglone rogi, dramatyczne cienie, klimat Inter-i-fioletu, który „krzyczy, że zrobił to AI\". Inne zgłaszane problemy obejmują zepsute layouty mobilne i instrukcje wyciekające do treści UI. Żadne z tych problemów nie są unikalne dla Hermes; to właśnie się dzieje, gdy jakikolwiek agent działa bez starannie dobranego kontekstu projektowego."}, {"kind": "steps", "items": [{"label": "Dodaj skill estetyczny", "body": "Wyselekcjonowany skill projektowy zmusza agenta do przyjęcia konkretnego kierunku zamiast domyślnego wyglądu."}, {"label": "Zweryfikuj w prawdziwej przeglądarce", "body": "Niech Hermes renderuje i sprawdza się na punktach przerwania, by układy nie psuły się po cichu na mobile."}, {"label": "Dostarczaj tokeny i odniesienia", "body": "Prawdziwe design tokens i referencyjne screenshoty to najważniejsza dźwignia jakości wyników."}, {"label": "Zakoduj zasady w skill", "body": "Umieść reguły stylu typu „brak kart bohaterów, maksymalnie dwa kroje pisma, hierarchia brand-first\" w skill, który agent stosuje przy każdym uruchomieniu."}]}, {"kind": "p", "text": "Zauważ, że każde rozwiązanie polega na dostarczeniu agentowi wyselekcjonowanego kontekstu projektowego. Ręczne utrzymywanie tego kontekstu dla każdego projektu to właśnie trud, którego Open Design Cię zwalnia."}]}, {"id": "open-design", "heading": "Projektowanie z Hermes wewnątrz Open Design", "blocks": [{"kind": "p", "text": "Open Design to warstwa projektowa open-source, o którą prosi powyższy workflow. Traktuje Hermes jako adapter first-party i otacza go wyselekcjonowaną biblioteką skill i systemów projektowych, ustrukturyzowanym potokiem renderowania oraz lokalnym interfejsem desktopowym — dzięki czemu kontekst projektowy, który czyni Hermes dobrym, jest dostępny od pierwszego uruchomienia, a nie składany ręcznie za każdym razem. Oba projekty są open-source i local-first, co czyni to połączenie naturalnym wyborem."}, {"kind": "ol", "items": ["Zainstaluj Open Design i wybierz Hermes jako swojego agenta.", "Uwierzytelnij się własnym kluczem dostawcy (BYOK) — domyślnie xAI Grok, lub OpenAI albo Anthropic — dane uwierzytelniające pozostają na Twoim komputerze i nigdy nie są przekazywane przez nas.", "Wybierz system projektowy i skill, a następnie generuj prezentacje, prototypy i strony docelowe ze spójnym gustem.", "Każdy artefakt i plik DESIGN.md znajduje się w Twoim własnym repozytorium, a nie w hostowanej chmurze."]}, {"kind": "p", "text": "Ten sam agent Hermes, ten sam klucz — plus prawdziwy, przenośny, otwartoźródłowy proces projektowy wokół niego. Jest local-first i na licencji Apache-2.0, więc nic z Twojej pracy ani Twoich danych uwierzytelniających nie opuszcza Twojej maszyny."}]}], "faqTitle": "Często zadawane pytania", "faq": [{"name": "Czy Hermes naprawdę potrafi wykonywać pracę projektową?", "text": "Tak — z umiejętnością estetyczną (aesthetic skill), systemem projektowym i rzeczywistymi obrazami referencyjnymi w kontekście, Hermes produkuje responsywny UI o jakości produkcyjnej, a jako autonomiczny agent może samodzielnie renderować i weryfikować wynik względem referencji. Bez tego kontekstu ma tendencję do domyślnego generycznego wyglądu, co jest luką, którą wypełnia Open Design."}, {"name": "Których modeli i kluczy używa Hermes?", "text": "Hermes jest agnostyczny wobec dostawcy i bring-your-own-key. Domyślnie korzysta z xAI Grok (np. grok-4.3) i obsługuje również OpenAI, Anthropic, OpenRouter oraz wielu innych dostawców — dodajesz klucz dostawcy (lub przeprowadzasz jego przepływ OAuth) za pomocą hermes auth add i wybierasz model za pomocą hermes model. Open Design nigdy nie pośredniczy w Twoich danych uwierzytelniających."}, {"name": "Co sprawia, że Hermes jest dobry specyficznie do projektowania?", "text": "Dwie rzeczy: jest naprawdę autonomiczny, więc planuje, buduje i weryfikuje UI zamiast czekać na instrukcje linia po linii; i jest niezależny od dostawcy, więc możesz uruchomić model rozumowania, któremu ufasz. Obie pomagają — ale gust nadal pochodzi z systemu designu, skill i referencji, które dostarczasz."}, {"name": "Hermes czy Claude Code do projektowania frontendu?", "text": "Oba są mocne. Claude Code jest znany ze specyficznych, świadomych kontekstu kodu decyzji projektowych; przewagą Hermes jest autonomiczne planowanie i wykonywanie plus wybór dostawcy — a możesz nawet wskazać Hermes na klucz Anthropic. Wiele zespołów używa obu — Open Design pozwala przełączać agentów bez zmiany przepływu pracy projektowej."}, {"name": "Jak podłączyć Hermes do Figma?", "text": "Dodaj serwer MCP Figma w konfiguracji narzędzi Hermes. Hermes może wtedy pobrać rzeczywisty kontekst projektowy — komponenty, zmienne, dane layoutu — dzięki czemu wygenerowany kod pasuje do źródła zamiast go przybliżać."}, {"name": "Czy Open Design jest powiązany z Nous Research?", "text": "Nie. Hermes to produkt Nous Research; Open Design to niezależny projekt open-source, który wspiera go jako adapter first-party. Hermes i Nous Research są znakami towarowymi swoich właścicieli."}, {"name": "Czy moje pliki i poświadczenia są bezpieczne?", "text": "Tak — Open Design jest local-first i Apache-2.0. Twoje pliki, artefakty i DESIGN.md pozostają we własnym repozytorium, a Twoje dane uwierzytelniające dostawcy są używane bezpośrednio przez Twojego agenta, nigdy nie są kierowane przez serwery Open Design."}], "ctaTitle": "Projektuj z Hermes, w sposób otwarty.", "ctaBody": "Przynieś swój własny klucz xAI, OpenAI lub Anthropic, zachowaj wszystkie pliki lokalnie i uzyskaj dostęp do wyselekcjonowanej biblioteki projektowej wokół agenta, którego już używasz.", "ctaActions": [{"label": "Użyj Hermes w Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Gwiazdka na GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Pobierz aplikację desktopową", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Zobacz wszystkich wspieranych agentów"},
      },
      'devin': {
        ...en['devin']!,
        title: "Devin for Terminal do projektowania — Open Design",
        description: "Jak ludzie używają Devin for Terminal — autonomicznego AI inżyniera oprogramowania firmy Cognition w linii poleceń — do projektowania UI i stron internetowych, oraz jak Open Design przekształca go w local-first, open-source'owego agenta projektowego z wyselekcjonowaną biblioteką skill i systemów projektowych.",
        breadcrumb: "Devin for Terminal",
        label: "Agent · Devin",
        heading: "Devin for Terminal do projektowania.",
        lead: "Devin for Terminal to autonomiczny inżynier oprogramowania AI firmy Cognition, działający w Twoim terminalu. Planuje i wykonuje wieloetapowe zadania samodzielnie i może przekazać sesję do odizolowanego agenta w chmurze — co czyni go realnym sposobem na dostarczanie pracy front-endowej, gdy podasz mu referencje, konwencje i pętlę weryfikacyjną. Open Design włącza go do open-source'owego workflow projektowego: Twoje konto Devin, Twoje pliki, local-first.",
        rich: {"heroCtaLead": "Open Design zamienia Devin for Terminal w lokalny, open-source'owy agent designu — Twoje konto Devin, Twoje pliki, wyselekcjonowana biblioteka Skills i systemów projektowych wokół tego.", "heroCtaActions": [{"label": "Użyj Devin w Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Gwiazdka na GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Pobierz aplikację desktopową", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["Devin for Terminal to autonomiczny inżynier oprogramowania AI firmy Cognition, przeniesiony do lokalnej linii poleceń. Dwie rzeczy czynią go szczególnie interesującym dla projektowania: jest naprawdę agentowy, więc planuje i wykonuje wieloetapowe zadanie od początku do końca, a nie tylko uzupełnia linijki kodu; i może przekazać sesję do odizolowanego agenta w chmurze z własnym komputerem, dzięki czemu dłuższe buildy działają dalej po zamknięciu laptopa. W parze z odpowiednimi referencjami, konwencjami i pętlą weryfikacyjną buduje prawdziwy, responsywny UI. To praktyczny, kompleksowy przewodnik po używaniu Devin for Terminal do pracy nad UI, frontendem i systemami projektowymi oraz po podłączeniu go do ustrukturyzowanego workflow projektowego z Open Design.", "Omawia, czym właściwie jest Devin for Terminal, dlaczego autonomiczny inżynier oprogramowania pasuje do pracy projektowej, jak skonfigurować go od zera, pętlę screenshot-to-UI, jak reguły projektu i zewnętrzne narzędzia go rozszerzają, jak wypada na tle Codex, Claude Code, Cursor i Gemini CLI, pułapki sprawiające, że wynik AI wygląda generycznie, oraz jak Open Design wypełnia tę lukę jako otwarta, local-first warstwa projektowa — naturalne połączenie dla każdego agenta, który potrafi planować i dostarczać pracę front-endową."], "heroImage": {"src": "/agents/devin-design/devin-design-hero.webp", "alt": "Pętla feedbacku projektowego Devin for Terminal: autonomiczny agent terminalowy odczytujący obraz referencyjny, przeglądarka renderująca UI oraz przestrzeń robocza, z pętlą sprzężenia zwrotnego", "caption": "Podstawowa pętla: Devin czyta Twoje referencje w terminalu, planuje i buduje interfejs, weryfikuje go w prawdziwej przeglądarce i iteruje w oparciu o nie — przekazując dłuższe uruchomienia do chmury, gdy zajdzie taka potrzeba."}, "tocLabel": "Na tej stronie", "toc": [{"id": "what-is-devin", "label": "Czym właściwie jest Devin for Terminal"}, {"id": "why-design", "label": "Dlaczego autonomiczny inżynier oprogramowania pasuje do projektowania"}, {"id": "setup", "label": "Skonfiguruj Devin do projektowania (od zera)"}, {"id": "screenshot-workflow", "label": "Proces tworzenia interfejsu ze zrzutu ekranu"}, {"id": "extend", "label": "Reguły projektu, narzędzia i przekazanie do chmury"}, {"id": "vs", "label": "Devin vs Codex vs Claude Code vs Cursor vs Gemini CLI"}, {"id": "pitfalls", "label": "Pułapki i wygląd „AI slop\"\n```"}, {"id": "open-design", "label": "Projektowanie z Devin w Open Design"}, {"id": "faq", "label": "FAQ"}], "sections": [{"id": "what-is-devin", "heading": "Czym właściwie jest Devin for Terminal", "blocks": [{"kind": "p", "text": "Devin for Terminal to wersja wiersza poleceń Devin, autonomicznego inżyniera oprogramowania AI firmy Cognition. Działa jako lokalny agent kodujący z dostępem do Twojego kodu, narzędzi i środowiska — czyta repozytorium, edytuje pliki, wykonuje polecenia powłoki oraz planuje i weryfikuje pracę na podstawie zadania w języku naturalnym, a nie tylko uzupełnia linijki. Cognition zbudował dedykowaną bibliotekę renderowania terminala w Rust, aby interfejs był szybki i responsywny."}, {"kind": "p", "text": "W pracy projektowej wyróżniają się dwie właściwości. Jest prawdziwie autonomiczny, więc możesz opisać wynik, a on wykona wieloetapową ścieżkę, aby tam dotrzeć. A gdy build przerośnie twój laptop, możesz przekazać sesję do agenta w chmurze, który działa we własnym środowisku sandbox i kontynuuje pracę asynchronicznie — więc możesz wrócić do ukończonego pull requesta."}, {"kind": "steps", "items": [{"label": "Autonomiczne, agentowe wykonanie", "body": "Devin planuje i wykonuje wieloetapowe zadanie samodzielnie — implementuje funkcję, buduje UI, uruchamia i testuje — kierując się jasnymi promptami z wyraźnymi kryteriami zakończenia."}, {"label": "Lokalny agent, przekazanie do chmury", "body": "Działa lokalnie w Twoim terminalu i może eskalować sesję do agenta w chmurze w sandboxie, który ma własny komputer i kontynuuje pracę po Twoim wyjściu."}, {"label": "Wybór modelu oparty na koncie", "body": "Logujesz się za pomocą konta Devin (Cognition); Devin działa na modelach frontier — możesz wybierać między opcjami takimi jak własny model Cognition SWE-1.6 i inne modele frontier."}]}, {"kind": "ul", "items": ["Dostawca: Cognition", "Dane uwierzytelniające: konto Devin (Cognition) — logowanie oparte na subskrypcji/koncie, bez możliwości własnego klucza", "Forma: lokalny agent terminalowy z opcjonalnym przekazaniem do sandbox w chmurze"]}]}, {"id": "why-design", "heading": "Dlaczego autonomiczny inżynier oprogramowania pasuje do projektowania", "blocks": [{"kind": "p", "text": "Przewaga projektowa Devin wynika z tego, jak działa — autonomiczne, end-to-end wykonanie — ale, jak w przypadku każdego agenta, gust nadal trzeba dostarczyć."}, {"kind": "steps", "items": [{"label": "Kompleksowe, wieloetapowe buildy", "body": "Ponieważ Devin planuje i wykonuje całe zadania, może wygenerować szkielet strony, połączyć komponenty, uruchomić serwer deweloperski i przetestować wynik za jednym razem, zamiast zatrzymywać się na snippecie."}, {"label": "Sandboxowane uruchomienia w chmurze", "body": "Dłuższa praca nad frontendem — pełna strona lądowania, przepływ wieloekranowy — może przekazać do piaskownicy agenta w chmurze i kontynuować budowanie, więc iteracja nie jest blokowana przez twojego laptopa."}, {"label": "Konwencje w regułach projektu", "body": "Skieruj agenta na swoje tokeny, komponenty i rzeczywiste specyfikacje poprzez reguły i dokumentację projektu, aby pracował zgodnie z marką zamiast domyślnym wyglądem."}]}, {"kind": "image", "src": "/agents/devin-design/devin-design-taste-triangle.webp", "alt": "Diagram pokazujący system projektowy, skill oraz obraz referencyjny zbiegające się w dobry wynik projektowy", "caption": "Smak pochodzi z trzech danych wejściowych, które dostarczasz: systemu projektowego, skill oraz prawdziwych obrazów referencyjnych."}, {"kind": "p", "text": "Lekcja jest taka sama, jakiej uczy każdy agent: Devin nie ma smaku z definicji. Tworzy dobry design, gdy nadasz mu ograniczenia — system projektowy, estetyczny skill i konkretne odniesienia. Open Design pakuje dokładnie te dane wejściowe, dlatego oba rozwiązania pasują do siebie (więcej poniżej)."}]}, {"id": "setup", "heading": "Skonfiguruj Devin do pracy projektowej, od zera", "blocks": [{"kind": "p", "text": "Oto pełna ścieżka od czystej maszyny do Devin for Terminal, który potrafi budować i weryfikować UI."}, {"kind": "code", "lang": "bash", "code": "# 1. Install Devin for Terminal\ncurl -fsSL https://cli.devin.ai/install.sh | bash\n\n# 2. Start it in your project and sign in on first run\ncd your-project\ndevin             # sign in with your Devin (Cognition) account\n\n# 3. Describe the task in natural language, with clear\n#    completion criteria, and let Devin plan and execute.\n\n# 4. When a build outgrows your laptop, hand the session\n#    off to a sandboxed cloud agent that keeps working."}, {"kind": "image", "src": "/agents/devin-design/devin-design-setup-flow.webp", "alt": "Pięciokrokowy przepływ konfiguracji: zainstaluj, zaloguj się, zakoduj reguły projektowe, dodaj odniesienia, zweryfikuj w przeglądarce", "caption": "Sekwencja konfiguracji: instalacja → logowanie → zakodowanie reguł projektowych → dostarczenie referencji → weryfikacja w prawdziwej przeglądarce."}, {"kind": "steps", "items": [{"label": "Zakoduj swoje zasady projektowe", "body": "Umieść swoje tokens, prymitywy i konwencje tam, gdzie agent je odczytuje — w zasadach i dokumentacji projektu — aby wynik pasował do marki, zamiast domyślnie przybrać ogólny wygląd."}, {"label": "Dodaj weryfikację przeglądarki", "body": "Niech Devin renderuje w prawdziwej przeglądarce i sprawdza swój wynik na punktach przerwania, żeby weryfikować względem projektu, zamiast tylko potwierdzać, że build przeszedł."}]}]}, {"id": "screenshot-workflow", "heading": "Proces tworzenia interfejsu ze zrzutu ekranu", "blocks": [{"kind": "p", "text": "Najbardziej efektywna pętla projektowa z Devin polega na przekształceniu obrazu referencyjnego w działający, responsywny UI i iterowaniu, aż będzie pasował — pozwalając autonomicznemu agentowi budować, uruchamiać i porównywać wynik z odniesieniem."}, {"kind": "ol", "items": ["Zacznij od najjaśniejszych referencji wizualnych, jakie masz — i uwzględnij wiele stanów (desktop i mobile, hover, empty, loading), nie tylko jeden hero shot.", "Bądź precyzyjny w prompcie i podaj wyraźne kryteria zakończenia; niejasne prompty generują ogólnikowy UI nawet z silnym agentem.", "Przechowuj swój system projektowy i konwencje w regułach projektu i wskaż Devin, gdzie znajdują się tokens i kanoniczne prymitywy.", "Uruchom serwer deweloperski i pozwól Devin wyrenderować w prawdziwej przeglądarce, zmieniając rozmiar do breakpointów, by sprawdzić rezultat.", "Iteruj, zlecając Devin porównanie swojej implementacji z odniesieniami — a nie tylko potwierdzenie, że buduje się — i przekaż do chmury na dłuższe podejścia."]}, {"kind": "p", "text": "Przekaż Devin referencje i konkretne ograniczenia, z jasną definicją ukończenia:"}, {"kind": "code", "lang": "bash", "code": "devin\n# in the prompt:\n> Implement the attached reference (desktop + mobile) in\n  React + Vite + Tailwind + TypeScript.\n  Reuse my existing design-system components and tokens.\n  Match spacing, layout, and hierarchy; make it responsive.\n  Render it in the browser and iterate until it matches the\n  references across breakpoints. Done = pixel-close on both\n  desktop and mobile with no console errors."}, {"kind": "p", "text": "Utrzymuj komunikaty zwięzłe, commituj dobre iteracje i revertuj złe (informując Devin o revercie), by każde podejście budowało na czystej bazie."}]}, {"id": "extend", "heading": "Reguły projektu, narzędzia i przekazanie do chmury", "blocks": [{"kind": "p", "text": "Trzy punkty rozszerzenia sprawiają, że Devin for Terminal jest praktyczny w trwałej pracy projektowej, i wszystkie trzy czytelnie mapują się na otwarty przepływ pracy projektowej."}, {"kind": "steps", "items": [{"label": "Reguły projektu i kontekst", "body": "Trzymaj swoje konwencje projektowe, tokens i checklisty przeglądowe w zasadach i dokumentacji projektu, aby agent czytał je przy każdym uruchomieniu i działał zgodnie z twoją marką."}, {"label": "Baza kodu, narzędzia i środowisko", "body": "Devin działa jako lokalny agent z dostępem do Twojego kodu, narzędzi i środowiska — może uruchomić serwer deweloperski, wykonać build i zweryfikować wynik, nie opuszczając terminala."}, {"label": "Sandboxowane przekazanie do chmury", "body": "Przekaż sesję do agenta w chmurze w jego własnym piaskownicy, aby wykonać dłuższe buildy, testy i tworzenie PR asynchronicznie, a potem wróć do gotowego pull requesta."}]}, {"kind": "p", "text": "To dokładnie ten rodzaj przenośnych, agent-shaped możliwości, które Open Design zostało stworzone, aby orkiestrować, zamiast odtwarzać je w każdym projekcie."}]}, {"id": "vs", "heading": "Devin vs Codex vs Claude Code vs Cursor vs Gemini CLI do projektowania", "blocks": [{"kind": "p", "text": "Nie ma jednego zwycięzcy w pracy projektowej — każdy agent ma inną mocną stronę, a doświadczone zespoły je łączą. Uczciwe podsumowanie:"}, {"kind": "table", "columns": ["Agent", "Siła projektowa", "Najlepsze do"], "rows": [["Devin", "W pełni autonomiczny inżynier oprogramowania; planuje i wykonuje wieloetapowe buildy, przekazując sterowanie do izolowanego agenta w chmurze", "Delegowanie buildów end-to-end front-endu, które działają dalej po tym, jak się oddalasz"], ["Codex", "Silne wykończenie wizualne z frontendem skill; izolowane asynchroniczne buildy", "Delegowane asynchroniczne buildy i przenośne reguły AGENTS.md"], ["Claude Code", "Konkretne decyzje projektowe (hex, spacing, type) i UX świadomy bazy kodu", "Rozumowanie frontend i refaktoring dużych kontekstów"], ["Cursor", "Wizualna pętla budowania i podglądu z podglądem na żywo i edycją inline", "Zwarta praca iteracyjna nad UI z podglądem wewnątrz IDE"], ["Gemini CLI", "Silne wielomodalne rozumienie obrazu i kontekst 1M tokens; open-source z darmowym tierem", "Praca z dużą liczbą zrzutów ekranu i utrzymywanie całego systemu designu w kontekście"]]}, {"kind": "p", "text": "Powtarzający się werdykt społeczności jest taki, że gust pochodzi od ludzi: wszyscy bez wyjątku domyślnie stosują generyczną estetykę bez skills, referencji i ograniczeń. To jest prawdziwy problem do rozwiązania — i ma kształt narzędzia projektowego, a nie modelu."}]}, {"id": "pitfalls", "heading": "Pułapki i jak uniknąć wrażenia „AI slop\"", "blocks": [{"kind": "p", "text": "Najczęstszą skargą dotyczącą projektów generowanych przez AI jest to, że wyglądają generycznie — miękkie gradienty, unoszące się panele, powiększone zaokrąglone rogi, dramatyczne cienie, atmosfera Inter-i-fioletu, która „krzyczy, że zrobiło to AI\". Inne zgłaszane problemy obejmują zepsute layouty mobilne i instrukcje wyciekające do kopii UI. Żadne z tych problemów nie są unikalne dla Devin; to właśnie się dzieje, gdy jakikolwiek agent działa bez wyselekcjonowanego kontekstu projektowego."}, {"kind": "steps", "items": [{"label": "Dodaj skill estetyczny", "body": "Wyselekcjonowany skill projektowy zmusza agenta do przyjęcia konkretnego kierunku zamiast domyślnego wyglądu."}, {"label": "Zweryfikuj w prawdziwej przeglądarce", "body": "Niech Devin renderuje i sprawdza się na punktach przerwania, by układy nie psuły się po cichu na mobile."}, {"label": "Dostarczaj tokeny i odniesienia", "body": "Prawdziwe design tokens i referencyjne screenshoty to najważniejsza dźwignia jakości wyników."}, {"label": "Zakoduj zasady w kontekście projektu", "body": "Umieść reguły stylu takie jak „brak kart bohaterów, maksymalnie dwa kroje pisma, hierarchia najpierw marka\" tam, gdzie agent je odczyta przy każdym uruchomieniu, z jawnymi kryteriami ukończenia."}]}, {"kind": "p", "text": "Zauważ, że każde rozwiązanie polega na dostarczeniu agentowi wyselekcjonowanego kontekstu projektowego. Ręczne utrzymywanie tego kontekstu dla każdego projektu to właśnie trud, którego Open Design Cię zwalnia."}]}, {"id": "open-design", "heading": "Projektowanie z Devin wewnątrz Open Design", "blocks": [{"kind": "p", "text": "Open Design to warstwa projektowa open-source, o którą prosi powyższy workflow. Traktuje Devin for Terminal jako adapter first-party i otacza go wyselekcjonowaną biblioteką skill i systemów projektowych, ustrukturyzowanym potokiem renderowania oraz lokalnym interfejsem desktopowym — dzięki czemu kontekst projektowy, który czyni Devin dobrym, jest dostępny od pierwszego uruchomienia, a nie składany ręcznie za każdym razem. Open Design jest open-source i local-first, co czyni to połączenie naturalnym wyborem dla agenta, którego już uruchamiasz w swoim terminalu."}, {"kind": "ol", "items": ["Zainstaluj Open Design i wybierz Devin for Terminal jako swojego agenta.", "Uwierzytelnij się swoim kontem Devin (Cognition) — poświadczenia są używane bezpośrednio przez twojego agenta i nigdy nie są proxowane przez nas.", "Wybierz system projektowy i skill, a następnie generuj prezentacje, prototypy i strony docelowe ze spójnym gustem.", "Każdy artefakt i plik DESIGN.md znajduje się w Twoim własnym repozytorium, a nie w hostowanej chmurze."]}, {"kind": "p", "text": "Ten sam agent Devin, to samo konto — plus prawdziwy, przenośny, otwartoźródłowy proces projektowy wokół niego. Open Design jest local-first i na licencji Apache-2.0, więc nic z Twojej pracy ani Twoich danych uwierzytelniających nie opuszcza Twojej maszyny przez nas."}]}], "faqTitle": "Często zadawane pytania", "faq": [{"name": "Czy Devin for Terminal naprawdę potrafi wykonywać pracę projektową?", "text": "Tak — z umiejętnością estetyczną (aesthetic skill), systemem projektowym i rzeczywistymi obrazami referencyjnymi w kontekście, Devin produkuje responsywny UI o jakości produkcyjnej, a jako autonomiczny agent może zbudować, uruchomić i zweryfikować wynik względem Twoich referencji. Bez tego kontekstu ma tendencję do domyślnego generycznego wyglądu, co jest luką, którą wypełnia Open Design."}, {"name": "Jak zalogować się do Devin?", "text": "Devin jest oparty na koncie: logujesz się kontem Devin (Cognition), a nie przynosisz własny klucz modelu. Zainstaluj Devin for Terminal, uruchom go w swoim projekcie i uwierzytelnij się przy pierwszym uruchomieniu. Open Design nigdy nie pośredniczy w Twoich uwierzytelnieniach — agent używa ich bezpośrednio."}, {"name": "Co sprawia, że Devin jest dobry specyficznie do projektowania?", "text": "Jest w pełni autonomicznym inżynierem oprogramowania: planuje i wykonuje wieloetapowe buildy front-endowe od początku do końca i może przekazać sesję do agenta w chmurze w sandboxie, który kontynuuje pracę po Twoim wyjściu. Gust nadal pochodzi z systemu projektowego, skill i referencji, które dostarczasz."}, {"name": "Devin czy Claude Code do projektowania frontendu?", "text": "Oba są mocne. Claude Code jest znany ze specyficznych, świadomych kontekstu kodu decyzji projektowych; przewagą Devin jest w pełni autonomiczna, kompleksowa realizacja z przekazaniem do izolowanej chmury. Wiele zespołów używa obu — Open Design pozwala przełączać agentów bez zmiany przepływu pracy projektowej."}, {"name": "Czy Devin działa w sandboxie?", "text": "Devin for Terminal działa lokalnie z dostępem do Twojego kodu i środowiska, i może przekazać sesję do agenta w chmurze, który działa we własnym odizolowanym środowisku — przydatne przy dłuższych buildach, testach i tworzeniu PR-ów, które kontynuują się asynchronicznie."}, {"name": "Czy Open Design jest powiązany z Cognition?", "text": "Nie. Devin for Terminal to produkt Cognition; Open Design to niezależny projekt open-source, który wspiera go jako adapter first-party. Devin jest znakiem towarowym Cognition."}, {"name": "Czy moje pliki i poświadczenia są bezpieczne?", "text": "Tak — Open Design jest local-first i Apache-2.0. Twoje pliki, artefakty i DESIGN.md pozostają we własnym repozytorium, a Twoje dane uwierzytelniające Devin są używane bezpośrednio przez Twojego agenta, nigdy nie są kierowane przez serwery Open Design."}], "ctaTitle": "Projektuj z Devin, w sposób otwarty.", "ctaBody": "Zaloguj się swoim kontem Devin, zachowaj wszystkie pliki lokalnie i uzyskaj dostęp do starannie wyselekcjonowanej biblioteki projektowej wokół autonomicznego agenta, którego już używasz.", "ctaActions": [{"label": "Użyj Devin w Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Gwiazdka na GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Pobierz aplikację desktopową", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Zobacz wszystkich wspieranych agentów"},
      },
      'pi': {
        ...en['pi']!,
        title: "Pi dla designu — Open Design",
        description: "Jak ludzie używają Pi, open-source'owego wielodostawcowego agenta kodującego w terminalu, do projektowania UI i stron internetowych — jego routing dowolnego modelu, klucze dostawców BYOK, Skills i rozszerzenia — oraz jak Open Design przekształca Pi w local-first, open-source'owego agenta projektowego.",
        breadcrumb: "Pi",
        label: "Agent · Pi",
        heading: "Pi dla designu.",
        lead: "Pi to agent kodujący w terminalu o otwartym kodzie źródłowym, który kieruje zapytania do dowolnego modelu — Anthropic, OpenAI, Google i ponad 20 dostawców — na Twoich własnych kluczach API. Ta niezależność od dostawcy czyni go elastycznym narzędziem projektowym: wybierz model, który dziś najlepiej odczytuje zrzuty ekranu, jutro zmień, a workflow pozostaje takie samo. Open Design integruje go w workflow projektowy o otwartym kodzie źródłowym: Twoje klucze dostawcy, Twoje pliki, local-first.",
        rich: {"heroCtaLead": "Open Design zamienia Pi w lokalny, open-source'owy agent designu — Twoje własne klucze API dostawców, Twoje pliki, wyselekcjonowana biblioteka Skills i systemów projektowych wokół tego.", "heroCtaActions": [{"label": "Użyj Pi w Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Gwiazdka na GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Pobierz aplikację desktopową", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["Pi to agent kodujący AI o otwartym kodzie źródłowym (MIT) działający w terminalu. To, co czyni go szczególnie interesującym dla projektowania, to niezależność od dostawcy: normalizuje dostęp do Anthropic, OpenAI, Google i ponad 20 innych dostawców za jednym interfejsem, więc uwierzytelniasz się własnymi kluczami API (BYOK) i wybierasz model odpowiedni do zadania — możesz też zmienić model w trakcie sesji bez potrzeby ponownej nauki narzędzia. W parze z odpowiednimi referencjami, konwencjami i pętlą weryfikacji buduje rzeczywiste, responsywne interfejsy. To praktyczny przewodnik end-to-end dotyczący używania Pi do pracy nad UI, frontendem i systemami projektowymi oraz podłączania go do ustrukturyzowanego workflow projektowego z Open Design.", "Omawia, czym właściwie jest Pi, dlaczego wieloproviderowy agent BYOK pasuje do projektowania, jak skonfigurować go od zera, pętlę screenshot-to-UI, jak Skills i Extensions go rozszerzają, jak wypada na tle Codex, Claude Code, Cursor i Gemini CLI, pułapki sprawiające, że wynik AI wygląda generycznie, oraz jak Open Design wypełnia tę lukę jako otwarta, local-first warstwa projektowa — naturalne połączenie, ponieważ oba są open-source i działają na Twoim własnym komputerze."], "heroImage": {"src": "/agents/pi-design/pi-design-hero.webp", "alt": "Pętla feedbacku designu Pi: agent terminalowy czytający obraz referencyjny, przeglądarka renderująca UI i workspace, ze strzałką feedbacku zapętlającą się z powrotem", "caption": "Podstawowa pętla: Pi czyta Twoje referencje w terminalu, buduje i weryfikuje interfejs w prawdziwej przeglądarce i iteruje w oparciu o nie — u dowolnego dostawcy, na którego go wskażesz."}, "tocLabel": "Na tej stronie", "toc": [{"id": "what-is-pi", "label": "Czym właściwie jest Pi"}, {"id": "why-design", "label": "Dlaczego agent multi-provider BYOK pasuje do projektowania"}, {"id": "setup", "label": "Skonfiguruj Pi do projektowania (od zera)"}, {"id": "screenshot-workflow", "label": "Proces tworzenia interfejsu ze zrzutu ekranu"}, {"id": "extend", "label": "Skills, rozszerzenia i motywy"}, {"id": "vs", "label": "Pi vs Codex vs Claude Code vs Cursor vs Gemini CLI"}, {"id": "pitfalls", "label": "Pułapki i wygląd „AI slop\"\n```"}, {"id": "open-design", "label": "Projektowanie z Pi w Open Design"}, {"id": "faq", "label": "FAQ"}], "sections": [{"id": "what-is-pi", "heading": "Czym właściwie jest Pi", "blocks": [{"kind": "p", "text": "Pi to agent kodujący AI o otwartym kodzie źródłowym (MIT) działający w terminalu, część zestawu narzędzi earendil-works pi. Odczytuje repozytorium, edytuje pliki i wykonuje polecenia powłoki — planując i weryfikując pracę na podstawie zadań sformułowanych w języku naturalnym, zamiast jedynie uzupełniać linie kodu. Jego rdzeń jest celowo niewielki: cztery domyślne narzędzia — read, write, edit i bash — oraz wbudowane grep, find i ls."}, {"kind": "p", "text": "W pracy projektowej wyróżniającą się właściwością jest to, że Pi jest niezależny od dostawcy. Normalizuje dostęp do Anthropic, OpenAI, Google i wielu innych dostawców za jednym zunifikowanym API, więc przynosisz własne klucze i wybierasz model do każdego zadania — na przykład mocny model multimodalny do odczytu referencyjnych screenshotów — i przełączasz przez /model lub Ctrl+L w trakcie sesji bez zmiany swojego przepływu pracy."}, {"kind": "steps", "items": [{"label": "Dowolny model, twoje klucze", "body": "Pi kieruje zapytania do ponad 20 dostawców, w tym Anthropic i OpenAI. Uwierzytelniasz się własnymi kluczami API (BYOK) lub logujesz przez /login do subskrypcji Claude Pro/Max, ChatGPT Plus/Pro lub GitHub Copilot."}, {"label": "Skills + rozszerzenia", "body": "Pi ładuje Skills (pakiety zdolności w Markdown zgodne ze standardem Agent Skills) oraz rozszerzenia TypeScript — naturalne miejsce do kodowania konwencji projektowych i dodawania własnych narzędzi."}, {"label": "Rozgałęzione sesje", "body": "Sesje są zapisywane jako drzewa JSONL, więc możesz rozgałęziać eksplorację i nawigować po historii w pojedynczym pliku bez utraty wcześniejszych przebiegów."}]}, {"kind": "ul", "items": ["Vendor: earendil-works (projekt społeczności open-source)", "Dane uwierzytelniające: własny klucz API dostawcy (BYOK — Anthropic, OpenAI, Google itp.) lub logowanie przez subskrypcję za pomocą /login; przechowywane lokalnie w ~/.pi/agent/auth.json (0600)", "Licencja: MIT, open source"]}]}, {"id": "why-design", "heading": "Dlaczego agent wielodostępowy BYOK pasuje do projektowania", "blocks": [{"kind": "p", "text": "Przewaga Pi w zakresie designu to elastyczność, nie pojedynczy wbudowany model — ale, jak w przypadku każdego agenta, gust wciąż musi być dostarczony."}, {"kind": "steps", "items": [{"label": "Wybierz odpowiedni model do zadania", "body": "Ponieważ Pi kieruje do dowolnego dostawcy, możesz sięgnąć po mocny model multimodalny do odczytu referencyjnych zrzutów ekranu, a potem przełączyć na inny do refaktoryzacji — bez opuszczania agenta."}, {"label": "Twoje klucze, brak przywiązania", "body": "BYOK oznacza, że nie jesteś przywiązany do cennika ani limitów kontekstu jednego dostawcy; wybierz model, którego mocne strony pasują do bieżącego zadania projektowego."}, {"label": "Konwencje w Skills", "body": "Skill (wraz ze źródłem MCP, takim jak serwer Figma) wskazuje agentowi twoje tokeny, komponenty i rzeczywiste specyfikacje, dzięki czemu pracuje zgodnie z marką zamiast domyślnego wyglądu."}]}, {"kind": "image", "src": "/agents/pi-design/pi-design-taste-triangle.webp", "alt": "Diagram pokazujący system projektowy, skill oraz obraz referencyjny zbiegające się w dobry wynik projektowy", "caption": "Smak pochodzi z trzech danych wejściowych, które dostarczasz: systemu projektowego, skill oraz prawdziwych obrazów referencyjnych."}, {"kind": "p", "text": "Lekcja jest taka sama, jakiej uczy każdy agent: Pi nie ma smaku z definicji, a żaden wybór modelu go nie zapewni. Tworzy dobry design, gdy nadasz mu ograniczenia — system projektowy, estetyczny skill i konkretne odniesienia. Open Design pakuje dokładnie te dane wejściowe, dlatego oba rozwiązania pasują do siebie (więcej poniżej)."}]}, {"id": "setup", "heading": "Skonfiguruj Pi do pracy projektowej, od zera", "blocks": [{"kind": "p", "text": "Oto pełna ścieżka od czystej maszyny do Pi, które potrafi budować i weryfikować UI."}, {"kind": "code", "lang": "bash", "code": "# 1. Install the Pi coding agent CLI (Node)\nnpm install -g --ignore-scripts @earendil-works/pi-coding-agent\n\n# 2. Authenticate with your own provider key (BYOK)\nexport ANTHROPIC_API_KEY=sk-ant-...   # or OPENAI_API_KEY=sk-...\n#    (or run /login inside Pi for a Claude / ChatGPT / Copilot subscription)\n\n# 3. Start it in your project\ncd your-project\npi\n\n# 4. Switch models any time with /model or Ctrl+L"}, {"kind": "image", "src": "/agents/pi-design/pi-design-setup-flow.webp", "alt": "Pięciokrokowy przepływ konfiguracji: zainstaluj, uwierzytelnij się, zakoduj reguły projektowe, dodaj skill, zweryfikuj", "caption": "Sekwencja konfiguracji: instalacja → uwierzytelnienie (BYOK) → zakodowanie reguł projektowych w Skill → wybór modelu → włączenie weryfikacji w przeglądarce."}, {"kind": "steps", "items": [{"label": "Zakoduj swoje zasady projektowe", "body": "Umieść swoje tokens, prymitywy i konwencje w Skill i skieruj Pi na nie, aby output pasował do marki zamiast domyślnie wyglądać ogólnie."}, {"label": "Dodaj weryfikację przeglądarki", "body": "Podłącz Playwright lub MCP przeglądarki, aby Pi renderował w prawdziwej przeglądarce i sprawdzał wynik na różnych breakpointach zamiast tylko potwierdzać, że build przechodzi."}]}]}, {"id": "screenshot-workflow", "heading": "Proces tworzenia interfejsu ze zrzutu ekranu", "blocks": [{"kind": "p", "text": "Najbardziej efektywna pętla projektowania z Pi polega na przekształceniu obrazu referencyjnego w działający, responsywny interfejs użytkownika i iterowaniu, aż będzie pasował — opierając się na multimodalnym modelu do porównywania wyniku z referencją. Ponieważ Pi jest niezależny od dostawcy, wskaż ten model, który najlepiej odczytuje obrazy w danym przypadku."}, {"kind": "ol", "items": ["Zacznij od najjaśniejszych referencji wizualnych, jakie masz — i uwzględnij wiele stanów (desktop i mobile, hover, empty, loading), nie tylko jeden hero shot.", "Wybierz mocny model multimodalny do przebiegu za pomocą /model, ponieważ rozumienie obrazu decyduje o jakości przekształcania zrzutów ekranu w interfejs.", "Bądź precyzyjny w prompcie; niejasne prompty generują ogólnikowy UI nawet z mocnym modelem.", "Przechowuj swój system projektowy i konwencje w Skill i wskaż Pi, gdzie znajdują się tokens i kanoniczne prymitywy.", "Uruchom serwer deweloperski i pozwól Pi renderować w prawdziwej przeglądarce, zmieniając rozmiar do breakpointów, a następnie iteruj, porównując jego implementację ze zrzutami ekranu — nie tylko potwierdzaj, że się buduje."]}, {"kind": "p", "text": "Przekaż agentowi referencje i konkretne ograniczenia z góry:"}, {"kind": "code", "lang": "bash", "code": "pi\n# in the prompt:\n> Implement reference-desktop.png and reference-mobile.png in\n  React + Vite + Tailwind + TypeScript.\n  Reuse my existing design-system components and tokens (see the Skill).\n  Match spacing, layout, and hierarchy; make it responsive.\n  Render it in the browser and iterate until it matches the references\n  across breakpoints."}, {"kind": "p", "text": "Utrzymuj komunikaty małe i zwięzłe, commituj dobre iteracje i revertuj złe (informując Pi o revercie), by każde podejście budowało na czystej bazie. Rozgałęzione sesje JSONL w Pi pozwalają też eksplorować alternatywę bez utraty oryginalnego wątku."}]}, {"id": "extend", "heading": "Skills, rozszerzenia i motywy", "blocks": [{"kind": "p", "text": "Pi rozszerza się samodzielnie w czasie wykonania przez kilka warstw, które klarownie przekładają się na workflow open design."}, {"kind": "steps", "items": [{"label": "Skills", "body": "Pakiety możliwości w formacie Markdown zgodne ze standardem Agent Skills — trwały, przenośny dom dla Twoich konwencji projektowych, tokenów i list kontrolnych przeglądu. Ten sam Skill działa na kompatybilnych agentach, nie tylko Pi."}, {"label": "Rozszerzenia i szablony promptów", "body": "TypeScript Extensions dodają niestandardowe narzędzia, komendy i UI; szablony promptów wielokrotnego użytku uruchamia się przez /name. Obie pozwalają skryptować pętlę weryfikacji bez wychodzenia z terminala."}, {"label": "MCP i motywy", "body": "Pi łączy się z serwerami MCP, aby wprowadzić zewnętrzny kontekst designu (najbardziej istotny to serwer Figma MCP), a motywy ładują się na gorąco, więc interfejs terminala pozostaje czytelny podczas pracy."}]}, {"kind": "p", "text": "To przenośne możliwości — zwłaszcza Skills i MCP — dokładnie ten rodzaj rzeczy, które Open Design zostało stworzone, aby orkiestrować, zamiast odtwarzać je w każdym projekcie."}]}, {"id": "vs", "heading": "Pi vs Codex vs Claude Code vs Cursor vs Gemini CLI dla projektowania", "blocks": [{"kind": "p", "text": "Nie ma jednego zwycięzcy w pracy projektowej — każdy agent ma inną mocną stronę, a doświadczone zespoły je łączą. Uczciwe podsumowanie:"}, {"kind": "table", "columns": ["Agent", "Siła projektowa", "Najlepsze do"], "rows": [["Pi", "Niezależny od dostawcy i BYOK — kierowanie do dowolnego modelu (Anthropic, OpenAI, Google…) i zmiana w trakcie sesji; MIT, możliwość rozszerzania", "Wybór najlepszego modelu do każdego zadania bez uzależnienia od dostawcy"], ["Codex", "Silne wykończenie wizualne z frontendem skill; izolowane asynchroniczne buildy", "Delegowane asynchroniczne buildy i przenośne reguły AGENTS.md"], ["Claude Code", "Konkretne decyzje projektowe (hex, spacing, type) i UX świadomy bazy kodu", "Rozumowanie frontend i refaktoring dużych kontekstów"], ["Cursor", "Wizualna pętla budowania i podglądu z podglądem na żywo i edycją inline", "Zwarta praca iteracyjna nad UI z podglądem wewnątrz IDE"], ["Gemini CLI", "Silne wielomodalne rozumienie obrazu i kontekst 1M tokens; darmowy tier", "Praca z dużą liczbą zrzutów ekranu i utrzymywanie całego systemu designu w kontekście"]]}, {"kind": "p", "text": "Podejście Pi jest ortogonalne do pozostałych: to agent, który pozwala używać dowolnego z tych bazowych modeli na własnych kluczach. Powtarzający się werdykt społeczności wciąż obowiązuje — gust pochodzi od ludzi: wszystkie one domyślnie generują generyczną estetykę bez skills, odniesień i ograniczeń. To jest prawdziwy problem do rozwiązania i ma on kształt narzędzia projektowego, a nie modelu."}]}, {"id": "pitfalls", "heading": "Pułapki i jak uniknąć wrażenia „AI slop\"", "blocks": [{"kind": "p", "text": "Najczęstszą skargą na design generowany przez AI jest to, że wygląda generycznie — miękkie gradienty, unoszące się panele, przesadnie zaokrąglone rogi, dramatyczne cienie, klimat Inter-i-fioletu, który „krzyczy, że zrobiło to AI\". Inne zgłaszane problemy obejmują zepsute layouty mobilne i instrukcje przenikające do tekstów UI. Żadne z tych problemów nie są unikalne dla Pi ani dla żadnego konkretnego modelu; dzieje się tak, gdy jakikolwiek agent działa bez starannie przygotowanego kontekstu designu."}, {"kind": "steps", "items": [{"label": "Dodaj skill estetyczny", "body": "Wyselekcjonowany skill projektowy zmusza agenta do przyjęcia konkretnego kierunku zamiast domyślnego wyglądu — a ponieważ jest to przenośny Skill, podróżuje z tobą przez różne modele."}, {"label": "Zweryfikuj w prawdziwej przeglądarce", "body": "Wybierz model multimodalny, a Pi wyrenderuje i sprawdzi układy w różnych punktach przełamania, aby nie psuły się po cichu na urządzeniach mobilnych."}, {"label": "Dostarczaj tokeny i odniesienia", "body": "Prawdziwe design tokens i referencyjne screenshoty to najważniejsza dźwignia jakości wyników."}, {"label": "Zakoduj zasady tam, gdzie Pi je odczytuje", "body": "Umieść reguły stylu takie jak „bez kart bohaterów, maksymalnie dwa kroje pisma, hierarchia brand-first\" w Skill, który agent wczytuje przy każdym uruchomieniu."}]}, {"kind": "p", "text": "Zauważ, że każde rozwiązanie polega na dostarczeniu agentowi wyselekcjonowanego kontekstu projektowego — niezależnie od tego, do którego dostawcy kierujesz zapytania. Ręczne utrzymywanie tego kontekstu dla każdego projektu to właśnie trud, którego Open Design Cię zwalnia."}]}, {"id": "open-design", "heading": "Projektowanie z Pi wewnątrz Open Design", "blocks": [{"kind": "p", "text": "Open Design to warstwa projektowa open-source, o którą prosi powyższy workflow. Traktuje Pi jako adapter first-party i otacza go wyselekcjonowaną biblioteką skill i systemów projektowych, ustrukturyzowanym potokiem renderowania oraz lokalnym interfejsem desktopowym — dzięki czemu kontekst projektowy, który czyni Pi dobrym, jest dostępny od pierwszego uruchomienia, a nie składany ręcznie za każdym razem. Oba projekty są open-source i local-first, co czyni to połączenie naturalnym wyborem."}, {"kind": "ol", "items": ["Zainstaluj Open Design i wybierz Pi jako swojego agenta.", "Uwierzytelnij się własnym kluczem API dostawcy (BYOK) lub loginem subskrypcji — dane uwierzytelniające pozostają na Twoim komputerze w ~/.pi/agent/auth.json i nigdy nie są przekazywane przez nas.", "Wybierz system projektowy i skill, a następnie generuj prezentacje, prototypy i strony docelowe ze spójnym gustem.", "Każdy artefakt i plik DESIGN.md znajduje się w Twoim własnym repozytorium, a nie w hostowanej chmurze."]}, {"kind": "p", "text": "Ten sam agent Pi, te same klucze, ta sama swoboda przełączania modeli — plus prawdziwy, przenośny, open-source'owy workflow projektowy wokół niego. Jest local-first i na licencji MIT, więc nic dotyczącego Twojej pracy ani danych uwierzytelniających nie opuszcza Twojej maszyny."}]}], "faqTitle": "Często zadawane pytania", "faq": [{"name": "Czy Pi naprawdę potrafi wykonywać pracę projektową?", "text": "Tak — z umiejętnością estetyczną (aesthetic skill), systemem projektowym i rzeczywistymi obrazami referencyjnymi w kontekście, Pi produkuje responsywny UI o jakości produkcyjnej, a możesz go skierować do mocnego modelu multimodalnego, aby zweryfikować wynik względem referencji. Bez tego kontekstu ma tendencję do domyślnego generycznego wyglądu, co jest luką, którą wypełnia Open Design."}, {"name": "Czy muszę płacić za projektowanie z Pi?", "text": "Sam Pi jest darmowy i open source (MIT). Płacisz tylko za model bazowy — używaj własnego klucza API dostawcy (BYOK) lub loguj się przez /login do subskrypcji Claude Pro/Max, ChatGPT Plus/Pro lub GitHub Copilot. Open Design nigdy nie pośredniczy w Twoich poświadczeniach."}, {"name": "Co sprawia, że Pi jest dobry specyficznie do projektowania?", "text": "Jest niezależny od providera: przynosisz własne klucze i kierujesz do dowolnego z 20+ providerów, wybierając model, którego mocne strony pasują do zadania i zmieniając w trakcie sesji. Ale gust nadal pochodzi z systemu projektowego, skill i referencji, które dostarczasz, nie z modelu."}, {"name": "Którego modelu powinienem używać z Pi do projektowania frontend?", "text": "Pi kieruje zapytania do wielu dostawców, więc wybieraj zależnie od zadania — mocny model multimodalny dobrze odczytuje referencyjne zrzuty ekranu, podczas gdy inne mogą się sprawdzić przy refaktoryzacji. Przewaga Pi polega na tym, że możesz zmieniać model bez zmiany workflow. Open Design pozwala zachować ten sam kontekst projektowy niezależnie od wybranego modelu."}, {"name": "Jak podłączyć Pi do Figma?", "text": "Pi obsługuje serwery MCP, więc możesz dodać serwer Figma MCP i pobrać prawdziwy kontekst projektowy — komponenty, zmienne, dane układu — dzięki czemu wygenerowany kod odpowiada źródłu zamiast go przybliżać."}, {"name": "Czy Open Design jest powiązany z Pi?", "text": "Nie. Pi to niezależny projekt open-source autorstwa earendil-works; Open Design to oddzielny niezależny projekt open-source, który obsługuje Pi jako adapter first-party."}, {"name": "Czy moje pliki i poświadczenia są bezpieczne?", "text": "Tak — Open Design jest lokalny i open source. Twoje pliki, artefakty i DESIGN.md pozostają w Twoim własnym repo, a klucze dostawców są używane bezpośrednio przez Pi (przechowywane lokalnie w ~/.pi/agent/auth.json), nigdy nie są kierowane przez serwery Open Design."}], "ctaTitle": "Projektuj z Pi, w sposób otwarty.", "ctaBody": "Przynieś własne klucze dostawców, kieruj do dowolnego modelu, przechowuj każdy plik lokalnie i uzyskaj wyselekcjonowaną bibliotekę projektową wokół agenta, którego już używasz.", "ctaActions": [{"label": "Użyj Pi w Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Gwiazdka na GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Pobierz aplikację desktopową", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Zobacz wszystkich wspieranych agentów"},
      },
      'kiro': {
        ...en['kiro']!,
        title: "Kiro CLI dla designu — Open Design",
        description: "Jak ludzie używają Amazon Kiro CLI do projektowania UI i stron internetowych — jego rozwój oparty na specyfikacji, hooki agenta, pliki sterujące i MCP — oraz jak Open Design przekształca Kiro CLI w local-first, open-source'owego agenta projektowego.",
        breadcrumb: "Kiro CLI",
        label: "Agent · Kiro CLI",
        heading: "Kiro CLI dla designu.",
        lead: "Kiro CLI to terminalowy agent Amazon do developmentu opartego na specyfikacji — przekształca prompt w specyfikację wymagań, dokument designu i listę zadań, zanim napisze kod. Ta struktura to dokładnie to, czego potrzebuje praca nad designem: najpierw intencja, potem budowanie. Open Design łączy to z open-source'owym workflow designu: twój Builder ID lub logowanie, twoje pliki, local-first.",
        rich: {"heroCtaLead": "Open Design zamienia Kiro CLI w lokalny, open-source'owy agent designu — Twój AWS Builder ID lub logowanie, Twoje pliki, wyselekcjonowana biblioteka Skills i systemów projektowych wokół tego.", "heroCtaActions": [{"label": "Użyj Kiro CLI w Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Gwiazdka na GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Pobierz aplikację desktopową", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["Kiro CLI to terminalowy agent Amazon do developmentu opartego na specyfikacji. To, co czyni go wyjątkowym, to workflow: zamiast przeskakiwać od razu od promptu do kodu, Kiro formalizuje wymagania w specyfikację, tworzy dokument designu i sekwencyjną listę zadań, i dopiero wtedy implementuje — utrzymując proces budowania zgodnym z określoną intencją. Oferuje również haki agenta uruchamiane przy zdarzeniach takich jak zapis pliku, pliki sterujące zawierające twoje standardy i konwencje w każdym uruchomieniu, oraz wsparcie Model Context Protocol dla zewnętrznych narzędzi. Kiro jest w wersji preview, dostępny jako IDE, CLI i interfejs webowy, i możesz zacząć za darmo. To praktyczny, kompleksowy przewodnik po używaniu Kiro CLI do pracy nad UI, frontendem i systemami designu oraz do podłączenia go do ustrukturyzowanego workflow designu z Open Design.", "Omawia, czym właściwie jest Kiro CLI, dlaczego workflow oparty na specyfikacji pasuje do projektowania, jak skonfigurować go od zera, pętlę screenshot-to-UI, jak steering, hooki i MCP go rozszerzają, jak wypada na tle Codex, Claude Code, Cursor i Gemini CLI, pułapki sprawiające, że wynik AI wygląda generycznie, oraz jak Open Design wypełnia tę lukę jako otwarta, local-first warstwa projektowa wokół niego."], "heroImage": {"src": "/agents/kiro-design/kiro-design-hero.webp", "alt": "Pętla feedbacku designu Kiro CLI: agent terminalowy przekształcający specyfikację w design, przeglądarka renderująca UI i przestrzeń robocza, ze strzałką feedbacku zapętloną z powrotem", "caption": "Podstawowa pętla: Kiro CLI przekształca Twój zamiar w specyfikację i listę zadań w terminalu, buduje i weryfikuje interfejs w prawdziwej przeglądarce i iteruje w oparciu o Twoje referencje."}, "tocLabel": "Na tej stronie", "toc": [{"id": "what-is-kiro", "label": "Czym właściwie jest Kiro CLI"}, {"id": "why-design", "label": "Dlaczego rozwój oparty na specyfikacji pasuje do projektowania"}, {"id": "setup", "label": "Skonfiguruj Kiro CLI do projektowania (od zera)"}, {"id": "screenshot-workflow", "label": "Proces tworzenia interfejsu ze zrzutu ekranu"}, {"id": "extend", "label": "Specs, steering, hooks i MCP"}, {"id": "vs", "label": "Kiro vs Codex vs Claude Code vs Cursor vs Gemini CLI"}, {"id": "pitfalls", "label": "Pułapki i wygląd „AI slop\"\n```"}, {"id": "open-design", "label": "Projektowanie z Kiro CLI w Open Design"}, {"id": "faq", "label": "FAQ"}], "sections": [{"id": "what-is-kiro", "heading": "Czym właściwie jest Kiro CLI", "blocks": [{"kind": "p", "text": "Kiro to agentowa AI od Amazon dostępna jako IDE, interfejs wiersza poleceń i interfejs webowy, zbudowana, aby przeprowadzić cię od prototypu do produkcji z developmentem opartym na specyfikacji. Kiro CLI wprowadza tego agenta do twojego terminala: możesz rozpocząć interaktywną sesję czatu, tworzyć i zarządzać agentami oraz uruchamiać serwery Model Context Protocol — wszystko z wiersza poleceń. Kiro jest w wersji preview."}, {"kind": "p", "text": "W pracy projektowej decydującą właściwością jest przepływ pracy. Zamiast zamieniać prompt bezpośrednio w kod, Kiro najpierw pisze specyfikację — wymagania, dokument projektowy i uporządkowaną listę zadań — i implementuje zgodnie z nią. To sprawia, że plan agenta jest widoczny i możliwy do przeglądu zanim jakikolwiek interfejs zostanie zbudowany, co czysto mapuje się na to, jak powinny być podejmowane decyzje projektowe: najpierw intencja, potem wykonanie."}, {"kind": "steps", "items": [{"label": "Specs", "body": "Kiro przekształca prompt w ustrukturyzowaną specyfikację — wymagania, dokument designu i dyskretne zadania — zanim napisze kod, więc plan jest możliwy do sprawdzenia z góry."}, {"label": "Steering + hooki", "body": "Pliki Steering wprowadzają Twoje standardy, konwencje i preferowane narzędzia w każdym uruchomieniu; hooki agenta wyzwalają się na zdarzeniach, takich jak zapis pliku, aby automatycznie uruchamiać zadania w tle."}, {"label": "Darmowy start, gotowy na MCP", "body": "Zaloguj się za pomocą Builder ID, Google, GitHub lub swojej organizacji i zacznij za darmo; Kiro CLI zarządza również serwerami MCP, aby wprowadzić zewnętrzny kontekst."}]}, {"kind": "ul", "items": ["Dostawca: Amazon (AWS)", "Dane uwierzytelniające: AWS Builder ID, Google, GitHub lub AWS IAM Identity Center przez kiro-cli login (konto AWS nie jest wymagane)", "Status: W wersji preview; dostępny jako IDE, CLI i interfejs webowy"]}]}, {"id": "why-design", "heading": "Dlaczego rozwój oparty na specyfikacji pasuje do projektowania", "blocks": [{"kind": "p", "text": "Przewaga designowa Kiro CLI wynika z jego workflow — ale, jak w przypadku każdego agenta, gust wciąż trzeba dostarczyć."}, {"kind": "steps", "items": [{"label": "Intencja przed pikselami", "body": "Ponieważ Kiro najpierw pisze specyfikację i dokument projektowy, możesz skorygować układ, hierarchię i zakres na etapie planowania — zanim agent zaangażuje się w ogólnikową implementację."}, {"label": "Steering niesie Twoją markę", "body": "Pliki Steering utrzymują Twoje tokens, komponenty i konwencje na widoku agenta w każdym uruchomieniu, dzięki czemu wynik działa zgodnie z marką, a nie domyślnym wyglądem."}, {"label": "Hooki wymuszają pętlę", "body": "Agent hooks mogą automatycznie uruchamiać sprawdzenia przy zapisie — miejsce do podłączenia kroku weryfikacji lub przeglądu zamiast polegania na tym, że agent o tym pamięta."}]}, {"kind": "image", "src": "/agents/kiro-design/kiro-design-taste-triangle.webp", "alt": "Diagram pokazujący system projektowy, skill oraz obraz referencyjny zbiegające się w dobry wynik projektowy", "caption": "Smak pochodzi z trzech danych wejściowych, które dostarczasz: systemu projektowego, skill oraz prawdziwych obrazów referencyjnych."}, {"kind": "p", "text": "Lekcja jest taka sama, jakiej uczy każdy agent: Kiro CLI nie ma smaku z definicji. Specyfikacja utrzymuje budowę w ryzach, ale dobry design powstaje tylko wtedy, gdy nadasz mu ograniczenia — system projektowy, estetyczny skill i konkretne odniesienia. Open Design pakuje dokładnie te dane wejściowe, dlatego oba rozwiązania pasują do siebie (więcej poniżej)."}]}, {"id": "setup", "heading": "Skonfiguruj Kiro CLI do pracy projektowej, od zera", "blocks": [{"kind": "p", "text": "Oto pełna ścieżka od czystej maszyny do Kiro CLI, który potrafi budować i weryfikować UI."}, {"kind": "code", "lang": "bash", "code": "# 1. Install Kiro CLI (see kiro.dev/docs/cli for the macOS/Linux/Windows command)\n\n# 2. Authenticate — opens your browser to complete sign-in\nkiro-cli login   # choose Builder ID, Google, GitHub, or your organization\n\n# 3. Confirm you are signed in\nkiro-cli whoami\n\n# 4. Start an interactive session in your project\ncd your-project\nkiro-cli chat\n\n# 5. Wire MCP servers (optional, e.g. for design handoff)\nkiro-cli mcp add ..."}, {"kind": "image", "src": "/agents/kiro-design/kiro-design-setup-flow.webp", "alt": "Pięciokrokowy przepływ konfiguracji: zainstaluj, uwierzytelnij się, dodaj sterowanie, dodaj skill, zweryfikuj", "caption": "Sekwencja konfiguracji: instalacja → uwierzytelnienie → dodanie sterowania i specyfikacji projektowej → dodanie skill → włączenie weryfikacji w przeglądarce."}, {"kind": "steps", "items": [{"label": "Zakoduj swoje zasady projektowe", "body": "Umieść swoje tokeny, prymitywy i konwencje w plikach sterujących, aby agent czytał je przy każdym uruchomieniu, a wynik odpowiadał marce zamiast domyślnego, generycznego wyglądu."}, {"label": "Dodaj weryfikację przeglądarki", "body": "Podłącz serwer Playwright lub MCP przeglądarki, aby Kiro renderował w prawdziwej przeglądarce i sprawdzał wynik na różnych breakpointach zamiast tylko potwierdzać, że build przechodzi."}]}]}, {"id": "screenshot-workflow", "heading": "Proces tworzenia interfejsu ze zrzutu ekranu", "blocks": [{"kind": "p", "text": "Najbardziej efektywna pętla projektowania z Kiro CLI polega na przekształceniu obrazu referencyjnego w działający, responsywny interfejs użytkownika i iterowaniu, aż będzie pasował — pozwalając specyfikacji najpierw uchwycić intencję, a następnie budując według niej."}, {"kind": "ol", "items": ["Zacznij od najjaśniejszych referencji wizualnych, jakie masz — i uwzględnij wiele stanów (desktop i mobile, hover, empty, loading), nie tylko jeden hero shot.", "Pozwól Kiro napisać specyfikację i dokument designu z twojego promptu i sprawdź plan, zanim zacznie budować — to moment, w którym wcześnie wyłapujesz problemy z layoutem i zakresem.", "Przechowuj swój system projektowy i konwencje w plikach sterujących i wskaż Kiro, gdzie znajdują się tokens i kanoniczne prymitywy.", "Uruchom serwer deweloperski i pozwól Kiro renderować w prawdziwej przeglądarce, zmieniając rozmiar do breakpointów, aby sprawdzić wynik.", "Iteruj, zlecając Kiro porównanie swojej implementacji z odniesieniami — a nie tylko potwierdzenie, że buduje się."]}, {"kind": "p", "text": "Otwórz interaktywną sesję i podaj konkretne wymagania z góry, aby specyfikacja, którą napisze, odzwierciedlała Twoje rzeczywiste intencje:"}, {"kind": "code", "lang": "bash", "code": "kiro-cli chat\n# in the prompt:\n> Here are my references: reference-desktop.png and reference-mobile.png.\n  Write a spec, then implement this design in React + Vite + Tailwind + TypeScript.\n  Reuse my existing design-system components and tokens (see my steering files).\n  Match spacing, layout, and hierarchy; make it responsive.\n  Render it in the browser and iterate until it matches the references\n  across breakpoints."}, {"kind": "p", "text": "Utrzymuj zadania małe i zwięzłe, commituj dobre iteracje i revertuj złe (informując Kiro o revercie), by każde podejście budowało na czystej bazie."}]}, {"id": "extend", "heading": "Specs, steering, hooks i MCP", "blocks": [{"kind": "p", "text": "Cztery punkty rozszerzeń sprawiają, że Kiro CLI jest praktyczny do ciągłej pracy projektowej, a wszystkie cztery klarownie mapują się na otwarty przepływ projektowania."}, {"kind": "steps", "items": [{"label": "Specs", "body": "Wymagania, dokument projektowy oraz usekwencjonowana lista zadań — trwały zapis tego, czym ma być dana funkcjonalność, możliwy do przeglądu przed i w trakcie budowy."}, {"label": "Pliki Steering", "body": "Dodaj kontekst, standardy kodowania i preferowane przepływy pracy lub narzędzia, które agent odczytuje przy każdym uruchomieniu — naturalne miejsce na twoje konwencje projektowe i tokeny."}, {"label": "Agent hooks", "body": "Automatyzacje wyzwalane zdarzeniami takimi jak zapis pliku, uruchamiające zadania w tle jak sprawdzenia lub dokumentacja — miejsce na automatyczne egzekwowanie kroków weryfikacyjnych."}, {"label": "Serwery MCP", "body": "Kiro CLI zarządza serwerami Model Context Protocol, przenośnym sposobem wprowadzania zewnętrznego kontekstu designu i narzędzi, które działają we wszystkich agentach, nie tylko w Kiro."}]}, {"kind": "p", "text": "To przenośne możliwości multi-agent — dokładnie ten rodzaj rzeczy, które Open Design zostało stworzone, aby orkiestrować, zamiast odtwarzać je w każdym projekcie."}]}, {"id": "vs", "heading": "Kiro vs Codex vs Claude Code vs Cursor vs Gemini CLI dla designu", "blocks": [{"kind": "p", "text": "Nie ma jednego zwycięzcy w pracy projektowej — każdy agent ma inną mocną stronę, a doświadczone zespoły je łączą. Uczciwe podsumowanie:"}, {"kind": "table", "columns": ["Agent", "Siła projektowa", "Najlepsze do"], "rows": [["Kiro CLI", "Przepływ pracy oparty na specyfikacji — wymagania, dokument projektowy i lista zadań przed kodem; pliki sterujące i hooki utrzymują buildy zgodnie z marką", "Ustrukturyzowane, sprawdzalne buildy, w których intencja i zakres są zablokowane przed implementacją"], ["Codex", "Silne wykończenie wizualne z frontendem skill; izolowane asynchroniczne buildy", "Delegowane asynchroniczne buildy i przenośne reguły AGENTS.md"], ["Claude Code", "Konkretne decyzje projektowe (hex, spacing, type) i UX świadomy bazy kodu", "Rozumowanie frontend i refaktoring dużych kontekstów"], ["Cursor", "Wizualna pętla budowania i podglądu z podglądem na żywo i edycją inline", "Zwarta praca iteracyjna nad UI z podglądem wewnątrz IDE"], ["Gemini CLI", "Silne multimodalne rozumienie obrazu i bardzo duży kontekst; open-source z darmowym poziomem", "Praca z dużą liczbą zrzutów ekranu i utrzymywanie całego systemu designu w kontekście"]]}, {"kind": "p", "text": "Powtarzający się werdykt społeczności jest taki, że gust pochodzi od ludzi: wszyscy bez wyjątku domyślnie stosują generyczną estetykę bez skills, referencji i ograniczeń. To jest prawdziwy problem do rozwiązania — i ma kształt narzędzia projektowego, a nie modelu."}]}, {"id": "pitfalls", "heading": "Pułapki i jak uniknąć wrażenia „AI slop\"", "blocks": [{"kind": "p", "text": "Najczęstszą skargą na projektowanie generowane przez AI jest to, że wygląda generycznie — miękkie gradienty, unoszące się panele, zbyt duże zaokrąglone rogi, dramatyczne cienie, klimat Inter-i-fioletu, który „krzyczy, że zrobiło to AI\". Inne zgłaszane problemy obejmują zepsute układy mobilne i instrukcje przeciekające do tekstu interfejsu. Żadne z tych problemów nie są unikalne dla Kiro CLI; są tym, co się dzieje, gdy dowolny agent działa bez starannie dobranego kontekstu projektowego — specyfikacja utrzymuje budowę na właściwym torze, ale nie dostarcza gustu."}, {"kind": "steps", "items": [{"label": "Dodaj skill estetyczny", "body": "Wyselekcjonowany skill projektowy zmusza agenta do przyjęcia konkretnego kierunku zamiast domyślnego wyglądu."}, {"label": "Zweryfikuj w prawdziwej przeglądarce", "body": "Renderuj i sprawdzaj na różnych breakpointach — podepnij to jako hook, jeśli możesz — aby układy nie psuły się po cichu na urządzeniach mobilnych."}, {"label": "Dostarczaj tokeny i odniesienia", "body": "Prawdziwe design tokens i referencyjne screenshoty to najważniejsza dźwignia jakości wyników."}, {"label": "Zakoduj zasady w plikach sterujących", "body": "Umieść zasady stylu typu „żadnych kart bohaterów, maksymalnie dwa kroje pisma, hierarchia najpierw brand\" tam, gdzie agent odczytuje je przy każdym uruchomieniu."}]}, {"kind": "p", "text": "Zauważ, że każde rozwiązanie polega na dostarczeniu agentowi wyselekcjonowanego kontekstu projektowego. Ręczne utrzymywanie tego kontekstu dla każdego projektu to właśnie trud, którego Open Design Cię zwalnia."}]}, {"id": "open-design", "heading": "Projektowanie z Kiro CLI wewnątrz Open Design", "blocks": [{"kind": "p", "text": "Open Design to warstwa projektowa open-source, o którą prosi powyższy workflow. Traktuje Kiro CLI jako adapter first-party i otacza go wyselekcjonowaną biblioteką skill i systemów projektowych, ustrukturyzowanym potokiem renderowania oraz lokalnym interfejsem desktopowym — dzięki czemu kontekst projektowy, który czyni Kiro dobrym, jest dostępny od pierwszego uruchomienia, a nie składany ręcznie za każdym razem. Open Design jest local-first, co upraszcza to połączenie: Twoje pliki i logowanie pozostają na Twoim komputerze."}, {"kind": "ol", "items": ["Zainstaluj Open Design i wybierz Kiro CLI jako swojego agenta.", "Uwierzytelnij się swoim AWS Builder ID lub innym loginem — poświadczenia zostają na twojej maszynie i nigdy nie są proxowane przez nas.", "Wybierz system projektowy i skill, a następnie generuj prezentacje, prototypy i strony docelowe ze spójnym gustem.", "Każdy artefakt i plik DESIGN.md znajduje się w Twoim własnym repozytorium, a nie w hostowanej chmurze."]}, {"kind": "p", "text": "Ten sam agent CLI Kiro, to samo logowanie — plus prawdziwy, przenośny, open-source'owy workflow projektowy wokół niego. Open Design jest local-first i na licencji Apache-2.0, więc nic dotyczącego Twojej pracy ani danych uwierzytelniających nie opuszcza Twojej maszyny."}]}], "faqTitle": "Często zadawane pytania", "faq": [{"name": "Czy Kiro CLI naprawdę potrafi wykonywać pracę projektową?", "text": "Tak — z umiejętnością estetyczną (aesthetic skill), systemem projektowym i rzeczywistymi obrazami referencyjnymi w kontekście, Kiro CLI produkuje responsywny UI o jakości produkcyjnej, a jego workflow oparty na specyfikacji utrzymuje build zgodny z określonym zamiarem. Bez tego kontekstu ma tendencję do domyślnego generycznego wyglądu, co jest luką, którą wypełnia Open Design."}, {"name": "Czy potrzebuję konta AWS, żeby używać Kiro CLI?", "text": "Nie — Kiro pozwala zalogować się za pomocą AWS Builder ID, Google, GitHub lub Twojej organizacji (AWS IAM Identity Center) i nie potrzebujesz konta AWS, aby z niego korzystać. Kiro jest w wersji preview i bezpłatny na start. Open Design również nigdy nie pośredniczy w Twoich poświadczeniach w żaden sposób."}, {"name": "Co sprawia, że Kiro CLI jest dobry specyficznie do projektowania?", "text": "Jego workflow sterowany specyfikacją: Kiro pisze wymagania, dokument projektowy i listę zadań, zanim zacznie kodować, dzięki czemu poprawiasz layout i zakres przed commitem budowy. Pliki sterujące zawierają twoje konwencje, a hooki mogą wymuszać sprawdzenia — ale gust nadal pochodzi z design systemu, skill i odniesień, które dostarczasz."}, {"name": "Kiro CLI czy Claude Code do designu frontendowego?", "text": "Oba są mocne. Claude Code jest znany ze specyficznych, świadomych kontekstu kodu decyzji projektowych; przewagą Kiro CLI jest przepływ pracy oparty na specyfikacji, z możliwością przeglądu, sterowaniem i hakami. Wiele zespołów używa obu — Open Design pozwala przełączać agentów bez zmiany przepływu pracy projektowej."}, {"name": "Jak podłączyć Kiro CLI do zewnętrznych narzędzi projektowych?", "text": "Kiro CLI zarządza serwerami Model Context Protocol (MCP) — użyj kiro-cli mcp, aby je dodać. Serwer MCP może wprowadzić rzeczywisty kontekst designu i narzędzia do agenta, aby wygenerowany kod pasował do źródła zamiast go przybliżać."}, {"name": "Czy Open Design jest powiązany z Amazon lub AWS?", "text": "Nie. Kiro jest produktem Amazon (AWS); Open Design to niezależny projekt open-source, który obsługuje go jako adapter first-party. Kiro jest znakiem towarowym Amazon."}, {"name": "Czy moje pliki i poświadczenia są bezpieczne?", "text": "Tak — Open Design jest local-first i Apache-2.0. Twoje pliki, artefakty i DESIGN.md pozostają we własnym repozytorium, a Twoje logowanie Kiro jest używane bezpośrednio przez Twojego agenta, nigdy nie jest kierowane przez serwery Open Design."}], "ctaTitle": "Projektuj z Kiro CLI, w sposób otwarty.", "ctaBody": "Przynieś własny AWS Builder ID lub zaloguj się, przechowuj każdy plik lokalnie i uzyskaj wyselekcjonowaną bibliotekę projektową wokół agenta, którego już używasz.", "ctaActions": [{"label": "Użyj Kiro CLI w Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Gwiazdka na GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Pobierz aplikację desktopową", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Zobacz wszystkich wspieranych agentów"},
      },
      'kilo': {
        ...en['kilo']!,
        title: "Kilo Code do projektowania — Open Design",
        description: "Jak ludzie używają Kilo Code — open-source'owego, model-agnostycznego AI agenta kodującego — do projektowania UI i stron internetowych: jego tryby Architect/Code, wsparcie MCP, BYOK dla wielu dostawców, oraz jak Open Design przekształca Kilo w local-first, open-source'owego agenta projektowego.",
        breadcrumb: "Kilo",
        label: "Agent · Kilo",
        heading: "Kilo Code do projektowania.",
        lead: "Kilo Code to open-source'owy, agnostyczny modelowo agent kodujący AI dla twojego IDE i CLI. Ponieważ możesz skierować go na niemal dowolny model i przynieść własne klucze dostawcy, staje się prawdziwym narzędziem projektowym, gdy dostarczysz mu referencje, konwencje i pętlę weryfikacji. Open Design integruje go w open-source'owy workflow projektowy: twoje klucze dostawcy, twoje pliki, local-first.",
        rich: {"heroCtaLead": "Open Design zamienia Kilo Code w lokalny, open-source'owy agent designu — Twoje klucze dostawców, Twoje pliki, wyselekcjonowana biblioteka Skills i systemów projektowych wokół tego.", "heroCtaActions": [{"label": "Użyj Kilo Code w Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Gwiazdka na GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Pobierz aplikację desktopową", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["Kilo Code to open-source'owy agent kodujący AI, który działa w VS Code, IDE JetBrains oraz w terminalu. Dwie rzeczy czynią go szczególnie interesującym dla projektowania: jest agnostyczny modelowo, więc możesz nim sterować za pomocą dowolnego czołowego modelu zdolnego do widzenia, który najlepiej odczytuje zrzut ekranu; oraz działa na zasadzie BYOK u wielu dostawców, dzięki czemu zachowujesz kontrolę nad kosztami i poświadczeniami. W parze z odpowiednimi referencjami, konwencjami i pętlą weryfikacji buduje prawdziwy, responsywny interfejs. To praktyczny, kompleksowy przewodnik po używaniu Kilo Code do pracy z UI, frontendem i systemami projektowymi oraz po integrowaniu go w ustrukturyzowany workflow projektowy z Open Design.", "Omawia, czym właściwie jest Kilo Code, dlaczego model-agnostyczny, otwarty agent pasuje do projektowania, jak skonfigurować go od zera, pętlę screenshot-to-UI, jak niestandardowe reguły i MCP go rozszerzają, jak wypada na tle Codex, Claude Code, Cursor i Gemini CLI, pułapki sprawiające, że wynik AI wygląda generycznie, oraz jak Open Design wypełnia tę lukę jako otwarta, local-first warstwa projektowa — naturalne połączenie, ponieważ oba są open-source i działają na Twoim własnym komputerze."], "heroImage": {"src": "/agents/kilo-design/kilo-design-hero.webp", "alt": "Pętla feedbacku projektowego Kilo Code: agent w IDE i terminalu odczytujący obraz referencyjny, przeglądarka renderująca UI oraz workspace, z pętlą feedbacku zamykającą cykl", "caption": "Podstawowa pętla: Kilo Code czyta Twoje referencje w IDE lub CLI, buduje i weryfikuje interfejs w prawdziwej przeglądarce i iteruje w oparciu o nie — z modelem, który wybierzesz."}, "tocLabel": "Na tej stronie", "toc": [{"id": "what-is-kilo", "label": "Czym właściwie jest Kilo Code"}, {"id": "why-design", "label": "Dlaczego otwarty, niezależny od modelu agent pasuje do projektowania"}, {"id": "setup", "label": "Skonfiguruj Kilo Code do projektowania (od zera)"}, {"id": "screenshot-workflow", "label": "Proces tworzenia interfejsu ze zrzutu ekranu"}, {"id": "extend", "label": "Tryby, niestandardowe reguły i MCP"}, {"id": "vs", "label": "Kilo Code vs Codex vs Claude Code vs Cursor vs Gemini CLI"}, {"id": "pitfalls", "label": "Pułapki i wygląd „AI slop\"\n```"}, {"id": "open-design", "label": "Projektowanie z Kilo Code w Open Design"}, {"id": "faq", "label": "FAQ"}], "sections": [{"id": "what-is-kilo", "heading": "Czym właściwie jest Kilo Code", "blocks": [{"kind": "p", "text": "Kilo Code to open-source'owy agent kodujący AI zbudowany przez Kilo Code, Inc. Działa jako rozszerzenie VS Code, w IDE JetBrains oraz jako interfejs wiersza poleceń — czytając repozytorium, edytując pliki, wykonując polecenia oraz planując i weryfikując pracę na podstawie zadań w języku naturalnym, zamiast jedynie uzupełniać linie kodu. Jego cechą wyróżniającą jest agnostycyzm modelowy: to ty wybierasz, który model nim steruje, i przynosisz własne klucze dostawcy."}, {"kind": "p", "text": "W pracy projektowej wyróżniają się dwie właściwości. Ponieważ jest niezależny od modelu, możesz skierować go na najsilniejszy model z możliwościami wizyjnymi, który najlepiej odczytuje referencyjny screenshot i rozumuje o układzie. A ponieważ jest open-source i BYOK, możesz sprawdzić dokładnie jaki kontekst jest wysyłany i zachować poświadczenia i koszty pod własną kontrolą."}, {"kind": "steps", "items": [{"label": "Tryby agenta", "body": "Kilo oferuje wyspecjalizowane tryby — Architect do planowania, Code do budowania, Debug do naprawiania i Ask do pytań — plus tryby niestandardowe, dzięki czemu możesz zaplanować design, a następnie zaimplementować go w osobnych, skoncentrowanych podejściach."}, {"label": "Niestandardowe reguły + MCP", "body": "Czyta niestandardowe reguły na poziomie projektu dla trwałego kontekstu i wspiera serwery MCP (z marketplace MCP), więc możesz dodać zewnętrzny kontekst, taki jak plik Figma na żywo lub narzędzia projektowe."}, {"label": "Przynieś własne klucze", "body": "Kilo działa na zasadzie BYOK u wielu dostawców — Anthropic, OpenAI, Google, OpenRouter i innych — lub możesz skorzystać z własnego gateway Kilo, które udostępnia ponad 500 modeli po koszcie dostawcy."}]}, {"kind": "ul", "items": ["Dostawca: Kilo Code, Inc. (open source)", "Dane uwierzytelniające: własny klucz API dostawcy (BYOK — Anthropic, OpenAI, Google, OpenRouter i inne) lub własna bramka Kilo", "Licencja: open source"]}]}, {"id": "why-design", "heading": "Dlaczego otwarty, niezależny od modelu agent pasuje do projektowania", "blocks": [{"kind": "p", "text": "Przewaga projektowa Kilo Code wynika z otwartości i wyboru modelu — ale, jak w przypadku każdego agenta, gust wciąż musi być dostarczony."}, {"kind": "steps", "items": [{"label": "Niezależny od modelu z założenia", "body": "Ponieważ wybierasz model, możesz sterować Kilo dowolnym modelem wizyjnym, który najlepiej odczytuje referencyjne zrzuty ekranu — i zmienić go, gdy pojawi się lepszy, bez zmiany swojego przepływu pracy."}, {"label": "Otwarty i możliwy do inspekcji", "body": "Kilo jest open-source, więc możesz dokładnie zobaczyć, jaki kontekst i prompty są wysyłane — przydatne, gdy chcesz, aby agent ponownie wykorzystywał twoje rzeczywiste prymitywy projektowe, zamiast wymyślać jednorazowe style."}, {"label": "Konwencje w niestandardowych regułach", "body": "Niestandardowe reguły projektu (oraz serwer MCP dla Figma) kierują agenta na Twoje tokeny, komponenty i rzeczywiste specyfikacje, dzięki czemu pracuje zgodnie z marką zamiast domyślnego wyglądu."}]}, {"kind": "image", "src": "/agents/kilo-design/kilo-design-taste-triangle.webp", "alt": "Diagram pokazujący system projektowy, skill oraz obraz referencyjny zbiegające się w dobry wynik projektowy", "caption": "Smak pochodzi z trzech danych wejściowych, które dostarczasz: systemu projektowego, skill oraz prawdziwych obrazów referencyjnych."}, {"kind": "p", "text": "Lekcja jest taka sama, jakiej uczy każdy agent: Kilo Code nie ma smaku z definicji. Tworzy dobry design, gdy nadasz mu ograniczenia — system projektowy, estetyczny skill i konkretne odniesienia. Open Design pakuje dokładnie te dane wejściowe, dlatego oba rozwiązania pasują do siebie (więcej poniżej)."}]}, {"id": "setup", "heading": "Skonfiguruj Kilo Code do pracy projektowej, od zera", "blocks": [{"kind": "p", "text": "Oto pełna ścieżka od czystej maszyny do Kilo Code, który potrafi budować i weryfikować UI."}, {"kind": "code", "lang": "bash", "code": "# 1. Install the Kilo Code extension from the VS Code\n#    (or JetBrains) marketplace, or install the CLI.\n\n# 2. Open your project and sign in / add a provider key\ncd your-project\nkilo              # connect your provider (BYOK) or Kilo's gateway\n\n# 3. Add project context\n#    create custom rules for this project's design conventions\n\n# 4. Wire the Figma MCP server (optional, for design handoff)\n#    add it from the MCP marketplace / MCP settings"}, {"kind": "image", "src": "/agents/kilo-design/kilo-design-setup-flow.webp", "alt": "Pięciokrokowy przepływ konfiguracji: zainstaluj, uwierzytelnij się, dodaj niestandardowe reguły, dodaj skill, zweryfikuj", "caption": "Sekwencja konfiguracji: instalacja → połączenie z dostawcą → dodanie niestandardowych reguł → dodanie skill → włączenie weryfikacji w przeglądarce."}, {"kind": "steps", "items": [{"label": "Zakoduj swoje zasady projektowe", "body": "Umieść swoje design tokens, prymitywy i konwencje w niestandardowych regułach Kilo i skieruj agenta na nie, aby wynik odpowiadał marce zamiast domyślnie generycznego wyglądu."}, {"label": "Dodaj weryfikację przeglądarki", "body": "Podłącz Playwright lub MCP przeglądarki, aby Kilo renderował w prawdziwej przeglądarce i sprawdzał wynik na różnych breakpointach zamiast tylko potwierdzać, że build przechodzi."}]}]}, {"id": "screenshot-workflow", "heading": "Proces tworzenia interfejsu ze zrzutu ekranu", "blocks": [{"kind": "p", "text": "Najbardziej efektywna pętla projektowa z Kilo Code polega na przekształceniu obrazu referencyjnego w działający, responsywny UI i iterowaniu, aż będzie pasował — opierając się na modelu z obsługą wizji do porównywania wyniku z odniesieniem."}, {"kind": "ol", "items": ["Zacznij od najjaśniejszych referencji wizualnych, jakie masz — i uwzględnij wiele stanów (desktop i mobile, hover, empty, loading), nie tylko jeden hero shot.", "Bądź precyzyjny w prompcie; niejasne prompty generują ogólnikowy UI nawet z mocnym modelem.", "Trzymaj swój design system i konwencje w niestandardowych zasadach Kilo i powiedz agentowi, gdzie znajdują się tokens i kanoniczne prymitywy.", "Uruchom serwer deweloperski i pozwól Kilo renderować w prawdziwej przeglądarce, zmieniając rozmiar do breakpointów, aby sprawdzić wynik.", "Iteruj, zlecając Kilo porównanie swojej implementacji ze zrzutami ekranu — a nie tylko potwierdzenie, że buduje się."]}, {"kind": "p", "text": "Użyj trybu Architect, aby zaplanować budowę, a następnie przełącz się na tryb Code i dołącz swoje referencje z konkretnymi ograniczeniami:"}, {"kind": "code", "lang": "bash", "code": "# Plan in Architect mode, then build in Code mode:\n> Implement this design from @reference-desktop.png and\n  @reference-mobile.png in React + Vite + Tailwind + TypeScript.\n  Reuse my existing design-system components and tokens\n  from the custom rules.\n  Match spacing, layout, and hierarchy; make it responsive.\n  Render it in the browser and iterate until it matches the\n  references across breakpoints."}, {"kind": "p", "text": "Utrzymuj komunikaty małe i zwięzłe, commituj dobre iteracje i revertuj złe (informując Kilo o revercie), by każde podejście budowało na czystej bazie."}]}, {"id": "extend", "heading": "Tryby, niestandardowe reguły i MCP", "blocks": [{"kind": "p", "text": "Trzy punkty rozszerzenia sprawiają, że Kilo Code jest praktyczny w trwałej pracy projektowej, i wszystkie trzy czytelnie mapują się na otwarty przepływ pracy projektowej."}, {"kind": "steps", "items": [{"label": "Tryby (Architect → Code)", "body": "Zaplanuj strukturę ekranu w trybie Architect, następnie zaimplementuj ją w trybie Code i napraw problemy w trybie Debug — rozdzielając intencję projektową od implementacji. Niestandardowe tryby pozwalają zakodować własny proces przeglądu designu."}, {"label": "Niestandardowe reguły", "body": "Niestandardowe reguły projektu to trwałe miejsce dla Twoich konwencji projektowych — tokens, prymitywów i list kontrolnych przeglądu — odczytywane przy każdym uruchomieniu, dzięki czemu agent pracuje zgodnie z Twoją marką."}, {"label": "Serwery MCP", "body": "Kilo obsługuje serwery MCP przez swój marketplace — przenośny sposób na wprowadzenie kontekstu designu i zewnętrznych narzędzi, w tym najbardziej istotnego serwera Figma MCP, które działają we wszystkich agentach, nie tylko w Kilo."}]}, {"kind": "p", "text": "To przenośne możliwości multi-agent — dokładnie ten rodzaj rzeczy, które Open Design zostało stworzone, aby orkiestrować, zamiast odtwarzać je w każdym projekcie."}]}, {"id": "vs", "heading": "Kilo Code vs Codex vs Claude Code vs Cursor vs Gemini CLI do projektowania", "blocks": [{"kind": "p", "text": "Nie ma jednego zwycięzcy w pracy projektowej — każdy agent ma inną mocną stronę, a doświadczone zespoły je łączą. Uczciwe podsumowanie:"}, {"kind": "table", "columns": ["Agent", "Siła projektowa", "Najlepsze do"], "rows": [["Kilo Code", "Open-source i niezależny od modelu z BYOK dla wielu dostawców; tryby Architect/Code i MCP", "Wybór własnego modelu do każdego zadania przy zachowaniu kontroli nad kosztami i danymi uwierzytelniającymi"], ["Codex", "Silne wykończenie wizualne z frontendem skill; izolowane asynchroniczne buildy", "Delegowane asynchroniczne buildy i przenośne reguły AGENTS.md"], ["Claude Code", "Konkretne decyzje projektowe (hex, spacing, type) i UX świadomy bazy kodu", "Rozumowanie frontend i refaktoring dużych kontekstów"], ["Cursor", "Wizualna pętla budowania i podglądu z podglądem na żywo i edycją inline", "Zwarta praca iteracyjna nad UI z podglądem wewnątrz IDE"], ["Gemini CLI", "Silne wielomodalne rozumienie obrazu i kontekst 1M tokens", "Praca z dużą liczbą zrzutów ekranu i utrzymywanie całego systemu designu w kontekście"]]}, {"kind": "p", "text": "Powtarzający się werdykt społeczności jest taki, że gust pochodzi od ludzi: wszyscy bez wyjątku domyślnie stosują generyczną estetykę bez skills, referencji i ograniczeń. To jest prawdziwy problem do rozwiązania — i ma kształt narzędzia projektowego, a nie modelu."}]}, {"id": "pitfalls", "heading": "Pułapki i jak uniknąć wrażenia „AI slop\"", "blocks": [{"kind": "p", "text": "Najczęstszą skargą na projekty generowane przez AI jest to, że wyglądają generycznie — miękkie gradienty, unoszące się panele, przesadnie zaokrąglone rogi, dramatyczne cienie, atmosfera Inter-i-fioletu, która „krzyczy, że zrobiło to AI\". Inne zgłaszane problemy to zepsute layouty mobilne i instrukcje wyciekające do treści UI. Żadne z tych problemów nie są unikalne dla Kilo Code; dzieje się tak, gdy jakikolwiek agent działa bez wyselekcjonowanego kontekstu projektowego."}, {"kind": "steps", "items": [{"label": "Dodaj skill estetyczny", "body": "Wyselekcjonowany skill projektowy zmusza agenta do przyjęcia konkretnego kierunku zamiast domyślnego wyglądu."}, {"label": "Zweryfikuj w prawdziwej przeglądarce", "body": "Użyj modelu zdolnego do przetwarzania obrazów, aby renderować i sprawdzać układ na różnych punktach przerwania, dzięki czemu układ nie ulegnie cichemu załamaniu na urządzeniach mobilnych."}, {"label": "Dostarczaj tokeny i odniesienia", "body": "Prawdziwe design tokens i referencyjne screenshoty to najważniejsza dźwignia jakości wyników."}, {"label": "Zakoduj zasady w niestandardowych regułach", "body": "Umieść zasady stylu typu „żadnych kart bohaterów, maksymalnie dwa kroje pisma, hierarchia najpierw brand\" tam, gdzie agent odczytuje je przy każdym uruchomieniu."}]}, {"kind": "p", "text": "Zauważ, że każde rozwiązanie polega na dostarczeniu agentowi wyselekcjonowanego kontekstu projektowego. Ręczne utrzymywanie tego kontekstu dla każdego projektu to właśnie trud, którego Open Design Cię zwalnia."}]}, {"id": "open-design", "heading": "Projektowanie z Kilo Code wewnątrz Open Design", "blocks": [{"kind": "p", "text": "Open Design to warstwa projektowa open-source, o którą prosi powyższy workflow. Traktuje Kilo Code jako adapter first-party i otacza go wyselekcjonowaną biblioteką skill i systemów projektowych, ustrukturyzowanym potokiem renderowania oraz lokalnym interfejsem desktopowym — dzięki czemu kontekst projektowy, który czyni Kilo dobrym, jest dostępny od pierwszego uruchomienia, a nie składany ręcznie za każdym razem. Oba projekty są open-source i local-first, co czyni to połączenie naturalnym wyborem."}, {"kind": "ol", "items": ["Zainstaluj Open Design i wybierz Kilo Code jako swojego agenta.", "Uwierzytelnij się własnym kluczem dostawcy (BYOK) lub bramką Kilo — dane uwierzytelniające pozostają na Twoim komputerze i nigdy nie są przekazywane przez nas.", "Wybierz system projektowy i skill, a następnie generuj prezentacje, prototypy i strony docelowe ze spójnym gustem.", "Każdy artefakt i plik DESIGN.md znajduje się w Twoim własnym repozytorium, a nie w hostowanej chmurze."]}, {"kind": "p", "text": "Ten sam agent Kilo Code, te same klucze — plus prawdziwy, przenośny, open-source'owy workflow projektowy wokół niego. Jest local-first i open-source, więc nic dotyczącego Twojej pracy ani danych uwierzytelniających nie opuszcza Twojej maszyny."}]}], "faqTitle": "Często zadawane pytania", "faq": [{"name": "Czy Kilo Code naprawdę potrafi wykonywać pracę projektową?", "text": "Tak — z umiejętnością estetyczną (aesthetic skill), systemem projektowym i rzeczywistymi obrazami referencyjnymi w kontekście, Kilo Code produkuje responsywny UI o jakości produkcyjnej, a model obsługujący wizję weryfikuje wynik względem referencji. Bez tego kontekstu ma tendencję do domyślnego generycznego wyglądu, co jest luką, którą wypełnia Open Design."}, {"name": "Czy muszę płacić za projektowanie z Kilo Code?", "text": "Kilo Code jest open-source i darmowy do instalacji. Przynosisz własny klucz API dostawcy (BYOK) i płacisz bezpośrednio temu dostawcy lub korzystasz z własnego gateway Kilo po koszcie dostawcy. Open Design nigdy nie pośredniczy w twoich poświadczeniach w żadnym przypadku."}, {"name": "Co sprawia, że Kilo Code jest dobry specyficznie do projektowania?", "text": "Jest model-agnostyczny i open-source, więc możesz sterować nim dowolnym modelem zdolnym do wizji, który najlepiej czyta referencyjne zrzuty ekranu, sprawdzić dokładnie jaki kontekst jest wysyłany i zachować kontrolę nad kosztami i danymi uwierzytelniającymi. Gust nadal pochodzi z systemu projektowego, skill i referencji, które dostarczasz."}, {"name": "Kilo Code czy Claude Code do projektowania frontendowego?", "text": "Oba są mocne. Claude Code jest znany ze specyficznych, świadomych kontekstu kodu decyzji projektowych; przewagą Kilo Code jest bycie open-source i agnostycznym względem modelu z BYOK, więc ty wybierasz model. Wiele zespołów używa obu — Open Design pozwala przełączać agentów bez zmiany przepływu pracy projektowej."}, {"name": "Jak podłączyć Kilo Code do Figma?", "text": "Dodaj serwer MCP Figma z marketplace MCP Kilo lub ustawień MCP. Kilo może wtedy pobrać rzeczywisty kontekst projektowy — komponenty, zmienne, dane layoutu — dzięki czemu wygenerowany kod pasuje do źródła zamiast go przybliżać."}, {"name": "Czy Open Design jest powiązany z Kilo Code?", "text": "Nie. Kilo Code jest produktem firmy Kilo Code, Inc.; Open Design to niezależny projekt open-source, który obsługuje go jako adapter first-party. Oba projekty są open-source, ale są odrębnymi projektami."}, {"name": "Czy moje pliki i poświadczenia są bezpieczne?", "text": "Tak — Open Design jest lokalny i open-source. Twoje pliki, artefakty i DESIGN.md pozostają w Twoim własnym repo, a dane uwierzytelniające dostawcy są używane bezpośrednio przez Twojego agenta, nigdy nie są kierowane przez serwery Open Design."}], "ctaTitle": "Projektuj z Kilo Code, w sposób otwarty.", "ctaBody": "Przynieś własny klucz dostawcy, przechowuj każdy plik lokalnie i uzyskaj wyselekcjonowaną bibliotekę projektową wokół agenta, którego już używasz.", "ctaActions": [{"label": "Użyj Kilo Code w Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Gwiazdka na GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Pobierz aplikację desktopową", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Zobacz wszystkich wspieranych agentów"},
      },
      'vibe': {
        ...en['vibe']!,
        title: "Mistral Vibe CLI do projektowania — Open Design",
        description: "Jak ludzie używają Mistral Vibe CLI do projektowania UI i stron internetowych — jego open-weights modele kodujące Devstral, agentyczną edycję wielu plików, config.toml, MCP i ACP — oraz jak Open Design przekształca Vibe CLI w local-first, open-source'owego agenta projektowego.",
        breadcrumb: "Mistral Vibe CLI",
        label: "Agent · Mistral Vibe CLI",
        heading: "Mistral Vibe CLI do projektowania.",
        lead: "Mistral Vibe CLI to open-source'owy terminalowy agent kodujący Mistral AI, zasilany przez rodzinę modeli Devstral. Edytuje pliki, uruchamia polecenia i działa przez Agent Client Protocol — co czyni go prawdziwym narzędziem projektowym, gdy nadasz mu odniesienia, konwencje i pętlę weryfikacji. Open Design podłącza go do open-source'owego przepływu projektowego: Twój klucz API Mistral (BYOK) lub modele lokalne, Twoje pliki, local-first.",
        rich: {"heroCtaLead": "Open Design zamienia Mistral Vibe CLI w lokalny, open-source'owy agent designu — Twój klucz API Mistral lub lokalne modele Devstral, Twoje pliki, wyselekcjonowana biblioteka Skills i systemów projektowych wokół tego.", "heroCtaActions": [{"label": "Użyj Vibe CLI wewnątrz Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Gwiazdka na GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Pobierz aplikację desktopową", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["Mistral Vibe CLI to open-source'owy (Apache-2.0) agent kodujący Mistral AI dla terminala. Skanuje strukturę plików projektu i status Git w celu uzyskania kontekstu, następnie eksploruje, edytuje i uruchamia zmiany w całej bazie kodu na podstawie zadań w języku naturalnym. Dwie rzeczy czynią go szczególnie interesującym dla projektowania: jest zasilany przez modele kodujące Mistral Devstral, część ekosystemu otwartych wag, który można uruchomić lokalnie lub w chmurze; oraz obsługuje Agent Client Protocol (ACP), dzięki czemu integruje się z edytorami i narzędziami zamiast funkcjonować tylko w jednym terminalu. W połączeniu z odpowiednimi odniesieniami, konwencjami i pętlą weryfikacji buduje prawdziwy, responsywny interfejs użytkownika. To praktyczny, kompleksowy przewodnik po używaniu Vibe CLI do pracy nad UI, frontendem i systemem projektowym oraz po podłączaniu go do ustrukturyzowanego przepływu projektowego z Open Design.", "Omawia, czym właściwie jest Vibe CLI, dlaczego agent kodujący oparty na open-weights pasuje do projektowania, jak skonfigurować go od zera, pętlę reference-to-UI, jak config.toml, MCP i ACP go rozszerzają, jak wypada na tle Codex, Claude Code, Cursor i Gemini CLI, pułapki sprawiające, że wynik AI wygląda generycznie, oraz jak Open Design wypełnia tę lukę jako otwarta, local-first warstwa projektowa — naturalne połączenie, ponieważ oba są open-source i działają na Twoim własnym komputerze."], "heroImage": {"src": "/agents/vibe-design/vibe-design-hero.webp", "alt": "Pętla informacji zwrotnej projektowej Mistral Vibe CLI: agent terminalowy czytający odniesienie, przeglądarka renderująca UI i przestrzeń robocza, ze strzałką informacji zwrotnej zapętloną z powrotem", "caption": "Główna pętla: Vibe CLI odczytuje odniesienia w terminalu, buduje i weryfikuje UI w prawdziwej przeglądarce oraz iteruje względem nich — napędzane modelami kodującymi Devstral od Mistral."}, "tocLabel": "Na tej stronie", "toc": [{"id": "what-is-vibe", "label": "Czym właściwie jest Mistral Vibe CLI"}, {"id": "why-design", "label": "Dlaczego agent kodujący z otwartymi wagami pasuje do projektowania"}, {"id": "setup", "label": "Skonfiguruj Vibe CLI do projektowania (od zera)"}, {"id": "screenshot-workflow", "label": "Przepływ pracy oparty na odwołaniach do UI"}, {"id": "extend", "label": "config.toml, MCP i ACP"}, {"id": "vs", "label": "Vibe CLI vs Codex vs Claude Code vs Cursor vs Gemini CLI"}, {"id": "pitfalls", "label": "Pułapki i wygląd „AI slop\"\n```"}, {"id": "open-design", "label": "Projektowanie z Vibe CLI w Open Design"}, {"id": "faq", "label": "FAQ"}], "sections": [{"id": "what-is-vibe", "heading": "Czym właściwie jest Mistral Vibe CLI", "blocks": [{"kind": "p", "text": "Mistral Vibe CLI to open-source'owy (Apache-2.0) agent kodujący, który Mistral AI dostarcza dla terminala. Zapewnia interaktywny interfejs czatu z narzędziami do manipulacji plikami, przeszukiwania kodu, kontroli wersji i wykonywania poleceń, oraz automatycznie skanuje strukturę plików projektu i status Git, aby dostarczyć agentowi odpowiedni kontekst. Jest zasilany przez modele kodujące Mistral Devstral — planujące i weryfikujące pracę na podstawie zadań w języku naturalnym, zamiast tylko uzupełniać linie."}, {"kind": "p", "text": "W pracy projektowej wyróżniają się dwie właściwości. Działa na rodzinie Devstral Mistral z otwartymi wagami (Devstral 2 i mniejszy Devstral Small 2), więc możesz uruchomić agenta przeciwko Mistral API w chmurze lub przeciwko modelom lokalnym — przydatne do wrażliwej na prywatność lub offline pracy projektowej. I mówi w Agent Client Protocol, więc ten sam agent może sterować edytorami i narzędziami, nie tylko jedną sesją terminalową."}, {"kind": "steps", "items": [{"label": "Pliki konfiguracyjne", "body": "Vibe CLI jest konfigurowany poprzez plik config.toml (na poziomie projektu ./.vibe/config.toml, z opcją zapasową w ~/.vibe/config.toml). To praktyczne miejsce do zakodowania dostawców, wyboru modelu i ustawień projektu."}, {"label": "Wbudowane narzędzia + MCP", "body": "Dostarcza narzędzia do plików, wyszukiwania, kontroli wersji i wykonywania poleceń oraz wspiera serwery MCP (konfigurowane w sekcji [[mcp_servers]]) do dodawania zewnętrznego kontekstu, takiego jak plik Figma na żywo."}, {"label": "BYOK lub lokalnie", "body": "Uwierzytelnij się kluczem API Mistral z konsoli Mistral lub wskaż go na lokalne/kompatybilne modele, aby działał całkowicie offline."}]}, {"kind": "ul", "items": ["Dostawca: Mistral AI", "Dane uwierzytelniające: klucz API Mistral (BYOK) z konsoli Mistral lub modele lokalne/kompatybilne", "Licencja: Apache-2.0, open source"]}]}, {"id": "why-design", "heading": "Dlaczego agent kodujący z otwartymi wagami pasuje do projektowania", "blocks": [{"kind": "p", "text": "Przewaga projektowa Vibe CLI wynika z jego rodziny modeli open-weights i zasięgu protokołów — ale, jak w przypadku każdego agenta, gust nadal musi być dostarczony."}, {"kind": "steps", "items": [{"label": "Modele kodujące Devstral", "body": "Vibe działa na rodzinie Devstral od Mistral, modelach dostrojonych do kodowania, zbudowanych do pracy agentowej, wieloplikowej — dzięki czemu agent edytuje w prawdziwej bazie kodu frontend zamiast emitować izolowane fragmenty."}, {"label": "Otwarte wagi i przyjazne dla lokalnego uruchamiania", "body": "Devstral Small 2 jest wystarczająco mały, by działać na sprzęcie konsumenckim, więc praca projektowa może pozostać w pełni lokalna i offline — referencje i kod nigdy nie muszą opuszczać Twojej maszyny."}, {"label": "Konwencje w config.toml + kontekst", "body": "Konfiguracja projektu i Twoje własne instrukcje kierują agenta na Twoje tokeny, komponenty i rzeczywiste specyfikacje, dzięki czemu pracuje zgodnie z marką zamiast domyślnego wyglądu."}]}, {"kind": "image", "src": "/agents/vibe-design/vibe-design-taste-triangle.webp", "alt": "Diagram pokazujący system projektowy, skill oraz obraz referencyjny zbiegające się w dobry wynik projektowy", "caption": "Smak pochodzi z trzech danych wejściowych, które dostarczasz: systemu projektowego, skill oraz prawdziwych obrazów referencyjnych."}, {"kind": "p", "text": "Lekcja jest taka sama, jakiej uczy każdy agent: Vibe CLI nie ma smaku z definicji. Tworzy dobry design, gdy nadasz mu ograniczenia — system projektowy, estetyczny skill i konkretne odniesienia. Open Design pakuje dokładnie te dane wejściowe, dlatego oba rozwiązania pasują do siebie (więcej poniżej)."}]}, {"id": "setup", "heading": "Skonfiguruj Vibe CLI do pracy projektowej, od zera", "blocks": [{"kind": "p", "text": "Oto pełna ścieżka od czystej maszyny do Vibe CLI, które potrafi budować i weryfikować UI."}, {"kind": "code", "lang": "bash", "code": "# 1. Install Mistral Vibe CLI\nuv tool install mistral-vibe\n# or: pip install mistral-vibe\n\n# 2. Run the setup wizard to register your API key\nvibe --setup     # saves config to ~/.vibe/config.toml and ~/.vibe/.env\n#    or set it directly:  export MISTRAL_API_KEY=...\n\n# 3. Start Vibe in your project\ncd your-project\nvibe\n\n# 4. Wire the Figma MCP server (optional, for design handoff)\n#    add an [[mcp_servers]] entry in your config.toml"}, {"kind": "image", "src": "/agents/vibe-design/vibe-design-setup-flow.webp", "alt": "Pięciokrokowy przepływ konfiguracji: zainstaluj, uwierzytelnij się, skonfiguruj config.toml, dodaj skill, zweryfikuj", "caption": "Sekwencja konfiguracji: instalacja → uwierzytelnienie → skonfigurowanie config.toml → dodanie skill → włączenie weryfikacji w przeglądarce."}, {"kind": "steps", "items": [{"label": "Zakoduj swoje zasady projektowe", "body": "Przechowuj swoje tokens, prymitywy i konwencje tam, gdzie agent je odczytuje, i skieruj na nie Vibe, aby wynik odpowiadał brandowi, zamiast domyślnie przyjmować generyczny wygląd."}, {"label": "Dodaj weryfikację przeglądarki", "body": "Podłącz Playwright lub przeglądarkowy MCP, aby Vibe renderował się w prawdziwej przeglądarce i sprawdzał swoje wyjście w różnych breakpointach, zamiast jedynie potwierdzać, że build przechodzi."}]}]}, {"id": "screenshot-workflow", "heading": "Przepływ pracy oparty na odwołaniach do UI", "blocks": [{"kind": "p", "text": "Najbardziej efektywna pętla projektowania z Vibe CLI polega na przekształceniu jasnej referencji w działający, responsywny interfejs użytkownika i iterowaniu, aż będzie pasował — opierając się na narzędziach agenta do renderowania, inspekcji i korygowania własnego wyniku."}, {"kind": "ol", "items": ["Zacznij od najjaśniejszych referencji, jakie masz — i opisz wiele stanów (desktop i mobile, hover, empty, loading), nie tylko jeden hero shot.", "Bądź precyzyjny w prompcie; niejasne prompty generują ogólnikowy UI nawet z mocnym modelem.", "Przechowuj swój system projektowy i konwencje tam, gdzie Vibe je odczytuje, i wskaż mu, gdzie znajdują się tokens i kanoniczne prymitywy.", "Uruchom serwer deweloperski i pozwól Vibe renderować w prawdziwej przeglądarce, zmieniając rozmiar do breakpointów, aby sprawdzić wynik.", "Iteruj, zlecając Vibe porównanie swojej implementacji z odniesieniami — a nie tylko potwierdzenie, że buduje się."]}, {"kind": "p", "text": "Odwołuj się do plików za pomocą @ (Vibe autouzupełnia ścieżki plików) i steruj poleceniami slash za pomocą /, a następnie podaj konkretne ograniczenia:"}, {"kind": "code", "lang": "bash", "code": "vibe\n# in the prompt:\n> @design-spec.md @tokens.css\n  Implement this design in React + Vite + Tailwind + TypeScript.\n  Reuse my existing design-system components and tokens.\n  Match spacing, layout, and hierarchy; make it responsive.\n  Run the dev server, render it in the browser, and iterate until\n  it matches the references across breakpoints."}, {"kind": "p", "text": "Utrzymuj komunikaty małe i zwięzłe, commituj dobre iteracje i revertuj złe (informując Vibe o revercie), by każde podejście budowało na czystej bazie."}]}, {"id": "extend", "heading": "config.toml, MCP i ACP", "blocks": [{"kind": "p", "text": "Trzy punkty rozszerzenia sprawiają, że Vibe CLI jest praktyczny do długotrwałej pracy projektowej, a wszystkie trzy mapują się czysto na otwarty workflow projektowy."}, {"kind": "steps", "items": [{"label": "config.toml", "body": "Reguły projektu oraz ustawienia dostawcy/modelu znajdują się w pliku config.toml (na poziomie projektu, z rezerwowym ~/.vibe). To trwała siedziba konfiguracji połączenia agenta z projektem, odczytywana przy każdym uruchomieniu."}, {"label": "Serwery MCP", "body": "Skonfiguruj serwery MCP w swoim config.toml ([[mcp_servers]], z transportami HTTP, streamable-HTTP i stdio) — przenośny sposób na wprowadzenie kontekstu projektowego i narzędzi zewnętrznych, w szczególności serwera Figma MCP, które działają ze wszystkimi agentami, nie tylko z Vibe."}, {"label": "Agent Client Protocol", "body": "Vibe mówi ACP, więc ten sam agent może być sterowany z edytorów i innych klientów ACP. Dokładnie tak integruje go Open Design — przez ACP za pomocą binariów vibe-acp."}]}, {"kind": "p", "text": "To przenośne możliwości multi-agent — dokładnie ten rodzaj rzeczy, które Open Design zostało stworzone, aby orkiestrować, zamiast odtwarzać je w każdym projekcie."}]}, {"id": "vs", "heading": "Vibe CLI vs Codex vs Claude Code vs Cursor vs Gemini CLI do projektowania", "blocks": [{"kind": "p", "text": "Nie ma jednego zwycięzcy w pracy projektowej — każdy agent ma inną mocną stronę, a doświadczone zespoły je łączą. Uczciwe podsumowanie:"}, {"kind": "table", "columns": ["Agent", "Siła projektowa", "Najlepsze do"], "rows": [["Mistral Vibe CLI", "Modele kodowania Devstral z otwartymi wagami, które możesz uruchomić lokalnie; Apache-2.0 i natywne dla ACP", "Praca projektowa wrażliwa na prywatność lub offline oraz stos oparty na otwartych wagach"], ["Codex", "Silne wykończenie wizualne z frontendem skill; izolowane asynchroniczne buildy", "Delegowane asynchroniczne buildy i przenośne reguły AGENTS.md"], ["Claude Code", "Konkretne decyzje projektowe (hex, spacing, type) i UX świadomy bazy kodu", "Rozumowanie frontend i refaktoring dużych kontekstów"], ["Cursor", "Wizualna pętla budowania i podglądu z podglądem na żywo i edycją inline", "Zwarta praca iteracyjna nad UI z podglądem wewnątrz IDE"], ["Gemini CLI", "Silne multimodalne rozumienie obrazu i bardzo duże okno kontekstu", "Praca z dużą liczbą zrzutów ekranu i utrzymywanie całego systemu designu w kontekście"]]}, {"kind": "p", "text": "Powtarzający się werdykt społeczności jest taki, że gust pochodzi od ludzi: wszyscy bez wyjątku domyślnie stosują generyczną estetykę bez skills, referencji i ograniczeń. To jest prawdziwy problem do rozwiązania — i ma kształt narzędzia projektowego, a nie modelu."}]}, {"id": "pitfalls", "heading": "Pułapki i jak uniknąć wrażenia „AI slop\"", "blocks": [{"kind": "p", "text": "Najczęstszą skargą na design generowany przez AI jest to, że wygląda generycznie — miękkie gradienty, unoszące się panele, przesadnie zaokrąglone rogi, dramatyczne cienie, klimat Inter-i-fioletu, który „krzyczy, że zrobiło to AI\". Inne zgłaszane problemy obejmują zepsute layouty mobilne i instrukcje wyciekające do treści UI. Żadne z tych problemów nie są unikalne dla Vibe CLI; to jest to, co się dzieje, gdy jakikolwiek agent działa bez starannie dobranego kontekstu designowego."}, {"kind": "steps", "items": [{"label": "Dodaj skill estetyczny", "body": "Wyselekcjonowany skill projektowy zmusza agenta do przyjęcia konkretnego kierunku zamiast domyślnego wyglądu."}, {"label": "Zweryfikuj w prawdziwej przeglądarce", "body": "Niech Vibe renderuje i sprawdza się na punktach przerwania, by układy nie psuły się po cichu na mobile."}, {"label": "Dostarczaj tokeny i odniesienia", "body": "Prawdziwe design tokens i referencyjne screenshoty to najważniejsza dźwignia jakości wyników."}, {"label": "Zakoduj zasady w config i kontekście", "body": "Umieść zasady stylu typu „żadnych kart bohaterów, maksymalnie dwa kroje pisma, hierarchia najpierw brand\" tam, gdzie agent odczytuje je przy każdym uruchomieniu."}]}, {"kind": "p", "text": "Zauważ, że każde rozwiązanie polega na dostarczeniu agentowi wyselekcjonowanego kontekstu projektowego. Ręczne utrzymywanie tego kontekstu dla każdego projektu to właśnie trud, którego Open Design Cię zwalnia."}]}, {"id": "open-design", "heading": "Projektowanie z Vibe CLI wewnątrz Open Design", "blocks": [{"kind": "p", "text": "Open Design to warstwa projektowa open-source, o którą prosi powyższy workflow. Traktuje Mistral Vibe CLI jako adapter first-party — sterując nim przez ACP za pomocą binarki vibe-acp — i otacza go wyselekcjonowaną biblioteką skill i systemów projektowych, ustrukturyzowanym potokiem renderowania oraz lokalnym interfejsem desktopowym. Dzięki temu kontekst projektowy, który czyni Vibe dobrym, jest dostępny od pierwszego uruchomienia, a nie składany ręcznie za każdym razem. Oba projekty są open-source i local-first, co czyni to połączenie naturalnym wyborem."}, {"kind": "ol", "items": ["Zainstaluj Open Design i wybierz Mistral Vibe CLI jako swojego agenta.", "Uwierzytelnij się swoim kluczem API Mistral (BYOK) lub wskaż Vibe na lokalne modele — poświadczenia zostają na twojej maszynie i nigdy nie są proxowane przez nas.", "Wybierz system projektowy i skill, a następnie generuj prezentacje, prototypy i strony docelowe ze spójnym gustem.", "Każdy artefakt i plik DESIGN.md znajduje się w Twoim własnym repozytorium, a nie w hostowanej chmurze."]}, {"kind": "p", "text": "Ten sam agent CLI Vibe, ten sam klucz — plus prawdziwy, przenośny, open-source'owy workflow projektowy wokół niego. Jest local-first i na licencji Apache-2.0, więc nic dotyczącego Twojej pracy ani danych uwierzytelniających nie opuszcza Twojej maszyny."}]}], "faqTitle": "Często zadawane pytania", "faq": [{"name": "Czy Mistral Vibe CLI naprawdę potrafi wykonywać pracę projektową?", "text": "Tak — z umiejętnością estetyczną (aesthetic skill), systemem projektowym i rzeczywistymi referencjami w kontekście, Vibe CLI produkuje responsywny UI o jakości produkcyjnej, a jego modele Devstral edytują w obrębie rzeczywistej bazy kodu frontendu. Bez tego kontekstu ma tendencję do domyślnego generycznego wyglądu, co jest luką, którą wypełnia Open Design."}, {"name": "Jak uwierzytelnić Vibe CLI?", "text": "Uruchom kreatora konfiguracji poleceniem vibe --setup, aby zarejestrować klucz API Mistral (z konsoli Mistral), lub ustaw MISTRAL_API_KEY w swoim środowisku. Można też uruchomić go z lokalnymi lub kompatybilnymi modelami, całkowicie offline. Open Design w żaden sposób nie pośredniczy w przekazywaniu Twoich danych uwierzytelniających."}, {"name": "Co sprawia, że Vibe CLI jest dobry specjalnie do projektowania?", "text": "Jest to agent Apache-2.0, natywny dla ACP, napędzany przez open-weights modele kodujące Devstral firmy Mistral — możesz więc uruchomić go lokalnie dla pracy wymagającej prywatności i edytować w prawdziwym codebase. Ale gust nadal pochodzi z systemu projektowego, skill i referencji, które dostarczasz."}, {"name": "Vibe CLI czy Claude Code do projektowania front-endu?", "text": "Oba są mocne. Claude Code jest znany ze specyficznych, świadomych kontekstu kodu decyzji projektowych; przewagą Vibe CLI jest stos open-weights Devstral, który możesz uruchomić lokalnie oraz licencja Apache-2.0. Wiele zespołów używa obu — Open Design pozwala przełączać agentów bez zmiany przepływu pracy projektowej."}, {"name": "Jak podłączyć Vibe CLI do Figma?", "text": "Dodaj serwer MCP Figma jako wpis [[mcp_servers]] w swoim config.toml. Vibe może wtedy pobrać rzeczywisty kontekst projektowy — komponenty, zmienne, dane layoutu — dzięki czemu wygenerowany kod pasuje do źródła zamiast go przybliżać."}, {"name": "Czy Open Design jest powiązany z Mistral AI?", "text": "Nie. Mistral Vibe CLI jest produktem Mistral AI; Open Design to niezależny projekt open-source, który obsługuje go jako adapter first-party, sterując nim przez ACP. Mistral jest znakiem towarowym Mistral AI."}, {"name": "Czy moje pliki i poświadczenia są bezpieczne?", "text": "Tak — Open Design jest local-first i Apache-2.0. Twoje pliki, artefakty i DESIGN.md pozostają we własnym repozytorium, a Twoje dane uwierzytelniające Mistral są używane bezpośrednio przez Twojego agenta, nigdy nie są kierowane przez serwery Open Design."}], "ctaTitle": "Projektuj z Mistral Vibe CLI, w sposób otwarty.", "ctaBody": "Przynieś własny klucz API Mistral lub modele lokalne, przechowuj każdy plik lokalnie i uzyskaj wyselekcjonowaną bibliotekę projektową wokół agenta, którego już używasz.", "ctaActions": [{"label": "Użyj Vibe CLI wewnątrz Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Gwiazdka na GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Pobierz aplikację desktopową", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Zobacz wszystkich wspieranych agentów"},
      },
      'qoder': {
        ...en['qoder']!,
        title: "Qoder CLI dla designu — Open Design",
        description: "Jak ludzie używają Qoder CLI — agentycznej platformy kodującej Alibaba — do projektowania UI i stron internetowych: jego tryby agent i quest, głębokie rozumienie repozytorium i repo wiki oraz poziomy modeli Lite/Efficient/Auto — oraz jak Open Design przekształca Qoder CLI w local-first, open-source'owego agenta projektowego.",
        breadcrumb: "Qoder CLI",
        label: "Agent · Qoder CLI",
        heading: "Qoder CLI dla designu.",
        lead: "Qoder CLI to agent terminalowy Qoder, agentowej platformy kodującej Alibaba. Rozumie całe repozytorium — architekturę, wzorce i konwencje utrwalone w wiki repo — i wykonuje autonomiczną pracę opartą na specyfikacji, co czyni go prawdziwym narzędziem designerskim, gdy dostarczysz mu referencji, konwencji i pętli weryfikacyjnej. Open Design wplata go w przepływ pracy open-source: Twoje konto Qoder, Twoje pliki, local-first.",
        rich: {"heroCtaLead": "Open Design zamienia Qoder CLI w lokalny, open-source'owy agent designu — Twoje konto Qoder, Twoje pliki, wyselekcjonowana biblioteka Skills i systemów projektowych wokół tego.", "heroCtaActions": [{"label": "Użyj Qoder CLI wewnątrz Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Gwiazdka na GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Pobierz aplikację desktopową", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["Qoder CLI to agent terminalowy Qoder, agentowej platformy kodującej Alibaba. Dwie rzeczy czynią go interesującym konkretnie dla designu: buduje głęboki kontekst repozytorium — architekturę, wzorce projektowe i konwencje, które destyluje do wiki repozytorium — więc ponownie wykorzystuje Twoje rzeczywiste prymitywy zamiast wymyślać jednorazowe style; i wykonuje autonomiczne zadania oparte na specyfikacji, które planują, implementują i weryfikują zadanie od końca do końca, a nie tylko uzupełniają linie. W parze z odpowiednimi referencjami, konwencjami i pętlą weryfikacyjną buduje prawdziwy, responsywny UI. To praktyczny przewodnik end-to-end po użyciu Qoder CLI do pracy nad UI, frontendem i systemami designu oraz po wpleceniu go w ustrukturyzowany przepływ pracy designerskiej z Open Design.", "Omawia, czym właściwie jest Qoder CLI, dlaczego jego rozumienie repozytorium i agentywne questy pasują do projektowania, jak skonfigurować go od zera, pętlę reference-to-UI, jak reguły, MCP i wiki repozytorium go rozszerzają, jak wypada na tle Codex, Claude Code, Cursor i Gemini CLI, pułapki sprawiające, że wynik AI wygląda generycznie, oraz jak Open Design wypełnia tę lukę jako otwarta, local-first warstwa projektowa wokół agenta, którego już używasz."], "heroImage": {"src": "/agents/qoder-design/qoder-design-hero.webp", "alt": "Pętla informacji zwrotnej projektowania Qoder CLI: agent terminalowy odczytujący obraz referencyjny z kontekstem wiki repozytorium, przeglądarka renderująca UI oraz obszar roboczy, z strzałką informacji zwrotnej zamykającą pętlę", "caption": "Podstawowa pętla: Qoder CLI czyta Twoje referencje i kontekst repozytorium w terminalu, buduje i weryfikuje interfejs w prawdziwej przeglądarce i iteruje w oparciu o nie."}, "tocLabel": "Na tej stronie", "toc": [{"id": "what-is-qoder", "label": "Czym właściwie jest Qoder CLI"}, {"id": "why-design", "label": "Dlaczego kontekst agentowy + repozytorium pasuje do projektowania"}, {"id": "setup", "label": "Skonfiguruj Qoder CLI do projektowania (od zera)"}, {"id": "screenshot-workflow", "label": "Przepływ pracy oparty na odwołaniach do UI"}, {"id": "extend", "label": "Reguły, MCP oraz wiki repozytorium"}, {"id": "vs", "label": "Qoder CLI vs Codex vs Claude Code vs Cursor vs Gemini CLI"}, {"id": "pitfalls", "label": "Pułapki i wygląd „AI slop\"\n```"}, {"id": "open-design", "label": "Projektowanie z Qoder CLI w Open Design"}, {"id": "faq", "label": "FAQ"}], "sections": [{"id": "what-is-qoder", "heading": "Czym właściwie jest Qoder CLI", "blocks": [{"kind": "p", "text": "Qoder to agentyczna platforma kodowania od Alibaba — środowisko programistyczne AI, dostępne jako aplikacja desktopowa i CLI, które rozumie rzeczywiste bazy kodu i obsługuje zadania deweloperskie end-to-end. Qoder CLI przenosi ten silnik do terminala: czyta repozytorium, edytuje pliki, wykonuje polecenia shell i realizuje zadania z języka naturalnego zamiast tylko uzupełniać linie. Loguje się kontem Qoder."}, {"kind": "p", "text": "W pracy projektowej wyróżniają się dwie właściwości. Qoder buduje głęboki kontekst twojego repozytorium — architekturę, wzorce projektowe i konwencje destylowane w wiki repozytorium — więc uzasadnia output w twoich rzeczywistych prymitywach. I uruchamia agentowy, sterowany specyfikacją przepływ pracy: zarysowujesz co chcesz, a on planuje, implementuje i weryfikuje pracę, włącznie z wieloma krokami."}, {"kind": "steps", "items": [{"label": "Tryby Agent i Quest", "body": "Tryb Agent to konwersacyjne programowanie w parach z punktami kontrolnymi human-in-the-loop; tryb Quest deleguje dłuższą, wieloetapową pracę autonomicznemu agentowi, który planuje, implementuje i weryfikuje sam siebie — naturalne miejsce do przekazania zadania projektowego opartego na specyfikacji."}, {"label": "Wiki repozytorium + MCP", "body": "Qoder destyluje Twoją bazę kodu do wiki repozytorium z architekturą i konwencjami oraz obsługuje serwery MCP, aby włączyć kontekst zewnętrzny, taki jak aktywny plik Figma."}, {"label": "Poziomy modeli", "body": "Qoder CLI udostępnia poziomy Lite, Efficient i Auto; Auto pozwala jego harmonogramowi wybrać model dla każdego zadania, więc nie musisz ręcznie zarządzać wyborem modelu."}]}, {"kind": "ul", "items": ["Dostawca: Alibaba", "Dane uwierzytelniające: konto Qoder (logowanie przez przeglądarkę lub osobisty token dostępu Qoder do użytku nieinteraktywnego)", "Poziomy modeli: Lite, Efficient, Auto"]}]}, {"id": "why-design", "heading": "Dlaczego agentowy, świadomy repozytorium agent pasuje do projektowania", "blocks": [{"kind": "p", "text": "Przewaga designerska Qoder CLI wynika z dwóch właściwości — ale, jak w przypadku każdego agenta, gust wciąż trzeba dostarczyć."}, {"kind": "steps", "items": [{"label": "Głębokie rozumienie repozytorium", "body": "Ponieważ Qoder buduje kontekst na całej bazie kodu i destyluje go do wiki repozytorium, agent ponownie wykorzystuje Twoje istniejące komponenty i tokens zamiast wymyślać jednorazowe style dla każdego ekranu."}, {"label": "Autonomiczne questy oparte na specyfikacji", "body": "Tryb Quest przekształca pisaną specyfikację w zaplanowany, zaimplementowany i samoweryfikowany rezultat, więc zadanie projektowe przebiega end-to-end zamiast kończyć się na pierwszym szkicu."}, {"label": "Konwencje odczytywane przez agenta", "body": "Reguły projektu (plus serwer MCP Figma) wskazują agentowi twoje tokeny, komponenty i rzeczywiste specyfikacje, dzięki czemu pracuje zgodnie z marką zamiast domyślnego wyglądu."}]}, {"kind": "image", "src": "/agents/qoder-design/qoder-design-taste-triangle.webp", "alt": "Diagram pokazujący system projektowy, skill oraz obraz referencyjny zbiegające się w dobry wynik projektowy", "caption": "Smak pochodzi z trzech danych wejściowych, które dostarczasz: systemu projektowego, skill oraz prawdziwych obrazów referencyjnych."}, {"kind": "p", "text": "Lekcja jest taka sama, jakiej uczy każdy agent: Qoder CLI nie ma smaku z definicji. Tworzy dobry design, gdy nadasz mu ograniczenia — system projektowy, estetyczny skill i konkretne odniesienia. Open Design pakuje dokładnie te dane wejściowe, dlatego oba rozwiązania pasują do siebie (więcej poniżej)."}]}, {"id": "setup", "heading": "Skonfiguruj Qoder CLI do pracy projektowej, od zera", "blocks": [{"kind": "p", "text": "Oto pełna ścieżka od czystej maszyny do Qoder CLI, które potrafi budować i weryfikować UI."}, {"kind": "code", "lang": "bash", "code": "# 1. Install Qoder CLI (Node 20+)\nnpm install -g @qoder-ai/qodercli\n# (macOS/Linux via Homebrew also available)\n\n# 2. Verify the install\nqodercli --version\n\n# 3. Start it in your project and sign in on first run\ncd your-project\nqodercli          # then /login — sign in via browser or a Qoder access token\n\n# 4. Pick a model tier for the session\n#    Lite, Efficient, or Auto (Auto lets the scheduler choose per task)"}, {"kind": "image", "src": "/agents/qoder-design/qoder-design-setup-flow.webp", "alt": "Pięciokrokowy przepływ konfiguracji: zainstaluj, uwierzytelnij się, skonfiguruj reguły, dodaj skill, zweryfikuj", "caption": "Sekwencja konfiguracji: instalacja → logowanie → konfiguracja reguł projektu → dodanie skill → włączenie weryfikacji w przeglądarce."}, {"kind": "steps", "items": [{"label": "Zakoduj swoje zasady projektowe", "body": "Umieść swoje tokeny, prymitywy i konwencje tam, gdzie agent je odczytuje, aby wynik pasował do marki zamiast domyślnie przyjmować ogólny wygląd. Wiki repozytorium Qoder pomaga utrzymać ten kontekst aktualnym."}, {"label": "Dodaj weryfikację przeglądarki", "body": "Podłącz Playwright lub MCP przeglądarki, aby Qoder renderował w prawdziwej przeglądarce i sprawdzał wynik na różnych breakpointach zamiast tylko potwierdzać, że build przechodzi."}]}]}, {"id": "screenshot-workflow", "heading": "Przepływ pracy oparty na odwołaniach do UI", "blocks": [{"kind": "p", "text": "Najbardziej efektywna pętla projektowania z Qoder CLI polega na przekształceniu referencji w działający, responsywny interfejs użytkownika i iterowaniu, aż będzie pasował — opierając się na kontekście repozytorium agenta i rzeczywistej pętli weryfikacji do porównywania wyniku z referencją."}, {"kind": "ol", "items": ["Zacznij od najjaśniejszych referencji wizualnych, jakie masz — i uwzględnij wiele stanów (desktop i mobile, hover, empty, loading), nie tylko jeden hero shot.", "Bądź precyzyjny w prompcie; niejasne prompty generują ogólnikowy UI nawet z wydajnym agentem.", "Wskaż Qoder na swój system projektowy i konwencje, oraz powiedz mu, gdzie znajdują się tokens i kanoniczne prymitywy.", "Uruchom serwer deweloperski i pozwól Qoder renderować w prawdziwej przeglądarce, zmieniając rozmiar do breakpointów, aby sprawdzić wynik.", "Iteruj, zlecając Qoder porównanie swojej implementacji z odniesieniami — a nie tylko potwierdzenie, że buduje się."]}, {"kind": "p", "text": "Napisz zadanie jako jasną specyfikację i pozwól questowi je przeprowadzić, podając konkretne ograniczenia:"}, {"kind": "code", "lang": "bash", "code": "qodercli\n# in the prompt:\n> Implement this design from reference-desktop.png and\n  reference-mobile.png in React + Vite + Tailwind + TypeScript.\n  Reuse my existing design-system components and tokens.\n  Match spacing, layout, and hierarchy; make it responsive.\n  Render it in the browser and iterate until it matches the references\n  across breakpoints."}, {"kind": "p", "text": "Utrzymuj komunikaty małe i zwięzłe, commituj dobre iteracje i revertuj złe (informując Qoder o revercie), by każde podejście budowało na czystej bazie."}]}, {"id": "extend", "heading": "Reguły, MCP oraz wiki repozytorium", "blocks": [{"kind": "p", "text": "Trzy punkty rozszerzenia sprawiają, że Qoder CLI jest praktyczny w trwałej pracy projektowej, i wszystkie trzy czytelnie mapują się na otwarty przepływ pracy projektowej."}, {"kind": "steps", "items": [{"label": "Reguły projektu", "body": "Zakoduj swoje konwencje projektowe jako trwałe zasady projektowe, które agent odczytuje przy każdym uruchomieniu — dom dla tokens, prymitywów i list kontrolnych weryfikacji."}, {"label": "Serwery MCP", "body": "MCP to przenośny sposób na wprowadzenie kontekstu projektowego i zewnętrznych narzędzi, w tym najważniejszego serwera Figma MCP, i działa na różnych agentach, nie tylko Qoder."}, {"label": "Repozytorium wiki", "body": "Wiki repozytorium Qoder automatycznie destyluje architekturę i konwencje, więc agent ciągle ponownie używa Twoich rzeczywistych komponentów zamiast uczyć się bazy kodu przy każdym zadaniu."}]}, {"kind": "p", "text": "To przenośne możliwości multi-agent — dokładnie ten rodzaj rzeczy, które Open Design zostało stworzone, aby orkiestrować, zamiast odtwarzać je w każdym projekcie."}]}, {"id": "vs", "heading": "Qoder CLI vs Codex vs Claude Code vs Cursor vs Gemini CLI dla designu", "blocks": [{"kind": "p", "text": "Nie ma jednego zwycięzcy w pracy projektowej — każdy agent ma inną mocną stronę, a doświadczone zespoły je łączą. Uczciwe podsumowanie:"}, {"kind": "table", "columns": ["Agent", "Siła projektowa", "Najlepsze do"], "rows": [["Qoder CLI", "Głębokie rozumienie repozytorium z wiki repo i spec-driven, autonomicznymi questami; poziomy Lite/Efficient/Auto", "Praca mocno osadzona w kontekście repozytorium oraz delegowanie wieloetapowych budów sterowanych specyfikacją"], ["Codex", "Silne wykończenie wizualne z frontendem skill; izolowane asynchroniczne buildy", "Delegowane asynchroniczne buildy i przenośne reguły AGENTS.md"], ["Claude Code", "Konkretne decyzje projektowe (hex, spacing, type) i UX świadomy bazy kodu", "Rozumowanie frontend i refaktoring dużych kontekstów"], ["Cursor", "Wizualna pętla budowania i podglądu z podglądem na żywo i edycją inline", "Zwarta praca iteracyjna nad UI z podglądem wewnątrz IDE"], ["Gemini CLI", "Silne wielomodalne rozumienie obrazu i kontekst 1M tokens; darmowy tier", "Praca z dużą liczbą zrzutów ekranu i utrzymywanie całego systemu designu w kontekście"]]}, {"kind": "p", "text": "Powtarzający się werdykt społeczności jest taki, że gust pochodzi od ludzi: wszyscy bez wyjątku domyślnie stosują generyczną estetykę bez skills, referencji i ograniczeń. To jest prawdziwy problem do rozwiązania — i ma kształt narzędzia projektowego, a nie modelu."}]}, {"id": "pitfalls", "heading": "Pułapki i jak uniknąć wrażenia „AI slop\"", "blocks": [{"kind": "p", "text": "Najczęstszą skargą na wygenerowany przez AI design jest to, że wygląda generycznie — miękkie gradienty, unoszące się panele, przesadnie zaokrąglone rogi, dramatyczne cienie, klimat Inter-i-fioletu, który „krzyczy, że zrobił to AI\". Inne zgłaszane problemy obejmują zepsute layouty mobilne i instrukcje wyciekające do tekstów UI. Żadne z tych zjawisk nie są charakterystyczne wyłącznie dla Qoder CLI; to po prostu efekt działania dowolnego agenta bez starannie przygotowanego kontekstu designu."}, {"kind": "steps", "items": [{"label": "Dodaj skill estetyczny", "body": "Wyselekcjonowany skill projektowy zmusza agenta do przyjęcia konkretnego kierunku zamiast domyślnego wyglądu."}, {"label": "Zweryfikuj w prawdziwej przeglądarce", "body": "Renderuj i sprawdzaj na różnych breakpointach, aby układy nie psuły się po cichu na urządzeniach mobilnych."}, {"label": "Dostarczaj tokeny i odniesienia", "body": "Prawdziwe design tokens i referencyjne screenshoty to najważniejsza dźwignia jakości wyników."}, {"label": "Zakoduj zasady, które agent odczytuje", "body": "Umieść zasady stylu takie jak „no hero cards, max two typefaces, brand-first hierarchy\" w regułach projektu i wiki repozytorium, gdzie agent je odczytuje przy każdym uruchomieniu."}]}, {"kind": "p", "text": "Zauważ, że każde rozwiązanie polega na dostarczeniu agentowi wyselekcjonowanego kontekstu projektowego. Ręczne utrzymywanie tego kontekstu dla każdego projektu to właśnie trud, którego Open Design Cię zwalnia."}]}, {"id": "open-design", "heading": "Projektowanie z Qoder CLI wewnątrz Open Design", "blocks": [{"kind": "p", "text": "Open Design to warstwa projektowa open-source, o którą prosi powyższy workflow. Traktuje Qoder CLI jako adapter first-party i otacza go wyselekcjonowaną biblioteką skill i systemów projektowych, ustrukturyzowanym potokiem renderowania oraz lokalnym interfejsem desktopowym — dzięki czemu kontekst projektowy, który czyni Qoder dobrym, jest dostępny od pierwszego uruchomienia, a nie składany ręcznie za każdym razem. Open Design jest local-first, więc Twoja praca pozostaje na Twoim własnym komputerze."}, {"kind": "ol", "items": ["Zainstaluj Open Design i wybierz Qoder CLI jako swojego agenta.", "Uwierzytelnij się swoim kontem Qoder — poświadczenia zostają na twojej maszynie i nigdy nie są proxowane przez nas.", "Wybierz system projektowy i skill, a następnie generuj prezentacje, prototypy i strony docelowe ze spójnym gustem.", "Każdy artefakt i plik DESIGN.md znajduje się w Twoim własnym repozytorium, a nie w hostowanej chmurze."]}, {"kind": "p", "text": "Ten sam agent CLI Qoder, to samo konto — plus prawdziwy, przenośny, open-source'owy workflow projektowy wokół niego. Jest local-first i na licencji Apache-2.0, więc nic dotyczącego Twojej pracy ani danych uwierzytelniających nie opuszcza Twojej maszyny."}]}], "faqTitle": "Często zadawane pytania", "faq": [{"name": "Czy Qoder CLI naprawdę potrafi wykonywać pracę projektową?", "text": "Tak — z umiejętnością estetyczną (aesthetic skill), systemem projektowym i rzeczywistymi obrazami referencyjnymi w kontekście, Qoder CLI produkuje responsywny UI o jakości produkcyjnej, a jego głębokie rozumienie repozytorium pomaga w ponownym wykorzystaniu rzeczywistych komponentów. Bez tego kontekstu ma tendencję do domyślnego generycznego wyglądu, co jest luką, którą wypełnia Open Design."}, {"name": "Jak uwierzytelnić Qoder CLI?", "text": "Uruchom qodercli i użyj /login, aby zalogować się do swojego konta Qoder przez przeglądarkę, lub podaj osobisty token dostępu Qoder dla środowisk nieinteraktywnych. Open Design nigdy nie pośredniczy w przekazywaniu Twoich danych uwierzytelniających — agent używa ich bezpośrednio."}, {"name": "Co sprawia, że Qoder CLI jest dobry specyficznie do projektowania?", "text": "Dwie rzeczy: buduje głęboki kontekst repozytorium — architekturę, konwencje i wiki repo — dzięki czemu używa ponownie twoich rzeczywistych prymitywów, a jego questy oparte na specyfikacjach realizują zadanie designerskie od początku do końca. Obie pomagają, ale gust nadal pochodzi z systemu designu, skill i referencji, które dostarczasz."}, {"name": "Czym są warstwy modeli Lite, Efficient i Auto?", "text": "Qoder CLI pozwala wybrać warstwę modelu: Lite, Efficient lub Auto. Auto pozwala harmonogramowi Qoder wybrać model na zadanie, więc nie zarządzasz wyborem modelu ręcznie. Wybierz warstwę pasującą do zadania; Auto to rozsądny domyślny wybór."}, {"name": "Jak podłączyć Qoder CLI do Figma?", "text": "Dodaj serwer MCP Figma do konfiguracji MCP Qoder. Qoder może wtedy pobrać rzeczywisty kontekst projektowy — komponenty, zmienne, dane layoutu — dzięki czemu wygenerowany kod pasuje do źródła zamiast go przybliżać."}, {"name": "Czy Open Design jest powiązany z Qoder lub Alibaba?", "text": "Nie. Qoder jest produktem Alibaba; Open Design to niezależny projekt open-source, który obsługuje go jako adapter first-party. Qoder jest znakiem towarowym odpowiedniego właściciela."}, {"name": "Czy moje pliki i poświadczenia są bezpieczne?", "text": "Tak — Open Design jest local-first i Apache-2.0. Twoje pliki, artefakty i DESIGN.md pozostają we własnym repozytorium, a Twoje dane uwierzytelniające Qoder są używane bezpośrednio przez Twojego agenta, nigdy nie są kierowane przez serwery Open Design."}], "ctaTitle": "Projektuj z Qoder CLI, w sposób otwarty.", "ctaBody": "Przynieś własne konto Qoder, przechowuj każdy plik lokalnie i uzyskaj wyselekcjonowaną bibliotekę projektową wokół agenta, którego już używasz.", "ctaActions": [{"label": "Użyj Qoder CLI wewnątrz Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Gwiazdka na GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Pobierz aplikację desktopową", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Zobacz wszystkich wspieranych agentów"},
      },
    },
  };
}
